_PORTFOLIO_SUMMARY_CACHE = {}
_PORTFOLIO_COVERAGE_CACHE = {}
_NAV_BENCHMARK_OVERRIDE_CACHE = {"ts": 0, "data": {}}
_PORTFOLIO_SUMMARY_TTL_SEC = 30 * 60
_UPCOMING_DIVIDENDS_CACHE = {}
_DIVIDEND_CALENDAR_CACHE = {}
_EARNINGS_CALENDAR_CACHE = {}
_DIVIDEND_GROWTH_CACHE = {}
_DIVIDEND_EVENT_TTL_SEC = 60 * 60
_EARNINGS_EVENT_TTL_SEC = 6 * 60 * 60
_DIVIDEND_GROWTH_TTL_SEC = 12 * 60 * 60
_CEFCONNECT_CACHE = {}
_CEFCONNECT_TTL_SEC = 30 * 60
_CEFCONNECT_BASE_URL = "https://www.cefconnect.com"
_FX_RATE_CACHE = {}
_FX_RATE_TTL_SEC = 6 * 60 * 60

# Full price+dividend history per ticker for the Reinvestment Impact page.
# Each yfinance history(period="max") call is slow; cache the raw frame.
_REINVEST_HISTORY_CACHE = {}
_REINVEST_HISTORY_TTL_SEC = 6 * 60 * 60

# ETF/Stock comparer chart data. Each request makes several slow yfinance calls
# (price + dividend downloads, benchmark download, .info), so cache the rendered
# response, the shared benchmark frame, and per-ticker .info dicts. The Refresh
# button bumps a nonce in the query string, which busts the response cache.
_ETF_SCREEN_DATA_CACHE = {}
_ETF_SCREEN_DATA_TTL_SEC = 10 * 60
_ETF_SCREEN_MARKET_CACHE = {}
_ETF_SCREEN_MARKET_TTL_SEC = 10 * 60
_ETF_SCREEN_BENCH_CACHE = {}
_ETF_SCREEN_BENCH_TTL_SEC = 10 * 60
_YF_INFO_CACHE = {}
_YF_INFO_TTL_SEC = 30 * 60
_YF_DIVIDENDS_CACHE = {}
_YF_DIVIDENDS_TTL_SEC = 30 * 60
_OFFICIAL_DISTRIBUTION_CACHE = {}
_OFFICIAL_DISTRIBUTION_TTL_SEC = 30 * 60
_RESEARCH_RETURN_SERIES_CACHE = {}
_RESEARCH_RETURN_SERIES_TTL_SEC = 30 * 60


def _cached_yf_info(yf_ticker_obj, symbol):
    """Return yfinance .info for a symbol, cached for a while (it's a slow call)."""
    cached = _cache_get(_YF_INFO_CACHE, symbol, _YF_INFO_TTL_SEC)
    if cached is not None:
        return cached
    try:
        info = yf_ticker_obj.info or {}
    except Exception:
        info = {}
    if info:
        _cache_set(_YF_INFO_CACHE, symbol, info)
    return info


def _cached_yf_dividends(yf_ticker_obj, symbol):
    """Return a ticker's full dividend history without repeating slow calls."""
    cached = _cache_get(_YF_DIVIDENDS_CACHE, symbol, _YF_DIVIDENDS_TTL_SEC)
    if cached is not None:
        return cached
    try:
        dividends = yf_ticker_obj.dividends
    except Exception:
        dividends = pd.Series(dtype=float)
    if dividends is None:
        dividends = pd.Series(dtype=float)
    _cache_set(_YF_DIVIDENDS_CACHE, symbol, dividends)
    return dividends


def _cache_value(value):
    if value is None:
        return None
    try:
        if pd.isna(value):
            return None
    except Exception:
        pass
    if hasattr(value, "isoformat"):
        return value.isoformat()
    return value


def _rows_signature(rows, columns):
    return tuple(
        tuple(_cache_value(row[col]) for col in columns)
        for row in rows
    )


def _cache_get(cache, key, ttl=_DIVIDEND_EVENT_TTL_SEC):
    entry = cache.get(key)
    if not entry:
        return None
    ts, payload = entry
    if time.time() - ts > ttl:
        cache.pop(key, None)
        return None
    return payload


def _cache_set(cache, key, payload):
    cache[key] = (time.time(), payload)


def _clear_dividend_event_caches():
    _UPCOMING_DIVIDENDS_CACHE.clear()
    _DIVIDEND_CALENDAR_CACHE.clear()


@app.errorhandler(500)
def handle_500(e):
    return jsonify({"error": "Internal server error", "detail": str(e)}), 500


@app.errorhandler(sqlite3.OperationalError)
def handle_sqlite_operational_error(e):
    detail = str(e)
    if "database is locked" in detail.lower():
        return jsonify({
            "error": "Database is busy. Wait a moment and try again.",
            "detail": detail,
        }), 503
    return jsonify({"error": "Database error", "detail": detail}), 500


@app.errorhandler(Exception)
def handle_api_exception(e):
    if isinstance(e, HTTPException):
        return e
    if request.path.startswith("/api/"):
        return jsonify({"error": "Internal server error", "detail": str(e)}), 500
    raise e


@app.errorhandler(404)
def handle_404(e):
    return jsonify({"error": "Not found"}), 404

