def _cash_flow_scope():
    aggregate_id = _request_aggregate_id()
    if aggregate_id is not None:
        return "aggregate", aggregate_id
    return "profile", get_profile_id()


def _cash_flow_plan_for_scope(conn, plan_id=None):
    """Return a plan that belongs to the current profile/aggregate selection."""
    scope_type, scope_id = _cash_flow_scope()
    if plan_id in (None, ""):
        return _get_or_create_default_cash_flow_plan(
            conn, scope_type, scope_id
        )
    try:
        plan_id = int(plan_id)
    except (TypeError, ValueError):
        return None
    return conn.execute(
        """SELECT * FROM cash_flow_plans
           WHERE id = ? AND scope_type = ? AND scope_id = ?""",
        (plan_id, scope_type, scope_id),
    ).fetchone()


def _cash_flow_touch_plan(conn, plan_id):
    conn.execute(
        """UPDATE cash_flow_plans
           SET version = version + 1, updated_at = CURRENT_TIMESTAMP
           WHERE id = ?""",
        (int(plan_id),),
    )


def _cash_flow_item_result(conn, row):
    item = _serialize_cash_flow_item(row)
    schedule = _next_cash_flow_bill(row)
    item["current_due_date"] = schedule["due_date"]
    item["current_pay_date"] = schedule["pay_date"]
    item["paid"] = False
    item["paid_at"] = None
    if schedule["due_date"]:
        payment = conn.execute(
            """SELECT paid_at
               FROM cash_flow_item_payments
               WHERE item_id = ? AND due_date = ?""",
            (row["id"], schedule["due_date"]),
        ).fetchone()
        if payment:
            item["paid"] = True
            item["paid_at"] = payment["paid_at"]
    return item


def _cash_flow_portfolio_snapshot(conn, profile_ids):
    ids = list(dict.fromkeys(int(pid) for pid in profile_ids if pid is not None))
    if not ids:
        return {
            "value": 0.0,
            "annual_income": 0.0,
            "profile_count": 0,
            "holdings": [],
        }
    placeholders = ",".join("?" * len(ids))
    rows = conn.execute(
        f"""SELECT a.ticker, a.description, a.classification_type,
                   a.current_value, a.quantity, a.current_price,
                   a.estim_payment_per_year, a.approx_monthly_income,
                   g.etf_category, g.etf_strategy, o.fund_kind
            FROM all_account_info a
            LEFT JOIN general_scanner_cache g ON g.ticker = a.ticker
            LEFT JOIN etf_type_overrides o ON o.ticker = a.ticker
            WHERE a.profile_id IN ({placeholders})
              AND COALESCE(a.quantity, 0) > 0""",
        ids,
    ).fetchall()
    override_rows = conn.execute(
        f"""SELECT ticker, bucket
            FROM income_overrides
            WHERE profile_id IN ({placeholders})""",
        ids,
    ).fetchall()
    income_overrides = {row["ticker"]: row["bucket"] for row in override_rows}

    holdings_by_ticker = {}
    for row in rows:
        ticker = str(row["ticker"] or "").strip().upper()
        if not ticker:
            continue
        current_value = float(row["current_value"] or 0)
        if current_value <= 0:
            current_value = float(row["quantity"] or 0) * float(
                row["current_price"] or 0
            )
        estimated = float(row["estim_payment_per_year"] or 0)
        if estimated <= 0:
            estimated = float(row["approx_monthly_income"] or 0) * 12.0
        holding = holdings_by_ticker.setdefault(
            ticker,
            {
                "ticker": ticker,
                "description": row["description"] or "",
                "classification_type": row["classification_type"] or "",
                "etf_category": row["etf_category"] or "",
                "etf_strategy": row["etf_strategy"] or "",
                "fund_kind": row["fund_kind"] or "",
                "value": 0.0,
                "annual_income": 0.0,
            },
        )
        holding["value"] += max(0.0, current_value)
        holding["annual_income"] += max(0.0, estimated)
        for field in (
            "description",
            "classification_type",
            "etf_category",
            "etf_strategy",
            "fund_kind",
        ):
            if not holding[field] and row[field]:
                holding[field] = row[field]

    holdings = []
    for holding in holdings_by_ticker.values():
        override = income_overrides.get(holding["ticker"])
        if override and override != "Excluded":
            holding["income_bucket"] = override
        else:
            holding["income_bucket"] = _get_income_bucket(
                holding["ticker"],
                holding["classification_type"],
                holding["description"],
            )
        holding["value"] = round(holding["value"], 2)
        holding["annual_income"] = round(holding["annual_income"], 2)
        holding["scenario_type"] = _classify_cash_flow_holding(holding)
        holdings.append(holding)
    holdings.sort(key=lambda row: (-row["annual_income"], -row["value"], row["ticker"]))

    value = sum(row["value"] for row in holdings)
    annual_income = sum(row["annual_income"] for row in holdings)
    return {
        "value": round(value, 2),
        "annual_income": round(annual_income, 2),
        "profile_count": len(ids),
        "holdings": holdings,
    }


def _cash_flow_month_or_current(raw=None):
    value = raw or datetime.date.today().strftime("%Y-%m")
    return _parse_cash_flow_month(value).strftime("%Y-%m")


@app.route("/api/cash-flow/plans", methods=["GET", "POST"])
def cash_flow_plans():
    conn = get_connection()
    ensure_tables_exist(conn)
    scope_type, scope_id = _cash_flow_scope()

    if request.method == "POST":
        data = request.get_json(silent=True) or {}
        name = str(data.get("name", "")).strip()
        if not name:
            conn.close()
            return jsonify(error="Plan name is required."), 400
        if len(name) > 100:
            conn.close()
            return jsonify(error="Plan name must be 100 characters or less."), 400
        try:
            cur = conn.execute(
                """INSERT INTO cash_flow_plans
                   (name, scope_type, scope_id, is_default)
                   VALUES (?, ?, ?, 0)""",
                (name, scope_type, scope_id),
            )
            conn.execute(
                """INSERT INTO cash_flow_settings (plan_id)
                   VALUES (?)""",
                (cur.lastrowid,),
            )
            conn.commit()
            row = conn.execute(
                "SELECT * FROM cash_flow_plans WHERE id = ?", (cur.lastrowid,)
            ).fetchone()
        except sqlite3.IntegrityError:
            conn.rollback()
            conn.close()
            return jsonify(error="A cash-flow plan with that name already exists."), 409
        result = _serialize_cash_flow_plan(row)
        conn.close()
        return jsonify(plan=result), 201

    _get_or_create_default_cash_flow_plan(conn, scope_type, scope_id)
    rows = conn.execute(
        """SELECT * FROM cash_flow_plans
           WHERE scope_type = ? AND scope_id = ?
           ORDER BY is_default DESC, name, id""",
        (scope_type, scope_id),
    ).fetchall()
    result = [_serialize_cash_flow_plan(row) for row in rows]
    conn.close()
    return jsonify(plans=result)


@app.route("/api/cash-flow/plans/<int:plan_id>", methods=["PUT", "DELETE"])
def cash_flow_plan_detail(plan_id):
    conn = get_connection()
    ensure_tables_exist(conn)
    plan = _cash_flow_plan_for_scope(conn, plan_id)
    if not plan:
        conn.close()
        return jsonify(error="Cash-flow plan not found."), 404

    if request.method == "DELETE":
        count = conn.execute(
            """SELECT COUNT(*) AS count FROM cash_flow_plans
               WHERE scope_type = ? AND scope_id = ?""",
            (plan["scope_type"], plan["scope_id"]),
        ).fetchone()["count"]
        if count <= 1:
            conn.close()
            return jsonify(error="The only cash-flow plan cannot be deleted."), 400
        item_ids = [
            row["id"]
            for row in conn.execute(
                "SELECT id FROM cash_flow_items WHERE plan_id = ?", (plan_id,)
            ).fetchall()
        ]
        if item_ids:
            placeholders = ",".join("?" * len(item_ids))
            conn.execute(
                f"DELETE FROM cash_flow_item_payments WHERE item_id IN ({placeholders})",
                item_ids,
            )
            conn.execute(
                f"DELETE FROM cash_flow_month_overrides WHERE item_id IN ({placeholders})",
                item_ids,
            )
        conn.execute("DELETE FROM cash_flow_items WHERE plan_id = ?", (plan_id,))
        conn.execute("DELETE FROM cash_flow_settings WHERE plan_id = ?", (plan_id,))
        conn.execute("DELETE FROM cash_flow_plans WHERE id = ?", (plan_id,))
        conn.commit()
        conn.close()
        return jsonify(ok=True)

    data = request.get_json(silent=True) or {}
    name = str(data.get("name", "")).strip()
    if not name:
        conn.close()
        return jsonify(error="Plan name is required."), 400
    try:
        conn.execute(
            """UPDATE cash_flow_plans
               SET name = ?, version = version + 1,
                   updated_at = CURRENT_TIMESTAMP
               WHERE id = ?""",
            (name[:100], plan_id),
        )
        conn.commit()
    except sqlite3.IntegrityError:
        conn.rollback()
        conn.close()
        return jsonify(error="A cash-flow plan with that name already exists."), 409
    row = conn.execute(
        "SELECT * FROM cash_flow_plans WHERE id = ?", (plan_id,)
    ).fetchone()
    result = _serialize_cash_flow_plan(row)
    conn.close()
    return jsonify(plan=result)


@app.route("/api/cash-flow/items", methods=["GET", "POST"])
def cash_flow_items():
    conn = get_connection()
    ensure_tables_exist(conn)
    if request.method == "GET":
        plan = _cash_flow_plan_for_scope(conn, request.args.get("plan_id"))
        if not plan:
            conn.close()
            return jsonify(error="Cash-flow plan not found."), 404
        rows = conn.execute(
            """SELECT * FROM cash_flow_items
               WHERE plan_id = ?
               ORDER BY kind, active DESC, name, id""",
            (plan["id"],),
        ).fetchall()
        result = [_cash_flow_item_result(conn, row) for row in rows]
        conn.close()
        return jsonify(items=result)

    data = request.get_json(silent=True) or {}
    plan = _cash_flow_plan_for_scope(conn, data.get("plan_id"))
    if not plan:
        conn.close()
        return jsonify(error="Cash-flow plan not found."), 404
    try:
        item = _validate_cash_flow_item(data)
    except ValueError as exc:
        conn.close()
        return jsonify(error=str(exc)), 400
    cur = conn.execute(
        """INSERT INTO cash_flow_items
           (plan_id, kind, name, category, amount_cents, frequency,
            start_date, end_date, due_date, pay_date, essential, tax_rate_pct,
            annual_change_pct, notes, active)
           VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
        (
            plan["id"],
            item["kind"],
            item["name"],
            item["category"],
            item["amount_cents"],
            item["frequency"],
            item["start_date"],
            item["end_date"],
            item["due_date"],
            item["pay_date"],
            item["essential"],
            item["tax_rate_pct"],
            item["annual_change_pct"],
            item["notes"],
            item["active"],
        ),
    )
    _cash_flow_touch_plan(conn, plan["id"])
    conn.commit()
    row = conn.execute(
        "SELECT * FROM cash_flow_items WHERE id = ?", (cur.lastrowid,)
    ).fetchone()
    result = _cash_flow_item_result(conn, row)
    conn.close()
    return jsonify(item=result), 201


@app.route("/api/cash-flow/items/<int:item_id>", methods=["PUT", "DELETE"])
def cash_flow_item_detail(item_id):
    conn = get_connection()
    ensure_tables_exist(conn)
    row = conn.execute(
        """SELECT i.*, p.scope_type, p.scope_id
           FROM cash_flow_items i
           JOIN cash_flow_plans p ON p.id = i.plan_id
           WHERE i.id = ?""",
        (item_id,),
    ).fetchone()
    scope_type, scope_id = _cash_flow_scope()
    if (
        not row
        or row["scope_type"] != scope_type
        or int(row["scope_id"]) != int(scope_id)
    ):
        conn.close()
        return jsonify(error="Cash-flow item not found."), 404

    if request.method == "DELETE":
        conn.execute(
            "DELETE FROM cash_flow_item_payments WHERE item_id = ?", (item_id,)
        )
        conn.execute(
            "DELETE FROM cash_flow_month_overrides WHERE item_id = ?", (item_id,)
        )
        conn.execute("DELETE FROM cash_flow_items WHERE id = ?", (item_id,))
        _cash_flow_touch_plan(conn, row["plan_id"])
        conn.commit()
        conn.close()
        return jsonify(ok=True)

    data = request.get_json(silent=True) or {}
    try:
        item = _validate_cash_flow_item(data)
    except ValueError as exc:
        conn.close()
        return jsonify(error=str(exc)), 400
    conn.execute(
        """UPDATE cash_flow_items
           SET kind = ?, name = ?, category = ?, amount_cents = ?,
               frequency = ?, start_date = ?, end_date = ?, due_date = ?,
               pay_date = ?, essential = ?, tax_rate_pct = ?,
               annual_change_pct = ?, notes = ?, active = ?,
               updated_at = CURRENT_TIMESTAMP
           WHERE id = ?""",
        (
            item["kind"],
            item["name"],
            item["category"],
            item["amount_cents"],
            item["frequency"],
            item["start_date"],
            item["end_date"],
            item["due_date"],
            item["pay_date"],
            item["essential"],
            item["tax_rate_pct"],
            item["annual_change_pct"],
            item["notes"],
            item["active"],
            item_id,
        ),
    )
    _cash_flow_touch_plan(conn, row["plan_id"])
    conn.commit()
    updated = conn.execute(
        "SELECT * FROM cash_flow_items WHERE id = ?", (item_id,)
    ).fetchone()
    result = _cash_flow_item_result(conn, updated)
    conn.close()
    return jsonify(item=result)


@app.route("/api/cash-flow/items/<int:item_id>/move", methods=["POST"])
def cash_flow_item_move(item_id):
    """Move one expense or additional-income item to another profile."""
    conn = get_connection()
    ensure_tables_exist(conn)
    row = conn.execute(
        """SELECT i.*, p.scope_type, p.scope_id
           FROM cash_flow_items i
           JOIN cash_flow_plans p ON p.id = i.plan_id
           WHERE i.id = ?""",
        (item_id,),
    ).fetchone()
    scope_type, scope_id = _cash_flow_scope()
    if (
        not row
        or row["scope_type"] != scope_type
        or int(row["scope_id"]) != int(scope_id)
    ):
        conn.close()
        return jsonify(error="Cash-flow item not found."), 404

    data = request.get_json(silent=True) or {}
    target_scope_type = str(data.get("target_scope_type") or "").strip().lower()
    target_scope_id_raw = data.get("target_scope_id")
    if not target_scope_type and data.get("target_profile_id") not in (None, ""):
        # Backward compatibility for clients that predate aggregate destinations.
        target_scope_type = "profile"
        target_scope_id_raw = data.get("target_profile_id")
    if target_scope_type not in {"profile", "aggregate"}:
        conn.close()
        return jsonify(error="Choose a destination account."), 400
    try:
        target_scope_id = int(target_scope_id_raw)
    except (TypeError, ValueError):
        conn.close()
        return jsonify(error="Choose a destination account."), 400
    target_table = "profiles" if target_scope_type == "profile" else "aggregates"
    target_scope = conn.execute(
        f"SELECT id, name FROM {target_table} WHERE id = ?",
        (target_scope_id,),
    ).fetchone()
    if not target_scope:
        conn.close()
        return jsonify(error="Destination account not found."), 404
    if scope_type == target_scope_type and int(scope_id) == target_scope_id:
        conn.close()
        return jsonify(error="Choose a different destination account."), 400

    source_plan_id = int(row["plan_id"])
    target_plan = _get_or_create_default_cash_flow_plan(
        conn, target_scope_type, target_scope_id
    )
    conn.execute(
        """UPDATE cash_flow_items
           SET plan_id = ?, updated_at = CURRENT_TIMESTAMP
           WHERE id = ?""",
        (target_plan["id"], item_id),
    )
    _cash_flow_touch_plan(conn, source_plan_id)
    _cash_flow_touch_plan(conn, target_plan["id"])
    conn.commit()
    updated = conn.execute(
        "SELECT * FROM cash_flow_items WHERE id = ?", (item_id,)
    ).fetchone()
    result = _cash_flow_item_result(conn, updated)
    target = {
        "scope_type": target_scope_type,
        "scope_id": int(target_scope["id"]),
        "scope_name": target_scope["name"],
        "profile_id": (
            int(target_scope["id"]) if target_scope_type == "profile" else None
        ),
        "profile_name": (
            target_scope["name"] if target_scope_type == "profile" else None
        ),
        "aggregate_id": (
            int(target_scope["id"]) if target_scope_type == "aggregate" else None
        ),
        "aggregate_name": (
            target_scope["name"] if target_scope_type == "aggregate" else None
        ),
        "plan_id": int(target_plan["id"]),
        "plan_name": target_plan["name"],
    }
    conn.close()
    return jsonify(ok=True, item=result, target=target)


@app.route(
    "/api/cash-flow/items/<int:item_id>/months/<month>",
    methods=["PUT", "DELETE"],
)
def cash_flow_item_month_override(item_id, month):
    try:
        month = _parse_cash_flow_month(month).strftime("%Y-%m")
    except ValueError as exc:
        return jsonify(error=str(exc)), 400
    conn = get_connection()
    ensure_tables_exist(conn)
    row = conn.execute(
        """SELECT i.plan_id, p.scope_type, p.scope_id
           FROM cash_flow_items i
           JOIN cash_flow_plans p ON p.id = i.plan_id
           WHERE i.id = ?""",
        (item_id,),
    ).fetchone()
    scope_type, scope_id = _cash_flow_scope()
    if (
        not row
        or row["scope_type"] != scope_type
        or int(row["scope_id"]) != int(scope_id)
    ):
        conn.close()
        return jsonify(error="Cash-flow item not found."), 404
    if request.method == "DELETE":
        conn.execute(
            "DELETE FROM cash_flow_month_overrides WHERE item_id = ? AND month = ?",
            (item_id, month),
        )
    else:
        data = request.get_json(silent=True) or {}
        amount_cents = None
        if data.get("amount") not in (None, ""):
            try:
                amount_cents = _cash_flow_money_to_cents(data.get("amount"))
            except ValueError as exc:
                conn.close()
                return jsonify(error=str(exc)), 400
        conn.execute(
            """INSERT INTO cash_flow_month_overrides
               (item_id, month, amount_cents, excluded, notes)
               VALUES (?, ?, ?, ?, ?)
               ON CONFLICT(item_id, month) DO UPDATE SET
                   amount_cents = excluded.amount_cents,
                   excluded = excluded.excluded,
                   notes = excluded.notes,
                   updated_at = CURRENT_TIMESTAMP""",
            (
                item_id,
                month,
                amount_cents,
                1 if data.get("excluded") else 0,
                str(data.get("notes", "") or "")[:1000] or None,
            ),
        )
    _cash_flow_touch_plan(conn, row["plan_id"])
    conn.commit()
    conn.close()
    return jsonify(ok=True)


@app.route(
    "/api/cash-flow/items/<int:item_id>/payments/<due_date>",
    methods=["PUT"],
)
def cash_flow_item_payment(item_id, due_date):
    """Toggle one due occurrence without tying it to the selected view month."""
    try:
        due_date = datetime.date.fromisoformat(str(due_date)).isoformat()
    except (TypeError, ValueError):
        return jsonify(error="Due date must use YYYY-MM-DD format."), 400
    conn = get_connection()
    ensure_tables_exist(conn)
    row = conn.execute(
        """SELECT i.*, p.scope_type, p.scope_id
           FROM cash_flow_items i
           JOIN cash_flow_plans p ON p.id = i.plan_id
           WHERE i.id = ?""",
        (item_id,),
    ).fetchone()
    scope_type, scope_id = _cash_flow_scope()
    if (
        not row
        or row["scope_type"] != scope_type
        or int(row["scope_id"]) != int(scope_id)
    ):
        conn.close()
        return jsonify(error="Cash-flow item not found."), 404
    schedule = _next_cash_flow_bill(row)
    if schedule["due_date"] != due_date:
        conn.close()
        return jsonify(error="This bill has rolled to a new due date. Refresh and try again."), 409
    data = request.get_json(silent=True) or {}
    if data.get("paid"):
        conn.execute(
            """INSERT INTO cash_flow_item_payments (item_id, due_date)
               VALUES (?, ?)
               ON CONFLICT(item_id, due_date) DO UPDATE SET
                   paid_at = CURRENT_TIMESTAMP""",
            (item_id, due_date),
        )
    else:
        conn.execute(
            """DELETE FROM cash_flow_item_payments
               WHERE item_id = ? AND due_date = ?""",
            (item_id, due_date),
        )
    _cash_flow_touch_plan(conn, row["plan_id"])
    conn.commit()
    updated = conn.execute(
        "SELECT * FROM cash_flow_items WHERE id = ?", (item_id,)
    ).fetchone()
    result = _cash_flow_item_result(conn, updated)
    conn.close()
    return jsonify(ok=True, item=result)


@app.route("/api/cash-flow/settings", methods=["GET", "PUT"])
def cash_flow_settings():
    conn = get_connection()
    ensure_tables_exist(conn)
    plan_id = (
        request.args.get("plan_id")
        if request.method == "GET"
        else (request.get_json(silent=True) or {}).get("plan_id")
    )
    plan = _cash_flow_plan_for_scope(conn, plan_id)
    if not plan:
        conn.close()
        return jsonify(error="Cash-flow plan not found."), 404
    if request.method == "GET":
        result = _cash_flow_settings_for_plan(conn, plan["id"])
        conn.commit()
        conn.close()
        return jsonify(settings=result)

    data = request.get_json(silent=True) or {}
    try:
        horizon = int(data.get("horizon_years", 20))
        inflation = float(data.get("expense_inflation_pct", 3))
        tax_rate = float(data.get("portfolio_tax_pct", 15))
        starting_cash_cents = _cash_flow_money_to_cents(
            data.get("starting_cash", 0), "Starting cash"
        )
    except (TypeError, ValueError) as exc:
        conn.close()
        return jsonify(error=str(exc)), 400
    surplus_mode = str(data.get("surplus_mode", "reinvest")).lower()
    if not 1 <= horizon <= 50:
        conn.close()
        return jsonify(error="Horizon must be between 1 and 50 years."), 400
    if not -10 <= inflation <= 30:
        conn.close()
        return jsonify(error="Expense inflation must be between -10 and 30."), 400
    if not 0 <= tax_rate <= 95:
        conn.close()
        return jsonify(error="Portfolio tax rate must be between 0 and 95."), 400
    if surplus_mode not in {"cash", "reinvest"}:
        conn.close()
        return jsonify(error="Surplus mode must be cash or reinvest."), 400
    conn.execute(
        """INSERT INTO cash_flow_settings
           (plan_id, horizon_years, expense_inflation_pct, portfolio_tax_pct,
            starting_cash_cents, surplus_mode, updated_at)
           VALUES (?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
           ON CONFLICT(plan_id) DO UPDATE SET
               horizon_years = excluded.horizon_years,
               expense_inflation_pct = excluded.expense_inflation_pct,
               portfolio_tax_pct = excluded.portfolio_tax_pct,
               starting_cash_cents = excluded.starting_cash_cents,
               surplus_mode = excluded.surplus_mode,
               updated_at = CURRENT_TIMESTAMP""",
        (
            plan["id"],
            horizon,
            inflation,
            tax_rate,
            starting_cash_cents,
            surplus_mode,
        ),
    )
    _cash_flow_touch_plan(conn, plan["id"])
    conn.commit()
    result = _cash_flow_settings_for_plan(conn, plan["id"])
    conn.close()
    return jsonify(settings=result)


@app.route("/api/cash-flow/summary", methods=["GET"])
def cash_flow_summary():
    conn = get_connection()
    ensure_tables_exist(conn)
    plan = _cash_flow_plan_for_scope(conn, request.args.get("plan_id"))
    if not plan:
        conn.close()
        return jsonify(error="Cash-flow plan not found."), 404
    try:
        month = _cash_flow_month_or_current(request.args.get("month"))
    except ValueError as exc:
        conn.close()
        return jsonify(error=str(exc)), 400
    settings = _cash_flow_settings_for_plan(conn, plan["id"])
    series = _expand_cash_flow_plan(conn, plan["id"], month, 12)
    current = series[0]
    is_aggregate, profile_ids = get_profile_filter()
    portfolio_profile_ids = _cash_profile_ids_for_read(
        conn, is_aggregate, profile_ids
    )
    portfolio = _cash_flow_portfolio_snapshot(conn, portfolio_profile_ids)
    portfolio_monthly_gross = portfolio["annual_income"] / 12.0
    portfolio_monthly_net = portfolio_monthly_gross * (
        1.0 - settings["portfolio_tax_pct"] / 100.0
    )
    total_spendable = portfolio_monthly_net + current["additional_income_net"]
    gap = total_spendable - current["expenses"]
    average_expenses = sum(row["expenses"] for row in series) / len(series)
    average_income = sum(row["additional_income_net"] for row in series) / len(series)
    result = {
        **current,
        "plan": _serialize_cash_flow_plan(plan),
        "portfolio_value": portfolio["value"],
        "portfolio_profile_count": portfolio["profile_count"],
        "portfolio_annual_income": portfolio["annual_income"],
        "portfolio_monthly_income_gross": round(portfolio_monthly_gross, 2),
        "portfolio_monthly_income_net": round(portfolio_monthly_net, 2),
        "total_spendable_income": round(total_spendable, 2),
        "surplus_shortfall": round(gap, 2),
        "coverage_ratio": (
            round(total_spendable / current["expenses"], 4)
            if current["expenses"] > 0
            else None
        ),
        "covered": gap >= -0.005,
        "normalized_monthly_expenses": round(average_expenses, 2),
        "normalized_portfolio_required": round(
            max(0.0, average_expenses - average_income), 2
        ),
    }
    conn.commit()
    conn.close()
    return jsonify(summary=result)


@app.route("/api/cash-flow/series", methods=["GET"])
def cash_flow_series():
    conn = get_connection()
    ensure_tables_exist(conn)
    plan = _cash_flow_plan_for_scope(conn, request.args.get("plan_id"))
    if not plan:
        conn.close()
        return jsonify(error="Cash-flow plan not found."), 404
    try:
        start_month = _cash_flow_month_or_current(request.args.get("start_month"))
        months = max(1, min(600, int(request.args.get("months", 12))))
        series = _expand_cash_flow_plan(conn, plan["id"], start_month, months)
    except (ValueError, TypeError) as exc:
        conn.close()
        return jsonify(error=str(exc)), 400
    conn.commit()
    conn.close()
    return jsonify(
        plan=_serialize_cash_flow_plan(plan),
        start_month=start_month,
        months=months,
        series=series,
    )


@app.route("/api/cash-flow/simulate", methods=["POST"])
def cash_flow_simulate():
    data = request.get_json(silent=True) or {}
    conn = get_connection()
    ensure_tables_exist(conn)
    plan = _cash_flow_plan_for_scope(conn, data.get("plan_id"))
    if not plan:
        conn.close()
        return jsonify(error="Cash-flow plan not found."), 404
    settings = _cash_flow_settings_for_plan(conn, plan["id"])
    try:
        start_month = _cash_flow_month_or_current(data.get("start_month"))
        horizon = int(data.get("horizon_years", settings["horizon_years"]))
    except (TypeError, ValueError) as exc:
        conn.close()
        return jsonify(error=str(exc)), 400
    if not 1 <= horizon <= 50:
        conn.close()
        return jsonify(error="Horizon must be between 1 and 50 years."), 400

    months = horizon * 12
    series = _expand_cash_flow_plan(conn, plan["id"], start_month, months)
    is_aggregate, profile_ids = get_profile_filter()
    portfolio_profile_ids = _cash_profile_ids_for_read(
        conn, is_aggregate, profile_ids
    )
    portfolio = _cash_flow_portfolio_snapshot(conn, portfolio_profile_ids)
    results = []
    for scenario in ("bullish", "neutral", "bearish"):
        for include_income in (True, False):
            results.append(
                _simulate_cash_flow_sustainability(
                    series,
                    portfolio_value=portfolio["value"],
                    annual_portfolio_income=portfolio["annual_income"],
                    portfolio_holdings=portfolio["holdings"],
                    portfolio_tax_pct=settings["portfolio_tax_pct"],
                    starting_cash=settings["starting_cash"],
                    surplus_mode=settings["surplus_mode"],
                    scenario=scenario,
                    include_additional_income=include_income,
                )
            )
    scenario_assumptions = {
        scenario: _cash_flow_scenario_assumptions(
            portfolio["holdings"], scenario
        )
        for scenario in ("bullish", "neutral", "bearish")
    }
    portfolio_public = {
        key: value for key, value in portfolio.items() if key != "holdings"
    }
    portfolio_public["distribution_yield_pct"] = round(
        portfolio["annual_income"] / portfolio["value"] * 100.0, 2
    ) if portfolio["value"] > 0 else 0.0
    conn.commit()
    conn.close()
    return jsonify(
        plan=_serialize_cash_flow_plan(plan),
        settings=settings,
        start_month=start_month,
        horizon_years=horizon,
        portfolio=portfolio_public,
        scenario_assumptions=scenario_assumptions,
        results=results,
    )


def _dividend_payment_profile_ids_for_read(conn, profile_ids):
    ids = []
    for pid in profile_ids or [1]:
        pid = int(pid)
        if pid == 1:
            source_ids = _get_owner_source_profile_ids(conn)
            ids.extend(source_ids or [1])
        else:
            ids.append(pid)
    return list(dict.fromkeys(ids))


def _dividend_payment_totals_by_ticker(conn, profile_ids):
    """Sum dividend_payments per ticker, scoped to the current holding lot.

    A ticker can be sold and later re-bought in the same account. The
    dividend_payments ledger keeps every historical payment, including ones
    from before the current purchase_date. Joining against the live
    all_account_info row and requiring payment_date >= purchase_date keeps
    those pre-purchase payments from inflating total_divs_received (and thus
    total_return) for a freshly (re)opened position.
    """
    ids = list(dict.fromkeys(int(pid) for pid in (profile_ids or []) if pid is not None))
    if not ids:
        return {}
    placeholders = ",".join("?" * len(ids))
    rows = conn.execute(
        f"""SELECT dp.ticker, COALESCE(SUM(dp.amount), 0) AS total_divs_received
            FROM dividend_payments dp
            JOIN all_account_info a
              ON a.ticker = dp.ticker AND a.profile_id = dp.profile_id
            WHERE dp.profile_id IN ({placeholders})
              AND (a.purchase_date IS NULL OR dp.payment_date >= a.purchase_date)
            GROUP BY dp.ticker""",
        ids,
    ).fetchall()
    return {
        row["ticker"]: _num_or_zero(row["total_divs_received"])
        for row in rows
    }


def _apply_dividend_payment_total_floor(rows, payment_totals):
    if not payment_totals:
        return rows
    for row in rows:
        ticker = row.get("ticker")
        payment_total = _num_or_zero(payment_totals.get(ticker))
        if payment_total <= 0:
            continue
        row["total_divs_received"] = max(
            _num_or_zero(row.get("total_divs_received")),
            payment_total,
        )
    return rows


def _cumulative_invested_cost_by_ticker(conn, profile_ids):
    """Total out-of-pocket cash invested per ticker, from BUY transactions.

    Used as the "original cost" denominator for paid-for-itself and total return.
    total_divs_received is a LIFETIME figure (every dividend the ledger ever
    recorded), but the current cost basis only reflects the shares still held.
    When a position has been trimmed, dividing lifetime dividends by the residual
    basis produces absurd percentages (a near-sold holding shows tens of
    thousands of percent). The cumulative cash invested is the comparable
    denominator. DRIP reinvestment buys are excluded so only out-of-pocket
    capital counts toward "original cost".

    A ticker can also be sold to zero and later re-bought as a fresh lot (e.g.
    EGGY: sold down to zero in Sept 2025, re-bought 2026-06-29). BUY
    transactions from that earlier, closed-out lot aren't capital behind the
    current position, so — exactly like the dividend-payment floor above —
    join against the live holding row and only count BUYs on/after its
    purchase_date. Otherwise a freshly reopened position with zero dividends
    could show a *lower* total return than price return (invested inflated
    above the tiny fresh cost basis), which is never mathematically valid when
    dividends are non-negative.
    """
    ids = list(dict.fromkeys(int(pid) for pid in (profile_ids or []) if pid is not None))
    if not ids:
        return {}
    placeholders = ",".join("?" * len(ids))
    rows = conn.execute(
        f"""SELECT t.ticker, COALESCE(SUM(t.shares * t.price_per_share), 0) AS invested
            FROM transactions t
            JOIN all_account_info a
              ON a.ticker = t.ticker AND a.profile_id = t.profile_id
            WHERE t.profile_id IN ({placeholders})
              AND UPPER(t.transaction_type) = 'BUY'
              AND COALESCE(t.notes, '') NOT LIKE '%DRIP%'
              AND COALESCE(t.notes, '') NOT LIKE '%reinvest%'
              AND (a.purchase_date IS NULL OR t.transaction_date >= a.purchase_date)
            GROUP BY t.ticker""",
        ids,
    ).fetchall()
    return {row["ticker"]: _num_or_zero(row["invested"]) for row in rows}


def _realized_gains_by_ticker(conn, profile_ids):
    """Sum realized gains per ticker, scoped to the current holding lot.

    all_account_info.realized_gains is a running total accumulated across a
    ticker+profile's ENTIRE transaction history by _rollup_transactions, with
    no purchase_date scoping. For a position that was fully sold and later
    re-bought (e.g. EGGY: closed out Sept 2025, re-bought 2026-06-29), that
    total still includes gains/losses realized on the old, closed-out lot —
    the same "old lot bleeds into new lot" issue already fixed above for
    dividend payments and invested cost. Recompute from the per-transaction
    realized_gain ledger instead (already excludes transfers — see
    _is_transfer_txn), joined to the live holding row and scoped to
    transaction_date >= purchase_date, so a freshly reopened position doesn't
    inherit a prior lot's trading history. It's also, incidentally, the fix
    for the 'Owner' aggregate row's own realized_gains column always reading
    0 (never synced from its real sub-accounts) — this sums the sub-accounts
    directly instead of trusting that column.
    """
    ids = list(dict.fromkeys(int(pid) for pid in (profile_ids or []) if pid is not None))
    if not ids:
        return {}
    placeholders = ",".join("?" * len(ids))
    rows = conn.execute(
        f"""SELECT t.ticker, COALESCE(SUM(t.realized_gain), 0) AS realized
            FROM transactions t
            JOIN all_account_info a
              ON a.ticker = t.ticker AND a.profile_id = t.profile_id
            WHERE t.profile_id IN ({placeholders})
              AND t.realized_gain IS NOT NULL
              AND (a.purchase_date IS NULL OR t.transaction_date >= a.purchase_date)
            GROUP BY t.ticker""",
        ids,
    ).fetchall()
    return {row["ticker"]: _num_or_zero(row["realized"]) for row in rows}


def _resolve_aggregate_profile(ticker, profile_ids):
    """For aggregate writes, find the profile with the largest position for a ticker."""
    conn = get_connection()
    placeholders = ",".join("?" * len(profile_ids))
    row = conn.execute(
        f"SELECT profile_id FROM all_account_info WHERE ticker = ? AND profile_id IN ({placeholders}) ORDER BY quantity DESC LIMIT 1",
        [ticker] + profile_ids,
    ).fetchone()
    conn.close()
    if row:
        return row["profile_id"] if isinstance(row, dict) else row[0]
    return profile_ids[0]


def _get_write_profile_id():
    """Get a single profile_id for write operations, resolving aggregate if needed."""
    is_agg, pids = get_profile_filter()
    if is_agg:
        return pids[0]  # default; caller should use _resolve_aggregate_profile for ticker-specific ops
    return pids[0]


def rows_to_dicts(rows):
    """Convert sqlite3.Row results to a list of dicts."""
    return [dict(r) for r in rows]


def _num_or_zero(value):
    try:
        return float(value or 0)
    except (TypeError, ValueError):
        return 0.0


def _apply_holding_display_quantities(rows):
    """Ensure holdings API rows include user-facing DRIP/base share figures."""
    for row in rows:
        qty = _num_or_zero(row.get("quantity"))
        drip_shares = _num_or_zero(row.get("shares_bought_from_dividend"))
        row["base_quantity"] = round(max(qty - drip_shares, 0.0), 6)


def _repair_drip_tracking_for_profiles(conn, profile_ids):
    """Backfill visible holdings whose saved transaction history has DRIP buys."""
    if not profile_ids:
        return 0
    placeholders = ",".join("?" * len(profile_ids))
    rows = conn.execute(
        f"""SELECT DISTINCT t.ticker, t.profile_id
            FROM transactions t
            JOIN all_account_info a
              ON a.ticker = t.ticker AND a.profile_id = t.profile_id
            WHERE t.profile_id IN ({placeholders})
              AND t.transaction_type = 'BUY'
              AND (t.notes LIKE '%[DRIP]%' OR LOWER(COALESCE(t.notes, '')) LIKE '%reinvest%')
              AND COALESCE(a.quantity, 0) > 1e-9""",
        profile_ids,
    ).fetchall()
    for row in rows:
        ticker = row["ticker"] if isinstance(row, dict) else row[0]
        profile_id = row["profile_id"] if isinstance(row, dict) else row[1]
        _refresh_drip_tracking_from_transactions(ticker, profile_id, conn)
    repaired = len(rows)

    fallback_rows = conn.execute(
        f"""SELECT ticker, profile_id
            FROM all_account_info
            WHERE profile_id IN ({placeholders})
              AND reinvest = 'Y'
              AND COALESCE(quantity, 0) > 1e-9
              AND COALESCE(shares_bought_from_dividend, 0) <= 1e-9
              AND COALESCE(total_cash_reinvested, 0) <= 1e-9""",
        profile_ids,
    ).fetchall()
    for row in fallback_rows:
        ticker = row["ticker"] if isinstance(row, dict) else row[0]
        profile_id = row["profile_id"] if isinstance(row, dict) else row[1]
        if _estimate_drip_tracking_from_dividend_history(ticker, profile_id, conn):
            repaired += 1
    return repaired


def _estimate_drip_tracking_from_dividend_history(ticker, profile_id, conn):
    """Estimate DRIP tracking when a broker feed lacks reinvestment buy lots."""
    holding = conn.execute(
        """SELECT quantity, current_price, price_paid, reinvest,
                  shares_bought_from_dividend, total_cash_reinvested,
                  ytd_divs, total_divs_received, dividend_paid
           FROM all_account_info
           WHERE ticker = ? AND profile_id = ?""",
        (ticker, profile_id),
    ).fetchone()
    if not holding or (holding["reinvest"] if isinstance(holding, dict) else holding[3]) != "Y":
        return False

    existing_shares = _num_or_zero(holding["shares_bought_from_dividend"] if isinstance(holding, dict) else holding[4])
    existing_cash = _num_or_zero(holding["total_cash_reinvested"] if isinstance(holding, dict) else holding[5])
    if existing_shares > 1e-9 or existing_cash > 1e-9:
        return False

    tagged_buys = conn.execute(
        "SELECT COUNT(*) FROM transactions "
        "WHERE ticker = ? AND profile_id = ? AND transaction_type = 'BUY' "
        "AND (notes LIKE '%[DRIP]%' OR LOWER(COALESCE(notes, '')) LIKE '%reinvest%')",
        (ticker, profile_id),
    ).fetchone()[0]
    if tagged_buys:
        return False

    payment_row = conn.execute(
        "SELECT COALESCE(SUM(amount), 0) FROM dividend_payments "
        "WHERE ticker = ? AND profile_id = ? AND amount > 0",
        (ticker, profile_id),
    ).fetchone()
    payment_cash = _num_or_zero(payment_row[0] if payment_row else 0)
    # Only estimate reinvestment from dividends that have actually been
    # received. dividend_paid is a current-period accrual set on the ex-date
    # (before the cash is paid), so counting it here fabricated DRIP shares for
    # holdings whose latest distribution has not yet paid. Use cumulative
    # received figures instead.
    fallback_cash = max(
        payment_cash,
        _num_or_zero(holding["total_divs_received"] if isinstance(holding, dict) else holding[7]),
        _num_or_zero(holding["ytd_divs"] if isinstance(holding, dict) else holding[6]),
    )
    if fallback_cash <= 1e-9:
        return False

    qty = _num_or_zero(holding["quantity"] if isinstance(holding, dict) else holding[0])
    price = _num_or_zero(holding["current_price"] if isinstance(holding, dict) else holding[1])
    if price <= 1e-9:
        price = _num_or_zero(holding["price_paid"] if isinstance(holding, dict) else holding[2])
    if qty <= 1e-9 or price <= 1e-9:
        return False

    drip_shares = min(fallback_cash / price, qty)
    drip_cash = min(fallback_cash, drip_shares * price)
    conn.execute(
        "UPDATE all_account_info SET shares_bought_from_dividend = ?, "
        "total_cash_reinvested = ? WHERE ticker = ? AND profile_id = ?",
        (round(drip_shares, 6), round(drip_cash, 2), ticker, profile_id),
    )
    return True


def _basis_mode():
    mode = (request.args.get("basis_mode") or "original").strip().lower()
    return "broker_adjusted" if mode in {"broker", "broker_adjusted", "adjusted"} else "original"


def _basis_total_expr(alias="a"):
    prefix = f"{alias}." if alias else ""
    if _basis_mode() == "broker_adjusted":
        price = f"COALESCE({prefix}broker_price_paid, {prefix}price_paid, {prefix}original_price_paid)"
        stored = f"COALESCE({prefix}broker_purchase_value, {prefix}purchase_value, {prefix}original_purchase_value)"
    else:
        price = f"COALESCE({prefix}original_price_paid, {prefix}price_paid, {prefix}broker_price_paid)"
        stored = f"COALESCE({prefix}original_purchase_value, {prefix}purchase_value, {prefix}broker_purchase_value)"
    # The explicit total is authoritative. It can legitimately differ from
    # quantity x average price when the displayed share count includes DRIP
    # shares or when a broker supplies an adjusted total with more precision.
    # Import and transaction rollups refresh the stored total after position
    # changes; derive it only for legacy/incomplete rows where no total exists.
    return (f"COALESCE({stored}, "
            f"CASE WHEN {price} IS NOT NULL AND {prefix}quantity IS NOT NULL "
            f"THEN ROUND({prefix}quantity * {price}, 2) END)")


def _first_not_none(*values):
    for v in values:
        if v is not None:
            return v
    return None


def _basis_fallback_total(row, mode=None):
    mode = mode or _basis_mode()
    if mode == "broker_adjusted":
        stored = _first_not_none(row.get("broker_purchase_value"), row.get("purchase_value"), row.get("original_purchase_value"))
    else:
        stored = _first_not_none(row.get("original_purchase_value"), row.get("purchase_value"), row.get("broker_purchase_value"))
    if stored is not None:
        return stored

    # Legacy/incomplete row fallback: reconstruct a total only when no explicit
    # cost-basis total is available in any basis field.
    price = _basis_fallback_price(row, mode)
    qty = row.get("quantity")
    if price is not None and qty is not None:
        try:
            return round(float(qty) * float(price), 2)
        except (TypeError, ValueError):
            pass
    return None


def _basis_fallback_price(row, mode=None):
    mode = mode or _basis_mode()
    if mode == "broker_adjusted":
        return _first_not_none(row.get("broker_price_paid"), row.get("price_paid"), row.get("original_price_paid"))
    return _first_not_none(row.get("original_price_paid"), row.get("price_paid"), row.get("broker_price_paid"))


def _ensure_basis_columns(conn):
    """Make older/minimal databases understand the split basis fields."""
    cols = {r[1] for r in conn.execute("PRAGMA table_info(all_account_info)").fetchall()}
    needed = {
        "original_price_paid": "REAL",
        "original_purchase_value": "REAL",
        "broker_price_paid": "REAL",
        "broker_purchase_value": "REAL",
    }
    for col, col_type in needed.items():
        if col not in cols:
            conn.execute(f"ALTER TABLE all_account_info ADD COLUMN {col} {col_type}")
    conn.execute("""
        UPDATE all_account_info
           SET original_price_paid = COALESCE(original_price_paid, price_paid),
               original_purchase_value = COALESCE(original_purchase_value, purchase_value),
               broker_price_paid = COALESCE(broker_price_paid, price_paid),
               broker_purchase_value = COALESCE(broker_purchase_value, purchase_value)
         WHERE original_price_paid IS NULL
            OR original_purchase_value IS NULL
            OR broker_price_paid IS NULL
            OR broker_purchase_value IS NULL
    """)
    conn.commit()


# Above this dividends/basis multiple, a holding with no buy-transaction history is
# treated as a trimmed-but-untracked position and its paid-for-itself is shown as
# unknown rather than an absurd percentage. Legitimate long-held high-yield funds
# can exceed 100%, so this is set well clear of plausible real recovery ratios.
_PFI_NO_TXN_MAX_RATIO = 10.0  # i.e. 1000%


def _apply_basis_mode_to_holdings(results, invested_by_ticker=None, realized_by_ticker=None):
    """Expose selected basis through the legacy price_paid/purchase_value fields."""
    mode = _basis_mode()
    for r in results:
        selected_total = _basis_fallback_total(r, mode)
        selected_price = _basis_fallback_price(r, mode)
        current_value = r.get("current_value")
        total_divs = r.get("total_divs_received")
        annual = r.get("estim_payment_per_year")

        r["basis_mode"] = mode
        r["selected_basis_mode"] = mode
        r["price_paid"] = selected_price
        r["purchase_value"] = selected_total

        cost = float(selected_total) if selected_total else 0
        if cost > 0 and current_value is not None:
            gain = round(float(current_value) - cost, 2)
            gain_pct = round(gain / cost, 6)
            r["gain_or_loss"] = gain
            r["gain_or_loss_percentage"] = gain_pct
            r["percent_change"] = gain_pct
        # Paid-for-itself compares LIFETIME dividends to ORIGINAL cost. For a
        # trimmed position `cost` is only the residual basis, so prefer the
        # cumulative cash invested when it is larger (it never shrinks when shares
        # are sold). Falls back to current basis when no buy history is available.
        pfi_cost = cost
        invested = _num_or_zero(invested_by_ticker.get(r.get("ticker"))) if invested_by_ticker else 0.0
        if invested > pfi_cost:
            pfi_cost = invested
        divs_unreliable = (
            invested == 0 and total_divs is not None and pfi_cost > 0
            and float(total_divs) > pfi_cost * _PFI_NO_TXN_MAX_RATIO
        )
        if pfi_cost > 0 and total_divs is not None:
            # Guard: with no buy history (invested == 0) we can't reconstruct the
            # original cost of a trimmed position, so lifetime dividends would be
            # divided by a tiny residual basis. When that ratio is implausibly high
            # the number is a data artifact, not a real recovery %, so surface it as
            # unknown (—) instead of a fabricated value. Import the account's
            # transactions to restore the true figure.
            if divs_unreliable:
                r["paid_for_itself"] = None
            else:
                r["paid_for_itself"] = round(float(total_divs) / pfi_cost, 6)
        if cost > 0 and annual is not None:
            r["annual_yield_on_cost"] = round(float(annual) / cost, 6)
        # Total return (price change + lifetime dividends) has the exact same
        # blowup risk as paid-for-itself: FEPI showed 5255% total return because
        # its lifetime dividends were earned on far more shares than the 0.25
        # remaining after a big trim, divided by that tiny residual basis. Reuse
        # the same invested-cost floor and unreliable-dividend guard here so a
        # trimmed position's total return is judged against the capital that
        # actually earned those dividends, consistent with paid-for-itself.
        r["total_return_basis"] = round(pfi_cost, 2) if pfi_cost > 0 else None
        r["total_return_divs_component"] = 0.0 if divs_unreliable else _num_or_zero(total_divs)
        # A trimmed (not fully sold) position's unrealized gain/loss (`gain`
        # above) only reflects the shares still held. Without also counting
        # gains/losses already realized on the shares that were sold, a
        # zero-dividend trimmed position can show a total return that doesn't
        # match its price return even though nothing else changed hands.
        r["total_return_realized_component"] = _num_or_zero(
            realized_by_ticker.get(r.get("ticker")) if realized_by_ticker else 0.0
        )
    return results


_ACCOUNT_MATCH_IGNORED_TOKENS = {
    "account", "acct", "portfolio",
    "etrade", "e", "trade",
    "schwab", "charles", "fidelity", "robinhood", "shear", "group",
    "snowball", "analytics",
    "traditional",
}


def _normalize_account_tokens(label):
    text = re.sub(r"[^a-z0-9]+", " ", (label or "").strip().lower())
    return [tok for tok in text.split() if tok]


def _account_match_info(account_name, profile_name, source_format=None):
    """Return whether an import file account appears to match the target profile."""
    if not account_name:
        return {"matched": True, "reason": "missing_account_name"}

    account_tokens = _normalize_account_tokens(account_name)
    profile_tokens = _normalize_account_tokens(profile_name)
    source_format = (source_format or "").strip().lower()

    account_core = {
        tok for tok in account_tokens
        if not tok.isdigit() and tok not in _ACCOUNT_MATCH_IGNORED_TOKENS
    }
    profile_core = {
        tok for tok in profile_tokens
        if not tok.isdigit() and tok not in _ACCOUNT_MATCH_IGNORED_TOKENS
    }

    if not account_core:
        return {"matched": True, "reason": "no_core_tokens"}

    if source_format.startswith("fidelity"):
        matched = "fidelity" in profile_tokens
        return {
            "matched": matched,
            "reason": "broker_profile_match" if matched else "broker_profile_mismatch",
            "message": None if matched else (
                f"Fidelity files can only be imported into a Fidelity portfolio. "
                f"'{profile_name}' is not marked as Fidelity."
            ),
        }

    matched = account_core == profile_core
    reason = "exact_core_match" if matched else "core_token_mismatch"
    message = None
    if matched and source_format.startswith("etrade") and "etrade" not in profile_tokens:
        matched = False
        reason = "broker_profile_mismatch"
        message = (
            f"E*TRADE files can only be imported into an E*TRADE portfolio. "
            f"'{profile_name}' is not marked as E*TRADE."
        )
    elif not matched:
        message = (
            f"File account '{account_name}' does not match selected portfolio "
            f"'{profile_name}'. Switch portfolios before importing."
        )

    return {
        "matched": matched,
        "reason": reason,
        "message": message,
    }


def _get_profile_name(profile_id):
    conn = get_connection()
    try:
        row = conn.execute("SELECT name FROM profiles WHERE id = ?", (profile_id,)).fetchone()
        if not row:
            return "Portfolio"
        return row["name"] if isinstance(row, dict) else row[0]
    finally:
        conn.close()


def _profile_is_positions_managed(profile_id, conn=None):
    close = False
    if conn is None:
        conn = get_connection()
        close = True
    try:
        row = conn.execute(
            "SELECT positions_managed FROM profiles WHERE id = ?",
            (profile_id,),
        ).fetchone()
        if not row:
            return False
        return bool(row["positions_managed"] if isinstance(row, dict) else row[0])
    finally:
        if close:
            conn.close()


def _set_profile_positions_managed(profile_id, managed, conn=None):
    close = False
    if conn is None:
        conn = get_connection()
        close = True
    try:
        conn.execute(
            "UPDATE profiles SET positions_managed = ? WHERE id = ?",
            (1 if managed else 0, profile_id),
        )
        if close:
            conn.commit()
    finally:
        if close:
            conn.close()


def _set_profile_cash_value(conn, profile_id, cash_value, source="positions_import"):
    """Persist a broker-reported cash balance when the schema supports it."""
    profile_cols = {
        row[1] for row in conn.execute("PRAGMA table_info(profiles)").fetchall()
    }
    if "cash_value" not in profile_cols:
        return
    conn.execute(
        """UPDATE profiles
           SET cash_value = ?, cash_source = ?, cash_updated_at = ?
           WHERE id = ?""",
        (
            round(float(cash_value or 0), 2),
            source,
            datetime.datetime.now().isoformat(),
            profile_id,
        ),
    )


def _large_unsold_position_drop_guard(conn, profile_id, ticker, pos, existing):
    """Keep prior broker quantity when a positions row looks like a bad partial lot.

    Positions imports normally own current share counts. This guard is deliberately
    narrow: it only protects an existing, transaction-backed holding from a large
    imported quantity collapse when no recent SELL transaction explains the drop.
    """
    if not existing:
        return None
    existing_qty = _num_or_zero(existing["quantity"] if isinstance(existing, dict) else existing[0])
    incoming_qty = _num_or_zero(pos.get("quantity"))
    if existing_qty <= 0 or incoming_qty <= 0:
        return None
    reduction = existing_qty - incoming_qty
    if reduction <= max(5.0, existing_qty * 0.25):
        return None

    txn_row = conn.execute(
        "SELECT COUNT(*) AS cnt FROM transactions WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchone()
    txn_count = int((txn_row["cnt"] if isinstance(txn_row, dict) else txn_row[0]) or 0)
    if txn_count <= 0:
        return None

    import_date = existing["import_date"] if isinstance(existing, dict) else existing[4]
    params = [ticker, profile_id]
    date_clause = ""
    if import_date:
        date_clause = "AND transaction_date >= ?"
        params.append(import_date)
    sell_row = conn.execute(
        f"""SELECT COALESCE(SUM(shares), 0) AS shares
            FROM transactions
            WHERE ticker = ? AND profile_id = ?
              AND UPPER(COALESCE(transaction_type, '')) = 'SELL'
              AND NOT (LOWER(COALESCE(notes, '')) LIKE '%transfer%')
              {date_clause}""",
        params,
    ).fetchone()
    recent_sell_shares = _num_or_zero(sell_row["shares"] if isinstance(sell_row, dict) else sell_row[0])
    if recent_sell_shares >= reduction - _basis_share_tolerance(existing_qty):
        return None

    corrected = dict(pos)
    broker_price = _num_or_zero(existing["broker_price_paid"] if isinstance(existing, dict) else existing[5])
    price_paid = _num_or_zero(existing["price_paid"] if isinstance(existing, dict) else existing[1])
    broker_total = _num_or_zero(existing["broker_purchase_value"] if isinstance(existing, dict) else existing[6])
    purchase_total = _num_or_zero(existing["purchase_value"] if isinstance(existing, dict) else existing[2])
    current_price = _num_or_zero(pos.get("current_price"))
    corrected["quantity"] = existing_qty
    corrected["cost_per_share"] = broker_price or price_paid
    corrected["purchase_value"] = round(broker_total or purchase_total, 2)
    if current_price > 0:
        corrected["current_value"] = round(existing_qty * current_price, 2)
    else:
        corrected["current_value"] = _num_or_zero(existing["current_value"] if isinstance(existing, dict) else existing[3])
    corrected["gain_or_loss"] = round(
        corrected["current_value"] - corrected["purchase_value"],
        2,
    )
    corrected["_quantity_preserved"] = {
        "ticker": ticker,
        "imported_quantity": round(incoming_qty, 6),
        "kept_quantity": round(existing_qty, 6),
        "unexplained_drop": round(reduction, 6),
    }
    return corrected


def _cash_profile_ids_for_read(conn, is_aggregate, profile_ids):
    """Resolve the source profiles whose cash belongs in the active view."""
    ids = list(dict.fromkeys(int(pid) for pid in (profile_ids or [1])))
    if not is_aggregate and ids == [1]:
        source_ids = _get_owner_source_profile_ids(conn)
        return source_ids or ids
    return ids


def _get_owner_source_profile_ids(conn):
    """Return profile ids that feed Owner reconciliation/DRIP sync."""
    rows = conn.execute(
        "SELECT id FROM profiles WHERE id != 1 AND include_in_owner = 1 ORDER BY id"
    ).fetchall()
    return [r["id"] if isinstance(r, dict) else r[0] for r in rows]


def _get_aggregate_member_profile_ids(conn, aggregate_id=None):
    """Return profile ids that feed an aggregate portfolio.

    If aggregate_id is None, returns the distinct union of members across all aggregates.
    """
    if aggregate_id is None:
        rows = conn.execute(
            "SELECT DISTINCT member_profile_id FROM aggregate_config ORDER BY member_profile_id"
        ).fetchall()
    else:
        rows = conn.execute(
            "SELECT member_profile_id FROM aggregate_config WHERE aggregate_id = ? ORDER BY member_profile_id",
            (aggregate_id,),
        ).fetchall()
    return [r["member_profile_id"] if isinstance(r, dict) else r[0] for r in rows]


def _list_aggregates(conn):
    """Return [{id, name, member_ids}] for every aggregate."""
    agg_rows = conn.execute("SELECT id, name FROM aggregates ORDER BY id").fetchall()
    aggregates = []
    for row in agg_rows:
        aid = row["id"] if isinstance(row, dict) else row[0]
        name = row["name"] if isinstance(row, dict) else row[1]
        members = _get_aggregate_member_profile_ids(conn, aid)
        aggregates.append({"id": aid, "name": name, "member_ids": members})
    return aggregates


def _get_transaction_read_scope(conn, is_aggregate, profile_ids):
    """Return profile ids and whether rows should be source-account labeled."""
    if is_aggregate:
        return list(dict.fromkeys(profile_ids or [1])), True

    profile_id = int(profile_ids[0]) if profile_ids else 1
    if profile_id == 1:
        source_ids = _get_owner_source_profile_ids(conn)
        if source_ids:
            return list(dict.fromkeys([1, *source_ids])), True

    return [profile_id], False


def _load_profile_name_map(conn, profile_ids):
    ids = list(dict.fromkeys(int(pid) for pid in profile_ids if pid is not None))
    if not ids:
        return {}
    placeholders = ",".join("?" * len(ids))
    rows = conn.execute(
        f"SELECT id, name FROM profiles WHERE id IN ({placeholders})",
        ids,
    ).fetchall()
    return {
        int(row["id"] if isinstance(row, dict) else row[0]): (row["name"] if isinstance(row, dict) else row[1])
        for row in rows
    }


def _add_transaction_source_notes(transactions, profile_names, include_account_note):
    """Decorate virtual aggregate/Owner rows with their source account in notes."""
    for txn in transactions:
        profile_id = int(txn.get("profile_id") or 1)
        account_name = profile_names.get(profile_id)
        raw_notes = txn.get("notes") or ""
        txn["source_profile_id"] = profile_id
        txn["source_account_name"] = account_name
        txn["raw_notes"] = raw_notes
        if include_account_note and account_name:
            txn["notes"] = f"Account: {account_name}; {raw_notes}" if raw_notes else f"Account: {account_name}"
    return transactions


def _request_nav_date():
    raw = (request.form.get("nav_date") or request.args.get("nav_date") or "").strip()
    if not raw:
        return None
    try:
        return datetime.date.fromisoformat(raw).isoformat()
    except ValueError:
        raise ValueError("NAV snapshot date must use YYYY-MM-DD format.")


def _is_backdated_nav(nav_date):
    return bool(nav_date and nav_date != datetime.date.today().isoformat())


def _snapshot_nav_after_profile_update(profile_id, nav_date=None):
    """Snapshot NAV rows affected by an import/update for a single profile."""
    conn = get_connection()
    try:
        if _is_backdated_nav(nav_date):
            profile_ids = [profile_id]
        else:
            aggregate_ids = set(_get_aggregate_member_profile_ids(conn))
            if profile_id == 1:
                profile_ids = [1, *_get_owner_source_profile_ids(conn), *aggregate_ids]
            else:
                profile_ids = [profile_id, 1]
                if profile_id in aggregate_ids:
                    profile_ids.extend(aggregate_ids)
    finally:
        conn.close()

    for pid in dict.fromkeys(profile_ids):
        snapshot_nav(pid, nav_date=nav_date)


def _snapshot_nav_after_multi_profile_update(profile_ids, nav_date=None):
    """Snapshot NAV rows affected by a multi-profile import/update."""
    affected = [int(pid) for pid in profile_ids if pid is not None]
    if not affected:
        return
    if _is_backdated_nav(nav_date):
        for pid in dict.fromkeys(affected):
            snapshot_nav(pid, nav_date=nav_date)
        return

    conn = get_connection()
    try:
        owner_source_ids = set(_get_owner_source_profile_ids(conn))
        aggregate_ids = set(_get_aggregate_member_profile_ids(conn))
    finally:
        conn.close()

    if 1 in affected:
        affected.extend(owner_source_ids)
        affected.extend(aggregate_ids)
    if any(pid in aggregate_ids for pid in affected):
        affected.extend(aggregate_ids)
    if 1 in affected or any(pid in owner_source_ids for pid in affected):
        affected.append(1)

    for pid in dict.fromkeys(affected):
        snapshot_nav(pid, nav_date=nav_date)


def _broker_import_target_error(profile_id, conn):
    """Return an error message when broker/Snowball imports should be blocked."""
    if _request_aggregate_id() is not None:
        return (
            "Broker and Snowball imports cannot be imported into an Aggregate view. "
            "Select a specific source portfolio first."
        )

    if profile_id == 1:
        owner_sources = _get_owner_source_profile_ids(conn)
        if len(owner_sources) > 1:
            return (
                "Broker and Snowball imports cannot be imported into Owner when Owner is made up "
                "of more than one account. Import into the underlying source portfolio instead."
            )

    return None


_SNOWBALL_LAYERED_BROKER_SOURCES = {"schwab", "etrade", "fidelity", "shear_group", "generic", "other"}


def _profile_broker_source(profile_id, conn):
    try:
        row = conn.execute(
            "SELECT broker_source FROM profiles WHERE id = ?",
            (profile_id,),
        ).fetchone()
    except sqlite3.OperationalError:
        return ""
    if not row:
        return ""
    value = row["broker_source"] if isinstance(row, dict) else row[0]
    return (value or "").strip().lower()


def _should_preserve_positions_for_transaction_import(profile_id, fmt, conn):
    """Return True when transaction imports should not recalculate holdings."""
    fmt = (fmt or "").strip().lower()
    if fmt in {"schwab", "etrade", "fidelity", "snowball_holdings", "robinhood", "shear_group"}:
        return False

    existing_holdings = conn.execute(
        "SELECT COUNT(*) FROM all_account_info WHERE profile_id = ? AND quantity > 0",
        (profile_id,),
    ).fetchone()[0]

    if (
        fmt == "snowball"
        and existing_holdings > 0
        and _profile_broker_source(profile_id, conn) in _SNOWBALL_LAYERED_BROKER_SOURCES
    ):
        return True

    if _profile_is_positions_managed(profile_id, conn):
        return True

    return existing_holdings > 0


def _shear_group_account_aliases(account_name, account_number=None):
    tokens = [
        tok for tok in _normalize_account_tokens(account_name)
        if tok and tok not in _ACCOUNT_MATCH_IGNORED_TOKENS
    ]
    aliases = set()
    if tokens:
        aliases.add("".join(tokens))
        first_token = tokens[0]
        last_token = tokens[-1]
        if len(tokens) >= 2:
            aliases.add(f"{first_token}{last_token}")
            aliases.add(f"{last_token}{first_token}")
            aliases.add(f"{first_token}{last_token[:1]}")
            aliases.add(f"{last_token[:1]}{first_token}")
            aliases.add(f"{last_token}{first_token[:1]}")
            aliases.add(f"{first_token[:1]}{last_token}")
    account_number = re.sub(r"\D+", "", str(account_number or ""))
    if account_number:
        aliases.add(account_number)
    return {alias for alias in aliases if alias}


def _shear_group_account_matches_profile(profile_name, account_name, account_number):
    profile_tokens = _normalize_account_tokens(profile_name)
    profile_compact = "".join(profile_tokens)
    profile_digits = re.sub(r"\D+", "", profile_name or "")
    for alias in _shear_group_account_aliases(account_name, account_number):
        if alias.isdigit():
            if alias and alias in profile_digits:
                return True
            continue
        if alias in profile_tokens or alias in profile_compact:
            return True
    return False


def _merge_import_positions_by_ticker(positions):
    merged = {}
    for pos in positions:
        ticker = pos["ticker"]
        if ticker not in merged:
            merged[ticker] = dict(pos)
            continue

        existing = merged[ticker]
        total_qty = (existing.get("quantity") or 0) + (pos.get("quantity") or 0)
        total_purchase = (existing.get("purchase_value") or 0) + (pos.get("purchase_value") or 0)
        total_current = (existing.get("current_value") or 0) + (pos.get("current_value") or 0)
        total_gain = (existing.get("gain_or_loss") or 0) + (pos.get("gain_or_loss") or 0)

        existing["quantity"] = total_qty
        existing["purchase_value"] = round(total_purchase, 2)
        existing["current_value"] = round(total_current, 2)
        existing["gain_or_loss"] = round(total_gain, 2)
        existing["cost_per_share"] = round(total_purchase / total_qty, 4) if total_qty else 0
        existing["current_price"] = pos.get("current_price") or existing.get("current_price") or 0
        if not existing.get("description"):
            existing["description"] = pos.get("description") or ""
        if not existing.get("asset_type"):
            existing["asset_type"] = pos.get("asset_type") or ""
    return list(merged.values())


def _strip_shear_group_account_fields(items):
    for item in items or []:
        item.pop("_account_label", None)
        item.pop("_account_name", None)
        item.pop("_account_number", None)


def _filter_shear_group_result_for_profile(parsed, profile_id):
    source_format = (parsed.get("source_format") or "").strip().lower()
    if source_format not in {"shear_group", "shear_group_activity"}:
        return parsed

    profile_name = _get_profile_name(profile_id)
    raw_positions = parsed.pop("_raw_positions", None)
    cash_by_account = parsed.pop("_cash_by_account", {})

    if raw_positions is not None:
        account_labels = {
            pos.get("_account_label") for pos in raw_positions
            if pos.get("_account_label")
        }
        matched_positions = raw_positions
        matched_labels = set(account_labels)
        if len(account_labels) > 1:
            matched_positions = [
                pos for pos in raw_positions
                if _shear_group_account_matches_profile(
                    profile_name,
                    pos.get("_account_name") or pos.get("_account_label"),
                    pos.get("_account_number"),
                )
            ]
            matched_labels = {
                pos.get("_account_label") for pos in matched_positions
                if pos.get("_account_label")
            }
            if not matched_positions:
                available = ", ".join(sorted(account_labels))
                raise ValueError(
                    "This Shear Group positions file contains multiple accounts, but none match "
                    f"'{profile_name}'. Rename/select a portfolio with the account holder or account number, "
                    f"or import a single-account export. Available accounts: {available}"
                )

        merged_positions = _merge_import_positions_by_ticker(matched_positions)
        _strip_shear_group_account_fields(merged_positions)
        parsed["positions"] = merged_positions
        summary = parsed.setdefault("summary", {})
        cash_value = round(sum(cash_by_account.get(label, 0.0) for label in matched_labels), 2)
        summary["holdings"] = len(merged_positions)
        summary["cash"] = cash_value
        summary["account_count"] = len(matched_labels)
        summary["account_value"] = round(sum(p["current_value"] for p in merged_positions) + cash_value, 2)
        parsed["target_profile_name"] = profile_name
        parsed["account_match"] = {
            "matched": True,
            "reason": "shear_group_account_filter",
            "matched_accounts": sorted(matched_labels),
        }
        return parsed

    transactions = parsed.get("transactions") or []
    account_labels = {
        txn.get("_account_label") for txn in transactions
        if txn.get("_account_label")
    }
    if len(account_labels) > 1:
        matched_transactions = [
            txn for txn in transactions
            if _shear_group_account_matches_profile(
                profile_name,
                txn.get("_account_name") or txn.get("_account_label"),
                txn.get("_account_number"),
            )
        ]
        if not matched_transactions:
            available = ", ".join(sorted(account_labels))
            raise ValueError(
                "This Shear Group activity file contains multiple accounts, but none match "
                f"'{profile_name}'. Available accounts: {available}"
            )
        parsed["transactions"] = matched_transactions
        summary = parsed.setdefault("summary", {})
        summary["buys"] = sum(1 for txn in matched_transactions if txn.get("type") == "BUY")
        summary["sells"] = sum(1 for txn in matched_transactions if txn.get("type") == "SELL")
        summary["dividends"] = sum(1 for txn in matched_transactions if txn.get("type") == "DIVIDEND")
        summary["account_count"] = len({
            txn.get("_account_label") for txn in matched_transactions
            if txn.get("_account_label")
        })
        parsed["target_profile_name"] = profile_name
        parsed["account_match"] = {"matched": True, "reason": "shear_group_account_filter"}

    _strip_shear_group_account_fields(parsed.get("transactions"))
    return parsed


def _get_gains_losses_profile_scope(conn):
    """Return holding and transaction profile scopes for Gains & Losses views."""
    is_agg, pids = get_profile_filter()
    if is_agg:
        profile_ids = list(dict.fromkeys(pids or [1]))
        return {
            "is_aggregate": True,
            "primary_profile_id": profile_ids[0],
            "holding_profile_ids": profile_ids,
            "transaction_profile_ids": profile_ids,
        }

    profile_id = int(pids[0]) if pids else 1
    transaction_profile_ids, _ = _get_transaction_read_scope(conn, False, [profile_id])
    return {
        "is_aggregate": False,
        "primary_profile_id": profile_id,
        "holding_profile_ids": [profile_id],
        "transaction_profile_ids": transaction_profile_ids,
    }


def _get_refresh_target_info(conn):
    """Resolve which profiles a holdings refresh should update."""
    agg_id = _request_aggregate_id()
    if agg_id is not None:
        pids = _get_aggregate_member_profile_ids(conn, agg_id)
        return {
            "scope": "aggregate",
            "source_profile_ids": pids or [1],
            "selected_profile_id": None,
        }

    profile_id = get_profile_id()
    if profile_id == 1:
        source_ids = _get_owner_source_profile_ids(conn)
        return {
            "scope": "owner",
            "source_profile_ids": source_ids or [1],
            "selected_profile_id": 1,
        }

    return {
        "scope": "profile",
        "source_profile_ids": [profile_id],
        "selected_profile_id": profile_id,
    }


def _estimate_month_income(holding, month):
    """Estimate income for a specific month (1-12) from a single holding.

    Uses div_frequency and ex_div_date to determine whether the holding
    pays out in the given calendar month and returns qty * div if so.
    Weekly payers use 4.33 payments per month (52 / 12).
    """
    import datetime

    qty = float(holding.get("quantity") or 0)
    div = float(holding.get("div") or 0)
    freq = (holding.get("div_frequency") or "").strip().upper()
    ex_raw = holding.get("ex_div_date") or ""

    if qty <= 0 or div <= 0 or not freq:
        return 0.0

    # Weekly: one payment per week, 52 per year ≈ 4.33 per month.
    # Consistent with the projected income chart (annual / 52 * 4.33).
    if freq in ("W", "52"):
        return round(qty * div * 4.33, 2)

    # Monthly: always pays
    if freq == "M":
        return round(qty * div, 2)

    # For Q / SA / A we need the ex_div_date to figure out the cycle
    ex_month = None
    for fmt in ("%m/%d/%y", "%Y-%m-%d", "%m/%d/%Y"):
        try:
            ex_month = datetime.datetime.strptime(ex_raw.strip(), fmt).month
            break
        except (ValueError, TypeError):
            continue

    if ex_month is None:
        return 0.0

    period = {"Q": 3, "SA": 6, "A": 12}.get(freq)
    if period is None:
        return 0.0

    if (month - ex_month) % period == 0:
        return round(qty * div, 2)

    return 0.0


def _estimate_current_month_income(holding):
    """Estimate income for the current month from a single holding."""
    import datetime
    if not _holding_eligible_for_current_dividend(
        holding.get("purchase_date"),
        holding.get("ex_div_date"),
    ):
        return 0.0
    return _estimate_month_income(holding, datetime.date.today().month)


def _estimate_ytd_income(holding):
    """Estimate year-to-date income from a single holding (Jan through last completed month).
    Excludes current month since it's incomplete — avoids overcounting."""
    import datetime
    cur_month = datetime.date.today().month
    return sum(_estimate_month_income(holding, m) for m in range(1, cur_month))


def _frequency_to_payments_per_year(freq):
    return {
        "W": 52,
        "52": 52,
        "M": 12,
        "Q": 4,
        "SA": 2,
        "A": 1,
    }.get((freq or "").strip().upper(), 0)


def _current_dividend_paid(quantity, div):
    """Cash amount of one dividend payment for the current share count."""
    try:
        qty = float(quantity or 0)
        per_share = float(div or 0)
    except (TypeError, ValueError):
        return 0.0
    if qty <= 0 or per_share <= 0:
        return 0.0
    return round(qty * per_share, 6)


def _optional_float(value):
    if value is None or value == "":
        return None
    try:
        return float(value)
    except (TypeError, ValueError):
        return None


def _prepare_manual_holding_payload(data, existing=None):
    """Recalculate direct holding value fields from the final edited inputs."""
    payload = dict(data or {})
    basis_mode = _basis_mode()

    def final_value(field):
        if field in payload:
            return payload[field]
        if existing is None:
            return None
        return existing[field] if hasattr(existing, "keys") and field in existing.keys() else None

    quantity = _optional_float(final_value("quantity"))
    price_paid = _optional_float(final_value("price_paid"))
    current_price = _optional_float(final_value("current_price"))
    total_divs = _optional_float(final_value("total_divs_received"))

    if quantity is not None and price_paid is not None:
        payload["purchase_value"] = round(quantity * price_paid, 2)
    elif "quantity" in payload or "price_paid" in payload:
        payload["purchase_value"] = None

    if quantity is not None and current_price is not None:
        payload["current_value"] = round(quantity * current_price, 2)
    elif "quantity" in payload or "current_price" in payload:
        payload["current_value"] = None

    purchase_value = _optional_float(final_value("purchase_value"))
    current_value = _optional_float(final_value("current_value"))
    if "purchase_value" in payload:
        purchase_value = _optional_float(payload["purchase_value"])
    if "current_value" in payload:
        current_value = _optional_float(payload["current_value"])

    if purchase_value is not None and current_value is not None:
        gain = round(current_value - purchase_value, 2)
        gain_pct = round(gain / purchase_value, 6) if purchase_value > 0 else 0
        payload["gain_or_loss"] = gain
        payload["gain_or_loss_percentage"] = gain_pct
        payload["percent_change"] = gain_pct
    elif any(field in payload for field in ("quantity", "price_paid", "current_price", "purchase_value", "current_value")):
        payload["gain_or_loss"] = None
        payload["gain_or_loss_percentage"] = None
        payload["percent_change"] = None

    if total_divs is not None and purchase_value is not None:
        payload["paid_for_itself"] = round(total_divs / purchase_value, 6) if purchase_value > 0 else 0

    if "price_paid" in payload:
        selected_price_field = "broker_price_paid" if basis_mode == "broker_adjusted" else "original_price_paid"
        fallback_price_field = "original_price_paid" if basis_mode == "broker_adjusted" else "broker_price_paid"
        payload[selected_price_field] = payload.get("price_paid")
        if existing is None or final_value(fallback_price_field) is None:
            payload[fallback_price_field] = payload.get("price_paid")
    if "purchase_value" in payload:
        selected_total_field = "broker_purchase_value" if basis_mode == "broker_adjusted" else "original_purchase_value"
        fallback_total_field = "original_purchase_value" if basis_mode == "broker_adjusted" else "broker_purchase_value"
        payload[selected_total_field] = payload.get("purchase_value")
        if existing is None or final_value(fallback_total_field) is None:
            payload[fallback_total_field] = payload.get("purchase_value")

    return payload


def _recompute_position_income_fields(
    conn,
    profile_id,
    ticker,
    broker_dividend_yield=None,
    preserve_existing_income=False,
    previous_quantity=None,
    previous_annual_income=None,
):
    row = conn.execute(
        """SELECT quantity, purchase_value, current_value, div, div_frequency, ex_div_date,
                  div_pay_date, purchase_date,
                  estim_payment_per_year, approx_monthly_income
           FROM all_account_info
           WHERE ticker = ? AND profile_id = ?""",
        (ticker, profile_id),
    ).fetchone()
    if not row:
        return

    quantity = float(row["quantity"] or 0)
    purchase_value = float(row["purchase_value"] or 0)
    current_value = float(row["current_value"] or 0)
    div = float(row["div"] or 0)
    div_frequency = row["div_frequency"] or ""
    imported_annual = float(row["estim_payment_per_year"] or 0)
    imported_monthly = float(row["approx_monthly_income"] or 0)
    payments_per_year = _frequency_to_payments_per_year(div_frequency)

    annual = 0.0
    try:
        previous_quantity = float(previous_quantity or 0)
    except (TypeError, ValueError):
        previous_quantity = 0.0
    try:
        previous_annual_income = float(previous_annual_income or 0)
    except (TypeError, ValueError):
        previous_annual_income = 0.0

    if quantity > 0 and div > 0 and payments_per_year > 0:
        annual = quantity * div * payments_per_year
    elif quantity > 0 and current_value > 0 and broker_dividend_yield:
        annual = current_value * (float(broker_dividend_yield) / 100.0)
    elif (
        quantity > 0
        and previous_quantity > 0
        and previous_annual_income > 0
        and abs(imported_annual - previous_annual_income) < 0.005
    ):
        annual = previous_annual_income * (quantity / previous_quantity)
    elif quantity > 0 and imported_annual > 0:
        annual = imported_annual

    monthly = annual / 12.0 if annual > 0 else 0.0
    if preserve_existing_income and imported_monthly > 0 and annual > 0:
        monthly = imported_monthly
    yoc = (annual / purchase_value) if annual > 0 and purchase_value > 0 else 0.0
    cur_yield = (annual / current_value) if annual > 0 and current_value > 0 else 0.0
    current_month_income = _estimate_current_month_income({
        "quantity": quantity,
        "div": div,
        "div_frequency": div_frequency,
        "ex_div_date": row["ex_div_date"],
        "purchase_date": row["purchase_date"],
    }) if quantity > 0 and payments_per_year > 0 else 0.0
    dividend_paid = (
        _current_dividend_paid(quantity, div)
        if _holding_eligible_for_current_dividend(row["purchase_date"], row["ex_div_date"])
        else 0.0
    )
    if dividend_paid <= 0 and not _holding_eligible_for_current_dividend(row["purchase_date"], row["ex_div_date"]):
        pay_dt = _date_from_value(row["div_pay_date"])
        if pay_dt is not None:
            try:
                conn.execute(
                    "DELETE FROM dividend_payments "
                    "WHERE ticker = ? AND profile_id = ? AND payment_date = ? AND source = ?",
                    (ticker, profile_id, pay_dt.isoformat(), REFRESH_ESTIMATE_DIVIDEND_SOURCE),
                )
            except Exception:
                pass

    conn.execute(
        """UPDATE all_account_info
           SET estim_payment_per_year = ?, approx_monthly_income = ?,
               annual_yield_on_cost = ?, current_annual_yield = ?,
               current_month_income = ?, dividend_paid = ?
           WHERE ticker = ? AND profile_id = ?""",
        (
            round(annual, 2),
            round(monthly, 2),
            round(yoc, 4),
            round(cur_yield, 4),
            round(current_month_income, 2),
            dividend_paid,
            ticker,
            profile_id,
        ),
    )


def _assign_position_category(conn, profile_id, ticker, category_name):
    category_name = (category_name or "").strip()
    if not category_name:
        return

    existing_cat = conn.execute(
        "SELECT id FROM categories WHERE name = ? AND profile_id = ?",
        (category_name, profile_id),
    ).fetchone()
    if existing_cat:
        category_id = existing_cat["id"] if isinstance(existing_cat, dict) else existing_cat[0]
    else:
        max_pos = conn.execute(
            "SELECT COALESCE(MAX(sort_order), 0) AS max_sort FROM categories WHERE profile_id = ?",
            (profile_id,),
        ).fetchone()
        next_sort = (max_pos["max_sort"] if isinstance(max_pos, dict) else max_pos[0]) + 1
        cur = conn.execute(
            "INSERT INTO categories (name, target_pct, sort_order, profile_id) VALUES (?, 0, ?, ?)",
            (category_name, next_sort, profile_id),
        )
        category_id = cur.lastrowid

    _replace_ticker_category(conn, profile_id, ticker, category_id)


def _replace_ticker_category(conn, profile_id, ticker, category_id, subcategory_id=None):
    ticker = (ticker or "").strip().upper()
    if not ticker:
        return
    conn.execute(
        "DELETE FROM ticker_categories WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    )
    conn.execute(
        "INSERT INTO ticker_categories (ticker, category_id, subcategory_id, profile_id) VALUES (?, ?, ?, ?)",
        (ticker, category_id, subcategory_id, profile_id),
    )


def _calc_dividend_growth_batch(tickers):
    """Calculate 3-year and 5-year dividend growth rates for a list of tickers.
    Returns dict of ticker -> {"div_growth_3y": float|None, "div_growth_5y": float|None}.
    Uses yfinance Ticker.dividends for accurate per-share dividend history.
    Compares annual per-share dividends (excluding current partial year).
    """
    import yfinance as yf
    import warnings
    import datetime
    warnings.filterwarnings("ignore")

    result = {t: {"div_growth_3y": None, "div_growth_5y": None} for t in tickers}
    if not tickers:
        return result

    current_year = datetime.date.today().year

    for t in tickers:
        try:
            divs = yf.Ticker(t).dividends
            if divs is None or len(divs) < 2:
                continue
            divs = divs[divs > 0]
            divs.index = pd.to_datetime(divs.index)
            # Exclude current partial year
            divs = divs[divs.index.year < current_year]
            if len(divs) < 2:
                continue

            yearly = divs.resample("YE").sum()
            yearly = yearly[yearly > 0]
            if len(yearly) < 2:
                continue

            recent = float(yearly.iloc[-1])

            if len(yearly) >= 4:
                past_3 = float(yearly.iloc[-4])
                if past_3 > 0:
                    result[t]["div_growth_3y"] = round(((recent / past_3) ** (1 / 3) - 1) * 100, 2)

            if len(yearly) >= 6:
                past_5 = float(yearly.iloc[-6])
                if past_5 > 0:
                    result[t]["div_growth_5y"] = round(((recent / past_5) ** (1 / 5) - 1) * 100, 2)
        except Exception:
            continue

    return result


@app.route("/api/holdings/dividend-growth", methods=["GET"])
def holdings_dividend_growth():
    """Return cached 3-year and 5-year dividend growth for requested holdings."""
    raw_tickers = request.args.get("tickers", "")
    if raw_tickers:
        tickers = sorted({
            t.strip().upper()
            for t in raw_tickers.split(",")
            if t and t.strip()
        })
    else:
        _, pids = get_profile_filter()
        conn = get_connection()
        try:
            placeholders = ",".join("?" * len(pids))
            rows = conn.execute(
                f"""SELECT DISTINCT ticker
                    FROM all_account_info
                    WHERE profile_id IN ({placeholders})
                      AND COALESCE(quantity, 0) > 1e-9
                    ORDER BY ticker""",
                pids,
            ).fetchall()
            tickers = []
            for row in rows:
                ticker = row["ticker"] if isinstance(row, dict) else row[0]
                ticker = (ticker or "").strip().upper()
                if ticker:
                    tickers.append(ticker)
        finally:
            conn.close()

    tickers = [t for t in tickers if t][:250]
    now = time.time()
    growth = {}
    missing = []
    yahoo_to_ticker = {}

    for ticker in tickers:
        cached = _DIVIDEND_GROWTH_CACHE.get(ticker)
        if cached and now - cached.get("ts", 0) < _DIVIDEND_GROWTH_TTL_SEC:
            growth[ticker] = cached.get("value") or {"div_growth_3y": None, "div_growth_5y": None}
            continue
        yahoo_symbol = _yahoo_symbol_for_ticker(ticker)
        yahoo_to_ticker[yahoo_symbol] = ticker
        missing.append(yahoo_symbol)

    if missing:
        fetched = _calc_dividend_growth_batch(missing)
        for yahoo_symbol in missing:
            ticker = yahoo_to_ticker.get(yahoo_symbol, yahoo_symbol)
            value = fetched.get(yahoo_symbol) or {"div_growth_3y": None, "div_growth_5y": None}
            _DIVIDEND_GROWTH_CACHE[ticker] = {"ts": now, "value": value}
            growth[ticker] = value

    return jsonify({"growth": growth})


def _auto_reconcile_owner():
    """Silently reconcile Owner (profile 1) from sub-profiles after any import.

    Only runs if the Owner import has been used (owner_import_used setting).
    Syncs quantities, prices, and income fields while preserving Owner-only
    data (ytd_divs, total_divs_received, paid_for_itself, current_month_income,
    estim_payment_per_year, approx_monthly_income).
    """
    from datetime import date as _date

    conn = get_connection()
    owner_id = 1

    # Only reconcile if Owner import was used
    _oiu = conn.execute(
        "SELECT value FROM settings WHERE key = 'owner_import_used'"
    ).fetchone()
    if not (_oiu and _oiu[0] == "true"):
        conn.close()
        return

    # Get all non-Owner profiles that are marked for inclusion
    rows = conn.execute("SELECT id FROM profiles WHERE id != ? AND include_in_owner = 1", (owner_id,)).fetchall()
    source_ids = [r["id"] if isinstance(r, dict) else r[0] for r in rows]
    if not source_ids:
        conn.close()
        return

    placeholders = ",".join("?" * len(source_ids))

    # Aggregate holdings from source portfolios
    agg_rows = conn.execute(f"""
        SELECT
            ticker,
            MAX(description) as description,
            MAX(classification_type) as classification_type,
            SUM(quantity) as quantity,
            CASE WHEN SUM(quantity) > 0 THEN SUM(purchase_value) / SUM(quantity) ELSE 0 END as price_paid,
            MAX(current_price) as current_price,
            SUM(purchase_value) as purchase_value,
            CASE WHEN SUM(quantity) > 0 THEN SUM(COALESCE(original_purchase_value, purchase_value)) / SUM(quantity) ELSE 0 END as original_price_paid,
            SUM(COALESCE(original_purchase_value, purchase_value)) as original_purchase_value,
            CASE WHEN SUM(quantity) > 0 THEN SUM(COALESCE(broker_purchase_value, purchase_value)) / SUM(quantity) ELSE 0 END as broker_price_paid,
            SUM(COALESCE(broker_purchase_value, purchase_value)) as broker_purchase_value,
            SUM(current_value) as current_value,
            SUM(gain_or_loss) as gain_or_loss,
            CASE WHEN SUM(purchase_value) > 0 THEN SUM(gain_or_loss) / SUM(purchase_value) ELSE 0 END as gain_or_loss_percentage,
            CASE WHEN SUM(purchase_value) > 0 THEN SUM(gain_or_loss) / SUM(purchase_value) ELSE 0 END as percent_change,
            MAX(div_frequency) as div_frequency,
            MAX(reinvest) as reinvest,
            MAX(ex_div_date) as ex_div_date,
            MAX(div_pay_date) as div_pay_date,
            MAX(div) as div,
            SUM(dividend_paid) as dividend_paid,
            SUM(estim_payment_per_year) as estim_payment_per_year,
            SUM(approx_monthly_income) as approx_monthly_income,
            SUM(withdraw_8pct_cost_annually) as withdraw_8pct_cost_annually,
            SUM(withdraw_8pct_per_month) as withdraw_8pct_per_month,
            SUM(cash_not_reinvested) as cash_not_reinvested,
            SUM(total_cash_reinvested) as total_cash_reinvested,
            SUM(shares_bought_from_dividend) as shares_bought_from_dividend,
            SUM(shares_bought_in_year) as shares_bought_in_year,
            SUM(shares_in_month) as shares_in_month,
            MIN(purchase_date) as purchase_date
        FROM all_account_info
        WHERE profile_id IN ({placeholders})
        GROUP BY ticker
    """, source_ids).fetchall()

    agg_map = {r["ticker"]: dict(r) for r in agg_rows}

    owner_rows = conn.execute(
        "SELECT ticker FROM all_account_info WHERE profile_id = ?", (owner_id,)
    ).fetchall()
    owner_tickers = {r["ticker"] for r in owner_rows}

    # Sync these fields from sub-profiles.  Owner-only payout history fields
    # (ytd_divs, total_divs_received, paid_for_itself, current_month_income)
    # are preserved since sub-profiles don't track those.
    sync_fields = [
        "description", "classification_type", "quantity", "price_paid",
        "current_price", "purchase_value", "original_price_paid", "original_purchase_value",
        "broker_price_paid", "broker_purchase_value", "current_value", "gain_or_loss",
        "gain_or_loss_percentage", "percent_change", "div_frequency", "reinvest",
        "ex_div_date", "div_pay_date", "div", "dividend_paid",
        "estim_payment_per_year", "approx_monthly_income",
        "withdraw_8pct_cost_annually", "withdraw_8pct_per_month",
        "cash_not_reinvested", "total_cash_reinvested",
        "shares_bought_from_dividend", "shares_bought_in_year", "shares_in_month",
        "purchase_date",
    ]

    for ticker, agg in agg_map.items():
        if ticker in owner_tickers:
            sets = [f"{f} = ?" for f in sync_fields] + ["import_date = ?"]
            vals = [agg.get(f) for f in sync_fields] + [_date.today().isoformat(), ticker, owner_id]
            conn.execute(
                f"UPDATE all_account_info SET {', '.join(sets)} WHERE ticker = ? AND profile_id = ?",
                vals,
            )
        else:
            cols = ["ticker", "profile_id", "import_date"] + sync_fields
            vals = [ticker, owner_id, _date.today().isoformat()] + [agg.get(f) for f in sync_fields]
            ph = ",".join("?" * len(cols))
            conn.execute(f"INSERT INTO all_account_info ({', '.join(cols)}) VALUES ({ph})", vals)

    # Remove tickers from Owner that no longer exist in any sub-portfolio
    for ticker in owner_tickers - set(agg_map.keys()):
        conn.execute(
            "DELETE FROM all_account_info WHERE ticker = ? AND profile_id = ?",
            (ticker, owner_id),
        )

    conn.commit()

    # Refresh derived tables for Owner
    populate_holdings(owner_id)
    populate_dividends(owner_id)
    populate_income_tracking(owner_id)

    conn.close()


