_GOLDMAN_FUND_LIST_CACHE = {"ts": 0, "funds": {}}
_GOLDMAN_FUND_LIST_URLS = (
    "https://am.gs.com/en-us/advisors/products/active-etfs",
    "https://am.gs.com/en-us/advisors/products/exchange-traded-funds",
)


def _is_goldman_sachs_fund(ticker, description=""):
    """Identify Goldman Sachs ETFs, including GPIQ/GPIX premium income funds."""
    ticker = (ticker or "").strip().upper()
    description_l = (description or "").lower()
    if "goldman sachs" in description_l or "gsam" in description_l:
        return True
    explicit_family = {
        # Goldman Sachs ETF hub entries, kept as a backstop for sparse Yahoo descriptions.
        "GPIX", "GPIQ", "GMUB", "GSGO", "GSST", "GSC", "GBND", "GSWO", "GTPE",
    }
    return ticker in explicit_family


def _goldman_clean_float(value):
    text = str(value or "").strip()
    if not text or text in {"--", "-", "N/A"}:
        return None
    text = re.sub(r"[^0-9.\-]", "", text)
    if not text:
        return None
    try:
        return float(text)
    except Exception:
        return None


def _goldman_collect_funds(node, found):
    if isinstance(node, dict):
        ticker = str(node.get("ticker") or "").strip().upper()
        pv = node.get("pvNumber")
        share_class = node.get("shareClassId")
        if ticker and pv and share_class:
            found[ticker] = {
                "ticker": ticker,
                "pvNumber": pv,
                "shareClassId": share_class,
                "fundName": node.get("fundName"),
            }
        for value in node.values():
            _goldman_collect_funds(value, found)
    elif isinstance(node, list):
        for item in node:
            _goldman_collect_funds(item, found)


def _fetch_goldman_fund_map():
    """Return ticker -> Goldman fund ids from public Goldman ETF pages."""
    import requests

    now = time.time()
    if _GOLDMAN_FUND_LIST_CACHE["funds"] and now - _GOLDMAN_FUND_LIST_CACHE["ts"] < 60 * 60 * 6:
        return _GOLDMAN_FUND_LIST_CACHE["funds"]

    funds = {}
    for url in _GOLDMAN_FUND_LIST_URLS:
        try:
            resp = requests.get(
                url,
                timeout=12,
                headers={"User-Agent": "Mozilla/5.0 PortfolioTrackingClient/1.0"},
            )
            resp.raise_for_status()
            match = re.search(
                r'<script id="__NEXT_DATA__" type="application/json">(.*?)</script>',
                resp.text or "",
                flags=re.DOTALL,
            )
            if not match:
                continue
            page_data = json.loads(match.group(1))
            _goldman_collect_funds(page_data, funds)
        except Exception:
            continue

    if funds:
        _GOLDMAN_FUND_LIST_CACHE["ts"] = now
        _GOLDMAN_FUND_LIST_CACHE["funds"] = funds
    return funds


def _fetch_goldman_distribution_snapshot(ticker):
    """Fetch official Goldman Sachs fund yield and distributions when available."""
    import requests

    ticker = (ticker or "").strip().upper()
    if not ticker:
        return None

    fund = _fetch_goldman_fund_map().get(ticker)
    if not fund:
        return None

    query = """
      query getFundsDetail($fundDetailRequest: FundDetailRequest) {
        fundsDetail(fundDetailRequest: $fundDetailRequest) {
          fundName
          ticker
          distributionFrequency
          yield {
            value
            label
            asAtDate
          }
          distributions
        }
      }
    """
    variables = {
        "fundDetailRequest": {
            "country": "US",
            "language": "en",
            "audience": "individual",
            "pvNumber": fund["pvNumber"],
            "shareClassId": fund["shareClassId"],
        }
    }

    try:
        resp = requests.post(
            "https://am.gs.com/services/funds",
            json={"query": query, "variables": variables},
            timeout=12,
            headers={
                "User-Agent": "Mozilla/5.0 PortfolioTrackingClient/1.0",
                "Content-Type": "application/json",
            },
        )
        resp.raise_for_status()
        payload = resp.json()
    except Exception:
        return None

    detail = ((payload.get("data") or {}).get("fundsDetail") or {})
    if not detail:
        return None

    yield_entries = detail.get("yield") or []
    distribution_rate_pct = None
    if isinstance(yield_entries, list):
        for item in yield_entries:
            distribution_rate_pct = _goldman_clean_float((item or {}).get("value"))
            if distribution_rate_pct is not None:
                break

    entries = []
    for row in detail.get("distributions") or []:
        amount = _goldman_clean_float((row or {}).get("amount") or (row or {}).get("income"))
        ex_ts = pd.to_datetime((row or {}).get("expirationDate"), format="%m/%d/%Y", errors="coerce")
        pay_ts = pd.to_datetime((row or {}).get("payableDate"), format="%m/%d/%Y", errors="coerce")
        if amount is None or pd.isna(ex_ts):
            continue
        entries.append((ex_ts.normalize(), amount, pay_ts.normalize() if not pd.isna(pay_ts) else None))

    history = pd.Series(dtype=float)
    latest_ex = None
    latest_pay = None
    if entries:
        entries.sort(key=lambda item: item[0])
        history = pd.Series(
            [item[1] for item in entries],
            index=pd.DatetimeIndex([item[0] for item in entries]),
        )
        history = history[~history.index.duplicated(keep="last")].sort_index()
        pay_map = {item[0]: item[2] for item in entries if item[2] is not None}
        latest_ex = history.index[-1]
        latest_pay = pay_map.get(latest_ex)

    if history.empty and distribution_rate_pct is None:
        return None

    freq_text = str(detail.get("distributionFrequency") or "").lower()
    freq = None
    if "week" in freq_text:
        freq = "W"
    elif "month" in freq_text:
        freq = "M"
    elif "quarter" in freq_text:
        freq = "Q"
    elif "semi" in freq_text:
        freq = "SA"
    elif "annual" in freq_text:
        freq = "A"
    if freq is None and not history.empty:
        freq = _infer_dividend_frequency_from_history(history)

    return {
        "known": True,
        "has_dividend": bool(not history.empty or distribution_rate_pct is not None),
        "div": float(history.iloc[-1]) if not history.empty else None,
        "ex_div_date": latest_ex.strftime("%m/%d/%y") if latest_ex is not None else None,
        "div_pay_date": latest_pay.strftime("%m/%d/%y") if latest_pay is not None else None,
        "freq": freq,
        "history": history,
        "distribution_rate_pct": distribution_rate_pct,
        "source": "Goldman Sachs",
    }


_TUTTLE_INCOME_BLAST_TICKERS = {"DRMP", "SPCI", "MEMY", "MAGO", "BITK"}


def _is_tuttle_capital_fund(ticker, description=""):
    """Identify Tuttle Capital / Income Blast funds with official holdings pages."""
    ticker = (ticker or "").strip().upper()
    description_l = (description or "").lower()
    return (
        ticker in _TUTTLE_INCOME_BLAST_TICKERS
        or "tuttle capital" in description_l
        or "income blast" in description_l
    )


_FUND_FAMILY_REGISTRY = [
    # (keywords_in_description, extra_condition_fn_or_None, fetcher)
    # Checked in order; first match wins.  Keywords are matched against a
    # combined lowercased text built from the ticker, fund name, description,
    # and yfinance issuer/family so that *any* new ticker from a known fund
    # family is automatically routed to the correct scraper.
    {
        "keywords": ["yieldmax"],
        "fetcher": "_fetch_yieldmax_distribution_snapshot",
        "legacy": _is_yieldmax_fund,
    },
    {
        "keywords": ["neos"],
        "fetcher": "_fetch_neos_distribution_snapshot",
        "legacy": _is_neos_fund,
    },
    {
        "keywords": ["tappalpha", "tapalpha", "tapp alpha"],
        "fetcher": "_fetch_tappalpha_distribution_snapshot",
        "legacy": _is_tappalpha_fund,
    },
    {
        "keywords": ["nicholas wealth", "xfunds", "nicholasx"],
        "fetcher": "_fetch_xfunds_distribution_snapshot",
        "legacy": _is_xfunds_fund,
    },
    {
        "keywords": ["kurv"],
        "fetcher": "_fetch_kurv_distribution_snapshot",
        "legacy": _is_kurv_fund,
    },
    {
        "keywords": ["infracap", "infrastructure capital"],
        "fetcher": "_fetch_infracap_distribution_snapshot",
        "legacy": _is_infracap_fund,
    },
    {
        "keywords": ["global x", "globalx"],
        "fetcher": "_fetch_globalx_distribution_snapshot",
        "legacy": _is_globalx_fund,
    },
    {
        "keywords": ["amplify"],
        "fetcher": "_fetch_amplify_distribution_snapshot",
        "legacy": _is_amplify_fund,
    },
    {
        "keywords": ["quantify", "incomestkd"],
        "fetcher": "_fetch_quantify_distribution_snapshot",
        "legacy": _is_quantify_fund,
    },
    {
        "keywords": ["rex shares", "rexshares"],
        "extra_keywords": ["income", "premium", "covered call", "growth & income", "growth and income"],
        "fetcher": "_fetch_rex_distribution_snapshot",
        "legacy": _is_rex_fund,
    },
    {
        "keywords": ["goldman sachs", "gsam"],
        "fetcher": "_fetch_goldman_distribution_snapshot",
        "legacy": _is_goldman_sachs_fund,
    },
    {
        "keywords": ["tuttle capital", "income blast"],
        "fetcher": "_fetch_income_blast_distribution_snapshot",
        "legacy": _is_tuttle_capital_fund,
    },
]


def _match_fund_family(ticker, description=""):
    """Identify which fund family a ticker belongs to using keyword matching."""
    ticker = (ticker or "").strip().upper()
    text = (description or "").lower()

    for entry in _FUND_FAMILY_REGISTRY:
        if entry["legacy"](ticker, description):
            return entry
        if any(kw in text for kw in entry["keywords"]):
            extra = entry.get("extra_keywords")
            if extra and not any(ek in text for ek in extra):
                continue
            return entry
    return None


def _fetch_official_distribution_snapshot(ticker, description=None):
    """Fetch issuer-published distribution data for supported fund families."""
    ticker = (ticker or "").strip().upper()
    description = description or ""

    entry = _match_fund_family(ticker, description)
    if entry is None:
        return None
    cache_key = (ticker, entry["fetcher"])
    cached = _cache_get(
        _OFFICIAL_DISTRIBUTION_CACHE,
        cache_key,
        _OFFICIAL_DISTRIBUTION_TTL_SEC,
    )
    if cached is False:
        return None
    if cached is not None:
        return cached
    fetcher = globals().get(entry["fetcher"])
    if fetcher is None:
        return None
    result = fetcher(ticker)
    # Cache misses too. Unsupported/new tickers otherwise repeatedly wait on
    # the same issuer page every time the return mode changes.
    _cache_set(_OFFICIAL_DISTRIBUTION_CACHE, cache_key, result if result is not None else False)
    return result


def _fetch_refresh_dividend_snapshot(yf_ticker, preferred_freq=None):
    """Fetch dividend metadata for refresh when the batch download is incomplete."""
    from datetime import timezone as _timezone

    snapshot = {
        "known": True,
        "has_dividend": False,
        "div": 0.0,
        "ex_div_date": None,
        "div_pay_date": None,
        "freq": None,
        "history": pd.Series(dtype=float),
    }

    preferred = (preferred_freq or "").strip().upper() or None
    info = {}
    try:
        info = yf_ticker.info or {}
    except Exception:
        info = {}

    ticker = getattr(yf_ticker, "ticker", None)
    description = (info or {}).get("longName") or (info or {}).get("shortName") or ""

    try:
        hist = yf_ticker.dividends
    except Exception:
        hist = None

    recent = pd.Series(dtype=float)
    if hist is not None and len(hist) > 0:
        try:
            if getattr(hist.index, "tz", None) is not None:
                one_year_ago = pd.Timestamp.now(tz=hist.index.tz) - pd.Timedelta(days=365)
            else:
                one_year_ago = pd.Timestamp.now() - pd.Timedelta(days=365)
            recent = hist[hist.index >= one_year_ago]
            recent = recent[recent > 0].dropna()
        except Exception:
            recent = pd.Series(dtype=float)

    if not recent.empty:
        snapshot["has_dividend"] = True
        snapshot["div"] = float(recent.iloc[-1])
        snapshot["ex_div_date"] = _format_mdy_date(recent.index[-1])
        snapshot["freq"] = _infer_dividend_frequency_from_history(recent)
        snapshot["history"] = recent
    else:
        annual_rate = info.get("dividendRate") or 0
        ex_ts = info.get("exDividendDate")
        if annual_rate and annual_rate > 0:
            freq = preferred or "Q"
            mult = {"W": 52, "52": 52, "M": 12, "Q": 4, "SA": 2, "A": 1}.get(freq, 4)
            snapshot["has_dividend"] = True
            snapshot["freq"] = freq
            snapshot["div"] = float(annual_rate) / mult if mult else float(annual_rate)
        if ex_ts:
            snapshot["has_dividend"] = True
            if isinstance(ex_ts, (int, float)):
                ex_ts = pd.Timestamp(ex_ts, unit="s", tz=_timezone.utc)
            snapshot["ex_div_date"] = _format_mdy_date(ex_ts)

    official = _fetch_official_distribution_snapshot(ticker, description)
    official_pay_date = None

    if official:
        snapshot.update(official)
        official_pay_date = official.get("div_pay_date")

    if not official_pay_date:
        try:
            cal = yf_ticker.calendar
            pay_date = None
            if isinstance(cal, dict):
                pay_date = cal.get("Dividend Date") or cal.get("Payment Date")
            elif hasattr(cal, "loc"):
                for key in ["Dividend Date", "Payment Date"]:
                    if key in cal.index:
                        pay_date = cal.loc[key].iloc[0] if hasattr(cal.loc[key], "iloc") else cal.loc[key]
                        break
            if isinstance(pay_date, (int, float)):
                pay_date = pd.Timestamp(pay_date, unit="s", tz=_timezone.utc)
            snapshot["div_pay_date"] = _format_mdy_date(pay_date)
        except Exception:
            pass

    if not snapshot["div_pay_date"] and snapshot["ex_div_date"]:
        est_pay_ts = _estimate_dividend_pay_from_pattern(
            snapshot["ex_div_date"],
            snapshot["freq"] or preferred,
            ticker=ticker,
            description=description,
        )
        snapshot["div_pay_date"] = _format_mdy_date(est_pay_ts)

    if snapshot["has_dividend"] and not snapshot["freq"]:
        snapshot["freq"] = preferred or "Q"

    return snapshot


def _apply_official_snapshot_override(ticker, snapshot, description=None):
    """Prefer official issuer data over Yahoo when the ticker belongs to a supported family."""
    ticker = (ticker or "").strip().upper()
    snapshot = dict(snapshot or {})
    description = description or ""

    official = _fetch_official_distribution_snapshot(ticker, description)

    if not official:
        return snapshot

    snapshot.update(official)
    return snapshot


def _simulate_drip_refresh(div_series, close_series, base_qty, start_date=None, today=None):
    """Simulate post-start DRIP activity and actual dividend cash by dividend date."""
    if div_series is None or div_series.empty or close_series is None or close_series.empty:
        return {
            "quantity": float(base_qty or 0),
            "drip_shares": 0.0,
            "drip_total_divs": 0.0,
            "ytd_divs": 0.0,
            "current_month_income": 0.0,
            "event_count": 0,
        }

    div_series = _ensure_naive_datetime_index(div_series)
    close_series = _ensure_naive_datetime_index(close_series)
    today_ts = _parse_timestamp_value(today) or pd.Timestamp.now().normalize()
    start_ts = _parse_timestamp_value(start_date)
    jan1 = pd.Timestamp(today_ts.year, 1, 1)
    first_of_month = pd.Timestamp(today_ts.year, today_ts.month, 1)
    ytd_floor = max(jan1, start_ts) if start_ts is not None else jan1
    month_floor = max(first_of_month, ytd_floor)

    eligible = div_series[div_series.index <= today_ts]
    if start_ts is not None:
        eligible = eligible[eligible.index > start_ts]

    running_qty = float(base_qty or 0)
    drip_shares = 0.0
    drip_total_divs = 0.0
    ytd_total = 0.0
    current_total = 0.0
    event_count = 0

    for div_date, div_amt in eligible.items():
        prices_on_or_before = close_series[close_series.index <= div_date]
        if prices_on_or_before.empty:
            continue
        reinvest_price = float(prices_on_or_before.iloc[-1])
        if reinvest_price <= 0:
            continue

        div_income = float(div_amt) * running_qty
        if div_date >= ytd_floor:
            ytd_total += div_income
        if div_date >= month_floor:
            current_total += div_income

        new_shares = div_income / reinvest_price
        drip_shares += new_shares
        drip_total_divs += div_income
        running_qty += new_shares
        event_count += 1

    return {
        "quantity": running_qty,
        "drip_shares": drip_shares,
        "drip_total_divs": drip_total_divs,
        "ytd_divs": ytd_total,
        "current_month_income": current_total,
        "event_count": event_count,
    }


def _reinvest_period_key(ts, view):
    """Bucket a timestamp into a sortable period key for the chosen granularity."""
    if view == "yearly":
        return f"{ts.year:04d}"
    if view == "weekly":
        iso = ts.isocalendar()
        return f"{iso[0]:04d}-W{int(iso[1]):02d}"
    return f"{ts.year:04d}-{ts.month:02d}"  # monthly


def _drip_period_series(div_series, close_series, base_qty, view,
                        reinvest=True, start_date=None, today=None):
    """Replay dividend reinvestment chronologically, emitting one record per
    period bucket (week / month / year).

    Mirrors the event walk in ``_simulate_drip_refresh`` but, instead of only
    end-state totals, returns the per-period story used by the Reinvestment
    Impact page. For each period key it accumulates:
        payout             — distribution cash that period (dps * shares held)
        dps                — distribution per share paid that period
        drip_shares_added  — shares bought by reinvesting that period's cash
        shares_start       — share count entering the period
        shares_end         — share count leaving the period
        reinvest_price     — last close used to reinvest in the period
    When ``reinvest`` is False, share count stays flat (payouts still accrue).
    """
    out = {}
    if div_series is None or div_series.empty or close_series is None or close_series.empty:
        return out

    div_series = _ensure_naive_datetime_index(div_series)
    close_series = _ensure_naive_datetime_index(close_series)
    today_ts = _parse_timestamp_value(today) or pd.Timestamp.now().normalize()
    start_ts = _parse_timestamp_value(start_date)

    eligible = div_series[div_series.index <= today_ts]
    if start_ts is not None:
        eligible = eligible[eligible.index > start_ts]

    running_qty = float(base_qty or 0)
    for div_date, div_amt in eligible.items():
        prices_on_or_before = close_series[close_series.index <= div_date]
        if prices_on_or_before.empty:
            continue
        reinvest_price = float(prices_on_or_before.iloc[-1])
        if reinvest_price <= 0:
            continue

        key = _reinvest_period_key(div_date, view)
        rec = out.get(key)
        if rec is None:
            rec = {
                "payout": 0.0,
                "dps": 0.0,
                "drip_shares_added": 0.0,
                "shares_start": running_qty,
                "shares_end": running_qty,
                "reinvest_price": reinvest_price,
            }
            out[key] = rec

        div_amt = float(div_amt)
        income = div_amt * running_qty
        new_shares = (income / reinvest_price) if reinvest else 0.0
        running_qty += new_shares

        rec["payout"] += income
        rec["dps"] += div_amt
        rec["drip_shares_added"] += new_shares
        rec["shares_end"] = running_qty
        rec["reinvest_price"] = reinvest_price

    return out


def _reinvest_history(ticker):
    """Cached full price+dividend frame for one ticker (yfinance, period=max)."""
    cached = _cache_get(_REINVEST_HISTORY_CACHE, ticker, ttl=_REINVEST_HISTORY_TTL_SEC)
    if cached is not None:
        return cached
    import yfinance as yf
    try:
        hist = yf.Ticker(ticker).history(period="max", auto_adjust=False, actions=True)
    except Exception:
        hist = None
    _cache_set(_REINVEST_HISTORY_CACHE, ticker, hist)
    return hist


# ── Refresh Market Data ─────────────────────────────────────────────────────────

def _portfolio_daily_price_change(
    holding_map,
    close_history,
    profile_ids,
    account_current_value=None,
):
    """Aggregate the latest session's price move using current share counts.

    When the full account value is known, use it for the percentage denominator
    so idle cash and temporarily uncovered holdings do not overstate the return.
    """
    included_profiles = set(profile_ids or [])
    current_value = 0.0
    previous_value = 0.0
    holdings_total = 0
    holdings_covered = 0
    as_of_dates = []
    previous_dates = []

    for (profile_id, ticker), holding in holding_map.items():
        if profile_id not in included_profiles:
            continue
        try:
            quantity = float(holding.get("qty") or 0)
        except (TypeError, ValueError):
            continue
        if quantity <= 0:
            continue

        holdings_total += 1
        series = close_history.get(ticker)
        if series is None:
            continue
        try:
            prices = series.dropna()
            if len(prices) < 2:
                continue
            latest_price = float(prices.iloc[-1])
            previous_price = float(prices.iloc[-2])
        except (TypeError, ValueError, IndexError):
            continue
        if latest_price <= 0 or previous_price <= 0:
            continue

        holdings_covered += 1
        current_value += quantity * latest_price
        previous_value += quantity * previous_price
        try:
            as_of_dates.append(pd.Timestamp(prices.index[-1]).date().isoformat())
            previous_dates.append(pd.Timestamp(prices.index[-2]).date().isoformat())
        except (TypeError, ValueError):
            pass

    if holdings_covered == 0 or previous_value <= 0:
        return None

    amount = current_value - previous_value
    account_previous_value = None
    percent_base = previous_value
    try:
        full_current_value = float(account_current_value)
        if full_current_value > 0:
            account_previous_value = full_current_value - amount
            if account_previous_value > 0:
                percent_base = account_previous_value
    except (TypeError, ValueError):
        full_current_value = None

    return {
        "amount": round(amount, 2),
        "percent": round((amount / percent_base) * 100, 4),
        "current_value": round(current_value, 2),
        "previous_value": round(previous_value, 2),
        "account_current_value": round(full_current_value, 2) if full_current_value else None,
        "account_previous_value": (
            round(account_previous_value, 2)
            if account_previous_value is not None
            else None
        ),
        "holdings_covered": holdings_covered,
        "holdings_total": holdings_total,
        "as_of_date": max(as_of_dates) if as_of_dates else None,
        "previous_date": max(previous_dates) if previous_dates else None,
    }


@app.route("/api/refresh", methods=["POST"])
def refresh_market_data():
    """Update current price, div/share, ex-div date, and frequency for all holdings from Yahoo Finance."""
    import yfinance as yf
    from datetime import datetime as _dt, timedelta as _td

    conn = get_connection()
    refresh_info = _get_refresh_target_info(conn)
    scope = refresh_info["scope"]
    source_pids = refresh_info["source_profile_ids"]
    selected_profile_id = refresh_info["selected_profile_id"]

    # Refresh only the profiles relevant to the current holdings view:
    # - single profile: just that profile
    # - Owner: source accounts that feed Owner
    # - Aggregate: aggregate member profiles
    all_rows = conn.execute(
        "SELECT profile_id, ticker, description, quantity, price_paid, purchase_value, purchase_date, reinvest, base_quantity, import_date, ex_div_date, div_pay_date, div_frequency, div, dividend_paid, estim_payment_per_year, approx_monthly_income, current_value, ytd_divs, current_month_income FROM all_account_info WHERE profile_id IN ({})".format(
            ",".join("?" * len(source_pids))
        ) + " AND quantity > 0",
        source_pids,
    ).fetchall()

    profile_name_rows = conn.execute(
        "SELECT id, name FROM profiles WHERE id IN ({})".format(",".join("?" * len(source_pids))),
        source_pids,
    ).fetchall()
    refresh_profile_names = {r["id"]: r["name"] for r in profile_name_rows}

    if not all_rows:
        dividend_update_accounts = [
            {
                "profile_id": pid,
                "name": refresh_profile_names.get(pid) or f"Profile {pid}",
                "dividend_updates": 0,
                "accrued_dividends": 0.0,
                "days_since_last_refresh": None,
                "distributions_today": [],
                "history_payments_recorded": 0,
                "history_payments_inserted": 0,
                "history_payments_updated": 0,
                "history_payments_existing": 0,
            }
            for pid in source_pids
        ]
        conn.close()
        return jsonify({
            "updated": 0,
            "dividend_updates": 0,
            "dividend_update_accounts": dividend_update_accounts,
            "daily_change": None,
            "refresh_date": _dt.now().date().isoformat(),
            "message": "No holdings to refresh",
        })

    tickers = list({r["ticker"] for r in all_rows})
    # Build per-profile holding map
    holding_map = {}
    for r in all_rows:
        holding_map[(r["profile_id"], r["ticker"])] = {
            "qty": r["quantity"] or 0,
            "description": r["description"] or "",
            "price_paid": r["price_paid"] or 0,
            "purchase_value": r["purchase_value"] or 0,
            "purchase_date": r["purchase_date"] or "",
            "reinvest": (r["reinvest"] or "").upper(),
            "base_quantity": r["base_quantity"] or r["quantity"] or 0,
            "import_date": r["import_date"] or "",
            "ex_div_date": r["ex_div_date"] or None,
            "div_pay_date": r["div_pay_date"] or None,
            "div_frequency": r["div_frequency"] or None,
            "div": r["div"] or 0,
            "dividend_paid": r["dividend_paid"] or 0,
            "estim_payment_per_year": r["estim_payment_per_year"] or 0,
            "approx_monthly_income": r["approx_monthly_income"] or 0,
            "current_value": r["current_value"] or 0,
            "ytd_divs": r["ytd_divs"] or 0,
            "current_month_income": r["current_month_income"] or 0,
        }
    description_map = {}
    existing_dividend_hint = {}
    for r in all_rows:
        if r["ticker"] not in description_map and r["description"]:
            description_map[r["ticker"]] = r["description"]
        if r["ticker"] not in existing_dividend_hint:
            existing_dividend_hint[r["ticker"]] = False
        if (
            (r["div"] or 0) > 0
            or (r["estim_payment_per_year"] or 0) > 0
            or (r["approx_monthly_income"] or 0) > 0
            or (r["ytd_divs"] or 0) > 0
            or (r["current_month_income"] or 0) > 0
            or bool(r["div_frequency"])
            or bool(r["ex_div_date"])
            or bool(r["div_pay_date"])
        ):
            existing_dividend_hint[r["ticker"]] = True

    # Batch download prices + dividends (one yfinance call for all tickers)
    ticker_str = " ".join(tickers)
    price_map = {}
    div_map = {}
    exdiv_map = {}
    freq_map = {}
    div_history = {}    # ticker -> pandas Series of positive dividends (index=dates)
    close_history = {}  # ticker -> pandas Series of close prices (index=dates)
    div_snapshot_map = {}
    raw = pd.DataFrame()

    try:
        raw = _chunked_yf_download(ticker_str, period="1y", progress=False, auto_adjust=False, actions=True)
        if not raw.empty:
            def _col(name):
                if isinstance(raw.columns, pd.MultiIndex):
                    return raw[name] if name in raw.columns.get_level_values(0) else None
                return raw[name] if name in raw.columns else None

            # Prices
            close = _col("Close")
            if close is not None:
                if isinstance(close, pd.Series):
                    s = close.dropna()
                    if len(s):
                        price_map[tickers[0]] = float(s.iloc[-1])
                        close_history[tickers[0]] = s
                else:
                    for t in tickers:
                        if t in close.columns:
                            s = close[t].dropna()
                            if len(s):
                                price_map[t] = float(s.iloc[-1])
                                close_history[t] = s

            # Dividends
            divs = _col("Dividends")
            if divs is not None:
                if isinstance(divs, pd.Series):
                    d = divs[divs > 0].dropna()
                    if not d.empty:
                        t0 = tickers[0]
                        div_map[t0] = float(d.iloc[-1])
                        exdiv_map[t0] = d.index[-1].strftime("%m/%d/%y")
                        n = len(d)
                        freq_map[t0] = "W" if n >= 45 else "M" if n >= 10 else "Q" if n >= 3 else "SA" if n >= 2 else "A"
                        div_history[t0] = d
                else:
                    for t in tickers:
                        if t in divs.columns:
                            d = divs[t][divs[t] > 0].dropna()
                            if not d.empty:
                                div_map[t] = float(d.iloc[-1])
                                exdiv_map[t] = d.index[-1].strftime("%m/%d/%y")
                                n = len(d)
                                freq_map[t] = "W" if n >= 45 else "M" if n >= 10 else "Q" if n >= 3 else "SA" if n >= 2 else "A"
                                div_history[t] = d
    except Exception:
        pass

    # Detect renamed tickers: if a ticker got no price data from batch download,
    # check if yfinance maps it to a new symbol and pull data under that column.
    rename_map = {}  # old_ticker -> new_ticker
    for t in tickers:
        if t not in price_map:
            try:
                info = yf.Ticker(t).info or {}
                new_sym = (info.get("symbol") or "").upper()
                if new_sym and new_sym != t:
                    rename_map[t] = new_sym
                    # Try to pull data from the new symbol's column in the batch download
                    if not raw.empty and isinstance(raw.columns, pd.MultiIndex):
                        close = raw["Close"] if "Close" in raw.columns.get_level_values(0) else None
                        if close is not None and not isinstance(close, pd.Series) and new_sym in close.columns:
                            s = close[new_sym].dropna()
                            if len(s):
                                price_map[t] = float(s.iloc[-1])
                                close_history[t] = s
                        divs = raw["Dividends"] if "Dividends" in raw.columns.get_level_values(0) else None
                        if divs is not None and not isinstance(divs, pd.Series) and new_sym in divs.columns:
                            d = divs[new_sym][divs[new_sym] > 0].dropna()
                            if not d.empty:
                                div_map[t] = float(d.iloc[-1])
                                exdiv_map[t] = d.index[-1].strftime("%m/%d/%y")
                                n = len(d)
                                freq_map[t] = "W" if n >= 45 else "M" if n >= 10 else "Q" if n >= 3 else "SA" if n >= 2 else "A"
                                div_history[t] = d
                    # If still no data, try a separate download for the new symbol
                    if t not in price_map:
                        try:
                            r2 = _chunked_yf_download(new_sym, period="1y", progress=False, auto_adjust=False, actions=True)
                            if not r2.empty:
                                c2 = r2["Close"] if "Close" in r2.columns else (r2["Close"][new_sym] if isinstance(r2.columns, pd.MultiIndex) else None)
                                if c2 is not None:
                                    s2 = c2.squeeze().dropna()
                                    if len(s2):
                                        price_map[t] = float(s2.iloc[-1])
                                        close_history[t] = s2
                                d2 = r2["Dividends"] if "Dividends" in r2.columns else (r2["Dividends"][new_sym] if isinstance(r2.columns, pd.MultiIndex) else None)
                                if d2 is not None:
                                    d2s = d2.squeeze()
                                    d2s = d2s[d2s > 0].dropna()
                                    if not d2s.empty:
                                        div_map[t] = float(d2s.iloc[-1])
                                        exdiv_map[t] = d2s.index[-1].strftime("%m/%d/%y")
                                        n = len(d2s)
                                        freq_map[t] = "W" if n >= 45 else "M" if n >= 10 else "Q" if n >= 3 else "SA" if n >= 2 else "A"
                                        div_history[t] = d2s
                        except Exception:
                            pass
                    # Update description if it matches the ticker (i.e., never got enriched)
                    if new_sym:
                        try:
                            new_info = yf.Ticker(new_sym).info or {}
                            new_desc = new_info.get("longName") or new_info.get("shortName")
                            if new_desc:
                                for pid in source_pids:
                                    conn.execute(
                                        "UPDATE all_account_info SET description = ? WHERE ticker = ? AND profile_id = ? AND (description = ? OR description IS NULL OR description = '')",
                                        (new_desc[:200], t, pid, t),
                                    )
                        except Exception:
                            pass
            except Exception:
                pass

    lag_pattern_map = _build_dividend_lag_patterns(conn)

    # Load known weekly tickers across all profiles
    weekly_set = set()
    try:
        wrows = conn.execute("SELECT DISTINCT ticker FROM weekly_payout_tickers").fetchall()
        weekly_set = {r["ticker"] for r in wrows}
    except Exception:
        pass

    # Load current DB frequencies across all profiles (use highest rank per ticker)
    db_freq_map = {}
    try:
        frows = conn.execute("SELECT ticker, div_frequency FROM all_account_info").fetchall()
        freq_rank = {'W': 6, '52': 6, 'M': 5, 'Q': 4, 'SA': 3, 'A': 2, None: 0}
        for r in frows:
            t, f = r["ticker"], r["div_frequency"]
            if freq_rank.get(f, 0) > freq_rank.get(db_freq_map.get(t), 0):
                db_freq_map[t] = f
    except Exception:
        pass

    # Resolve effective frequency per ticker (once, shared across profiles)
    freq_rank = {'W': 6, '52': 6, 'M': 5, 'Q': 4, 'SA': 3, 'A': 2, None: 0}
    effective_freq = {}
    for t in tickers:
        if t in div_history and div_map.get(t) is not None:
            div_snapshot_map[t] = {
                "known": True,
                "has_dividend": True,
                "div": div_map.get(t) or 0.0,
                "ex_div_date": exdiv_map.get(t),
                "div_pay_date": _format_mdy_date(
                    _estimate_dividend_pay_from_pattern(
                        exdiv_map.get(t),
                        freq_map.get(t),
                        pattern=lag_pattern_map.get(t),
                        ticker=t,
                        description=description_map.get(t),
                    )
                ),
                "freq": freq_map.get(t),
                "history": div_history.get(t, pd.Series(dtype=float)),
            }
        elif t in close_history:
            # Batch download returned valid market data for this ticker and
            # showed no positive dividends in the period. If this ticker already
            # had dividend data, preserve those fields unless a fallback source
            # positively returns replacement dividend data; Yahoo often returns
            # prices while omitting actions for income funds.
            if existing_dividend_hint.get(t):
                preferred_freq = 'W' if t in weekly_set else db_freq_map.get(t)
                lookup_symbol = rename_map.get(t, t)
                try:
                    fallback_snapshot = _fetch_refresh_dividend_snapshot(
                        yf.Ticker(lookup_symbol),
                        preferred_freq=preferred_freq,
                    )
                except Exception:
                    fallback_snapshot = None

                if fallback_snapshot and fallback_snapshot.get("has_dividend"):
                    div_snapshot_map[t] = fallback_snapshot
                else:
                    div_snapshot_map[t] = {
                        "known": False,
                        "has_dividend": False,
                        "div": 0.0,
                        "ex_div_date": None,
                        "div_pay_date": None,
                        "freq": None,
                        "history": pd.Series(dtype=float),
                    }
            else:
                div_snapshot_map[t] = {
                    "known": True,
                    "has_dividend": False,
                    "div": 0.0,
                    "ex_div_date": None,
                    "div_pay_date": None,
                    "freq": None,
                    "history": pd.Series(dtype=float),
                }
        else:
            preferred_freq = 'W' if t in weekly_set else db_freq_map.get(t)
            lookup_symbol = rename_map.get(t, t)
            try:
                div_snapshot_map[t] = _fetch_refresh_dividend_snapshot(
                    yf.Ticker(lookup_symbol),
                    preferred_freq=preferred_freq,
                )
            except Exception:
                div_snapshot_map[t] = {
                    "known": False,
                    "has_dividend": False,
                    "div": 0.0,
                    "ex_div_date": None,
                    "div_pay_date": None,
                    "freq": None,
                    "history": pd.Series(dtype=float),
                }

        div_snapshot_map[t] = _apply_official_snapshot_override(
            t,
            div_snapshot_map.get(t),
            description=description_map.get(t),
        )

        snapshot = div_snapshot_map[t]
        if snapshot.get("has_dividend"):
            nf = snapshot.get("freq")
            if t in weekly_set:
                nf = 'W'
            else:
                db_rank = freq_rank.get(db_freq_map.get(t), 0)
                new_rank = freq_rank.get(nf, 0)
                if new_rank < db_rank:
                    nf = db_freq_map.get(t)
            effective_freq[t] = nf
        else:
            effective_freq[t] = None

    def _refresh_num_changed(old_value, new_value, tolerance=0.005):
        try:
            return abs(float(old_value or 0) - float(new_value or 0)) > tolerance
        except Exception:
            return (old_value or "") != (new_value or "")

    def _refresh_text_changed(old_value, new_value):
        return (old_value or "") != (new_value or "")

    def _refresh_parse_date(value):
        if not value:
            return None
        for fmt in ("%m/%d/%y", "%m/%d/%Y", "%Y-%m-%d"):
            try:
                return _dt.strptime(str(value).strip(), fmt).date()
            except Exception:
                pass
        return None

    def _refresh_frequency_multiplier(freq):
        return {'W': 52, '52': 52, 'M': 12, 'Q': 4, 'SA': 2, 'A': 1}.get(
            (freq or 'Q').upper(),
            4,
        )

    def _refresh_annual_income_from_rate(div, quantity, freq):
        try:
            div = float(div or 0)
            quantity = float(quantity or 0)
        except (TypeError, ValueError):
            return 0.0
        if div <= 0 or quantity <= 0:
            return 0.0
        return div * quantity * _refresh_frequency_multiplier(freq)

    def _refresh_income_matches_rate(income, div, quantity, freq):
        expected = _refresh_annual_income_from_rate(div, quantity, freq)
        if expected <= 0:
            return False
        return not _refresh_num_changed(income, expected, tolerance=max(1.0, expected * 0.03))

    def _refresh_expected_pay_date(ex_div_date, pay_date, freq):
        parsed_pay = _refresh_parse_date(pay_date)
        if parsed_pay:
            return parsed_pay
        parsed_ex = _refresh_parse_date(ex_div_date)
        if not parsed_ex:
            return None
        lag_days = {"W": 3, "M": 7, "Q": 10, "SA": 14, "A": 14}
        return parsed_ex + _td(days=lag_days.get((freq or "Q").upper(), 10))

    # Load last-refresh timestamps per profile so we can estimate accrued dividends
    last_refresh_times = {}
    for pid in source_pids:
        row = conn.execute(
            "SELECT value FROM settings WHERE key = ?", (f"last_refresh_{pid}",)
        ).fetchone()
        if row and row[0]:
            try:
                last_refresh_times[pid] = _dt.fromisoformat(row[0])
            except Exception:
                pass

    updated = 0
    dividend_updates = 0
    dividend_updates_by_profile = {pid: 0 for pid in source_pids}
    accrued_divs_by_profile = {pid: 0.0 for pid in source_pids}
    days_since_refresh_by_profile = {}
    distributions_today_by_profile = {pid: [] for pid in source_pids}
    ineligible_refresh_payments_by_profile = {pid: [] for pid in source_pids}
    history_payments_recorded_by_profile = {pid: 0 for pid in source_pids}
    history_payments_inserted_by_profile = {pid: 0 for pid in source_pids}
    history_payments_updated_by_profile = {pid: 0 for pid in source_pids}
    history_payments_existing_by_profile = {pid: 0 for pid in source_pids}
    refresh_date = _dt.now().date()
    refresh_month_start = refresh_date.replace(day=1)
    updated_pids = set()
    refreshed_owner_source = False
    owner_source_ids = set(_get_owner_source_profile_ids(conn))
    positions_managed_ids = {
        r["id"]
        for r in conn.execute(
            "SELECT id FROM profiles WHERE positions_managed = 1 AND id IN ({})".format(
                ",".join("?" * len(source_pids))
            ),
            source_pids,
        ).fetchall()
    }
    for pid in source_pids:
        if pid in owner_source_ids:
            refreshed_owner_source = True
        for t in tickers:
            key = (pid, t)
            if key not in holding_map:
                continue

            snapshot = div_snapshot_map.get(t, {
                "known": False,
                "has_dividend": False,
                "div": 0.0,
                "ex_div_date": None,
                "div_pay_date": None,
                "freq": None,
                "history": pd.Series(dtype=float),
            })
            snapshot_known = bool(snapshot.get("known"))
            has_dividend = bool(snapshot.get("has_dividend"))
            new_price = price_map.get(t)
            new_div = snapshot.get("div") if has_dividend else None
            new_exdiv = snapshot.get("ex_div_date") if has_dividend else None
            new_pay_date = snapshot.get("div_pay_date") if has_dividend else None
            new_freq = effective_freq.get(t)

            if not new_price and not snapshot_known:
                continue

            h = holding_map[key]

            # Estimate dividends accrued since last refresh for this holding
            if pid in last_refresh_times:
                last_rt = last_refresh_times[pid]
                days_elapsed = max(0.0, (_dt.now() - last_rt).total_seconds() / 86400.0)
                _freq_days = {'W': 7.0, 'M': 30.44, 'Q': 91.25, 'SA': 182.5, 'A': 365.0}
                _h_div = float(h.get("div") or 0)
                _h_qty = float(h.get("qty") or 0)
                _h_freq = (h.get("div_frequency") or "Q").upper()
                _fd = _freq_days.get(_h_freq, 91.25)
                if _h_div > 0 and _h_qty > 0 and _fd > 0:
                    accrued_divs_by_profile[pid] = accrued_divs_by_profile.get(pid, 0.0) + (
                        _h_div * _h_qty * (days_elapsed / _fd)
                    )
                days_since_refresh_by_profile[pid] = days_elapsed

            qty = h["qty"]
            price_paid = h["price_paid"]
            purchase_value = h["purchase_value"]
            purchase_date = h["purchase_date"]
            base_qty = h["base_quantity"]
            is_drip = h["reinvest"] == "Y"
            import_date = h["import_date"]
            old_exdiv = h["ex_div_date"]
            old_pay_date = h["div_pay_date"]
            old_freq = h["div_frequency"]
            existing_estim_annual = float(h.get("estim_payment_per_year") or 0)
            # Preserve the existing income estimate when:
            #  (a) this profile is positions-managed (broker-supplied income)
            #      AND that import is still recent (≤30 days old), OR
            #  (b) we don't have fresh positive dividend data from the source
            #      (yfinance sometimes serves prices but omits the dividend
            #       field — treating that as "no dividend" used to zero out
            #       good income data).
            # When broker data ages past 30 days, fall through to the recompute
            # path so estim_payment_per_year tracks current div × qty × freq.
            fresh_div = snapshot.get("div") if bool(snapshot.get("has_dividend")) else None
            parsed_import_date = _refresh_parse_date(import_date)
            broker_data_fresh = (
                parsed_import_date is not None
                and (refresh_date - parsed_import_date).days <= 30
            )
            existing_income_is_run_rate = _refresh_income_matches_rate(
                existing_estim_annual,
                h.get("div"),
                qty,
                old_freq,
            )
            preserve_income_estimate = existing_estim_annual > 0 and (
                (pid in positions_managed_ids and broker_data_fresh)
                or not (fresh_div and float(fresh_div) > 0)
            ) and not (fresh_div and float(fresh_div) > 0 and existing_income_is_run_rate)
            sets = []
            vals = []
            dividend_row_updated = False

            # Backfill purchase_value if missing
            if not purchase_value and price_paid and qty:
                purchase_value = qty * price_paid
                sets.append("purchase_value = ?")
                vals.append(round(purchase_value, 2))

            # ── DRIP simulation ──────────────────────────────────────────
            # For reinvest=Y holdings, simulate dividend reinvestment from
            # import_date forward using actual dividend history + close prices.
            # base_quantity already includes all DRIP through the import date
            # (whether imported from spreadsheet or entered via form), so we
            # only add shares for dividends received AFTER that date.
            drip_shares = 0.0
            drip_total_divs = 0.0
            ytd_divs = 0.0
            current_month_income = 0.0
            div_series = snapshot.get("history")
            # Only recognize distributions that have actually been PAID. A fund
            # can trade ex-dividend a few days before it pays; until the pay
            # date arrives no cash has been received, so a gone-ex-but-unpaid
            # distribution must not count toward income (ytd / current month) or
            # DRIP share growth. Drop that pending event here so the whole
            # simulation below excludes it; it re-enters once the pay date lands.
            if div_series is not None and not div_series.empty:
                _pending_ex = _refresh_parse_date(snapshot.get("ex_div_date"))
                _pending_pay = _refresh_parse_date(snapshot.get("div_pay_date"))
                if (
                    _pending_ex is not None
                    and _pending_pay is not None
                    and _pending_pay > refresh_date
                ):
                    # Normalize the index first: Yahoo history can be tz-aware,
                    # which would otherwise raise when compared to a naive stamp.
                    div_series = _ensure_naive_datetime_index(div_series)
                    div_series = div_series[div_series.index < pd.Timestamp(_pending_ex)]
            close_series = close_history.get(t)
            has_dividend_history = div_series is not None and not div_series.empty

            if (
                is_drip
                and has_dividend_history
                and close_series is not None
            ):
                drip_start = import_date or purchase_date or None
                drip_result = _simulate_drip_refresh(
                    div_series,
                    close_series,
                    base_qty,
                    start_date=drip_start,
                )
                drip_shares = drip_result["drip_shares"]
                drip_total_divs = drip_result["drip_total_divs"]
                ytd_divs = drip_result["ytd_divs"]
                current_month_income = drip_result["current_month_income"]
                if pid in positions_managed_ids:
                    # Broker-managed account: the position feed owns the share
                    # count, and reinvested shares/cash are rebuilt from the
                    # imported transaction history
                    # (_refresh_drip_tracking_from_transactions). Use the
                    # simulated income figures above, but never simulate the
                    # quantity or overwrite the DRIP-tracking columns here —
                    # that would double-count against the broker feed and wipe
                    # the lifetime reinvestment totals.
                    pass
                else:
                    qty = drip_result["quantity"]
                    if drip_result["event_count"] > 0:
                        sets.extend(["quantity = ?", "base_quantity = ?",
                                     "shares_bought_from_dividend = ?",
                                     "total_cash_reinvested = ?"])
                        vals.extend([round(qty, 6), base_qty,
                                     round(drip_shares, 6),
                                     round(drip_total_divs, 2)])
                        purchase_value = (base_qty * price_paid) + drip_total_divs
                        sets.append("purchase_value = ?")
                        vals.append(round(purchase_value, 2))
                    elif qty != base_qty:
                        # No new DRIP dividends since import — reset to base
                        qty = base_qty
                        sets.extend(["quantity = ?", "base_quantity = ?",
                                     "shares_bought_from_dividend = ?",
                                     "total_cash_reinvested = ?"])
                        vals.extend([base_qty, base_qty, 0, 0])
                        purchase_value = base_qty * price_paid
                        sets.append("purchase_value = ?")
                        vals.append(round(purchase_value, 2))
            elif not is_drip and qty != base_qty:
                # reinvest changed from Y to N — clear accumulated DRIP shares
                qty = base_qty
                sets.extend(["quantity = ?", "shares_bought_from_dividend = ?",
                             "total_cash_reinvested = ?"])
                vals.extend([round(base_qty, 6), 0, 0])
                purchase_value = base_qty * price_paid
                sets.append("purchase_value = ?")
                vals.append(round(purchase_value, 2))

            if new_price:
                current_value = new_price * qty
                gain = current_value - purchase_value if purchase_value else 0
                gain_pct = (gain / purchase_value) if purchase_value else 0
                sets.extend(["current_price = ?", "current_value = ?", "gain_or_loss = ?",
                             "gain_or_loss_percentage = ?", "percent_change = ?"])
                vals.extend([new_price, current_value, gain, gain_pct, gain_pct])

            if snapshot_known:
                if old_exdiv and old_pay_date and (
                    old_exdiv != new_exdiv or old_pay_date != new_pay_date or (old_freq or "") != (new_freq or "")
                ):
                    try:
                        conn.execute(
                            """
                            INSERT OR IGNORE INTO dividend_schedule_history
                            (ticker, profile_id, ex_div_date, pay_date, frequency, source)
                            VALUES (?, ?, ?, ?, ?, ?)
                            """,
                            (t, pid, old_exdiv, old_pay_date, old_freq, "refresh"),
                        )
                    except Exception:
                        pass

                if new_div:
                    cur_freq = (new_freq or 'Q').upper()
                    mult = _refresh_frequency_multiplier(cur_freq)
                    annual_div = new_div * mult
                    if preserve_income_estimate:
                        estim_annual = float(h.get("estim_payment_per_year") or 0)
                        estim_monthly = float(h.get("approx_monthly_income") or 0) or (
                            estim_annual / 12 if estim_annual else 0
                        )
                        purchase_total = float(purchase_value or (qty * price_paid) or 0)
                        current_total = float((new_price or 0) * qty) if new_price else float(h.get("current_value") or 0)
                        yoc = (estim_annual / purchase_total) if purchase_total else 0
                        cur_yield = (estim_annual / current_total) if current_total else 0
                    else:
                        yoc = (annual_div / price_paid) if price_paid else 0
                        cur_yield = (annual_div / new_price) if new_price else 0
                        estim_annual = new_div * qty * mult
                        estim_monthly = estim_annual / 12 if estim_annual else 0
                    sets.extend(["div = ?", "annual_yield_on_cost = ?", "current_annual_yield = ?",
                                 "estim_payment_per_year = ?", "approx_monthly_income = ?"])
                    vals.extend([new_div, yoc, cur_yield, estim_annual, estim_monthly])
                    if (
                        _refresh_num_changed(h["div"], new_div, tolerance=0.000001)
                        or _refresh_num_changed(h["estim_payment_per_year"], estim_annual)
                        or _refresh_num_changed(h["approx_monthly_income"], estim_monthly)
                    ):
                        dividend_row_updated = True
                else:
                    if preserve_income_estimate:
                        estim_annual = float(h.get("estim_payment_per_year") or 0)
                        estim_monthly = float(h.get("approx_monthly_income") or 0) or (
                            estim_annual / 12 if estim_annual else 0
                        )
                        purchase_total = float(purchase_value or (qty * price_paid) or 0)
                        current_total = float((new_price or 0) * qty) if new_price else float(h.get("current_value") or 0)
                        yoc = (estim_annual / purchase_total) if purchase_total else 0
                        cur_yield = (estim_annual / current_total) if current_total else 0
                        sets.extend(["div = ?", "annual_yield_on_cost = ?", "current_annual_yield = ?",
                                     "estim_payment_per_year = ?", "approx_monthly_income = ?"])
                        vals.extend([0, yoc, cur_yield, estim_annual, estim_monthly])
                        if (
                            _refresh_num_changed(h["div"], 0, tolerance=0.000001)
                            or _refresh_num_changed(h["estim_payment_per_year"], estim_annual)
                            or _refresh_num_changed(h["approx_monthly_income"], estim_monthly)
                        ):
                            dividend_row_updated = True
                    else:
                        sets.extend(["div = ?", "annual_yield_on_cost = ?", "current_annual_yield = ?",
                                     "estim_payment_per_year = ?", "approx_monthly_income = ?"])
                        vals.extend([0, 0, 0, 0, 0])
                        if (
                            _refresh_num_changed(h["div"], 0, tolerance=0.000001)
                            or _refresh_num_changed(h["estim_payment_per_year"], 0)
                            or _refresh_num_changed(h["approx_monthly_income"], 0)
                        ):
                            dividend_row_updated = True

                sets.append("ex_div_date = ?")
                vals.append(new_exdiv)
                sets.append("div_pay_date = ?")
                vals.append(new_pay_date)

                sets.append("div_frequency = ?")
                vals.append(new_freq)
                if (
                    _refresh_text_changed(old_exdiv, new_exdiv)
                    or _refresh_text_changed(old_pay_date, new_pay_date)
                    or _refresh_text_changed(old_freq, new_freq)
                ):
                    dividend_row_updated = True

            # Actual YTD and current-month dividends from yfinance history,
            # filtered to only include dividends on or after purchase_date.
            # Uses DRIP-adjusted qty for accurate income calculation.
            if snapshot_known and has_dividend_history and not is_drip:
                div_series = _ensure_naive_datetime_index(div_series)
                jan1 = pd.Timestamp(_dt.now().year, 1, 1)
                today = pd.Timestamp(_dt.now().date())
                first_of_month = pd.Timestamp(today.year, today.month, 1)
                start = jan1
                if purchase_date:
                    try:
                        pdt = pd.Timestamp(purchase_date)
                        if pdt > start:
                            start = pdt
                    except Exception:
                        pass
                ytd = div_series[(div_series.index >= start) & (div_series.index <= today)]
                curmo_start = max(first_of_month, start)
                curmo = div_series[(div_series.index >= curmo_start) & (div_series.index <= today)]
                ytd_divs = round(float(ytd.sum()) * qty, 2) if not ytd.empty else 0
                current_month_income = round(float(curmo.sum()) * qty, 2) if not curmo.empty else 0

            if snapshot_known and (
                has_dividend_history
                or (not has_dividend and not existing_dividend_hint.get(t))
            ):
                next_ytd_divs = round(ytd_divs, 2)
                next_current_month_income = round(current_month_income, 2)
                if (
                    _refresh_num_changed(h["ytd_divs"], next_ytd_divs)
                    or _refresh_num_changed(h["current_month_income"], next_current_month_income)
                ):
                    dividend_row_updated = True
                sets.append("ytd_divs = ?")
                vals.append(next_ytd_divs)
                sets.append("current_month_income = ?")
                vals.append(next_current_month_income)

            effective_div = new_div if snapshot_known else h["div"]
            effective_exdiv = new_exdiv if snapshot_known else old_exdiv
            raw_dividend_paid = _current_dividend_paid(qty, effective_div)
            eligible_for_current_dividend = _holding_eligible_for_current_dividend(
                purchase_date,
                effective_exdiv,
            )
            expected_pay_date = _refresh_expected_pay_date(
                effective_exdiv,
                new_pay_date if snapshot_known else old_pay_date,
                new_freq if snapshot_known else old_freq,
            )
            # dividend_paid is cash actually received for the current
            # distribution, so it stays $0 until the pay date arrives — a fund
            # can trade ex-dividend several days before it pays. When neither a
            # pay nor ex date is known we can't gate, so fall back to the prior
            # ex-date eligibility rather than zeroing a holding of unknown timing.
            pay_date_reached = expected_pay_date is None or expected_pay_date <= refresh_date
            next_dividend_paid = (
                raw_dividend_paid
                if (eligible_for_current_dividend and pay_date_reached)
                else 0.0
            )
            if _refresh_num_changed(h["dividend_paid"], next_dividend_paid):
                dividend_row_updated = True
            sets.append("dividend_paid = ?")
            vals.append(next_dividend_paid)

            if (
                expected_pay_date is not None
                and refresh_month_start <= expected_pay_date <= refresh_date
                and raw_dividend_paid > 0
            ):
                if eligible_for_current_dividend:
                    distributions_today_by_profile.setdefault(pid, []).append({
                        "ticker": t,
                        "amount": round(float(next_dividend_paid), 2),
                        "div": round(float(effective_div or 0), 6),
                        "quantity": round(float(qty or 0), 6),
                        "frequency": (new_freq if snapshot_known else old_freq) or "",
                        "pay_date": expected_pay_date.isoformat(),
                    })
                else:
                    ineligible_refresh_payments_by_profile.setdefault(pid, []).append({
                        "ticker": t,
                        "pay_date": expected_pay_date.isoformat(),
                    })

            if sets:
                vals.extend([t, pid])
                conn.execute(
                    f"UPDATE all_account_info SET {', '.join(sets)} WHERE ticker = ? AND profile_id = ?",
                    vals,
                )
                updated += 1
                if dividend_row_updated:
                    dividend_updates += 1
                    dividend_updates_by_profile[pid] = dividend_updates_by_profile.get(pid, 0) + 1
                updated_pids.add(pid)
            h["qty"] = qty

    for pid, distributions in distributions_today_by_profile.items():
        for item in distributions:
            ticker = item["ticker"]
            pay_date = item["pay_date"]
            amount = float(item["amount"] or 0)
            if amount <= 0:
                continue
            existing = conn.execute(
                "SELECT id, source, amount, notes FROM dividend_payments WHERE ticker = ? AND profile_id = ? AND payment_date = ?",
                (ticker, pid, pay_date),
            ).fetchone()
            notes = (
                f"Recorded by Refresh Prices & Divs; div/share {item['div']}; "
                f"quantity {item['quantity']}; frequency {item['frequency'] or 'unknown'}"
            )
            if existing:
                if (existing["source"] or "").lower() == "refresh_estimate":
                    rounded_amount = round(amount, 2)
                    existing_amount = round(float(existing["amount"] or 0), 2)
                    if existing_amount != rounded_amount or (existing["notes"] or "") != notes:
                        conn.execute(
                            "UPDATE dividend_payments SET amount = ?, notes = ? WHERE id = ?",
                            (rounded_amount, notes, existing["id"]),
                        )
                        history_payments_recorded_by_profile[pid] = history_payments_recorded_by_profile.get(pid, 0) + 1
                        history_payments_updated_by_profile[pid] = history_payments_updated_by_profile.get(pid, 0) + 1
                    else:
                        history_payments_existing_by_profile[pid] = history_payments_existing_by_profile.get(pid, 0) + 1
                else:
                    history_payments_existing_by_profile[pid] = history_payments_existing_by_profile.get(pid, 0) + 1
                continue
            conn.execute(
                "INSERT INTO dividend_payments (ticker, profile_id, payment_date, amount, source, notes) "
                "VALUES (?, ?, ?, ?, ?, ?)",
                (ticker, pid, pay_date, round(amount, 2), "refresh_estimate", notes),
            )
            history_payments_recorded_by_profile[pid] = history_payments_recorded_by_profile.get(pid, 0) + 1
            history_payments_inserted_by_profile[pid] = history_payments_inserted_by_profile.get(pid, 0) + 1

    for pid, payments in ineligible_refresh_payments_by_profile.items():
        for item in payments:
            conn.execute(
                "DELETE FROM dividend_payments "
                "WHERE ticker = ? AND profile_id = ? AND payment_date = ? AND source = ?",
                (item["ticker"], pid, item["pay_date"], REFRESH_ESTIMATE_DIVIDEND_SOURCE),
            )

    # Save last-refresh timestamps for next refresh's accrual calculation
    now_iso = _dt.now().isoformat()
    for pid in source_pids:
        conn.execute(
            "INSERT OR REPLACE INTO settings (key, value) VALUES (?, ?)",
            (f"last_refresh_{pid}", now_iso),
        )

    conn.commit()

    # Update derived tables for all affected profiles
    for pid in updated_pids:
        populate_holdings(pid)
        populate_dividends(pid)

    placeholders = ",".join("?" * len(source_pids))
    account_value_row = conn.execute(
        f"""SELECT
                COALESCE((
                    SELECT SUM(current_value)
                    FROM all_account_info
                    WHERE profile_id IN ({placeholders}) AND quantity > 0
                ), 0)
                +
                COALESCE((
                    SELECT SUM(cash_value)
                    FROM profiles
                    WHERE id IN ({placeholders})
                ), 0)""",
        [*source_pids, *source_pids],
    ).fetchone()
    account_current_value = float(account_value_row[0] if account_value_row else 0)
    daily_change = _portfolio_daily_price_change(
        holding_map,
        close_history,
        source_pids,
        account_current_value=account_current_value,
    )
    conn.close()
    _clear_dividend_event_caches()

    # Sync Owner only when the refresh touched an Owner source account,
    # or when the Owner page itself initiated the refresh.
    if scope == "owner" or refreshed_owner_source:
        _auto_reconcile_owner()

    refreshed_rows = sum(1 for key in holding_map if key[0] in source_pids)
    if scope == "owner":
        msg = f"Refreshed {refreshed_rows} holdings across {len(source_pids)} Owner source portfolios."
    elif scope == "aggregate":
        msg = f"Refreshed {refreshed_rows} holdings across {len(source_pids)} Aggregate member portfolios."
    else:
        msg = f"Refreshed {refreshed_rows} holdings in {_get_profile_name(selected_profile_id)}."
    dividend_update_accounts = [
        {
            "profile_id": pid,
            "name": refresh_profile_names.get(pid) or f"Profile {pid}",
            "dividend_updates": dividend_updates_by_profile.get(pid, 0),
            "accrued_dividends": round(accrued_divs_by_profile.get(pid, 0.0), 2),
            "days_since_last_refresh": round(days_since_refresh_by_profile.get(pid, 0.0), 1)
            if pid in days_since_refresh_by_profile
            else None,
            "distributions_today": sorted(
                distributions_today_by_profile.get(pid, []),
                key=lambda item: item["ticker"],
            ),
            "history_payments_recorded": history_payments_recorded_by_profile.get(pid, 0),
            "history_payments_inserted": history_payments_inserted_by_profile.get(pid, 0),
            "history_payments_updated": history_payments_updated_by_profile.get(pid, 0),
            "history_payments_existing": history_payments_existing_by_profile.get(pid, 0),
        }
        for pid in source_pids
    ]
    return jsonify({
        "updated": updated,
        "dividend_updates": dividend_updates,
        "dividend_update_accounts": dividend_update_accounts,
        "daily_change": daily_change,
        "refresh_date": refresh_date.isoformat(),
        "message": msg,
    })


# ── Accrual summary (dividends earned since last refresh) ─────────────────────

@app.route("/api/holdings/accrual-summary", methods=["GET"])
def get_accrual_summary():
    """Return estimated dividends accrued since last refresh, per source account."""
    from datetime import datetime as _dt2, date as _date
    conn = get_connection()
    refresh_info = _get_refresh_target_info(conn)
    source_pids = refresh_info["source_profile_ids"]

    profile_name_rows = conn.execute(
        "SELECT id, name FROM profiles WHERE id IN ({})".format(",".join("?" * len(source_pids))),
        source_pids,
    ).fetchall()
    profile_names = {r["id"]: r["name"] for r in profile_name_rows}

    from datetime import timedelta as _td
    freq_days_map = {"W": 7.0, "M": 30.44, "Q": 91.25, "SA": 182.5, "A": 365.0}
    # Typical ex-div → payment lags by frequency
    pay_lag_days = {"W": 3, "M": 7, "Q": 10, "SA": 14, "A": 14}
    today = _date.today()

    def _parse_date(s):
        if not s:
            return None
        for fmt in ("%m/%d/%y", "%m/%d/%Y", "%Y-%m-%d"):
            try:
                return _dt2.strptime(s.strip(), fmt).date()
            except Exception:
                pass
        return None

    accounts = []
    for pid in source_pids:
        row = conn.execute(
            "SELECT value FROM settings WHERE key = ?", (f"last_refresh_{pid}",)
        ).fetchone()
        last_refresh_dt = None
        if row and row[0]:
            try:
                last_refresh_dt = _dt2.fromisoformat(row[0])
            except Exception:
                pass

        days_elapsed = None
        accrued = 0.0
        confirmed_payments = 0
        payment_details = []
        if last_refresh_dt:
            days_elapsed = max(0.0, (_dt2.now() - last_refresh_dt).total_seconds() / 86400.0)
            last_refresh_date = last_refresh_dt.date()
            holdings = conn.execute(
                "SELECT ticker, div, quantity, div_frequency, ex_div_date FROM all_account_info "
                "WHERE profile_id = ? AND quantity > 0",
                (pid,),
            ).fetchall()
            for h in holdings:
                div = float(h["div"] or 0)
                qty = float(h["quantity"] or 0)
                if div <= 0 or qty <= 0:
                    continue
                freq = (h["div_frequency"] or "Q").upper()
                fd = freq_days_map.get(freq, 91.25)
                # Estimate payment date from ex_div_date + typical lag for this frequency.
                # div_pay_date stored in DB uses a fixed 10-day lag that's wrong for weekly
                # payers — deriving from ex_div_date is more accurate.
                ex_date = _parse_date(h["ex_div_date"] or "")
                confirmed = False
                if ex_date:
                    lag = pay_lag_days.get(freq, 10)
                    expected_pay = ex_date + _td(days=lag)
                    if last_refresh_date <= expected_pay <= today:
                        amount = div * qty
                        accrued += amount
                        confirmed_payments += 1
                        payment_details.append({
                            "ticker": h["ticker"],
                            "expected_pay_date": expected_pay.isoformat(),
                            "ex_div_date": ex_date.isoformat(),
                            "amount": round(amount, 2),
                            "div_per_share": round(div, 6),
                            "shares": round(qty, 6),
                        })
                        confirmed = True
                if not confirmed and fd > 0:
                    accrued += div * qty * (days_elapsed / fd)

        accounts.append({
            "profile_id": pid,
            "name": profile_names.get(pid) or f"Profile {pid}",
            "accrued_dividends": round(accrued, 2),
            "confirmed_payments": confirmed_payments,
            "payment_details": sorted(
                payment_details,
                key=lambda p: (p["expected_pay_date"], p["ticker"]),
            ),
            "days_since_last_refresh": round(days_elapsed, 1) if days_elapsed is not None else None,
            "last_refresh": last_refresh_dt.isoformat() if last_refresh_dt else None,
        })

    conn.close()
    return jsonify({"accounts": accounts})


# Action Center

def _action_iso_date(value):
    if not value:
        return None
    if isinstance(value, datetime.date):
        return value.isoformat()
    raw = str(value).strip()
    if not raw:
        return None
    for fmt in ("%Y-%m-%d", "%m/%d/%Y", "%m/%d/%y"):
        try:
            return datetime.datetime.strptime(raw, fmt).date().isoformat()
        except ValueError:
            pass
    return None


def _action_days_from_today(value, today):
    iso = _action_iso_date(value)
    if not iso:
        return None, None
    try:
        dt = datetime.date.fromisoformat(iso)
    except ValueError:
        return None, None
    return iso, (dt - today).days


def _action_money(value):
    return f"${float(value or 0):,.2f}"


def _action_pct(value, digits=1):
    return f"{float(value or 0):.{digits}f}%"


def _action_item(items, kind, priority, title, detail, route, **extra):
    priority_rank = {"critical": 0, "warning": 1, "info": 2, "success": 3}
    items.append({
        "id": extra.pop("id", f"{kind}-{len(items) + 1}"),
        "kind": kind,
        "priority": priority,
        "priority_rank": priority_rank.get(priority, 9),
        "title": title,
        "detail": detail,
        "route": route,
        **extra,
    })


def _action_center_profile_info(conn):
    is_agg, pids = get_profile_filter()
    placeholders = ",".join("?" * len(pids))
    rows = conn.execute(
        f"SELECT id, name FROM profiles WHERE id IN ({placeholders})",
        pids,
    ).fetchall()
    names = {r["id"]: r["name"] for r in rows}
    profile_name = "Aggregate" if is_agg else names.get(pids[0], "Portfolio")
    return is_agg, pids, names, profile_name


def _action_center_refresh_profile_ids(conn, is_agg, pids):
    """Return the accounts whose refresh timestamps should drive stale-data alerts."""
    if is_agg:
        return pids
    profile_id = int(pids[0]) if pids else 1
    if profile_id == 1:
        source_ids = _get_owner_source_profile_ids(conn)
        return source_ids or [1]
    return [profile_id]


@app.route("/api/action-center", methods=["GET"])
def action_center():
    """Return prioritized portfolio follow-up items assembled from existing data."""
    today = datetime.date.today()
    limit = max(1, min(50, int(request.args.get("limit", 50))))
    conn = get_connection()
    try:
        is_agg, pids, profile_names, profile_name = _action_center_profile_info(conn)
        placeholders = ",".join("?" * len(pids))
        items = []

        holding_rows = conn.execute(
            f"""SELECT a.ticker, a.profile_id, a.description, a.quantity,
                       a.current_value, a.purchase_value, a.gain_or_loss_percentage,
                       a.approx_monthly_income, a.estim_payment_per_year,
                       a.current_annual_yield, a.div, a.div_frequency,
                       a.ex_div_date, a.div_pay_date, a.purchase_date,
                       a.dividend_actuals_source, a.import_date, a.nav_erosion_scope,
                       a.nav_benchmark_override, a.reinvest
                FROM all_account_info a
                WHERE a.profile_id IN ({placeholders})
                  AND COALESCE(a.quantity, 0) > 1e-9
                ORDER BY COALESCE(a.current_value, 0) DESC""",
            pids,
        ).fetchall()
        holdings = rows_to_dicts(holding_rows)
        total_value = sum(float(h.get("current_value") or 0) for h in holdings)
        total_monthly_income = sum(float(h.get("approx_monthly_income") or 0) for h in holdings)

        refresh_pids = _action_center_refresh_profile_ids(conn, is_agg, pids)
        missing_names = [pid for pid in refresh_pids if pid not in profile_names]
        if missing_names:
            name_placeholders = ",".join("?" * len(missing_names))
            name_rows = conn.execute(
                f"SELECT id, name FROM profiles WHERE id IN ({name_placeholders})",
                missing_names,
            ).fetchall()
            profile_names.update({r["id"]: r["name"] for r in name_rows})

        refresh_items = []
        for pid in refresh_pids:
            row = conn.execute(
                "SELECT value FROM settings WHERE key = ?",
                (f"last_refresh_{pid}",),
            ).fetchone()
            last_refresh = row["value"] if row else None
            days = None
            if last_refresh:
                try:
                    days = (datetime.datetime.now() - datetime.datetime.fromisoformat(last_refresh)).days
                except ValueError:
                    days = None
            if days is None or days >= 3:
                refresh_items.append({
                    "profile_id": pid,
                    "name": profile_names.get(pid, f"Profile {pid}"),
                    "days": days,
                })
        if refresh_items:
            oldest = max((r["days"] for r in refresh_items if r["days"] is not None), default=None)
            label = "No refresh recorded" if oldest is None else f"Oldest refresh is {oldest} day{'s' if oldest != 1 else ''} old"
            _action_item(
                items,
                "data",
                "warning" if oldest is None or oldest >= 7 else "info",
                "Refresh market data",
                f"{len(refresh_items)} account{'s' if len(refresh_items) != 1 else ''} may be stale. {label}.",
                "/holdings",
                cta="Refresh Prices & Divs",
                metric=oldest,
            )

        upcoming = []
        for h in holdings:
            iso, days = _action_days_from_today(h.get("div_pay_date"), today)
            if iso and days is not None and 0 <= days <= 14:
                upcoming.append({
                    "ticker": h["ticker"],
                    "date": iso,
                    "days": days,
                    "income": float(h.get("approx_monthly_income") or 0),
                })
        upcoming.sort(key=lambda r: (r["date"], r["ticker"]))
        for ev in upcoming[:5]:
            when = "today" if ev["days"] == 0 else f"in {ev['days']} day{'s' if ev['days'] != 1 else ''}"
            _action_item(
                items,
                "dividend",
                "info",
                f"{ev['ticker']} payment {when}",
                f"Estimated pay date {ev['date']}. Monthly estimate: {_action_money(ev['income'])}.",
                "/div-calendar",
                ticker=ev["ticker"],
                date=ev["date"],
                metric=ev["days"],
            )

        missing_meta = [
            h for h in holdings
            if (
                float(h.get("div") or 0) > 0
                or float(h.get("estim_payment_per_year") or 0) > 0
                or float(h.get("current_annual_yield") or 0) > 0
                or float(h.get("approx_monthly_income") or 0) > 0
            ) and (
                not h.get("div_frequency")
                or not _action_iso_date(h.get("div_pay_date"))
            )
        ]
        if missing_meta:
            examples = ", ".join(h["ticker"] for h in missing_meta[:6])
            _action_item(
                items,
                "data",
                "warning",
                "Complete dividend metadata",
                f"{len(missing_meta)} holding{'s' if len(missing_meta) != 1 else ''} need frequency, pay date, or dividend amount review: {examples}.",
                "/holdings",
                cta="Review holdings",
                metric=len(missing_meta),
            )

        if total_monthly_income > 0 and holdings:
            top_income = sorted(
                holdings,
                key=lambda h: float(h.get("approx_monthly_income") or 0),
                reverse=True,
            )[0]
            top_income_value = float(top_income.get("approx_monthly_income") or 0)
            top_income_pct = top_income_value / total_monthly_income * 100
            if top_income_pct >= 25:
                _action_item(
                    items,
                    "income",
                    "warning" if top_income_pct >= 35 else "info",
                    f"{top_income['ticker']} drives {_action_pct(top_income_pct)} of monthly income",
                    f"{_action_money(top_income_value)} of {_action_money(total_monthly_income)} estimated monthly income comes from one holding.",
                    "/dividends",
                    ticker=top_income["ticker"],
                    metric=top_income_pct,
                )

        if total_value > 0:
            cat_rows = conn.execute(
                f"""SELECT COALESCE(c.name, 'Unallocated') AS category,
                           MAX(COALESCE(c.target_pct, 0)) AS target_pct,
                           SUM(COALESCE(a.current_value, 0)) AS current_value,
                           COUNT(DISTINCT a.ticker) AS holding_count
                    FROM all_account_info a
                    LEFT JOIN ticker_categories tc
                      ON tc.ticker = a.ticker AND tc.profile_id = a.profile_id
                    LEFT JOIN categories c ON c.id = tc.category_id
                    WHERE a.profile_id IN ({placeholders})
                      AND COALESCE(a.quantity, 0) > 1e-9
                    GROUP BY COALESCE(c.name, 'Unallocated')""",
                pids,
            ).fetchall()
            drift_rows = []
            unallocated_value = 0.0
            for r in cat_rows:
                category = r["category"]
                value = float(r["current_value"] or 0)
                actual = value / total_value * 100
                target = float(r["target_pct"] or 0)
                if category == "Unallocated":
                    unallocated_value += value
                if target > 0:
                    drift = actual - target
                    if abs(drift) >= 5:
                        drift_rows.append((abs(drift), drift, category, actual, target, value))
            if unallocated_value > 0:
                _action_item(
                    items,
                    "allocation",
                    "warning",
                    "Assign unallocated holdings",
                    f"{_action_money(unallocated_value)} is not assigned to a category, which weakens drift and rebalance guidance.",
                    "/categories",
                    cta="Assign categories",
                    metric=unallocated_value,
                )
            for _, drift, category, actual, target, value in sorted(drift_rows, reverse=True)[:4]:
                direction = "over" if drift > 0 else "under"
                _action_item(
                    items,
                    "allocation",
                    "warning" if abs(drift) >= 10 else "info",
                    f"{category} is {_action_pct(abs(drift))} {direction} target",
                    f"Actual {_action_pct(actual)} vs target {_action_pct(target)} on {_action_money(value)}.",
                    "/rebalance-wizard",
                    cta="Open Rebalance Wizard",
                    metric=abs(drift),
                )

        near_long_term = []
        for h in holdings:
            iso = _action_iso_date(h.get("purchase_date"))
            if not iso:
                continue
            held_days = (today - datetime.date.fromisoformat(iso)).days
            days_left = 366 - held_days
            if 0 <= days_left <= 45:
                near_long_term.append((days_left, h))
        near_long_term.sort(key=lambda pair: pair[0])
        for days_left, h in near_long_term[:3]:
            _action_item(
                items,
                "tax",
                "info",
                f"{h['ticker']} approaches long-term status",
                f"Purchase date {h.get('purchase_date')} is about {days_left} day{'s' if days_left != 1 else ''} from the one-year mark.",
                "/tax-report",
                ticker=h["ticker"],
                metric=days_left,
            )

        year_start = today.replace(month=1, day=1).isoformat()
        sell_row = conn.execute(
            f"""SELECT COUNT(*) AS sell_count, COALESCE(SUM(realized_gain), 0) AS realized_gain
                FROM transactions
                WHERE profile_id IN ({placeholders})
                  AND UPPER(COALESCE(transaction_type, '')) = 'SELL'
                  AND transaction_date >= ?""",
            pids + [year_start],
        ).fetchone()
        if sell_row and int(sell_row["sell_count"] or 0) > 0:
            realized = float(sell_row["realized_gain"] or 0)
            sell_count = int(sell_row["sell_count"] or 0)
            _action_item(
                items,
                "tax",
                "info",
                "Review realized gains for this tax year",
                f"{sell_count} sell transaction{'s' if sell_count != 1 else ''} recorded YTD. Estimated realized gain/loss: {_action_money(realized)}.",
                "/tax-report",
                cta="Open Tax Report",
                metric=abs(realized),
            )

        plan_rows = conn.execute(
            f"""SELECT id, name, summary_json, updated_at
                FROM rebalance_saved_plans
                WHERE profile_id IN ({placeholders})
                ORDER BY updated_at DESC
                LIMIT 5""",
            pids,
        ).fetchall()
        for row in plan_rows:
            try:
                summary = json.loads(row["summary_json"] or "{}")
            except json.JSONDecodeError:
                summary = {}
            execution = summary.get("execution") or {}
            trade_count = int(summary.get("trade_count") or 0)
            filled = int(execution.get("filled") or 0)
            placed = int(execution.get("placed") or 0)
            reviewed = int(execution.get("reviewed") or 0)
            pending_work = max(0, trade_count - filled)
            if pending_work > 0:
                _action_item(
                    items,
                    "rebalance",
                    "warning" if placed or reviewed else "info",
                    f"Finish rebalance plan: {row['name']}",
                    f"{pending_work} of {trade_count} trade{'s' if trade_count != 1 else ''} not filled. {reviewed} reviewed, {placed} placed.",
                    "/rebalance-wizard",
                    cta="Load plan",
                    metric=pending_work,
                    plan_id=row["id"],
                    updated_at=row["updated_at"],
                )

        # Tax-loss harvest plans (status='planned')
        try:
            plan_rows = conn.execute(
                f"""SELECT id, ticker, shares, est_loss, est_tax_saved
                    FROM tax_loss_plan
                    WHERE profile_id IN ({placeholders})
                      AND status = 'planned'
                    ORDER BY est_loss ASC""",
                pids,
            ).fetchall()
        except sqlite3.OperationalError:
            plan_rows = []
        for pr in plan_rows[:5]:
            pr = dict(pr)
            tax_saved = float(pr.get("est_tax_saved") or 0)
            loss = float(pr.get("est_loss") or 0)
            _action_item(
                items,
                "tax",
                "warning",
                f"Harvest {pr['ticker']} for tax loss",
                f"Plan to realize ${abs(loss):,.2f} loss (~${tax_saved:,.2f} tax saved).",
                "/tax-loss",
                cta="Open Tax-Loss Harvest",
                metric=tax_saved,
                plan_id=pr["id"],
            )

        if not items and holdings:
            _action_item(
                items,
                "portfolio",
                "success",
                "No urgent follow-ups",
                "Current data did not surface stale refreshes, large allocation drift, metadata gaps, or unfinished rebalance work.",
                "/",
                metric=0,
            )

        items.sort(key=lambda item: (item["priority_rank"], -float(item.get("metric") or 0), item["title"]))
        for item in items:
            item.pop("priority_rank", None)
        counts = {}
        for item in items:
            counts[item["priority"]] = counts.get(item["priority"], 0) + 1
        summary = {
            "profile": profile_name,
            "is_aggregate": is_agg,
            "holding_count": len(holdings),
            "total_value": round(total_value, 2),
            "monthly_income": round(total_monthly_income, 2),
            "item_count": len(items),
            "counts": counts,
            "as_of": today.isoformat(),
        }
        return jsonify({"summary": summary, "items": items[:limit]})
    finally:
        conn.close()


# ── Holdings CRUD ──────────────────────────────────────────────────────────────

@app.route("/api/holdings", methods=["GET"])
def list_holdings():
    is_agg, pids = get_profile_filter()
    conn = get_connection()
    _ensure_basis_columns(conn)
    placeholders = ",".join("?" * len(pids))
    basis_total = _basis_total_expr("a")
    if _repair_drip_tracking_for_profiles(conn, pids):
        conn.commit()

    if is_agg and len(pids) > 1:
        # Check if Owner import was used — if so, prefer Owner's per-ticker
        # income/dividend data since the Owner spreadsheet is authoritative.
        # For generic-only imports (no Owner), just SUM across sub-profiles.
        _oiu = conn.execute(
            "SELECT value FROM settings WHERE key = 'owner_import_used'"
        ).fetchone()
        use_owner = _oiu and _oiu[0] == "true"

        def _own_or_sum(field):
            """COALESCE from Owner if Owner import exists, else plain SUM."""
            if use_owner:
                return (f"COALESCE((SELECT o.{field} FROM all_account_info o "
                        f"WHERE o.ticker = a.ticker AND o.profile_id = 1), SUM(a.{field}))")
            return f"SUM(a.{field})"

        # Income fields are recalculated by refresh for all profiles, so just SUM.
        # Payout history fields (ytd, total divs, current month) only exist in
        # Owner, so COALESCE from Owner when available.
        ytd = _own_or_sum("ytd_divs")
        tot_div = _own_or_sum("total_divs_received")
        cur_mo = _own_or_sum("current_month_income")

        # Aggregate: combine duplicate tickers across portfolios
        rows = conn.execute(
            f"""SELECT
                   a.ticker,
                   MAX(a.description) as description,
                   MAX(a.classification_type) as classification_type,
                   SUM(a.quantity) as quantity,
                   CASE WHEN SUM(a.quantity) > 0 THEN SUM({basis_total}) / SUM(a.quantity) ELSE 0 END as price_paid,
                   MAX(a.current_price) as current_price,
                   SUM({basis_total}) as purchase_value,
                   CASE WHEN SUM(a.quantity) > 0 THEN SUM(a.quantity * COALESCE(a.original_price_paid, a.price_paid)) / SUM(a.quantity) ELSE 0 END as original_price_paid,
                   SUM(a.quantity * COALESCE(a.original_price_paid, a.price_paid)) as original_purchase_value,
                   CASE WHEN SUM(a.quantity) > 0 THEN SUM(a.quantity * COALESCE(a.broker_price_paid, a.price_paid)) / SUM(a.quantity) ELSE 0 END as broker_price_paid,
                   SUM(a.quantity * COALESCE(a.broker_price_paid, a.price_paid)) as broker_purchase_value,
                   SUM(a.current_value) as current_value,
                   SUM(a.current_value) - SUM({basis_total}) as gain_or_loss,
                   CASE WHEN SUM({basis_total}) > 0 THEN (SUM(a.current_value) - SUM({basis_total})) / SUM({basis_total}) ELSE 0 END as gain_or_loss_percentage,
                   CASE WHEN SUM({basis_total}) > 0 THEN (SUM(a.current_value) - SUM({basis_total})) / SUM({basis_total}) ELSE 0 END as percent_change,
                   MAX(a.div_frequency) as div_frequency,
                   MAX(a.reinvest) as reinvest,
                   MAX(a.ex_div_date) as ex_div_date,
                   MAX(a.div_pay_date) as div_pay_date,
                   CASE WHEN SUM(a.quantity) > 0 THEN SUM(a.dividend_paid) / SUM(a.quantity) ELSE MAX(a.div) END as div,
                   SUM(a.dividend_paid) as dividend_paid,
                   SUM(a.estim_payment_per_year) as estim_payment_per_year,
                   SUM(a.approx_monthly_income) as approx_monthly_income,
                   SUM(CASE WHEN a.reinvest = 'Y' THEN a.approx_monthly_income ELSE 0 END) as monthly_income_reinvested,
                   SUM(CASE WHEN a.reinvest != 'Y' OR a.reinvest IS NULL THEN a.approx_monthly_income ELSE 0 END) as monthly_income_not_reinvested,
                   SUM(a.withdraw_8pct_cost_annually) as withdraw_8pct_cost_annually,
                   SUM(a.withdraw_8pct_per_month) as withdraw_8pct_per_month,
                   SUM(a.cash_not_reinvested) as cash_not_reinvested,
                   SUM(a.total_cash_reinvested) as total_cash_reinvested,
                   CASE WHEN SUM({basis_total}) > 0 THEN SUM(a.estim_payment_per_year) / SUM({basis_total}) ELSE 0 END as annual_yield_on_cost,
                   CASE WHEN SUM(a.current_value) > 0 THEN SUM(a.estim_payment_per_year) / SUM(a.current_value) ELSE 0 END as current_annual_yield,
                   NULL as percent_of_account,
                   SUM(a.shares_bought_from_dividend) as shares_bought_from_dividend,
                   SUM(a.shares_bought_in_year) as shares_bought_in_year,
                   SUM(a.shares_in_month) as shares_in_month,
                   {ytd} as ytd_divs,
                   {tot_div} as total_divs_received,
                   CASE WHEN SUM({basis_total}) > 0 THEN {tot_div} / SUM({basis_total}) ELSE 0 END as paid_for_itself,
                   MAX(a.import_date) as import_date,
                   MIN(a.purchase_date) as purchase_date,
                   {cur_mo} as current_month_income,
                   CASE
                       WHEN SUM(CASE WHEN a.nav_erosion_scope = 'test' THEN 1 ELSE 0 END) > 0 THEN 'test'
                       WHEN SUM(CASE WHEN a.nav_erosion_scope = 'skip' THEN 1 ELSE 0 END) = COUNT(*) THEN 'skip'
                       ELSE 'auto'
                   END as nav_erosion_scope,
                   MAX(a.nav_benchmark_override) as nav_benchmark_override,
                   GROUP_CONCAT(DISTINCT COALESCE(a.dividend_actuals_source, 'none')) as dividend_actuals_sources,
                   (SELECT c2.name FROM ticker_categories tc2
                    JOIN categories c2 ON tc2.category_id = c2.id
                    WHERE tc2.ticker = a.ticker AND tc2.profile_id = (
                        SELECT a2.profile_id FROM all_account_info a2
                        WHERE a2.ticker = a.ticker AND a2.profile_id IN ({placeholders})
                        ORDER BY a2.quantity DESC LIMIT 1
                    ) LIMIT 1) as category,
                   (SELECT tc3.subcategory_id FROM ticker_categories tc3
                    WHERE tc3.ticker = a.ticker AND tc3.profile_id = (
                        SELECT a3.profile_id FROM all_account_info a3
                        WHERE a3.ticker = a.ticker AND a3.profile_id IN ({placeholders})
                        ORDER BY a3.quantity DESC LIMIT 1
                    ) LIMIT 1) as subcategory_id,
                   (SELECT s4.name FROM ticker_categories tc4
                    JOIN subcategories s4 ON tc4.subcategory_id = s4.id
                    WHERE tc4.ticker = a.ticker AND tc4.profile_id = (
                        SELECT a4.profile_id FROM all_account_info a4
                        WHERE a4.ticker = a.ticker AND a4.profile_id IN ({placeholders})
                        ORDER BY a4.quantity DESC LIMIT 1
                    ) LIMIT 1) as subcategory
               FROM all_account_info a
               WHERE a.profile_id IN ({placeholders})
               GROUP BY a.ticker
               HAVING SUM(COALESCE(a.quantity, 0)) > 1e-9
               ORDER BY a.ticker""",
            pids + pids + pids + pids,
        ).fetchall()
    else:
        pid = pids[0]
        rows = conn.execute(
            """SELECT a.*,
                      (SELECT c.name FROM ticker_categories tc
                       JOIN categories c ON tc.category_id = c.id
                       WHERE tc.ticker = a.ticker AND tc.profile_id = a.profile_id
                       LIMIT 1) AS category,
                      (SELECT tc.subcategory_id FROM ticker_categories tc
                       WHERE tc.ticker = a.ticker AND tc.profile_id = a.profile_id
                       LIMIT 1) AS subcategory_id,
                      (SELECT s.name FROM ticker_categories tc
                       JOIN subcategories s ON tc.subcategory_id = s.id
                       WHERE tc.ticker = a.ticker AND tc.profile_id = a.profile_id
                       LIMIT 1) AS subcategory
               FROM all_account_info a
               WHERE a.profile_id = ?
                 AND COALESCE(a.quantity, 0) > 1e-9
               ORDER BY a.ticker""",
            (pid,),
        ).fetchall()

    # Recalculate percent_of_account
    results = rows_to_dicts(rows)
    payment_profile_ids = _dividend_payment_profile_ids_for_read(conn, pids)
    _apply_dividend_payment_total_floor(
        results,
        _dividend_payment_totals_by_ticker(conn, payment_profile_ids),
    )
    _apply_basis_mode_to_holdings(
        results,
        _cumulative_invested_cost_by_ticker(conn, payment_profile_ids),
        _realized_gains_by_ticker(conn, payment_profile_ids),
    )
    _apply_holding_display_quantities(results)

    # Single-profile reads return all_account_info.* verbatim, so a stale
    # stored current_annual_yield / annual_yield_on_cost (e.g. left at 0 while
    # estim_payment_per_year is populated) would surface here. The aggregate
    # path already recomputes these in SQL; mirror that for the single path so
    # derived yields are always consistent with estim_payment_per_year.
    if not (is_agg and len(pids) > 1):
        for r in results:
            estim = r.get("estim_payment_per_year") or 0
            cv = r.get("current_value") or 0
            pv = r.get("purchase_value") or 0
            r["current_annual_yield"] = (estim / cv) if cv > 0 else 0
            r["annual_yield_on_cost"] = (estim / pv) if pv > 0 else 0

    total_value = sum(r.get("current_value") or 0 for r in results)
    if total_value > 0:
        for r in results:
            r["percent_of_account"] = (r.get("current_value") or 0) / total_value

    # Use stored actuals from refresh if available, otherwise estimate.
    # IMPORTANT: use "is None" not falsy check — 0 is a valid actual value
    # (e.g. no dividends received yet this month) and should NOT trigger
    # the full-month estimate fallback.
    for r in results:
        raw_sources = r.pop("dividend_actuals_sources", None)
        if raw_sources is not None:
            source_set = {s for s in str(raw_sources).split(",") if s and s != "none"}
            r["dividend_actuals_source"] = (
                next(iter(source_set)) if len(source_set) == 1
                else "mixed" if len(source_set) > 1
                else "none"
            )
        if r.get("current_month_income") is None:
            r["current_month_income"] = _estimate_current_month_income(r)
        if r.get("ytd_divs") is None:
            r["ytd_divs"] = _estimate_ytd_income(r)
    if not is_agg and len(pids) == 1:
        import datetime
        payment_profile_ids = pids
        if pids[0] == 1:
            owner_source_ids = _get_owner_source_profile_ids(conn)
            if owner_source_ids:
                payment_profile_ids = owner_source_ids
        if payment_profile_ids:
            mph = ",".join("?" * len(payment_profile_ids))
            today_d = datetime.date.today()
            month_start = today_d.replace(day=1).isoformat()
            year_start = today_d.replace(month=1, day=1).isoformat()
            today_iso = today_d.isoformat()
            pay_rows = conn.execute(
                f"""SELECT ticker,
                           COALESCE(SUM(amount), 0) as ytd_amount,
                           COALESCE(SUM(CASE WHEN payment_date >= ? THEN amount ELSE 0 END), 0) as month_amount
                    FROM dividend_payments
                    WHERE profile_id IN ({mph})
                      AND payment_date >= ? AND payment_date <= ?
                    GROUP BY ticker""",
                [month_start] + payment_profile_ids + [year_start, today_iso],
            ).fetchall()
            if pay_rows:
                ytd_paid_by_ticker = {r["ticker"]: float(r["ytd_amount"] or 0) for r in pay_rows}
                month_paid_by_ticker = {r["ticker"]: float(r["month_amount"] or 0) for r in pay_rows}
                for r in results:
                    r["ytd_divs"] = round(ytd_paid_by_ticker.get(r["ticker"], 0), 2)
                    r["current_month_income"] = round(month_paid_by_ticker.get(r["ticker"], 0), 2)
    # For single-profile queries, compute reinvested/not-reinvested splits.
    # Owner (profile_id=1) uses sub-account DRIP ratios since the Owner
    # flag may be stale.  Sub-accounts use their own flag directly.
    if not is_agg or len(pids) <= 1:
        pid = pids[0]
        if pid == 1:
            # Owner: derive split from sub-accounts flagged as part of Owner
            member_rows = conn.execute(
                "SELECT id FROM profiles WHERE include_in_owner = 1 AND id != 1"
            ).fetchall()
            member_ids = [r["id"] if isinstance(r, dict) else r[0]
                          for r in member_rows]

            if member_ids:
                mph = ",".join("?" * len(member_ids))
                drip_rows = conn.execute(
                    f"""SELECT ticker,
                           SUM(CASE WHEN reinvest = 'Y' THEN approx_monthly_income ELSE 0 END) as ri,
                           SUM(approx_monthly_income) as ti
                        FROM all_account_info
                        WHERE profile_id IN ({mph})
                        GROUP BY ticker""",
                    member_ids,
                ).fetchall()
                drip_map = {}
                for dr in drip_rows:
                    t = dr["ticker"] if isinstance(dr, dict) else dr[0]
                    ri = (dr["ri"] if isinstance(dr, dict) else dr[1]) or 0
                    ti = (dr["ti"] if isinstance(dr, dict) else dr[2]) or 0
                    drip_map[t] = ri / ti if ti > 0 else 0

                for r in results:
                    if r.get("monthly_income_reinvested") is None:
                        mi = r.get("approx_monthly_income") or 0
                        pct = drip_map.get(r["ticker"], 0)
                        r["monthly_income_reinvested"] = round(mi * pct, 2)
                        r["monthly_income_not_reinvested"] = round(mi * (1 - pct), 2)
            else:
                for r in results:
                    if r.get("monthly_income_reinvested") is None:
                        mi = r.get("approx_monthly_income") or 0
                        if r.get("reinvest") == "Y":
                            r["monthly_income_reinvested"] = mi
                            r["monthly_income_not_reinvested"] = 0
                        else:
                            r["monthly_income_reinvested"] = 0
                            r["monthly_income_not_reinvested"] = mi
        else:
            # Sub-account: use its own DRIP flag directly
            for r in results:
                if r.get("monthly_income_reinvested") is None:
                    mi = r.get("approx_monthly_income") or 0
                    if r.get("reinvest") == "Y":
                        r["monthly_income_reinvested"] = mi
                        r["monthly_income_not_reinvested"] = 0
                    else:
                        r["monthly_income_reinvested"] = 0
                        r["monthly_income_not_reinvested"] = mi

    conn.close()
    return jsonify(results)


@app.route("/api/holdings", methods=["POST"])
def add_holding():
    """Add a single holding manually."""
    profile_id = get_profile_id()
    data = _prepare_manual_holding_payload(request.get_json() or {})
    ticker = (data.get("ticker") or "").strip().upper()
    if not ticker:
        return jsonify({"error": "Ticker is required"}), 400

    conn = get_connection()
    _ensure_basis_columns(conn)
    # Check for duplicate
    existing = conn.execute(
        "SELECT 1 FROM all_account_info WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchone()
    if existing:
        conn.close()
        return jsonify({"error": f"{ticker} already exists for this profile"}), 409

    cols = ["ticker", "profile_id"]
    vals = [ticker, profile_id]
    allowed_fields = [
        "description", "classification_type", "price_paid", "current_price",
        "quantity", "purchase_value", "original_price_paid", "original_purchase_value",
        "broker_price_paid", "broker_purchase_value", "current_value", "gain_or_loss",
        "gain_or_loss_percentage", "percent_change", "div_frequency", "reinvest",
        "ex_div_date", "div_pay_date", "div", "dividend_paid", "estim_payment_per_year",
        "approx_monthly_income", "annual_yield_on_cost", "current_annual_yield",
        "purchase_date", "ytd_divs", "total_divs_received", "paid_for_itself",
        "cash_not_reinvested", "total_cash_reinvested", "shares_bought_from_dividend",
        "nav_erosion_scope", "nav_benchmark_override",
    ]
    for field in allowed_fields:
        if field in data and data[field] is not None:
            cols.append(field)
            vals.append(data[field])

    # Set base_quantity and import_date for DRIP tracking
    from datetime import date as _date
    qty_val = data.get("quantity")
    if qty_val is not None:
        cols.append("base_quantity")
        vals.append(qty_val)
    cols.append("import_date")
    vals.append(_date.today().isoformat())

    placeholders = ", ".join(["?"] * len(cols))
    conn.execute(
        f"INSERT INTO all_account_info ({', '.join(cols)}) VALUES ({placeholders})",
        vals,
    )
    # Handle category assignment
    cat_name = (data.get("category") or "").strip()
    if cat_name:
        cat_row = conn.execute(
            "SELECT id FROM categories WHERE name = ? AND profile_id = ?",
            (cat_name, profile_id),
        ).fetchone()
        if cat_row:
            _replace_ticker_category(conn, profile_id, ticker, cat_row["id"])

    _recompute_position_income_fields(conn, profile_id, ticker)
    conn.commit()

    # Update derived tables
    populate_holdings(profile_id)
    populate_dividends(profile_id)
    conn.close()
    return jsonify({"ticker": ticker, "message": f"{ticker} added"}), 201


@app.route("/api/holdings/<ticker>", methods=["PUT"])
def update_holding(ticker):
    """Update a holding's fields."""
    is_agg, pids = get_profile_filter()
    data = request.get_json() or {}
    ticker = ticker.upper()

    if is_agg:
        profile_id = _resolve_aggregate_profile(ticker, pids)
    else:
        profile_id = pids[0]

    conn = get_connection()
    _ensure_basis_columns(conn)
    existing = conn.execute(
        "SELECT quantity, price_paid, current_price, purchase_value, current_value, "
        "       total_divs_received, estim_payment_per_year, broker_price_paid, "
        "       broker_purchase_value, original_price_paid, original_purchase_value "
        "FROM all_account_info WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchone()
    if not existing:
        conn.close()
        return jsonify({"error": f"{ticker} not found"}), 404
    data = _prepare_manual_holding_payload(data, existing)

    allowed_fields = [
        "description", "classification_type", "price_paid", "current_price",
        "quantity", "purchase_value", "original_price_paid", "original_purchase_value",
        "broker_price_paid", "broker_purchase_value", "current_value", "gain_or_loss",
        "gain_or_loss_percentage", "percent_change", "div_frequency", "reinvest",
        "ex_div_date", "div_pay_date", "div", "dividend_paid", "estim_payment_per_year",
        "approx_monthly_income", "annual_yield_on_cost", "current_annual_yield",
        "purchase_date", "ytd_divs", "total_divs_received", "paid_for_itself",
        "cash_not_reinvested", "total_cash_reinvested", "shares_bought_from_dividend",
        "nav_erosion_scope", "nav_benchmark_override",
    ]
    updates = []
    vals = []
    for field in allowed_fields:
        if field in data:
            updates.append(f"{field} = ?")
            vals.append(data[field])

    # When quantity is manually changed, reset base_quantity and import_date
    # so DRIP simulation restarts from this point (the user's new share count
    # already accounts for any DRIP up to now)
    if "quantity" in data:
        from datetime import date as _date
        updates.append("base_quantity = ?")
        vals.append(data["quantity"])
        updates.append("import_date = ?")
        vals.append(_date.today().isoformat())

    if not updates:
        conn.close()
        return jsonify({"error": "No fields to update"}), 400

    vals.extend([ticker, profile_id])
    conn.execute(
        f"UPDATE all_account_info SET {', '.join(updates)} WHERE ticker = ? AND profile_id = ?",
        vals,
    )
    # Handle category assignment
    if "category" in data:
        cat_name = (data["category"] or "").strip()
        # Remove existing assignment
        conn.execute(
            "DELETE FROM ticker_categories WHERE ticker = ? AND profile_id = ?",
            (ticker, profile_id),
        )
        if cat_name:
            cat_row = conn.execute(
                "SELECT id FROM categories WHERE name = ? AND profile_id = ?",
                (cat_name, profile_id),
            ).fetchone()
            if cat_row:
                _replace_ticker_category(conn, profile_id, ticker, cat_row["id"])

    previous_quantity = existing["quantity"] if isinstance(existing, dict) else existing[0]
    previous_annual_income = existing["estim_payment_per_year"] if isinstance(existing, dict) else existing[6]
    _recompute_position_income_fields(
        conn,
        profile_id,
        ticker,
        previous_quantity=previous_quantity,
        previous_annual_income=previous_annual_income,
    )
    conn.commit()

    populate_holdings(profile_id)
    populate_dividends(profile_id)
    conn.close()
    return jsonify({"ticker": ticker, "message": f"{ticker} updated"})


@app.route("/api/holdings/<ticker>/nav-erosion-scope", methods=["PUT"])
def update_holding_nav_erosion_scope(ticker):
    """Override whether a holding should be tested for NAV erosion and compared to a benchmark."""
    is_agg, pids = get_profile_filter()
    data = request.get_json() or {}
    ticker = ticker.upper()
    scope = str(data.get("nav_erosion_scope") or "auto").strip().lower()
    if scope not in {"auto", "test", "skip"}:
        return jsonify({"error": "nav_erosion_scope must be auto, test, or skip"}), 400
    benchmark = str(data.get("nav_benchmark_override") or "").strip().upper()
    benchmark = benchmark or None

    if is_agg:
        profile_id = _resolve_aggregate_profile(ticker, pids)
    else:
        profile_id = pids[0]

    conn = get_connection()
    existing = conn.execute(
        "SELECT 1 FROM all_account_info WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchone()
    if not existing:
        conn.close()
        return jsonify({"error": f"{ticker} not found"}), 404

    conn.execute(
        "UPDATE all_account_info SET nav_erosion_scope = ?, nav_benchmark_override = ? WHERE ticker = ? AND profile_id = ?",
        (scope, benchmark, ticker, profile_id),
    )
    conn.commit()
    conn.close()
    _PORTFOLIO_COVERAGE_CACHE.clear()
    return jsonify({
        "ticker": ticker,
        "nav_erosion_scope": scope,
        "nav_benchmark_override": benchmark,
        "message": f"{ticker} NAV erosion testing set to {scope}",
    })


@app.route("/api/holdings/<ticker>", methods=["DELETE"])
def delete_holding(ticker):
    """Delete a holding."""
    is_agg, pids = get_profile_filter()
    if is_agg:
        profile_id = _resolve_aggregate_profile(ticker, pids)
    else:
        profile_id = pids[0]
    ticker = ticker.upper()
    conn = get_connection()
    _delete_profile_ticker_records(conn, profile_id, ticker, include_transactions=True)
    conn.commit()
    conn.close()
    return jsonify({"ticker": ticker, "message": f"{ticker} deleted"})


# ── Transactions ───────────────────────────────────────────────────────────────

def _rerollup_after_import(profile_id):
    """After an import, re-rollup any tickers that have transactions so the
    transaction-managed position data overrides whatever the spreadsheet had."""
    conn = get_connection()
    if _profile_is_positions_managed(profile_id, conn):
        conn.close()
        return
    rows = conn.execute(
        "SELECT DISTINCT ticker FROM transactions WHERE profile_id = ?",
        (profile_id,),
    ).fetchall()
    for r in rows:
        ticker = r["ticker"] if isinstance(r, dict) else r[0]
        _rollup_transactions(ticker, profile_id, conn)
    conn.close()


def _snapshot_positions(profile_id):
    """Capture pre-import position data + transaction status for each ticker.

    Returns {ticker: {qty, price, date, has_txns}} — call BEFORE the import
    writes to all_account_info so we know what to seed vs. what's new.
    """
    conn = get_connection()
    rows = conn.execute(
        "SELECT ticker, quantity, price_paid, purchase_date "
        "FROM all_account_info WHERE profile_id = ?",
        (profile_id,),
    ).fetchall()
    snap = {}
    for r in rows:
        ticker = r["ticker"] if isinstance(r, dict) else r[0]
        cnt_row = conn.execute(
            "SELECT COUNT(*) as cnt FROM transactions WHERE ticker = ? AND profile_id = ?",
            (ticker, profile_id),
        ).fetchone()
        has_txns = (cnt_row["cnt"] if isinstance(cnt_row, dict) else cnt_row[0]) > 0
        snap[ticker] = {
            "qty": r["quantity"] if isinstance(r, dict) else r[1],
            "price": r["price_paid"] if isinstance(r, dict) else r[2],
            "date": r["purchase_date"] if isinstance(r, dict) else r[3],
            "has_txns": has_txns,
        }
    conn.close()
    return snap


def _import_as_transactions(profile_id, pre_snapshot):
    """Convert freshly-imported rows into delta-based transactions.

    pre_snapshot is the result of _snapshot_positions() taken BEFORE the import.
    The imported quantity represents the user's NEW total position. We compare
    it against the pre-import quantity to determine the delta:

    - delta > 0 → BUY delta shares at the imported price
    - delta < 0 → SELL abs(delta) shares at the imported price
    - delta == 0 → no transaction (position unchanged)
    - New ticker (not in snapshot) → first BUY for the full imported quantity
    - Existing ticker WITHOUT transactions → seed old position first, then
      apply the delta as a BUY or SELL
    """
    from datetime import date as _date
    conn = get_connection()

    rows = conn.execute(
        "SELECT ticker, quantity, price_paid, purchase_date "
        "FROM all_account_info WHERE profile_id = ?",
        (profile_id,),
    ).fetchall()

    for r in rows:
        ticker = r["ticker"] if isinstance(r, dict) else r[0]
        imp_qty = (r["quantity"] if isinstance(r, dict) else r[1]) or 0
        imp_price = (r["price_paid"] if isinstance(r, dict) else r[2]) or 0
        imp_date = (r["purchase_date"] if isinstance(r, dict) else r[3]) or _date.today().isoformat()

        old = pre_snapshot.get(ticker)

        if not old:
            # New ticker — create first BUY from imported data
            if imp_qty > 0:
                conn.execute(
                    "INSERT INTO transactions (ticker, profile_id, transaction_type, "
                    "transaction_date, shares, price_per_share, fees, notes) "
                    "VALUES (?, ?, 'BUY', ?, ?, ?, 0, 'Imported from spreadsheet')",
                    (ticker, profile_id, imp_date, imp_qty, imp_price),
                )
                conn.commit()
                _rollup_transactions(ticker, profile_id, conn)
            continue

        old_qty = old["qty"] or 0
        delta = round(imp_qty - old_qty, 6)

        if not old["has_txns"]:
            # Seed the pre-import position as the first transaction
            if old_qty > 0:
                conn.execute(
                    "INSERT INTO transactions (ticker, profile_id, transaction_type, "
                    "transaction_date, shares, price_per_share, fees, notes) "
                    "VALUES (?, ?, 'BUY', ?, ?, ?, 0, 'Seed from pre-import position')",
                    (ticker, profile_id, old["date"] or _date.today().isoformat(),
                     old_qty, old["price"] or 0),
                )
                conn.commit()

        if delta > 0:
            conn.execute(
                "INSERT INTO transactions (ticker, profile_id, transaction_type, "
                "transaction_date, shares, price_per_share, fees, notes) "
                "VALUES (?, ?, 'BUY', ?, ?, ?, 0, 'Imported from spreadsheet')",
                (ticker, profile_id, imp_date, delta, imp_price),
            )
            conn.commit()
            _rollup_transactions(ticker, profile_id, conn)
        elif delta < 0:
            conn.execute(
                "INSERT INTO transactions (ticker, profile_id, transaction_type, "
                "transaction_date, shares, price_per_share, fees, notes) "
                "VALUES (?, ?, 'SELL', ?, ?, ?, 0, 'Imported from spreadsheet')",
                (ticker, profile_id, imp_date, abs(delta), imp_price),
            )
            conn.commit()
            _rollup_transactions(ticker, profile_id, conn)
        elif not old["has_txns"] and old_qty > 0:
            # No delta but we seeded — still need to rollup
            _rollup_transactions(ticker, profile_id, conn)

    conn.close()


def _is_transfer_txn(notes):
    """True for inter-account/inter-broker transfers (ACAT, TDA internal transfer, etc.).

    These move shares between accounts at price_per_share=0 with a bracketed
    '[Transfer in]' / '[Transfer out]' notes tag — no real sale occurred.
    Treating a transfer-out as an ordinary $0 SELL records a fake realized
    loss equal to the entire cost basis of the transferred shares, which
    corrupts realized_gains (and anything built on it, like total return).
    """
    return bool(notes) and "[transfer" in str(notes).lower()


def _refresh_transaction_realized_gains(ticker, profile_id, conn):
    """Recompute realized gains from transactions without changing holdings."""
    rows = conn.execute(
        "SELECT id, transaction_type, shares, price_per_share, fees, transaction_date, notes "
        "FROM transactions WHERE ticker = ? AND profile_id = ? ORDER BY transaction_date, id",
        (ticker, profile_id),
    ).fetchall()
    if not rows:
        return

    def _val(r, key, idx):
        return r[key] if isinstance(r, dict) else r[idx]

    sell_ids = [
        _val(r, "id", 0)
        for r in rows
        if (_val(r, "transaction_type", 1) or "BUY").upper() == "SELL"
    ]
    alloc_map = _load_lot_alloc_map(conn, sell_ids)

    lots = []
    share_deficit = 0.0
    for r in rows:
        txn_id = _val(r, "id", 0)
        txn_type = (_val(r, "transaction_type", 1) or "BUY").upper()
        shares = abs(float(_val(r, "shares", 2) or 0))
        price = _val(r, "price_per_share", 3) or 0
        fees = _val(r, "fees", 4) or 0
        tdate = _val(r, "transaction_date", 5)
        notes = _val(r, "notes", 6)

        if txn_type == "BUY":
            if share_deficit > 1e-9:
                covered = min(share_deficit, shares)
                share_deficit -= covered
                shares -= covered
            _apply_buy_to_lots(lots, shares, price, fees, txn_id=txn_id, txn_date=tdate)
            conn.execute("UPDATE transactions SET realized_gain = NULL WHERE id = ?", (txn_id,))
        elif _is_transfer_txn(notes):
            # Shares moved accounts, not sold: still consume the lots so the
            # remaining queue is accurate for later transactions, but record
            # no realized gain/loss.
            _, sell_remaining = _consume_sell_lots(lots, shares, alloc_map.get(txn_id))
            share_deficit += sell_remaining
            conn.execute("UPDATE transactions SET realized_gain = NULL WHERE id = ?", (txn_id,))
        else:
            sell_proceeds = (shares * price) - fees
            cost_of_sold, sell_remaining = _consume_sell_lots(
                lots,
                shares,
                alloc_map.get(txn_id),
            )
            share_deficit += sell_remaining
            conn.execute(
                "UPDATE transactions SET realized_gain = ? WHERE id = ?",
                (round(sell_proceeds - cost_of_sold, 2), txn_id),
            )


def _sync_preserved_position_purchase_date(ticker, profile_id, conn):
    """Sync a broker-managed position to the earliest transaction lot still open.

    Transaction imports can be layered onto a broker position snapshot without
    changing the broker-reported quantity. When an older lot has been fully
    sold, the position's purchase date should advance to the earliest remaining
    BUY lot even though the rest of the holding row is intentionally preserved.
    """
    holding = conn.execute(
        "SELECT 1 FROM all_account_info WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchone()
    if not holding:
        return None

    rows = conn.execute(
        "SELECT id, transaction_type, shares, price_per_share, fees, transaction_date "
        "FROM transactions WHERE ticker = ? AND profile_id = ? ORDER BY transaction_date, id",
        (ticker, profile_id),
    ).fetchall()
    if not rows:
        return None

    def _val(row, key, index):
        return row[key] if isinstance(row, dict) else row[index]

    sell_ids = [
        _val(row, "id", 0)
        for row in rows
        if (_val(row, "transaction_type", 1) or "BUY").upper() == "SELL"
    ]
    alloc_map = _load_lot_alloc_map(conn, sell_ids)
    lots = []
    share_deficit = 0.0

    for row in rows:
        txn_id = _val(row, "id", 0)
        txn_type = (_val(row, "transaction_type", 1) or "BUY").upper()
        txn_shares = abs(float(_val(row, "shares", 2) or 0))
        price = _val(row, "price_per_share", 3) or 0
        fees = _val(row, "fees", 4) or 0
        txn_date = _val(row, "transaction_date", 5)

        if txn_type == "BUY":
            if share_deficit > 1e-9:
                covered = min(share_deficit, txn_shares)
                share_deficit -= covered
                txn_shares -= covered
            _apply_buy_to_lots(
                lots,
                txn_shares,
                price,
                fees,
                txn_id=txn_id,
                txn_date=txn_date,
            )
        else:
            _, sell_remaining = _consume_sell_lots(
                lots,
                txn_shares,
                alloc_map.get(txn_id),
            )
            share_deficit += sell_remaining

    open_dates = [
        lot.get("date")
        for lot in lots
        if float(lot.get("shares") or 0) > 1e-9 and lot.get("date")
    ]
    earliest_open_buy = min(open_dates) if open_dates else None
    if earliest_open_buy:
        conn.execute(
            "UPDATE all_account_info SET purchase_date = ? "
            "WHERE ticker = ? AND profile_id = ?",
            (earliest_open_buy, ticker, profile_id),
        )
    return earliest_open_buy


def _basis_share_tolerance(expected_shares):
    return max(0.01, abs(float(expected_shares or 0)) * 0.001)


def _infer_reinvested_share_gap_basis(conn, ticker, profile_id, share_delta, holding_shares, fallback_price=0.0):
    """Infer cost for small broker-share gaps caused by unlogged DRIP buys.

    Some broker transaction exports record the cash dividend but omit the paired
    reinvestment BUY, while the positions export already includes the fractional
    shares. If the gap is small and recorded dividend cash can fund it, treat it
    as reinvested basis instead of leaving the whole original basis stale.
    """
    try:
        gap_shares = float(share_delta or 0)
        expected_shares = float(holding_shares or 0)
    except (TypeError, ValueError):
        return None
    if gap_shares <= 1e-9 or expected_shares <= 1e-9:
        return None
    if gap_shares > max(0.5, expected_shares * 0.02):
        return None

    holding = conn.execute(
        """SELECT reinvest, current_price, price_paid, broker_price_paid,
                  total_divs_received, total_cash_reinvested
           FROM all_account_info
           WHERE ticker = ? AND profile_id = ?""",
        (ticker, profile_id),
    ).fetchone()
    if not holding:
        return None
    reinvest = holding["reinvest"] if isinstance(holding, dict) else holding[0]
    if (reinvest or "").upper() != "Y":
        return None

    payment_row = conn.execute(
        "SELECT COALESCE(SUM(amount), 0) AS cash FROM dividend_payments "
        "WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchone()
    payment_cash = _num_or_zero(payment_row["cash"] if isinstance(payment_row, dict) else payment_row[0])
    dividend_cash = max(
        payment_cash,
        _num_or_zero(holding["total_divs_received"] if isinstance(holding, dict) else holding[4]),
        _num_or_zero(holding["total_cash_reinvested"] if isinstance(holding, dict) else holding[5]),
    )
    if dividend_cash <= 1e-9:
        return None

    price = (
        _num_or_zero(holding["current_price"] if isinstance(holding, dict) else holding[1])
        or _num_or_zero(holding["broker_price_paid"] if isinstance(holding, dict) else holding[3])
        or _num_or_zero(holding["price_paid"] if isinstance(holding, dict) else holding[2])
        or _num_or_zero(fallback_price)
    )
    if price <= 1e-9:
        return None

    inferred_cost = gap_shares * price
    if inferred_cost > (dividend_cash * 1.5) + 1.0:
        return None
    return {
        "shares": gap_shares,
        "cost": inferred_cost,
        "price": price,
        "dividend_cash": dividend_cash,
    }


def _refresh_original_basis_from_transactions(ticker, profile_id, conn):
    """Update original basis from transaction lots when they reconcile to broker shares."""
    _ensure_basis_columns(conn)
    rows = conn.execute(
        "SELECT id, transaction_type, shares, price_per_share, fees, transaction_date "
        "FROM transactions WHERE ticker = ? AND profile_id = ? ORDER BY transaction_date, id",
        (ticker, profile_id),
    ).fetchall()
    if not rows:
        return {"status": "no_transactions", "ticker": ticker}

    holding = conn.execute(
        "SELECT quantity FROM all_account_info WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchone()
    holding_shares = (
        float((holding["quantity"] if isinstance(holding, dict) else holding[0]) or 0)
        if holding else 0.0
    )

    def _val(r, key, idx):
        return r[key] if isinstance(r, dict) else r[idx]

    sell_ids = [
        _val(r, "id", 0)
        for r in rows
        if (_val(r, "transaction_type", 1) or "BUY").upper() == "SELL"
    ]
    alloc_map = _load_lot_alloc_map(conn, sell_ids)

    lots = []
    share_deficit = 0.0
    total_realized = 0.0
    earliest_buy = None
    for r in rows:
        txn_id = _val(r, "id", 0)
        txn_type = (_val(r, "transaction_type", 1) or "BUY").upper()
        shares = abs(float(_val(r, "shares", 2) or 0))
        price = _val(r, "price_per_share", 3) or 0
        fees = _val(r, "fees", 4) or 0
        tdate = _val(r, "transaction_date", 5)

        if txn_type == "BUY":
            if share_deficit > 1e-9:
                covered = min(share_deficit, shares)
                share_deficit -= covered
                shares -= covered
            _apply_buy_to_lots(lots, shares, price, fees, txn_id=txn_id, txn_date=tdate)
            if shares > 1e-9 and tdate and (earliest_buy is None or tdate < earliest_buy):
                earliest_buy = tdate
            conn.execute("UPDATE transactions SET realized_gain = NULL WHERE id = ?", (txn_id,))
        else:
            sell_proceeds = (shares * price) - fees
            cost_of_sold, sell_remaining = _consume_sell_lots(
                lots,
                shares,
                alloc_map.get(txn_id),
            )
            share_deficit += sell_remaining
            realized = sell_proceeds - cost_of_sold
            total_realized += realized
            conn.execute(
                "UPDATE transactions SET realized_gain = ? WHERE id = ?",
                (round(realized, 2), txn_id),
            )

    # Closed position (no current holding row) — realized_gain on transactions
    # has been recomputed above; nothing to update on all_account_info.
    if not holding:
        return {
            "status": "no_holding",
            "ticker": ticker,
            "transaction_shares": round(sum(lot["shares"] for lot in lots) - share_deficit, 6),
            "total_realized": round(total_realized, 2),
        }

    total_shares = sum(lot["shares"] for lot in lots) - share_deficit
    total_cost = sum(lot["shares"] * lot["cost_per_share"] for lot in lots)
    avg_price = total_cost / total_shares if total_shares > 1e-9 else 0
    share_delta = round(total_shares - holding_shares, 6)
    if abs(share_delta) > _basis_share_tolerance(holding_shares):
        inferred_gap = _infer_reinvested_share_gap_basis(
            conn,
            ticker,
            profile_id,
            holding_shares - total_shares,
            holding_shares,
            fallback_price=avg_price,
        )
        if inferred_gap:
            total_shares = holding_shares
            total_cost += inferred_gap["cost"]
            avg_price = total_cost / total_shares if total_shares > 1e-9 else 0
            share_delta = 0.0
        else:
            conn.execute(
                """UPDATE all_account_info
                   SET realized_gains = ?,
                       purchase_date = COALESCE(purchase_date, ?)
                   WHERE ticker = ? AND profile_id = ?""",
                (round(total_realized, 2), earliest_buy, ticker, profile_id),
            )
            return {
                "status": "share_mismatch",
                "ticker": ticker,
                "holding_shares": round(holding_shares, 6),
                "transaction_shares": round(total_shares, 6),
                "share_delta": share_delta,
            }
    else:
        inferred_gap = None

    conn.execute(
        """UPDATE all_account_info
           SET original_price_paid = ?,
               original_purchase_value = ?,
               realized_gains = ?,
               purchase_date = COALESCE(purchase_date, ?)
           WHERE ticker = ? AND profile_id = ?""",
        (
            round(avg_price, 4) if total_shares > 1e-9 else 0,
            round(total_cost, 2) if total_shares > 1e-9 else 0,
            round(total_realized, 2),
            earliest_buy,
            ticker,
            profile_id,
        ),
    )
    return {
        "status": "updated",
        "ticker": ticker,
        "holding_shares": round(holding_shares, 6),
        "transaction_shares": round(total_shares, 6),
        "original_price_paid": round(avg_price, 4) if total_shares > 1e-9 else 0,
        "original_purchase_value": round(total_cost, 2) if total_shares > 1e-9 else 0,
        "purchase_date": earliest_buy,
        "inferred_reinvestment_shares": (
            round(inferred_gap["shares"], 6) if inferred_gap else 0.0
        ),
    }


def _refresh_drip_tracking_from_transactions(ticker, profile_id, conn):
    """Rebuild the holding's reinvestment tracking from DRIP BUY history.

    Broker position imports report current share counts but not how many of
    those shares came from reinvested dividends. The imported transaction
    history is the authoritative record of reinvestment, so when
    DRIP/reinvestment-tagged buys exist we recompute the two tracking columns
    from them. Sums every reinvestment buy ever recorded (lifetime), so the
    Holdings screen shows real DRIP shares/cash even for accounts whose
    quantities are managed by the broker feed.

    No-op when the ticker has no DRIP/reinvestment buys (so spreadsheet-sourced
    values and the forward-simulation path are left untouched) or when the
    position is no longer held.
    """
    row = conn.execute(
        "SELECT COALESCE(SUM(shares), 0) AS sh, "
        "       COALESCE(SUM(shares * COALESCE(price_per_share, 0)), 0) AS cash "
        "FROM transactions "
        "WHERE ticker = ? AND profile_id = ? AND transaction_type = 'BUY' "
        "AND (notes LIKE '%[DRIP]%' OR LOWER(COALESCE(notes, '')) LIKE '%reinvest%')",
        (ticker, profile_id),
    ).fetchone()
    drip_shares = float((row["sh"] if isinstance(row, dict) else row[0]) or 0)
    if drip_shares <= 1e-9:
        return  # no reinvestment history — leave existing values as-is
    drip_cash = float((row["cash"] if isinstance(row, dict) else row[1]) or 0)

    holding = conn.execute(
        "SELECT quantity FROM all_account_info WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchone()
    if not holding:
        return  # position fully sold — nothing on screen to annotate
    qty = float((holding["quantity"] if isinstance(holding, dict) else holding[0]) or 0)
    # A trimmed position can hold fewer shares than were ever reinvested; cap so
    # reinvested shares never exceed the shares actually on hand, scaling the
    # cash figure to match.
    if qty > 0 and drip_shares > qty:
        drip_cash *= qty / drip_shares
        drip_shares = qty

    conn.execute(
        "UPDATE all_account_info SET shares_bought_from_dividend = ?, "
        "total_cash_reinvested = ? WHERE ticker = ? AND profile_id = ?",
        (round(drip_shares, 6), round(drip_cash, 2), ticker, profile_id),
    )


def _rollup_transactions(ticker, profile_id, conn):
    """Recalculate all_account_info from transactions.

    BUY transactions add to a lot queue.
    SELL transactions consume lots using specific-lot allocations when stored
    in transaction_lot_allocations, otherwise falling back to FIFO.
    The remaining lots determine quantity, weighted-average price_paid, and
    purchase_value.  Realized gains are stored per-sell transaction and summed.
    """
    _ensure_basis_columns(conn)
    rows = conn.execute(
        "SELECT id, transaction_type, shares, price_per_share, fees, transaction_date, notes "
        "FROM transactions WHERE ticker = ? AND profile_id = ? ORDER BY transaction_date, id",
        (ticker, profile_id),
    ).fetchall()
    if not rows:
        return

    previous_income_row = conn.execute(
        "SELECT quantity, estim_payment_per_year FROM all_account_info WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchone()
    previous_quantity = (
        previous_income_row["quantity"] if isinstance(previous_income_row, dict) else previous_income_row[0]
    ) if previous_income_row else 0
    previous_annual_income = (
        previous_income_row["estim_payment_per_year"] if isinstance(previous_income_row, dict) else previous_income_row[1]
    ) if previous_income_row else 0

    def _val(r, key, idx):
        return r[key] if isinstance(r, dict) else r[idx]

    # Pre-load lot allocations for all sells in this ticker
    all_sell_ids = [
        _val(r, "id", 0)
        for r in rows
        if (_val(r, "transaction_type", 1) or "BUY").upper() == "SELL"
    ]
    alloc_map = _load_lot_alloc_map(conn, all_sell_ids)

    # Build lot queue and compute realized gains
    lots = []  # each lot: { id, shares, cost_per_share (incl. fees), date }
    share_deficit = 0.0
    total_realized = 0
    earliest_buy = None

    for r in rows:
        txn_id = _val(r, "id", 0)
        txn_type = (_val(r, "transaction_type", 1) or "BUY").upper()
        shares = abs(float(_val(r, "shares", 2) or 0))
        price = _val(r, "price_per_share", 3) or 0
        fees = _val(r, "fees", 4) or 0
        tdate = _val(r, "transaction_date", 5)
        notes = _val(r, "notes", 6)

        if txn_type == "BUY":
            if share_deficit > 1e-9:
                covered = min(share_deficit, shares)
                share_deficit -= covered
                shares -= covered
            _apply_buy_to_lots(lots, shares, price, fees, txn_id=txn_id, txn_date=tdate)
            if shares > 1e-9 and tdate and (earliest_buy is None or tdate < earliest_buy):
                earliest_buy = tdate
            # Clear any realized_gain on BUY rows
            conn.execute("UPDATE transactions SET realized_gain = NULL WHERE id = ?", (txn_id,))
        elif _is_transfer_txn(notes):
            # Shares moved accounts, not sold: still consume the lots so the
            # remaining queue (and thus quantity/cost basis) stays accurate,
            # but don't record a realized gain/loss for a non-economic event.
            _, sell_remaining = _consume_sell_lots(lots, shares, alloc_map.get(txn_id))
            share_deficit += sell_remaining
            conn.execute("UPDATE transactions SET realized_gain = NULL WHERE id = ?", (txn_id,))
        else:  # SELL
            sell_proceeds = (shares * price) - fees  # fees reduce proceeds
            cost_of_sold, sell_remaining = _consume_sell_lots(
                lots,
                shares,
                alloc_map.get(txn_id),
            )
            share_deficit += sell_remaining

            realized = sell_proceeds - cost_of_sold
            total_realized += realized
            conn.execute("UPDATE transactions SET realized_gain = ? WHERE id = ?",
                         (round(realized, 2), txn_id))

    # Remaining lots = current position
    total_shares = sum(lot["shares"] for lot in lots) - share_deficit
    total_cost = sum(lot["shares"] * lot["cost_per_share"] for lot in lots)
    avg_price = total_cost / total_shares if total_shares else 0

    from datetime import date as _date

    if total_shares <= 1e-9:
        # Fully sold — remove the holding row entirely
        conn.execute(
            "DELETE FROM all_account_info WHERE ticker = ? AND profile_id = ?",
            (ticker, profile_id),
        )
    else:
        # Get current_price so we can recompute value and G/L immediately
        cp_row = conn.execute(
            "SELECT current_price FROM all_account_info WHERE ticker = ? AND profile_id = ?",
            (ticker, profile_id),
        ).fetchone()
        if not cp_row:
            conn.execute(
                "INSERT INTO all_account_info (ticker, profile_id, import_date) VALUES (?, ?, ?)",
                (ticker, profile_id, _date.today().isoformat()),
            )
        cp = (cp_row["current_price"] if isinstance(cp_row, dict) else cp_row[0]) if cp_row else None
        cur_val = round(total_shares * cp, 2) if cp else None
        gl = round(cur_val - total_cost, 2) if cur_val is not None else None
        gl_pct = round(gl / total_cost, 6) if gl is not None and total_cost > 0 else None

        conn.execute(
            """UPDATE all_account_info
               SET quantity = ?, price_paid = ?, purchase_value = ?,
                   original_price_paid = ?, original_purchase_value = ?,
                   purchase_date = ?, base_quantity = ?, import_date = ?,
                   realized_gains = ?,
                   current_value = ?, gain_or_loss = ?,
                   gain_or_loss_percentage = ?, percent_change = ?
               WHERE ticker = ? AND profile_id = ?""",
            (round(total_shares, 6), round(avg_price, 4), round(total_cost, 2),
             round(avg_price, 4), round(total_cost, 2),
             earliest_buy, round(total_shares, 6), _date.today().isoformat(),
             round(total_realized, 2),
             cur_val, gl, gl_pct, gl_pct,
             ticker, profile_id),
        )
        _recompute_position_income_fields(
            conn,
            profile_id,
            ticker,
            previous_quantity=previous_quantity,
            previous_annual_income=previous_annual_income,
        )
        _refresh_drip_tracking_from_transactions(ticker, profile_id, conn)
    conn.commit()
    populate_holdings(profile_id)
    populate_dividends(profile_id)


def _seed_transaction_if_needed(ticker, profile_id, conn):
    """Auto-create a seed transaction from existing all_account_info data
    when a user first uses transactions for this ticker."""
    existing = conn.execute(
        "SELECT COUNT(*) as cnt FROM transactions WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchone()
    cnt = existing["cnt"] if isinstance(existing, dict) else existing[0]
    if cnt > 0:
        return  # already has transactions

    holding = conn.execute(
        "SELECT quantity, price_paid, purchase_date FROM all_account_info "
        "WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchone()
    if not holding:
        return
    qty = holding["quantity"] if isinstance(holding, dict) else holding[0]
    price = holding["price_paid"] if isinstance(holding, dict) else holding[1]
    pdate = holding["purchase_date"] if isinstance(holding, dict) else holding[2]
    if not qty:
        return
    conn.execute(
        "INSERT INTO transactions (ticker, profile_id, transaction_date, shares, price_per_share, fees, notes) "
        "VALUES (?, ?, ?, ?, ?, 0, 'Initial seed from existing holding')",
        (ticker, profile_id, pdate, qty, price),
    )


def _load_lot_alloc_map(conn, sell_ids):
    """Return {sell_txn_id: [{buy_txn_id, shares}, ...]} for the given sells."""
    alloc_map = {}
    if not sell_ids:
        return alloc_map

    placeholders = ",".join("?" * len(sell_ids))
    alloc_rows = conn.execute(
        f"SELECT sell_txn_id, buy_txn_id, shares FROM transaction_lot_allocations "
        f"WHERE sell_txn_id IN ({placeholders}) ORDER BY id",
        sell_ids,
    ).fetchall()
    for ar in alloc_rows:
        sid = ar["sell_txn_id"] if isinstance(ar, dict) else ar[0]
        bid = ar["buy_txn_id"] if isinstance(ar, dict) else ar[1]
        sh = ar["shares"] if isinstance(ar, dict) else ar[2]
        alloc_map.setdefault(sid, []).append({
            "buy_txn_id": bid,
            "shares": float(sh or 0),
        })
    return alloc_map


def _consume_sell_lots(lots, sell_shares, allocations=None):
    """Consume lots for a sell and return (cost_of_sold, remaining_sell_shares)."""
    cost_of_sold = 0.0
    sell_remaining = float(sell_shares or 0)

    if allocations:
        for alloc in allocations:
            buy_id = alloc["buy_txn_id"]
            alloc_shares = float(alloc["shares"] or 0)
            for lot in lots:
                if lot["id"] != buy_id:
                    continue
                take = min(alloc_shares, lot["shares"])
                cost_of_sold += take * lot["cost_per_share"]
                lot["shares"] -= take
                sell_remaining -= take
                break
    else:
        while sell_remaining > 1e-9 and lots:
            lot = lots[0]
            if lot["shares"] <= sell_remaining + 1e-9:
                cost_of_sold += lot["shares"] * lot["cost_per_share"]
                sell_remaining -= lot["shares"]
                lots.pop(0)
            else:
                cost_of_sold += sell_remaining * lot["cost_per_share"]
                lot["shares"] -= sell_remaining
                sell_remaining = 0

    lots[:] = [lot for lot in lots if lot["shares"] > 1e-9]
    return cost_of_sold, max(0.0, sell_remaining)


def _apply_buy_to_lots(lots, shares, price, fees, txn_id=None, txn_date=None):
    """Append a BUY lot and return its weighted cost per share."""
    shares = float(shares or 0)
    price = float(price or 0)
    fees = float(fees or 0)
    lot_cost = (shares * price) + fees
    cost_per = lot_cost / shares if shares else 0
    if shares > 1e-9:
        lot = {"shares": shares, "cost_per_share": cost_per}
        if txn_id is not None:
            lot["id"] = txn_id
        if txn_date is not None:
            lot["date"] = txn_date
        lots.append(lot)
    return cost_per


def _normalize_transaction_shares(raw_shares):
    """Store BUY/SELL quantities as a positive share count.

    Some broker screens display sells as negative quantities. The transaction
    type carries the direction in this app, so shares must remain positive.
    """
    try:
        shares = abs(float(raw_shares))
    except (TypeError, ValueError):
        raise ValueError("Shares is required")
    if shares <= 1e-9:
        raise ValueError("Shares must be greater than 0")
    return shares


def _validate_sell_quantity_available(
    conn,
    ticker,
    profile_id,
    shares,
    transaction_date=None,
    exclude_txn_id=None,
    sort_txn_id=None,
):
    """Reject a sell that would make the position negative at that point in time."""
    rows = conn.execute(
        "SELECT id, transaction_type, transaction_date, shares "
        "FROM transactions WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchall()

    max_id = 0
    events = []
    for row in rows:
        txn_id = row["id"] if isinstance(row, dict) else row[0]
        max_id = max(max_id, int(txn_id or 0))
        if exclude_txn_id is not None and txn_id == exclude_txn_id:
            continue
        events.append({
            "id": txn_id,
            "type": ((row["transaction_type"] if isinstance(row, dict) else row[1]) or "BUY").upper(),
            "date": row["transaction_date"] if isinstance(row, dict) else row[2],
            "shares": abs(float((row["shares"] if isinstance(row, dict) else row[3]) or 0)),
            "proposed": False,
        })

    events.append({
        "id": sort_txn_id if sort_txn_id is not None else max_id + 1,
        "type": "SELL",
        "date": transaction_date,
        "shares": float(shares or 0),
        "proposed": True,
    })

    events.sort(key=lambda e: ((e["date"] or ""), int(e["id"] or 0)))
    running_shares = 0.0
    seen_proposed = False
    for event in events:
        if event["type"] == "BUY":
            running_shares += event["shares"]
            continue

        if (event["proposed"] or seen_proposed) and event["shares"] - running_shares > 1e-6:
            date_label = event["date"] or "the selected date"
            raise ValueError(
                f"Cannot sell {event['shares']:.6f} shares on {date_label}; "
                f"only {max(0.0, running_shares):.6f} shares are available."
            )
        running_shares -= event["shares"]
        if event["proposed"]:
            seen_proposed = True


def _get_open_lots(conn, ticker, profile_ids, exclude_txn_id=None):
    """Return open BUY lots for a ticker after applying sells and allocations."""
    placeholders = ",".join("?" * len(profile_ids))
    rows = conn.execute(
        f"SELECT id, transaction_type, shares, price_per_share, fees, transaction_date "
        f"FROM transactions WHERE ticker = ? AND profile_id IN ({placeholders}) "
        f"ORDER BY transaction_date, id",
        [ticker] + profile_ids,
    ).fetchall()

    sell_ids = []
    for row in rows:
        txn_id = row["id"] if isinstance(row, dict) else row[0]
        txn_type = ((row["transaction_type"] if isinstance(row, dict) else row[1]) or "BUY").upper()
        if txn_id == exclude_txn_id:
            continue
        if txn_type == "SELL":
            sell_ids.append(txn_id)
    alloc_map = _load_lot_alloc_map(conn, sell_ids)

    lots = []
    share_deficit = 0.0
    for row in rows:
        txn_id = row["id"] if isinstance(row, dict) else row[0]
        if txn_id == exclude_txn_id:
            continue

        txn_type = ((row["transaction_type"] if isinstance(row, dict) else row[1]) or "BUY").upper()
        shares = abs(float((row["shares"] if isinstance(row, dict) else row[2]) or 0))
        price = float((row["price_per_share"] if isinstance(row, dict) else row[3]) or 0)
        fees = float((row["fees"] if isinstance(row, dict) else row[4]) or 0)
        txn_date = row["transaction_date"] if isinstance(row, dict) else row[5]

        if txn_type == "BUY":
            if share_deficit > 1e-9:
                covered = min(share_deficit, shares)
                share_deficit -= covered
                shares -= covered
            cost_per = _apply_buy_to_lots(lots, shares, price, fees, txn_id=txn_id, txn_date=txn_date)
            if shares > 1e-9:
                lots[-1]["price_per_share"] = price
                lots[-1]["cost_per_share"] = cost_per
                lots[-1]["fees"] = fees
                lots[-1]["transaction_date"] = txn_date
        else:
            _, sell_remaining = _consume_sell_lots(lots, shares, alloc_map.get(txn_id))
            share_deficit += sell_remaining

    result = []
    for lot in lots:
        if lot["shares"] <= 1e-9:
            continue
        result.append({
            "id": lot["id"],
            "shares_remaining": round(lot["shares"], 6),
            "price_per_share": lot["price_per_share"],
            "cost_per_share": round(lot["cost_per_share"], 4),
            "fees": lot["fees"],
            "transaction_date": lot["transaction_date"],
        })
    return result


def _normalize_lot_allocations(conn, ticker, profile_id, shares, lot_allocations, exclude_txn_id=None):
    """Validate specific-lot allocations and return a clean list."""
    if not lot_allocations:
        return []

    try:
        shares = float(shares or 0)
    except (TypeError, ValueError):
        raise ValueError("Shares is required")

    open_lots = _get_open_lots(conn, ticker, [profile_id], exclude_txn_id=exclude_txn_id)
    available_by_id = {lot["id"]: float(lot["shares_remaining"] or 0) for lot in open_lots}
    cleaned = {}

    for alloc in lot_allocations:
        try:
            buy_id = int(alloc["buy_txn_id"])
            alloc_shares = float(alloc["shares"])
        except (KeyError, TypeError, ValueError):
            raise ValueError("Each lot allocation must include buy_txn_id and shares")

        if alloc_shares <= 0:
            continue
        if buy_id not in available_by_id:
            raise ValueError("One or more selected lots are no longer available")
        cleaned[buy_id] = cleaned.get(buy_id, 0.0) + alloc_shares

    if not cleaned:
        raise ValueError("Specific-lot mode requires at least one lot allocation")

    for buy_id, alloc_shares in cleaned.items():
        available = available_by_id[buy_id]
        if alloc_shares - available > 1e-6:
            raise ValueError(
                f"Allocated shares exceed what is available for lot {buy_id} "
                f"({alloc_shares:.6f} > {available:.6f})"
            )

    total_alloc = sum(cleaned.values())
    if abs(total_alloc - shares) > 1e-6:
        raise ValueError(
            f"Specific-lot allocations must add up to shares sold "
            f"({total_alloc:.6f} allocated vs {shares:.6f} entered)"
        )

    return [
        {"buy_txn_id": buy_id, "shares": round(alloc_shares, 6)}
        for buy_id, alloc_shares in cleaned.items()
    ]


def _annotate_transaction_rows(rows, alloc_map):
    """Attach lot metadata and running position/cost info to transaction rows."""
    annotated = []
    lots = []
    share_deficit = 0.0

    for row in rows:
        txn = dict(row) if isinstance(row, dict) else dict(zip(row.keys(), row))
        txn_id = txn["id"]
        txn_type = (txn.get("transaction_type") or "BUY").upper()
        shares = abs(float(txn.get("shares") or 0))
        price = float(txn.get("price_per_share") or 0)
        fees = float(txn.get("fees") or 0)
        txn["shares"] = shares

        txn_allocs = alloc_map.get(txn_id, [])
        txn["lot_allocations"] = [
            {"buy_txn_id": alloc["buy_txn_id"], "shares": round(float(alloc["shares"] or 0), 6)}
            for alloc in txn_allocs
        ]
        txn["cost_basis_method"] = "SPECIFIC" if txn_allocs else "FIFO"

        if txn_type == "BUY":
            if share_deficit > 1e-9:
                covered = min(share_deficit, shares)
                share_deficit -= covered
                shares -= covered
            _apply_buy_to_lots(lots, shares, price, fees, txn_id=txn_id)
        else:
            _, sell_remaining = _consume_sell_lots(lots, shares, txn_allocs)
            share_deficit += sell_remaining

        total_shares = sum(lot["shares"] for lot in lots) - share_deficit
        total_cost = sum(lot["shares"] * lot["cost_per_share"] for lot in lots)
        avg_cost = total_cost / total_shares if total_shares else 0
        txn["position_after"] = round(total_shares, 6)
        txn["total_cost_after"] = round(total_cost, 2)
        txn["avg_cost_after"] = round(avg_cost, 4) if total_shares else 0
        annotated.append(txn)

    return annotated


@app.route("/api/holdings/<ticker>/open-lots", methods=["GET"])
def open_lots(ticker):
    """Return open (unsold) BUY lots for a ticker, computed via FIFO of existing sells."""
    is_agg, pids = get_profile_filter()
    ticker = ticker.upper()
    conn = get_connection()
    exclude_txn_id = request.args.get("exclude_txn_id", type=int)
    result = _get_open_lots(conn, ticker, pids, exclude_txn_id=exclude_txn_id)
    conn.close()
    return jsonify(result)


@app.route("/api/holdings/<ticker>/transactions", methods=["GET"])
def list_transactions(ticker):
    """List all transactions for a ticker."""
    is_agg, pids = get_profile_filter()
    ticker = ticker.upper()
    conn = get_connection()
    read_pids, include_account_note = _get_transaction_read_scope(conn, is_agg, pids)
    placeholders = ",".join("?" * len(read_pids))
    rows = conn.execute(
        f"SELECT * FROM transactions WHERE ticker = ? AND profile_id IN ({placeholders}) ORDER BY transaction_date, id",
        [ticker] + read_pids,
    ).fetchall()
    sell_ids = [
        row["id"] if isinstance(row, dict) else row[0]
        for row in rows
        if ((row["transaction_type"] if hasattr(row, "keys") else row[1]) or "BUY").upper() == "SELL"
    ]
    alloc_map = _load_lot_alloc_map(conn, sell_ids)
    profile_names = _load_profile_name_map(conn, read_pids) if include_account_note else {}
    conn.close()
    transactions = _annotate_transaction_rows(rows, alloc_map)
    return jsonify(_add_transaction_source_notes(transactions, profile_names, include_account_note))


@app.route("/api/holdings/<ticker>/transactions", methods=["POST"])
def add_transaction(ticker):
    """Add a new transaction for a ticker. Auto-seeds if first transaction."""
    is_agg, pids = get_profile_filter()
    if is_agg:
        profile_id = _resolve_aggregate_profile(ticker.upper(), pids)
    else:
        profile_id = pids[0]

    data = request.get_json()
    ticker = ticker.upper()

    try:
        shares = _normalize_transaction_shares(data.get("shares"))
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    conn = get_connection()

    txn_type = (data.get("transaction_type") or "BUY").upper()
    if txn_type not in ("BUY", "SELL"):
        conn.close()
        return jsonify({"error": "transaction_type must be BUY or SELL"}), 400

    # Validate date year if provided before creating or seeding any rows.
    txn_date = data.get("transaction_date")
    if txn_date:
        try:
            year = int(str(txn_date).split("-")[0])
            if year < 1900 or year > 2099:
                conn.close()
                return jsonify({"error": f"Invalid year {year} - must be between 1900 and 2099"}), 400
        except (ValueError, IndexError):
            conn.close()
            return jsonify({"error": "Invalid date format"}), 400

    # Check if the holding exists; if not, create it (new ticker via transaction flow)
    existing = conn.execute(
        "SELECT 1 FROM all_account_info WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchone()
    if not existing:
        # Create a minimal holding — the rollup will fill in quantity/price/value
        if txn_type == "SELL":
            conn.close()
            return jsonify({"error": f"Cannot sell {ticker} because no holding exists yet"}), 400
        from datetime import date as _date
        conn.execute(
            "INSERT INTO all_account_info (ticker, profile_id, description, import_date) VALUES (?, ?, ?, ?)",
            (ticker, profile_id, data.get("description", ""), _date.today().isoformat()),
        )
        # If a lookup was done on the frontend, apply those fields
        for field in ["description", "classification_type", "div", "div_frequency",
                      "ex_div_date", "div_pay_date", "current_price", "reinvest"]:
            if data.get(field) is not None:
                conn.execute(
                    f"UPDATE all_account_info SET {field} = ? WHERE ticker = ? AND profile_id = ?",
                    (data[field], ticker, profile_id),
                )
        # Handle category for new ticker
        cat_name = (data.get("category") or "").strip()
        if cat_name:
            cat_row = conn.execute(
                "SELECT id FROM categories WHERE name = ? AND profile_id = ?",
                (cat_name, profile_id),
            ).fetchone()
            if cat_row:
                cat_id = cat_row["id"] if isinstance(cat_row, dict) else cat_row[0]
                _replace_ticker_category(conn, profile_id, ticker, cat_id)
        conn.commit()
    else:
        # Auto-seed existing holding's current data as the first transaction
        _seed_transaction_if_needed(ticker, profile_id, conn)

    try:
        normalized_allocs = []
        if txn_type == "SELL":
            _validate_sell_quantity_available(
                conn,
                ticker,
                profile_id,
                shares,
                transaction_date=data.get("transaction_date"),
            )
            normalized_allocs = _normalize_lot_allocations(
                conn,
                ticker,
                profile_id,
                shares,
                data.get("lot_allocations"),
            )
    except ValueError as e:
        conn.close()
        return jsonify({"error": str(e)}), 400

    cur = conn.execute(
        "INSERT INTO transactions (ticker, profile_id, transaction_type, transaction_date, shares, price_per_share, fees, notes) "
        "VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
        (ticker, profile_id, txn_type, data.get("transaction_date"), shares,
         data.get("price_per_share"), data.get("fees", 0), data.get("notes")),
    )
    new_txn_id = cur.lastrowid
    conn.commit()

    # Store specific-lot allocations if provided
    if txn_type == "SELL" and normalized_allocs:
        for alloc in normalized_allocs:
            conn.execute(
                "INSERT INTO transaction_lot_allocations (sell_txn_id, buy_txn_id, shares) VALUES (?, ?, ?)",
                (new_txn_id, alloc["buy_txn_id"], float(alloc["shares"])),
            )
        conn.commit()

    # Rollup into all_account_info
    _rollup_transactions(ticker, profile_id, conn)
    conn.close()
    return jsonify({"ticker": ticker, "message": f"Transaction added for {ticker}"}), 201


@app.route("/api/holdings/<ticker>/transactions/<int:txn_id>", methods=["PUT"])
def update_transaction(ticker, txn_id):
    """Update an existing transaction."""
    is_agg, pids = get_profile_filter()
    ticker = ticker.upper()
    if is_agg:
        profile_id = _resolve_aggregate_profile(ticker, pids)
    else:
        profile_id = pids[0]

    data = request.get_json()

    # Validate date year if provided
    txn_date = data.get("transaction_date")
    if txn_date:
        try:
            year = int(str(txn_date).split("-")[0])
            if year < 1900 or year > 2099:
                return jsonify({"error": f"Invalid year {year} — must be between 1900 and 2099"}), 400
        except (ValueError, IndexError):
            return jsonify({"error": "Invalid date format"}), 400

    conn = get_connection()

    existing = conn.execute(
        "SELECT id, ticker, profile_id, transaction_type, shares, transaction_date FROM transactions WHERE id = ?",
        (txn_id,),
    ).fetchone()
    if not existing:
        conn.close()
        return jsonify({"error": "Transaction not found"}), 404
    existing_ticker = (existing["ticker"] if isinstance(existing, dict) else existing[1]).upper()
    existing_profile_id = existing["profile_id"] if isinstance(existing, dict) else existing[2]
    existing_type = ((existing["transaction_type"] if isinstance(existing, dict) else existing[3]) or "BUY").upper()
    existing_shares = existing["shares"] if isinstance(existing, dict) else existing[4]
    existing_date = existing["transaction_date"] if isinstance(existing, dict) else existing[5]
    if existing_ticker != ticker or existing_profile_id != profile_id:
        conn.close()
        return jsonify({"error": "Transaction does not belong to this holding/profile"}), 404

    existing_allocs = _load_lot_alloc_map(conn, [txn_id]).get(txn_id, [])

    new_type = (data.get("transaction_type") or existing_type).upper()
    try:
        new_shares = _normalize_transaction_shares(data.get("shares", existing_shares))
    except ValueError as e:
        conn.close()
        return jsonify({"error": str(e)}), 400
    if new_type not in ("BUY", "SELL"):
        conn.close()
        return jsonify({"error": "transaction_type must be BUY or SELL"}), 400

    try:
        normalized_allocs = []
        if new_type == "SELL":
            _validate_sell_quantity_available(
                conn,
                ticker,
                profile_id,
                new_shares,
                transaction_date=data.get("transaction_date", existing_date),
                exclude_txn_id=txn_id,
                sort_txn_id=txn_id,
            )
            if "lot_allocations" in data:
                normalized_allocs = _normalize_lot_allocations(
                    conn,
                    ticker,
                    profile_id,
                    new_shares,
                    data.get("lot_allocations"),
                    exclude_txn_id=txn_id,
                )
            elif existing_allocs:
                existing_alloc_total = sum(float(alloc["shares"] or 0) for alloc in existing_allocs)
                if abs(float(new_shares or 0) - existing_alloc_total) > 1e-6:
                    raise ValueError(
                        "This sell uses specific lots. Re-select the lots when changing the share count."
                    )
                normalized_allocs = [
                    {"buy_txn_id": alloc["buy_txn_id"], "shares": float(alloc["shares"] or 0)}
                    for alloc in existing_allocs
                ]
    except ValueError as e:
        conn.close()
        return jsonify({"error": str(e)}), 400

    updates = []
    vals = []
    for field in ["transaction_type", "transaction_date", "shares", "price_per_share", "fees", "notes"]:
        if field in data:
            updates.append(f"{field} = ?")
            vals.append(new_shares if field == "shares" else data[field])

    if not updates:
        conn.close()
        return jsonify({"error": "No fields to update"}), 400

    vals.append(txn_id)
    conn.execute(f"UPDATE transactions SET {', '.join(updates)} WHERE id = ?", vals)
    conn.execute("DELETE FROM transaction_lot_allocations WHERE sell_txn_id = ?", (txn_id,))
    if new_type == "SELL" and normalized_allocs:
        for alloc in normalized_allocs:
            conn.execute(
                "INSERT INTO transaction_lot_allocations (sell_txn_id, buy_txn_id, shares) VALUES (?, ?, ?)",
                (txn_id, alloc["buy_txn_id"], float(alloc["shares"])),
            )
    conn.commit()

    _rollup_transactions(ticker, profile_id, conn)
    conn.close()
    return jsonify({"ticker": ticker, "message": f"Transaction {txn_id} updated"})


@app.route("/api/holdings/<ticker>/transactions/<int:txn_id>", methods=["DELETE"])
def delete_transaction(ticker, txn_id):
    """Delete a transaction and re-rollup."""
    is_agg, pids = get_profile_filter()
    ticker = ticker.upper()
    if is_agg:
        profile_id = _resolve_aggregate_profile(ticker, pids)
    else:
        profile_id = pids[0]

    conn = get_connection()
    existing = conn.execute(
        "SELECT ticker, profile_id FROM transactions WHERE id = ?",
        (txn_id,),
    ).fetchone()
    if not existing:
        conn.close()
        return jsonify({"error": "Transaction not found"}), 404
    existing_ticker = (existing["ticker"] if isinstance(existing, dict) else existing[0]).upper()
    existing_profile_id = existing["profile_id"] if isinstance(existing, dict) else existing[1]
    if existing_ticker != ticker or existing_profile_id != profile_id:
        conn.close()
        return jsonify({"error": "Transaction does not belong to this holding/profile"}), 404

    conn.execute("DELETE FROM transactions WHERE id = ?", (txn_id,))
    conn.commit()

    # Check if any transactions remain
    remaining = conn.execute(
        "SELECT COUNT(*) as cnt FROM transactions WHERE ticker = ? AND profile_id = ?",
        (ticker, profile_id),
    ).fetchone()
    cnt = remaining["cnt"] if isinstance(remaining, dict) else remaining[0]
    if cnt > 0:
        _rollup_transactions(ticker, profile_id, conn)
    # If no transactions left, the holding stays as-is (user can manage via edit modal)

    conn.close()
    return jsonify({"ticker": ticker, "message": f"Transaction {txn_id} deleted"})


@app.route("/api/holdings/<ticker>/has_transactions", methods=["GET"])
def has_transactions(ticker):
    """Check if a ticker has any transactions (used by frontend to toggle read-only)."""
    is_agg, pids = get_profile_filter()
    ticker = ticker.upper()
    conn = get_connection()
    placeholders = ",".join("?" * len(pids))
    row = conn.execute(
        f"SELECT COUNT(*) as cnt FROM transactions WHERE ticker = ? AND profile_id IN ({placeholders})",
        [ticker] + pids,
    ).fetchone()
    conn.close()
    cnt = row["cnt"] if isinstance(row, dict) else row[0]
    return jsonify({"has_transactions": cnt > 0, "count": cnt})


