def _export_currency_context():
    currency = str(request.args.get("currency") or "USD").upper()
    if currency != "CAD":
        return {"currency": "USD", "rate": 1.0, "updated_at": None, "source": "Source data"}
    stored = _fx_settings()
    manual = _valid_fx_rate(stored.get("usd_cad_manual_rate"))
    live = _valid_fx_rate(stored.get("usd_cad_rate"))
    rate = manual or live
    if not rate:
        return {"currency": "USD", "rate": 1.0, "updated_at": None, "source": "Source data"}
    return {
        "currency": "CAD",
        "rate": rate,
        "updated_at": stored.get("usd_cad_manual_updated_at") if manual else stored.get("usd_cad_rate_updated_at"),
        "source": "Manual override" if manual else (stored.get("usd_cad_rate_source") or "Cached live rate"),
    }


def _convert_export_rows(rows, money_headers, fx):
    if fx["currency"] != "CAD":
        return rows
    converted = []
    for row in rows:
        next_row = dict(row)
        for header in money_headers:
            value = next_row.get(header)
            if value in (None, ""):
                continue
            try:
                next_row[header] = float(value) * fx["rate"]
            except (TypeError, ValueError):
                pass
        converted.append(next_row)
    return converted


def _add_export_info_sheet(wb, fx):
    from openpyxl.styles import Font
    ws = wb.create_sheet(title="Export Info", index=0)
    rows = [
        ("Export Currency", fx["currency"]),
        ("Source Currency", "USD"),
        ("USD/CAD Rate", fx["rate"] if fx["currency"] == "CAD" else ""),
        ("Rate Source", fx["source"]),
        ("Rate Last Updated", fx["updated_at"] or ""),
        ("Reimportable", "Yes" if fx["currency"] == "USD" else "No - report values were converted"),
    ]
    for row_index, (label, value) in enumerate(rows, 1):
        ws.cell(row=row_index, column=1, value=label).font = Font(bold=True)
        ws.cell(row=row_index, column=2, value=value)
    ws.column_dimensions["A"].width = 22
    ws.column_dimensions["B"].width = 34


def _export_profile_data(conn, profile_id):
    """Fetch export rows for a single profile. Returns (profile_name, [row_dicts])."""
    _ensure_basis_columns(conn)
    headers = [h for h, _ in _EXPORT_COL_MAP]
    sql_cols = list(dict.fromkeys(
        [c for _, c in _EXPORT_COL_MAP if c is not None]
        + [
            "original_price_paid", "original_purchase_value",
            "broker_price_paid", "broker_purchase_value",
        ]
    ))

    prof = conn.execute("SELECT name FROM profiles WHERE id = ?", (profile_id,)).fetchone()
    profile_name = prof["name"] if prof else f"Portfolio {profile_id}"

    rows = conn.execute(
        f"SELECT {', '.join(sql_cols)} FROM all_account_info WHERE profile_id = ?",
        (profile_id,),
    ).fetchall()

    cat_map = {}
    cat_rows = conn.execute(
        "SELECT tc.ticker, c.name AS category_name "
        "FROM ticker_categories tc JOIN categories c ON c.id = tc.category_id "
        "WHERE tc.profile_id = ?",
        (profile_id,),
    ).fetchall()
    for cr in cat_rows:
        cat_map.setdefault(cr["ticker"], []).append(cr["category_name"])

    raw_rows = rows_to_dicts(rows)
    _apply_basis_mode_to_holdings(
        raw_rows,
        _cumulative_invested_cost_by_ticker(conn, [profile_id]),
        _realized_gains_by_ticker(conn, [profile_id]),
    )

    out_rows = []
    for row in raw_rows:
        out = {}
        for header, sql_col in _EXPORT_COL_MAP:
            if header == "Category":
                out[header] = ", ".join(cat_map.get(row["ticker"], []))
            else:
                val = row.get(sql_col)
                out[header] = val if val is not None else ""
        out_rows.append(out)

    return profile_name, out_rows


