# ── Dividend Comparison (Forward vs TTM) ──────────────────────────────────────

@app.route("/api/dividend-compare/holdings", methods=["GET"])
def dividend_compare_holdings():
    """Return forward and trailing-12-month dividend data for current portfolio holdings."""
    import yfinance as yf
    from datetime import datetime as _dt

    is_agg, pids = get_profile_filter()
    conn = get_connection()
    placeholders = ",".join("?" * len(pids))

    if is_agg and len(pids) > 1:
        rows = conn.execute(
            f"""SELECT ticker, MAX(description) as description, SUM(quantity) as quantity,
                   MAX(div_frequency) as div_frequency, MAX(current_price) as current_price,
                   CASE WHEN SUM(quantity) > 0 THEN SUM(purchase_value) / SUM(quantity) ELSE 0 END as price_paid
               FROM all_account_info
               WHERE profile_id IN ({placeholders}) AND quantity > 0
               GROUP BY ticker""",
            pids,
        ).fetchall()
    else:
        rows = conn.execute(
            f"""SELECT ticker, description, quantity, div_frequency, current_price, price_paid
               FROM all_account_info
               WHERE profile_id IN ({placeholders}) AND quantity > 0""",
            pids,
        ).fetchall()
    conn.close()

    if not rows:
        return jsonify([])

    tickers = [r["ticker"] for r in rows]
    holding_map = {r["ticker"]: dict(r) for r in rows}

    # Batch download dividend history (one yfinance call for TTM)
    ttm_map = {}
    try:
        raw = _chunked_yf_download(" ".join(tickers), period="1y", progress=False, auto_adjust=False, actions=True)
        if not raw.empty:
            if isinstance(raw.columns, pd.MultiIndex):
                divs = raw["Dividends"] if "Dividends" in raw.columns.get_level_values(0) else None
            else:
                divs = raw[["Dividends"]] if "Dividends" in raw.columns else None

            if divs is not None:
                one_year_ago = pd.Timestamp.now() - pd.Timedelta(days=365)
                if hasattr(divs.index, 'tz') and divs.index.tz is not None:
                    one_year_ago = pd.Timestamp.now(tz=divs.index.tz) - pd.Timedelta(days=365)
                recent = divs[divs.index >= one_year_ago]

                if isinstance(recent, pd.Series):
                    # Single ticker
                    total = float(recent[recent > 0].sum())
                    if total > 0:
                        ttm_map[tickers[0]] = total
                else:
                    for t in tickers:
                        if t in recent.columns:
                            col = recent[t].dropna()
                            total = float(col[col > 0].sum())
                            if total > 0:
                                ttm_map[t] = total
    except Exception:
        pass

    # Fetch forward dividend rate via info (use threads for speed)
    from concurrent.futures import ThreadPoolExecutor, as_completed
    fwd_map = {}

    def _get_fwd(sym):
        try:
            info = yf.Ticker(sym).info or {}
            rate = info.get("dividendRate")
            return sym, rate if rate and rate > 0 else None
        except Exception:
            return sym, None

    with ThreadPoolExecutor(max_workers=8) as pool:
        futures = {pool.submit(_get_fwd, t): t for t in tickers}
        for fut in as_completed(futures):
            sym, rate = fut.result()
            if rate:
                fwd_map[sym] = rate

    # Build results
    results = []
    for tk_sym in tickers:
        h = holding_map[tk_sym]
        price = h["current_price"] or 0
        qty = h["quantity"] or 0
        fwd = fwd_map.get(tk_sym)
        ttm = ttm_map.get(tk_sym)

        entry = {
            "ticker": tk_sym,
            "description": h["description"] or tk_sym,
            "quantity": qty,
            "current_price": price,
            "price_paid": h["price_paid"] or 0,
            "div_frequency": h["div_frequency"] or "Q",
            "forward_annual_dividend": round(fwd, 4) if fwd else None,
            "forward_dividend_yield": round(fwd / price, 6) if fwd and price else None,
            "forward_income": round(fwd * qty, 2) if fwd else None,
            "ttm_dividend": round(ttm, 4) if ttm else None,
            "ttm_dividend_yield": round(ttm / price, 6) if ttm and price else None,
            "ttm_income": round(ttm * qty, 2) if ttm else None,
            "error": None if (fwd or ttm) else "Not enough information to compute",
        }
        results.append(entry)

    results.sort(key=lambda r: r["ticker"])
    return jsonify(results)


@app.route("/api/dividend-compare/lookup", methods=["POST"])
def dividend_compare_lookup():
    """Fetch forward and TTM dividend data for user-supplied tickers."""
    import yfinance as yf

    data = request.get_json()
    tickers = data.get("tickers", [])
    if not tickers:
        return jsonify([])

    results = []
    for tk_sym in tickers:
        tk_sym = tk_sym.strip().upper()
        if not tk_sym:
            continue
        entry = {
            "ticker": tk_sym,
            "description": tk_sym,
            "quantity": None,
            "current_price": 0,
            "price_paid": None,
            "div_frequency": None,
            "forward_annual_dividend": None,
            "forward_dividend_yield": None,
            "ttm_dividend": None,
            "ttm_dividend_yield": None,
            "ttm_income": None,
            "forward_income": None,
            "error": None,
        }
        try:
            tk = yf.Ticker(tk_sym)
            info = tk.info or {}
            price = info.get("regularMarketPrice") or info.get("currentPrice") or 0
            entry["current_price"] = price
            entry["description"] = (info.get("longName") or info.get("shortName") or tk_sym)[:200]

            # Infer frequency from history
            try:
                hist = tk.dividends
                if hist is not None and len(hist) > 0:
                    if hist.index.tz is not None:
                        one_year_ago = pd.Timestamp.now(tz=hist.index.tz) - pd.Timedelta(days=365)
                    else:
                        one_year_ago = pd.Timestamp.now() - pd.Timedelta(days=365)
                    recent = hist[hist.index >= one_year_ago]
                    n = len(recent[recent > 0])
                    entry["div_frequency"] = "W" if n >= 45 else "M" if n >= 10 else "Q" if n >= 3 else "SA" if n >= 2 else "A" if n >= 1 else None

                    ttm_total = float(recent[recent > 0].sum()) if n > 0 else 0
                    if ttm_total > 0:
                        entry["ttm_dividend"] = round(ttm_total, 4)
                        entry["ttm_dividend_yield"] = round(ttm_total / price, 6) if price else None
            except Exception:
                pass

            # Forward
            fwd = info.get("dividendRate")
            if fwd and fwd > 0:
                entry["forward_annual_dividend"] = round(fwd, 4)
                entry["forward_dividend_yield"] = round(fwd / price, 6) if price else None

            if entry["forward_annual_dividend"] is None and entry["ttm_dividend"] is None:
                entry["error"] = "Not enough information to compute"

        except Exception as e:
            entry["error"] = f"Lookup failed: {str(e)}"

        results.append(entry)

    return jsonify(results)


# ── Upcoming Dividends ─────────────────────────────────────────────────────────

@app.route("/api/upcoming-dividends", methods=["GET"])
def upcoming_dividends():
    """Return holdings with ex-div dates projected into the upcoming week."""
    from datetime import datetime, timedelta

    is_agg, pids = get_profile_filter()
    conn = get_connection()
    placeholders = ",".join("?" * len(pids))
    if is_agg and len(pids) > 1:
        rows = conn.execute(
            f"""SELECT ticker, MAX(description) as description, MAX(ex_div_date) as ex_div_date,
                   MAX(div_pay_date) as div_pay_date,
                   MAX(div) as div, MAX(div_frequency) as div_frequency,
                   SUM(quantity) as quantity, SUM(approx_monthly_income) as approx_monthly_income
               FROM all_account_info
               WHERE profile_id IN ({placeholders}) AND ex_div_date IS NOT NULL AND ex_div_date != ''
                 AND ex_div_date != '--' AND quantity > 0
               GROUP BY ticker""",
            pids,
        ).fetchall()
    else:
        rows = conn.execute(
            f"""SELECT ticker, description, ex_div_date, div_pay_date, div, div_frequency, quantity, approx_monthly_income
               FROM all_account_info
               WHERE profile_id IN ({placeholders}) AND ex_div_date IS NOT NULL AND ex_div_date != ''
                 AND ex_div_date != '--' AND quantity > 0""",
            pids,
        ).fetchall()
    conn.close()

    if not rows:
        return jsonify([])

    today = datetime.today().date()
    cache_columns = (
        "ticker", "description", "ex_div_date", "div_pay_date",
        "div", "div_frequency", "quantity", "approx_monthly_income",
    )
    cache_key = (
        tuple(pids),
        today.isoformat(),
        _rows_signature(rows, cache_columns),
    )
    cached = _cache_get(_UPCOMING_DIVIDENDS_CACHE, cache_key)
    if cached is not None:
        return jsonify(cached)

    week_end = today + timedelta(days=7)

    freq_days = {"W": 7, "52": 7, "M": 30, "Q": 91, "SA": 182, "A": 365}
    freq_labels = {"W": "Weekly", "52": "Weekly", "M": "Monthly", "Q": "Quarterly", "SA": "Semi-Annual", "A": "Annual"}
    freq_colors = {"M": "#00c9a7", "52": "#FFD700", "W": "#FFD700", "Q": "#7ecfff", "SA": "#f0a0ff", "A": "#f0a0ff"}
    official_cache = {}

    def next_biz(d):
        if d.weekday() == 5:
            d += timedelta(days=2)
        elif d.weekday() == 6:
            d += timedelta(days=1)
        return d

    def official_snapshot_for(ticker, description):
        key = ((ticker or "").strip().upper(), description or "")
        if key not in official_cache:
            try:
                official_cache[key] = _fetch_official_distribution_snapshot(key[0], key[1])
            except Exception:
                official_cache[key] = None
        return official_cache[key]

    events = []
    for r in rows:
        ticker = (r["ticker"] or "").strip().upper()
        description = r["description"] or ticker
        freq = (r["div_frequency"] or "Q").upper()
        amount = r["div"] or 0
        stored_pay = _date_from_value(r["div_pay_date"])
        official_pay = None
        official_lag = None
        official = official_snapshot_for(ticker, description)
        if official and official.get("has_dividend"):
            official_freq = (official.get("freq") or "").strip().upper()
            if official_freq:
                freq = official_freq
            try:
                official_div = official.get("div")
                if official_div is not None and float(official_div) > 0:
                    amount = float(official_div)
            except Exception:
                pass
            ex = _date_from_value(official.get("ex_div_date"))
            official_pay = _date_from_value(official.get("div_pay_date"))
            if official_pay is not None:
                stored_pay = official_pay
            lag_val = official.get("pay_lag_days")
            if lag_val is not None:
                try:
                    official_lag = int(lag_val)
                except (TypeError, ValueError):
                    official_lag = None
        else:
            ex = None

        try:
            if ex is None:
                ex = datetime.strptime(r["ex_div_date"], "%m/%d/%y").date()
        except (ValueError, TypeError):
            try:
                if ex is None:
                    ex = datetime.strptime(r["ex_div_date"], "%Y-%m-%d").date()
            except (ValueError, TypeError):
                continue

        step = freq_days.get(freq, 91)

        # Project forward — keep advancing until the estimated pay date >= today
        nxt = ex
        cycle_steps = 0
        while True:
            if stored_pay and cycle_steps == 0:
                pay = stored_pay
            elif official_lag is not None:
                pay = next_biz(nxt + timedelta(days=official_lag))
            elif freq in ("W", "52"):
                pay = next_biz(nxt + timedelta(days=1))
            elif freq == "M":
                pay = next_biz(nxt + timedelta(days=2))
            else:
                pay = next_biz(nxt + timedelta(days=14))
            # Show if pay date is today or later
            if pay >= today:
                break
            nxt += timedelta(days=step)
            cycle_steps += 1

        if nxt <= week_end:
            events.append({
                "ticker": ticker,
                "description": description,
                "ex_date": nxt.strftime("%Y-%m-%d"),
                "ex_weekday": nxt.strftime("%a"),
                "pay_date": pay.strftime("%Y-%m-%d"),
                "pay_weekday": pay.strftime("%a"),
                "pay_estimated": not (official_pay is not None and cycle_steps == 0),
                "amount": amount,
                "est_payment": round(amount * (r["quantity"] or 0), 2),
                "frequency": freq,
                "freq_label": freq_labels.get(freq, "Quarterly"),
                "color": freq_colors.get(freq, "#7ecfff"),
            })

    events.sort(key=lambda e: e["ex_date"])
    _cache_set(_UPCOMING_DIVIDENDS_CACHE, cache_key, events)
    return jsonify(events)


# ── Portfolio Summary Data (grades) ────────────────────────────────────────────

def _ticker_info_from_holding_rows(rows):
    """Deduplicate DB holding rows into the NAV coverage input shape."""
    ticker_info = {}
    for r in rows:
        tk = str(r["ticker"] if "ticker" in r.keys() else r[0]).strip().upper()
        if not tk:
            continue
        cur_price = float(r["current_price"] or 0) if "current_price" in r.keys() else 0.0
        qty = float(r["quantity"] or 0) if "quantity" in r.keys() else 0.0
        annual_income = float(r["estim_payment_per_year"] or 0) if "estim_payment_per_year" in r.keys() else 0.0
        current_value = float(r["current_value"] or 0) if "current_value" in r.keys() else cur_price * qty
        if tk not in ticker_info:
            ticker_info[tk] = {
                "current_price": cur_price,
                "quantity": qty,
                "description": r["description"] if "description" in r.keys() else "",
                "classification_type": r["classification_type"] if "classification_type" in r.keys() else "",
                "annual_income": annual_income,
                "current_value": current_value,
                "nav_erosion_scope": r["nav_erosion_scope"] if "nav_erosion_scope" in r.keys() else "auto",
                "nav_benchmark_override": r["nav_benchmark_override"] if "nav_benchmark_override" in r.keys() else None,
            }
        else:
            ticker_info[tk]["quantity"] += qty
            ticker_info[tk]["annual_income"] += annual_income
            ticker_info[tk]["current_value"] += current_value
            if cur_price > 0:
                ticker_info[tk]["current_price"] = cur_price
            if ticker_info[tk].get("nav_erosion_scope") != "test":
                scope = r["nav_erosion_scope"] if "nav_erosion_scope" in r.keys() else "auto"
                if scope == "test" or (scope == "skip" and ticker_info[tk].get("nav_erosion_scope") == "auto"):
                    ticker_info[tk]["nav_erosion_scope"] = scope
            bench_override = r["nav_benchmark_override"] if "nav_benchmark_override" in r.keys() else None
            if bench_override and not ticker_info[tk].get("nav_benchmark_override"):
                ticker_info[tk]["nav_benchmark_override"] = bench_override
    return ticker_info


def _build_nav_coverage_payload(ticker_info, cache_key=None, use_cache=True):
    """Shared benchmark-adjusted NAV erosion payload for dashboard and analytics."""
    import yfinance as yf
    from datetime import datetime as _dt, timedelta as _td

    tickers = list(ticker_info.keys())
    if cache_key and use_cache:
        cached = _PORTFOLIO_COVERAGE_CACHE.get(cache_key)
        if cached and (time.time() - cached[0]) < _PORTFOLIO_SUMMARY_TTL_SEC:
            return cached[1]

    one_year_ago = (_dt.now() - _td(days=365)).strftime("%Y-%m-%d")
    results = []
    total_price_return_dollars = 0.0
    total_dist_dollars = 0.0

    for tk in tickers:
        info = ticker_info[tk]
        cur_price = info.get("current_price", 0.0)
        qty = info.get("quantity", 0.0)
        nav_scope = info.get("nav_erosion_scope", "auto")
        if not _should_test_nav_erosion(
            tk,
            info.get("description", ""),
            info.get("classification_type", ""),
            nav_scope,
        ):
            total_dist_dollars += max(0.0, float(info.get("annual_income") or 0.0))
            results.append({
                "ticker": tk,
                "coverage_ratio": None,
                "benchmark": None,
                "nav_tested": False,
                "nav_erosion_scope": nav_scope,
                "nav_benchmark_override": info.get("nav_benchmark_override"),
            })
            continue

        if cur_price <= 0:
            results.append({"ticker": tk, "coverage_ratio": None, "benchmark": None, "nav_tested": False})
            continue

        try:
            yf_tk = yf.Ticker(tk)
            hist = yf_tk.history(start=one_year_ago, interval="1d", auto_adjust=False, actions=True)
            if hist.empty or len(hist) < 2:
                results.append({"ticker": tk, "coverage_ratio": None, "benchmark": None, "nav_tested": False})
                continue

            close = hist["Close"].dropna()
            if len(close) < 2:
                results.append({"ticker": tk, "coverage_ratio": None, "benchmark": None, "nav_tested": False})
                continue
            price_1yr_ago = float(close.iloc[0])
            cur_price = float(close.iloc[-1])
            if price_1yr_ago <= 0 or cur_price <= 0:
                results.append({"ticker": tk, "coverage_ratio": None, "benchmark": None, "nav_tested": False})
                continue

            fund_return = (cur_price - price_1yr_ago) / price_1yr_ago
            divs = yf_tk.dividends
            ttm_dist_yield, ttm_dist_per_share = _nav_distribution_yield_from_history(divs, cur_price, close)
            annual_income = max(0.0, float(info.get("annual_income") or 0.0))
            current_value = max(0.0, float(info.get("current_value") or 0.0))
            estimated_annual_yield = annual_income / current_value if current_value > 0 else 0.0
            if estimated_annual_yield > ttm_dist_yield:
                ttm_dist_yield = estimated_annual_yield

            benchmark_override = (info.get("nav_benchmark_override") or "").strip().upper()
            benchmark = benchmark_override or _nav_benchmark_for_ticker(
                tk,
                info.get("description", ""),
                info.get("classification_type", ""),
            )
            benchmark_return = fund_return
            component_returns = []
            try:
                for bench in _nav_benchmark_parts(benchmark):
                    bench_hist = yf.Ticker(bench).history(start=close.index[0], interval="1d", auto_adjust=True)
                    if bench_hist is not None and not bench_hist.empty and "Close" in bench_hist.columns:
                        bench_close = bench_hist["Close"].dropna()
                        aligned = _nav_align_series(close.rename("fund"), bench_close.rename("benchmark"))
                        if len(aligned) >= 2:
                            bench_start = float(aligned["benchmark"].iloc[0])
                            bench_end = float(aligned["benchmark"].iloc[-1])
                            if bench_start > 0 and bench_end > 0:
                                component_returns.append((bench_end - bench_start) / bench_start)
                if component_returns:
                    benchmark_return = sum(component_returns)
            except Exception:
                pass
            if benchmark_override and not component_returns:
                results.append({
                    "ticker": tk,
                    "coverage_ratio": None,
                    "benchmark": benchmark,
                    "benchmark_valid": False,
                    "nav_tested": False,
                    "nav_erosion_scope": nav_scope,
                    "nav_benchmark_override": info.get("nav_benchmark_override"),
                    "warning": "Benchmark override did not return price history",
                })
                continue

            numerator = _nav_erosion_numerator(fund_return, benchmark_return)
            coverage = round(numerator / ttm_dist_yield, 4) if ttm_dist_yield > 0 and numerator is not None else None
            price_change_pct = fund_return * 100
            severity = _nav_erosion_from_adjusted_ratio(coverage, price_change_pct=price_change_pct)

            results.append({
                "ticker": tk,
                "coverage_ratio": coverage,
                "price_change_pct": round(price_change_pct, 2),
                "nav_erosion_severity": severity,
                "benchmark": benchmark,
                "benchmark_valid": True,
                "nav_tested": coverage is not None,
                "nav_erosion_scope": nav_scope,
                "nav_benchmark_override": info.get("nav_benchmark_override"),
            })

            dist_dollars = ttm_dist_per_share * qty
            if dist_dollars > 0:
                erosion_dollars = (numerator or 0.0) * price_1yr_ago * qty
                total_dist_dollars += dist_dollars
                total_price_return_dollars += erosion_dollars

        except Exception:
            results.append({"ticker": tk, "coverage_ratio": None, "benchmark": None, "nav_tested": False})

    agg_coverage = round(total_price_return_dollars / total_dist_dollars, 4) if total_dist_dollars > 0 else None
    aggregate_severity = _nav_aggregate_severity(agg_coverage, results)
    payload = {
        "results": results,
        "aggregate_coverage": agg_coverage,
        "aggregate_severity": aggregate_severity,
    }
    if cache_key and use_cache:
        _PORTFOLIO_COVERAGE_CACHE[cache_key] = (time.time(), payload)
    return payload


def _nav_aggregate_severity(aggregate_coverage, results=None):
    """Classify portfolio NAV erosion from the dollar-weighted aggregate ratio."""
    del results
    return _nav_erosion_from_adjusted_ratio(aggregate_coverage)


@app.route("/api/portfolio-coverage", methods=["GET"])
def portfolio_coverage():
    """Compute benchmark-adjusted NAV erosion ratio for each ticker and aggregate."""
    import warnings
    warnings.filterwarnings("ignore")

    pid = get_profile_id()
    conn = get_connection()
    rows = conn.execute(
        "SELECT ticker, current_price, quantity, description, classification_type, "
        "       estim_payment_per_year, current_value, nav_erosion_scope, nav_benchmark_override "
        "FROM all_account_info "
        "WHERE profile_id = ? AND quantity > 0",
        (pid,),
    ).fetchall()
    conn.close()

    ticker_info = _ticker_info_from_holding_rows(rows)
    coverage_cache_key = (
        pid,
        "destructive-nav-v14",
        tuple(sorted((
            t,
            ticker_info[t].get("nav_erosion_scope", "auto"),
            ticker_info[t].get("nav_benchmark_override") or "",
        ) for t in ticker_info)),
    )
    return jsonify(_build_nav_coverage_payload(ticker_info, coverage_cache_key))


def _closure_risk_money(v):
    """Compact money label for closure-risk reason strings ($18.2M, $1.2B, $63k)."""
    if v is None:
        return "n/a"
    try:
        v = float(v)
    except (TypeError, ValueError):
        return "n/a"
    if v >= 1e9:
        return f"${v / 1e9:.1f}B"
    if v >= 1e6:
        return f"${v / 1e6:.1f}M"
    if v >= 1e3:
        return f"${v / 1e3:.0f}k"
    return f"${v:.0f}"


def _closure_risk_reason(tier, aum, er, est_revenue, fund_age_years, softened):
    """Plain-English tooltip explaining an ETF's closure-risk tier."""
    parts = [f"{_closure_risk_money(aum)} AUM"]
    if er is not None:
        parts.append(f"{er * 100:.2f}% ER")
    if est_revenue is not None:
        parts.append(f"~{_closure_risk_money(est_revenue)}/yr est. fee revenue")
    facts = " · ".join(parts)
    tail = {
        "high": "Well below the ~$500k a fund typically needs to cover its running costs — elevated chance the issuer closes it.",
        "elevated": "Below the fee revenue most funds need to stay profitable — worth watching for a closure notice.",
        "watch": "On the small side; comfortably profitable territory starts around $50M / ~$500k in annual fees.",
        "ok": "Comfortably above the size at which funds are usually shut down.",
    }.get(tier, "")
    age = ""
    if fund_age_years is not None:
        if fund_age_years < 1:
            months = max(1, int(round(fund_age_years * 12)))
            age = f" Fund launched ~{months} month{'s' if months != 1 else ''} ago"
        else:
            age = f" Fund is ~{fund_age_years:.1f} years old"
        if softened:
            age += " — a small size is normal this early, so the rating is capped at Watch."
        else:
            age += "."
    return f"{facts} — {tail}{age}".strip()


def _assess_etf_closure_risk(info):
    """Estimate an ETF's closure risk from AUM, expense ratio, and fund age.

    ETF issuers earn roughly (AUM × expense ratio) per year; a fund becomes a
    closure candidate when that fee revenue can't cover its running costs
    (~$250k–$500k/yr for a small fund). Raw AUM alone is misleading — a cheap
    fund needs far more assets to break even than an expensive one — so we
    combine an estimated-revenue test with AUM floors, and grant newly launched
    funds a grace period (they're seeded small on purpose).

    Returns None for anything that is not an ETF (individual stocks don't get
    liquidated for being small). Otherwise a dict with the tier
    ('ok' | 'watch' | 'elevated' | 'high' | 'unknown'), the inputs, and a
    plain-English reason for the dashboard tooltip.
    """
    if not isinstance(info, dict):
        return None
    quote_type = (info.get("quoteType") or "").upper()
    if quote_type != "ETF":
        return None

    aum = info.get("totalAssets") or info.get("totalNetAssets")
    try:
        aum = float(aum) if aum is not None else None
    except (TypeError, ValueError):
        aum = None

    er = info.get("annualReportExpenseRatio")
    if er is None:
        er = info.get("netExpenseRatio")
    try:
        er = float(er) if er is not None else None
    except (TypeError, ValueError):
        er = None
    # Yahoo sometimes returns the expense ratio as a percent (0.35) instead of a
    # fraction (0.0035). Anything above ~5% is certainly a percent-scaled value.
    if er is not None and er > 0.05:
        er = er / 100.0

    inception = info.get("fundInceptionDate")
    fund_age_years = None
    try:
        if inception:
            fund_age_years = max(0.0, (time.time() - float(inception)) / (365.25 * 86400))
    except (TypeError, ValueError):
        fund_age_years = None
    is_new = fund_age_years is not None and fund_age_years < 1.5

    est_revenue = aum * er if (aum is not None and er is not None) else None

    if aum is None:
        return {
            "tier": "unknown", "aum": None, "expense_ratio": er,
            "est_revenue": None, "fund_age_years": fund_age_years,
            "is_new": is_new, "quote_type": quote_type,
            "reason": "Fund size (AUM) unavailable from the data provider — closure risk can't be estimated.",
        }

    # Break-even style thresholds. Estimated annual fee revenue drives the call
    # when we can compute it; the AUM floors act as a fallback and hard floor.
    watch_rev, elev_rev, high_rev = 500_000, 350_000, 150_000
    watch_aum, elev_aum, high_aum = 50_000_000, 25_000_000, 10_000_000

    def _hit(rev_threshold, aum_threshold):
        rev_hit = est_revenue is not None and est_revenue < rev_threshold
        return rev_hit or aum < aum_threshold

    if _hit(high_rev, high_aum):
        tier = "high"
    elif _hit(elev_rev, elev_aum):
        tier = "elevated"
    elif _hit(watch_rev, watch_aum):
        tier = "watch"
    else:
        tier = "ok"

    # New funds are seeded small on purpose — don't sound the alarm on a fund
    # that simply launched recently. Cap the severity at 'watch'.
    softened = False
    if is_new and tier in ("elevated", "high"):
        tier = "watch"
        softened = True

    return {
        "tier": tier, "aum": aum, "expense_ratio": er,
        "est_revenue": est_revenue, "fund_age_years": fund_age_years,
        "is_new": is_new, "quote_type": quote_type,
        "reason": _closure_risk_reason(tier, aum, er, est_revenue, fund_age_years, softened),
    }


@app.route("/api/portfolio-summary/data", methods=["GET"])
def portfolio_summary_data():
    """Compute per-ticker grades and portfolio-level grade via yfinance."""
    import warnings
    import numpy as np
    import yfinance as yf
    from grading import ticker_score, grade_portfolio, letter_grade, _beta
    warnings.filterwarnings("ignore")

    is_agg, pids = get_profile_filter()
    conn = get_connection()
    placeholders = ",".join("?" * len(pids))
    # Gate on actually-held market value, NOT cost basis. Grades/beta/deltas are
    # derived purely from market price history, so a real position with a missing
    # cost basis (e.g. a broker import that left purchase_value = 0, like QQQI /
    # BTCI in some IRA accounts) must still be graded — keying on purchase_value
    # would silently drop it from the ticker set and blank its risk columns.
    rows = conn.execute(
        f"SELECT ticker, SUM(current_value) as current_value FROM all_account_info WHERE profile_id IN ({placeholders}) AND quantity > 0 AND current_value > 0 GROUP BY ticker",
        pids,
    ).fetchall()
    conn.close()

    if not rows:
        return jsonify({"error": "No data"}), 400

    tickers = [r["ticker"] for r in rows]
    # Key on ticker set + profile so intraday price movement doesn't bust the cache.
    # Weights within the 30-min window will be slightly stale if prices move, which
    # is acceptable for grade/ratio display; a buy/sell changes the ticker set and
    # naturally invalidates.
    cache_key = ("summary-beta-v2-ticker-risk", tuple(pids), tuple(sorted(r["ticker"] for r in rows)))
    default_ticker_grades = {t: {"grade": "N/A", "score": None} for t in tickers}
    cache_entry = _PORTFOLIO_SUMMARY_CACHE.get(cache_key)
    cached_ts, cached = cache_entry if cache_entry else (0, None)
    now = time.time()
    if cached and (now - cached_ts) < _PORTFOLIO_SUMMARY_TTL_SEC:
        return jsonify(cached)
    benchmark_symbols = {"sp500": "SPY", "nasdaq": "QQQ"}
    all_dl = list(set(tickers + list(benchmark_symbols.values())))

    # Detect renamed tickers and include both old and new in download. The same
    # per-ticker .info fetch also feeds the ETF closure-risk assessment, so it
    # rides along for free here rather than costing a second network round-trip.
    rename_map = {}
    ticker_closure_risk = {}
    for t in tickers:
        try:
            _info = yf.Ticker(t).info or {}
            _new = (_info.get("symbol") or "").upper()
            if _new and _new != t:
                rename_map[t] = _new
                if _new not in all_dl:
                    all_dl.append(_new)
            _closure = _assess_etf_closure_risk(_info)
            if _closure is not None:
                ticker_closure_risk[t] = _closure
        except Exception:
            pass

    try:
        raw = _chunked_yf_download(" ".join(all_dl), period="1y", auto_adjust=True, progress=False, threads=False)
        if raw.empty:
            if cached:
                return jsonify(cached)
            return jsonify(ticker_grades=default_ticker_grades, portfolio_grade={}, ticker_closure_risk=ticker_closure_risk)
    except Exception as e:
        if cached:
            return jsonify(cached)
        return jsonify(ticker_grades=default_ticker_grades, portfolio_grade={}, ticker_closure_risk=ticker_closure_risk, warning=str(e))

    if isinstance(raw.columns, pd.MultiIndex):
        close = raw["Close"].dropna(how="all") if "Close" in raw.columns.get_level_values(0) else pd.DataFrame()
    else:
        close = raw[["Close"]].dropna(how="all") if "Close" in raw.columns else pd.DataFrame()
        if not close.empty:
            close.columns = [all_dl[0]]

    if close.empty:
        if cached:
            return jsonify(cached)
        return jsonify(ticker_grades=default_ticker_grades, portfolio_grade={})

    # Map renamed ticker columns back to original names
    for old_t, new_t in rename_map.items():
        if old_t not in close.columns and new_t in close.columns:
            close[old_t] = close[new_t]

    bench_close = close["SPY"] if "SPY" in close.columns else None
    bench_ret = bench_close.pct_change().dropna() if bench_close is not None else None
    benchmark_returns = {}
    for benchmark_key, benchmark_symbol in benchmark_symbols.items():
        benchmark_close = close[benchmark_symbol] if benchmark_symbol in close.columns else None
        benchmark_returns[benchmark_key] = benchmark_close.pct_change().dropna() if benchmark_close is not None else None
    benchmark_closes = [
        (symbol, close[symbol])
        for symbol in benchmark_symbols.values()
        if symbol in close.columns
    ]

    ticker_grades = {}
    ticker_risk = {}
    available = []

    def _blank_risk():
        return {"beta": None, "beta_benchmark": None, "delta_up": None, "delta_down": None}

    def _compute_ticker_metrics(t, tc):
        """Grade + best-fit beta/deltas for one ticker's close series.

        Returns True when the ticker priced well enough to grade (so it can join
        the portfolio-level regression), False otherwise. Always populates
        ticker_grades[t] and ticker_risk[t].
        """
        if tc is None or len(tc) < 30:
            ticker_grades[t] = {"grade": "N/A", "score": None}
            ticker_risk[t] = _blank_risk()
            return False
        try:
            tr = tc.pct_change().dropna()
            score, *_ = ticker_score(tc, tr, bench_ret)
            ticker_grades[t] = {"grade": letter_grade(score), "score": score}
            computed_beta, beta_benchmark = _best_fit_beta(tc, benchmark_closes)
            delta_up = delta_down = None
            if beta_benchmark:
                beta_close = dict(benchmark_closes).get(beta_benchmark)
                if beta_close is not None:
                    delta_up, delta_down = _capture_deltas(tc, beta_close)
            ticker_risk[t] = {
                "beta": computed_beta,
                "beta_benchmark": beta_benchmark,
                "delta_up": delta_up,
                "delta_down": delta_down,
            }
            return True
        except Exception:
            ticker_grades[t] = {"grade": "N/A", "score": None}
            ticker_risk[t] = _blank_risk()
            return False

    for t in tickers:
        tc = close[t].dropna() if t in close.columns else None
        if _compute_ticker_metrics(t, tc):
            available.append(t)

    # Recovery pass: yfinance silently drops the occasional single symbol from a
    # batch download, leaving that ticker with no price column and a blank
    # beta/delta row — which then gets cached for the full TTL even though the
    # rest of the portfolio graded fine. Re-fetch just the missing symbols
    # individually (rare, so cheap) and recompute before we build the response.
    missing = [t for t in tickers if t not in close.columns]
    for t in missing:
        try:
            r = _chunked_yf_download(t, period="1y", auto_adjust=True, progress=False, threads=False)
            if r is None or r.empty:
                continue
            if isinstance(r.columns, pd.MultiIndex):
                series = r["Close"].iloc[:, 0] if "Close" in r.columns.get_level_values(0) else None
            else:
                series = r["Close"] if "Close" in r.columns else None
            if series is None:
                continue
            series = pd.to_numeric(series, errors="coerce").dropna()
            if series.empty:
                continue
            close[t] = series
            if _compute_ticker_metrics(t, close[t].dropna()) and t not in available:
                available.append(t)
        except Exception:
            continue

    # Safety net: if a ticker still came back blank (re-fetch also failed, or it
    # genuinely lacks enough history right now), reuse the last cached good beta
    # row rather than reverting a previously-computed value to "—". Market betas
    # move slowly, so a slightly stale row beats a blank one.
    if cached:
        cached_risk = cached.get("ticker_risk", {}) or {}
        for t in tickers:
            if ticker_risk.get(t, {}).get("beta") is None:
                prev = cached_risk.get(t)
                if prev and prev.get("beta") is not None:
                    ticker_risk[t] = prev

    import numpy as np
    portfolio_grade_info = {}
    if len(available) >= 2:
        try:
            returns_df = close[available].pct_change().fillna(0)
            val_map = {r["ticker"]: float(r["current_value"] or 0) for r in rows}
            weights_arr = np.array([val_map.get(t, 0.0) for t in available])
            pm = grade_portfolio(returns_df, weights_arr, bench_ret)
            portfolio_grade_info = pm.get("grade", {})
            portfolio_grade_info["sharpe"] = pm.get("sharpe")
            portfolio_grade_info["sortino"] = pm.get("sortino")
            portfolio_grade_info["calmar"] = pm.get("calmar")
            portfolio_grade_info["omega"] = pm.get("omega")
            portfolio_grade_info["max_drawdown"] = pm.get("max_drawdown")
            portfolio_grade_info["ulcer_index"] = pm.get("ulcer_index")
            portfolio_grade_info["beta_sp500"] = pm.get("beta")
            portfolio_daily = returns_df.dot(weights_arr / weights_arr.sum()) if weights_arr.sum() > 0 else None
            benchmark_betas = {}
            if portfolio_daily is not None:
                for benchmark_key, benchmark_ret in benchmark_returns.items():
                    benchmark_betas[benchmark_key] = _beta(portfolio_daily, benchmark_ret) if benchmark_ret is not None else None
            portfolio_grade_info["beta_nasdaq"] = benchmark_betas.get("nasdaq")
            portfolio_grade_info["benchmark_betas"] = benchmark_betas
        except Exception:
            portfolio_grade_info = {}

    # A partial/empty yfinance download can leave portfolio_grade_info empty even
    # for a portfolio with plenty of holdings (e.g. fewer than 2 tickers came back
    # with enough history). Fall back to the last good grade for this profile/
    # ticker-set rather than blanking the dashboard tiles.
    if not portfolio_grade_info and cached:
        portfolio_grade_info = cached.get("portfolio_grade", {}) or {}

    response = {"ticker_grades": ticker_grades, "ticker_risk": ticker_risk, "portfolio_grade": portfolio_grade_info, "ticker_closure_risk": ticker_closure_risk}
    # Only cache a usable result. Caching an empty grade from a transient/partial
    # yfinance download would pin blank tiles for the full 30-min TTL, so the
    # grades would "stick" blank across account switches and chart refreshes until
    # the cache expired. A genuinely ungradeable portfolio (<2 priceable holdings)
    # is still cached so we don't re-download on every load.
    if portfolio_grade_info or len(tickers) < 2:
        _PORTFOLIO_SUMMARY_CACHE[cache_key] = (time.time(), response)
    return jsonify(response)


# ── Ticker Return Chart ───────────────────────────────────────────────────────

def _research_price_and_dividend_series(raw, dl_ticker):
    """Extract close and dividend Series from yfinance output, tolerating missing actions."""
    if isinstance(raw.columns, pd.MultiIndex):
        close_block = raw["Close"]
        close_col = close_block[dl_ticker] if dl_ticker in close_block.columns else close_block.iloc[:, 0]
        if "Dividends" in raw.columns.get_level_values(0):
            divs_block = raw["Dividends"]
            divs_col = divs_block[dl_ticker] if dl_ticker in divs_block.columns else divs_block.iloc[:, 0]
        else:
            divs_col = pd.Series(0.0, index=close_col.index)
    else:
        close_col = raw["Close"]
        divs_col = raw["Dividends"] if "Dividends" in raw.columns else pd.Series(0.0, index=close_col.index)

    if not isinstance(close_col, pd.Series):
        close_col = pd.Series(close_col) if hasattr(close_col, "__iter__") else pd.Series(dtype=float)
    else:
        close_col = close_col.squeeze()
        if not isinstance(close_col, pd.Series):
            close_col = pd.Series(dtype=float)

    if not isinstance(divs_col, pd.Series):
        divs_col = pd.Series(0.0, index=close_col.index)
    else:
        divs_col = divs_col.squeeze()
        if not isinstance(divs_col, pd.Series):
            divs_col = pd.Series(0.0, index=close_col.index)

    close_col = pd.to_numeric(close_col, errors="coerce").dropna()
    divs_col = pd.to_numeric(divs_col, errors="coerce").reindex(close_col.index, fill_value=0).fillna(0)
    return close_col, divs_col


@app.route("/api/ticker-return/<ticker>", methods=["GET"])
def ticker_return_chart(ticker):
    """Return price return % and total return % data since purchase date."""
    import warnings
    import yfinance as yf
    warnings.filterwarnings("ignore")

    profile_id = get_profile_id()
    ticker = ticker.strip().upper()
    conn = get_connection()
    row = conn.execute(
        "SELECT purchase_date, price_paid, description FROM all_account_info WHERE ticker = ? AND profile_id = ? AND purchase_value > 0",
        (ticker, profile_id),
    ).fetchone()
    txn_row = conn.execute(
        """SELECT transaction_date, price_per_share
           FROM transactions
           WHERE ticker = ? AND profile_id = ?
             AND transaction_type = 'BUY'
             AND shares > 0
             AND price_per_share > 0
           ORDER BY transaction_date ASC
           LIMIT 1""",
        (ticker, profile_id),
    ).fetchone()
    conn.close()

    if not row:
        return jsonify({"error": f"No data found for {ticker}"}), 404

    purchase_date = pd.to_datetime(row["purchase_date"])
    price_paid = float(row["price_paid"] or 0)
    description = row["description"] or ticker

    if pd.isna(purchase_date) and txn_row:
        purchase_date = pd.to_datetime(txn_row["transaction_date"])
        price_paid = float(txn_row["price_per_share"] or 0)
    if price_paid <= 0 and txn_row:
        price_paid = float(txn_row["price_per_share"] or 0)

    if pd.isna(purchase_date) or price_paid <= 0:
        return jsonify({"error": f"Missing purchase date or price for {ticker}"}), 404

    start_str = purchase_date.strftime("%Y-%m-%d")

    # Detect ticker rename (e.g. TOPW → WPAY)
    dl_ticker = ticker
    try:
        _info = yf.Ticker(ticker).info or {}
        _new_sym = (_info.get("symbol") or "").upper()
        if _new_sym and _new_sym != ticker:
            dl_ticker = _new_sym
    except Exception:
        pass

    try:
        raw = _chunked_yf_download(dl_ticker, start=start_str, progress=False, auto_adjust=False, actions=True)
    except Exception as e:
        return jsonify({"error": f"Yahoo Finance error for {ticker}: {str(e)}"}), 404

    if raw.empty:
        return jsonify({"error": f"No Yahoo Finance data for {ticker}"}), 404

    try:
        close_col, divs_col = _research_price_and_dividend_series(raw, dl_ticker)

        if len(close_col) < 2:
            return jsonify({"error": f"Not enough price history for {ticker}"}), 404

        cum_divs = divs_col.cumsum()

        price_return = ((close_col - price_paid) / price_paid * 100).round(2)
        total_return = ((close_col - price_paid + cum_divs) / price_paid * 100).round(2)

        return jsonify({
            "ticker": ticker,
            "description": description,
            "purchase_date": start_str,
            "price_paid": price_paid,
            "dates": close_col.index.strftime("%Y-%m-%d").tolist(),
            "price_return": price_return.tolist(),
            "total_return": total_return.tolist(),
        })
    except Exception as e:
        return jsonify({"error": f"Could not compute return data for {ticker}: {str(e)}"}), 500


@app.route("/api/ticker-return-1y/<ticker>", methods=["GET"])
def ticker_return_1y(ticker):
    """Return 1-year price return % and total return % for any ticker (no portfolio required)."""
    import warnings
    import yfinance as yf
    warnings.filterwarnings("ignore")

    ticker = ticker.strip().upper()
    start_date = (pd.Timestamp.now() - pd.DateOffset(years=1)).strftime("%Y-%m-%d")

    dl_ticker = _yahoo_symbol_for_ticker(ticker)
    description = ticker
    try:
        _info = yf.Ticker(dl_ticker).info or {}
        description = _info.get("longName") or _info.get("shortName") or ticker
        _new_sym = (_info.get("symbol") or "").upper()
        if _new_sym and _new_sym != dl_ticker:
            dl_ticker = _new_sym
    except Exception:
        pass

    try:
        raw = _chunked_yf_download(dl_ticker, start=start_date, progress=False, auto_adjust=False, actions=True)
    except Exception as e:
        return jsonify({"error": f"Yahoo Finance error for {ticker}: {str(e)}"}), 404

    if raw.empty:
        return jsonify({"error": f"No Yahoo Finance data for {ticker}"}), 404

    try:
        close_col, divs_col = _research_price_and_dividend_series(raw, dl_ticker)

        if len(close_col) < 2:
            return jsonify({"error": f"Not enough price history for {ticker}"}), 404

        start_price = float(close_col.iloc[0])
        if start_price <= 0:
            return jsonify({"error": f"Invalid start price for {ticker}"}), 404

        cum_divs = divs_col.cumsum()
        price_return = ((close_col - start_price) / start_price * 100).round(2)
        total_return = ((close_col - start_price + cum_divs) / start_price * 100).round(2)

        return jsonify({
            "ticker": dl_ticker,
            "requested_ticker": ticker,
            "description": description,
            "start_price": round(start_price, 2),
            "dates": close_col.index.strftime("%Y-%m-%d").tolist(),
            "price_return": price_return.tolist(),
            "total_return": total_return.tolist(),
        })
    except Exception as e:
        return jsonify({"error": f"Could not compute return data for {ticker}: {str(e)}"}), 500


@app.route("/api/ticker-return-1y-bulk", methods=["GET"])
def ticker_return_1y_bulk():
    """Return the last 1-year total return % for a list of tickers in one call."""
    import warnings
    import yfinance as yf
    warnings.filterwarnings("ignore")

    tickers_param = request.args.get("tickers", "")
    tickers = [t.strip().upper() for t in tickers_param.split(",") if t.strip()]
    if not tickers:
        return jsonify({})

    start_date = (pd.Timestamp.now() - pd.DateOffset(years=1)).strftime("%Y-%m-%d")

    # Map each portfolio ticker to its Yahoo download symbol
    dl_map = {t: _yahoo_symbol_for_ticker(t) for t in tickers}
    dl_symbols = list(set(dl_map.values()))

    try:
        raw = _chunked_yf_download(dl_symbols, start=start_date,
                                   auto_adjust=False, actions=True, group_by="ticker")
    except Exception as e:
        return jsonify({"error": str(e)}), 500

    result = {}
    for ticker, dl_ticker in dl_map.items():
        try:
            if len(dl_symbols) == 1:
                ticker_raw = raw
            else:
                if dl_ticker not in raw.columns.get_level_values(0):
                    continue
                ticker_raw = raw[dl_ticker]

            close_col, divs_col = _research_price_and_dividend_series(ticker_raw, dl_ticker)
            if len(close_col) < 2:
                continue
            start_price = float(close_col.iloc[0])
            if start_price <= 0:
                continue
            cum_divs = divs_col.cumsum()
            total_ret = float((close_col.iloc[-1] - start_price + cum_divs.iloc[-1]) / start_price * 100)
            result[ticker] = round(total_ret, 2)
        except Exception:
            pass

    return jsonify(result)


def _research_clean_value(value):
    if value is None:
        return None
    try:
        if pd.isna(value):
            return None
    except Exception:
        pass
    if isinstance(value, (int, float)):
        if math.isnan(float(value)) or math.isinf(float(value)):
            return None
        return float(value)
    if hasattr(value, "item"):
        try:
            return _research_clean_value(value.item())
        except Exception:
            pass
    return value


def _research_info_value(info, *keys):
    for key in keys:
        value = _research_clean_value(info.get(key))
        if value not in (None, ""):
            return value
    return None


def _research_pct(value):
    value = _research_clean_value(value)
    if value is None:
        return None
    if isinstance(value, str):
        is_percent = "%" in value
        clean = re.sub(r"[^0-9.\-]", "", value)
        if not clean:
            return None
        if is_percent:
            return round(float(clean), 2)
        value = clean
    value = float(value)
    return round(value * 100, 2) if abs(value) <= 1 else round(value, 2)


def _research_money(value):
    value = _research_clean_value(value)
    if value is None:
        return None
    return round(float(value), 2)


def _research_expense_pct(*values):
    for value in values:
        value = _research_clean_value(value)
        if value is None:
            continue
        if isinstance(value, str):
            if "%" in value:
                return _research_pct(value)
            value = re.sub(r"[^0-9.\-]", "", value)
            if not value:
                continue
        value = float(value)
        return round(value * 100, 2) if abs(value) < 0.02 else round(value, 2)
    return None


def _research_dividend_frequency(dividends):
    if dividends is None or dividends.empty:
        return None
    divs = dividends[dividends > 0].dropna()
    if divs.empty:
        return None
    recent = divs[divs.index >= (divs.index.max() - pd.DateOffset(months=18))]
    count = len(recent) if len(recent) else len(divs.tail(12))
    if count >= 40:
        return "Weekly"
    if count >= 10:
        return "Monthly"
    if count >= 5:
        return "Quarterly/Monthly"
    if count >= 3:
        return "Quarterly"
    if count >= 2:
        return "Semiannual"
    return "Annual/Irregular"


def _fetch_neos_top_holdings(ticker, limit=25):
    """Fetch the full NEOS holdings CSV and keep the top securities rows."""
    import csv
    import requests
    from io import StringIO

    ticker = (ticker or "").strip().upper()
    if not ticker:
        return []

    url = f"https://neosfunds.com/wp-admin/admin-ajax.php?action=download_holdings_csv&ticker={ticker}"
    try:
        resp = requests.get(url, timeout=15, headers={"User-Agent": "PortfolioTrackingClient/1.0"})
        resp.raise_for_status()
    except Exception:
        return []

    try:
        reader = csv.DictReader(StringIO(resp.text or ""))
    except Exception:
        return []

    rows = []
    for row in reader:
        symbol = (row.get("StockTicker") or "").strip()
        name = (row.get("SecurityName") or "").strip()
        if not symbol or symbol.lower() in {"cash&other", "cash"}:
            continue
        if name.lower() in {"cash & other", "cash and other"}:
            continue
        try:
            weight = round(float((row.get("Weightings") or "").replace("%", "").strip()), 2)
        except Exception:
            weight = None
        rows.append({
            "symbol": symbol,
            "name": name or symbol,
            "weight_pct": weight,
        })
        if len(rows) >= limit:
            break
    return rows


def _income_blast_number(value):
    text = str(value or "").strip()
    if not text or text.lower() in {"null", "nan", "n/a", "--", "-"}:
        return None
    text = re.sub(r"[^0-9.\-]", "", text)
    if not text:
        return None
    try:
        return float(text)
    except Exception:
        return None


def _income_blast_page(ticker):
    import requests

    ticker = (ticker or "").strip().lower()
    if not ticker:
        return "", None

    url = f"https://www.incomeblastetfs.com/etf/{ticker}"
    try:
        resp = requests.get(url, timeout=15, headers={"User-Agent": "Mozilla/5.0 PortfolioTrackingClient/1.0"})
        if resp.status_code == 404:
            return "", url
        resp.raise_for_status()
        return resp.text or "", url
    except Exception:
        return "", url


def _income_blast_csv_url(html_text):
    import html as html_lib

    if not html_text:
        return None
    match = re.search(
        r"https://docs\.google\.com/spreadsheets/export\?[^\"'<> ]*exportFormat=csv[^\"'<> ]*",
        html_text,
        flags=re.I,
    )
    if match:
        return html_lib.unescape(match.group(0))
    match = re.search(r'href=["\']([^"\']*docs\.google\.com/spreadsheets/export[^"\']*)["\']', html_text, flags=re.I)
    return html_lib.unescape(match.group(1)) if match else None


def _fetch_income_blast_csv_holdings(csv_url, limit=25):
    import csv
    import requests
    from io import StringIO

    if not csv_url:
        return []
    try:
        resp = requests.get(csv_url, timeout=20, headers={"User-Agent": "Mozilla/5.0 PortfolioTrackingClient/1.0"})
        resp.raise_for_status()
    except Exception:
        return []

    try:
        reader = csv.DictReader(StringIO(resp.text or ""))
    except Exception:
        return []

    rows = []
    for row in reader:
        symbol = (row.get("Stock Ticker") or row.get("Ticker") or row.get("CUSIP") or "").strip()
        name = (row.get("Security Name") or row.get("Security Description") or "").strip()
        if not symbol and not name:
            continue
        weight = _income_blast_number(row.get("Weightings") or row.get("% of Funds") or row.get("Weight"))
        rows.append({
            "symbol": symbol or name,
            "name": name or symbol,
            "weight_pct": round(weight, 2) if weight is not None else None,
        })

    rows.sort(key=lambda r: (r["weight_pct"] is not None, r["weight_pct"] or -999999), reverse=True)
    return rows[:limit]


def _income_blast_text_from_html(html_text):
    import html as html_lib

    text = re.sub(r"(?is)<(script|style).*?</\1>", " ", html_text or "")
    text = re.sub(r"(?i)<br\s*/?>", "\n", text)
    text = re.sub(r"(?i)</(p|div|li|tr|td|th|h[1-6]|section|a)>", "\n", text)
    text = re.sub(r"(?s)<[^>]+>", " ", text)
    text = html_lib.unescape(text)
    lines = [re.sub(r"\s+", " ", line).strip() for line in text.splitlines()]
    return "\n".join(line for line in lines if line)


def _fetch_income_blast_table_holdings(html_text, limit=25):
    text = _income_blast_text_from_html(html_text)
    section = _vistashares_section(
        text,
        r"Holdings\s+As of:.*?Ticker\s+Security Description\s+CUSIP / ISIN\s+% of Funds\s+Shares\s+Market Value\s+(.*?)\s+Fund holdings and allocations",
    )
    if not section:
        return []

    lines = [line.strip() for line in section.splitlines() if line.strip()]
    rows = []
    i = 0
    while i + 5 < len(lines):
        symbol, name, _cusip, weight_text, _shares, _market_value = lines[i:i + 6]
        weight = _income_blast_number(weight_text)
        if symbol and name and weight is not None:
            rows.append({
                "symbol": symbol,
                "name": name,
                "weight_pct": round(weight, 2),
            })
            i += 6
        else:
            i += 1

    rows.sort(key=lambda r: (r["weight_pct"] is not None, r["weight_pct"] or -999999), reverse=True)
    return rows[:limit]


def _fetch_income_blast_top_holdings(ticker, limit=25):
    """Fetch Tuttle Capital Income Blast holdings from the official fund page."""
    html_text, _url = _income_blast_page(ticker)
    if not html_text:
        return []

    rows = _fetch_income_blast_csv_holdings(_income_blast_csv_url(html_text), limit=limit)
    if rows:
        return rows
    return _fetch_income_blast_table_holdings(html_text, limit=limit)


# Distributions table token: an issuer date ("Jul 2, 2026") or a per-share amount.
_INCOME_BLAST_DIST_TOKEN_RE = re.compile(
    r"(?P<date>[A-Z][a-z]{2}\s+\d{1,2},\s+\d{4})|(?P<amt>\d+\.\d{2,6})"
)


def _fetch_income_blast_distribution_snapshot(ticker):
    """Fetch official Tuttle Capital distribution data from incomeblastetfs.com.

    Each fund page publishes a Distributions table with Declaration / Record /
    Ex-Date / Pay Date / Amount columns.  Parsing the declared rows lets the
    dashboard dividend calendar use the issuer's real ex/pay dates and amount
    instead of a Yahoo-based estimate, which mis-dates the weekly pay by weeks.
    Returns None so callers transparently fall back to Yahoo when the page is
    unavailable or its layout has changed.
    """
    ticker = (ticker or "").strip().upper()
    if not ticker:
        return None

    html_text, _url = _income_blast_page(ticker)
    if not html_text:
        return None

    text = _income_blast_text_from_html(html_text)
    if not _is_tuttle_capital_fund(ticker, text):
        return None

    header = re.search(r"Ex-Date\s*\n\s*Pay Date\s*\n\s*Amount\b", text, re.S)
    if not header:
        return None

    rest = text[header.end():]
    tail = re.search(
        r"(The Fund currently expects|Distributions include a return of capital|\nHoldings\b)",
        rest,
        re.S,
    )
    region = rest[: tail.start()] if tail else rest

    # Distribution frequency straight from the issuer's distribution-policy text.
    freq = None
    disc = rest.lower()
    if "weekly basis" in disc or "on a weekly" in disc:
        freq = "W"
    elif "monthly basis" in disc or "on a monthly" in disc:
        freq = "M"
    elif "quarterly basis" in disc or "on a quarterly" in disc:
        freq = "Q"

    # Each declared row is 4 dates (Declaration, Record, Ex, Pay) then the amount.
    rows = []
    dates = []
    for match in _INCOME_BLAST_DIST_TOKEN_RE.finditer(region):
        if match.group("date"):
            ts = pd.to_datetime(match.group("date"), format="%b %d, %Y", errors="coerce")
            if pd.isna(ts):
                continue
            dates.append(ts.normalize())
            if len(dates) > 4:
                dates = dates[-4:]
        else:
            if len(dates) >= 4:
                _decl, _record, ex_ts, pay_ts = dates[-4:]
                rows.append((ex_ts, float(match.group("amt")), pay_ts))
            dates = []

    if not rows:
        return None

    rows.sort(key=lambda item: item[0])
    history = pd.Series(
        [amount for _ex, amount, _pay in rows],
        index=pd.DatetimeIndex([ex for ex, _amount, _pay in rows]),
    )
    history = history[~history.index.duplicated(keep="last")].sort_index()
    pay_map = {ex.normalize(): pay for ex, _amount, pay in rows}

    # Median declared ex->pay lag so projected (future) pay dates follow the
    # fund's real cadence (e.g. DRMP pays the Monday after a Thu/Fri ex-date)
    # instead of the generic "next business day" weekly assumption.
    lags = sorted(
        int((pay.normalize() - ex.normalize()).days)
        for ex, _amount, pay in rows
        if pay is not None and pay.normalize() >= ex.normalize()
        and 0 <= int((pay.normalize() - ex.normalize()).days) <= 14
    )
    pay_lag_days = None
    if lags:
        mid = len(lags) // 2
        pay_lag_days = lags[mid] if len(lags) % 2 else round((lags[mid - 1] + lags[mid]) / 2)

    # Surface the nearest upcoming declared row when one exists, else the latest.
    today = pd.Timestamp.now().normalize()
    chosen_ex = history.index[-1]
    upcoming = sorted(ex for ex in history.index if ex >= today)
    if upcoming:
        chosen_ex = upcoming[0]
    chosen_pay = pay_map.get(chosen_ex.normalize())

    if not freq:
        freq = _infer_dividend_frequency_from_history(history)

    return {
        "known": True,
        "has_dividend": True,
        "div": float(history.loc[chosen_ex]),
        "ex_div_date": chosen_ex.strftime("%m/%d/%y"),
        "div_pay_date": chosen_pay.strftime("%m/%d/%y") if chosen_pay is not None else None,
        "freq": freq or "W",
        "history": history,
        "pay_lag_days": pay_lag_days,
        "source": "Income Blast (Tuttle Capital)",
    }


def _strip_html_text(value):
    import html
    import re

    text = re.sub(r"(?s)<!--.*?-->", "", str(value or ""))
    text = re.sub(r"(?s)<[^>]+>", "", text)
    return html.unescape(re.sub(r"\s+", " ", text)).strip()


def _fetch_stockanalysis_top_holdings(ticker, limit=25):
    """Fetch the free Top 25 holdings table exposed on StockAnalysis ETF pages."""
    import re
    import requests

    ticker = (ticker or "").strip().lower()
    if not ticker:
        return []

    url = f"https://stockanalysis.com/etf/{ticker}/holdings/"
    try:
        resp = requests.get(url, timeout=15, headers={"User-Agent": "PortfolioTrackingClient/1.0"})
        if resp.status_code == 404:
            # CEFs live under /stocks/ on StockAnalysis, not /etf/
            alt_url = f"https://stockanalysis.com/stocks/{ticker}/holdings/"
            try:
                resp = requests.get(alt_url, timeout=15, headers={"User-Agent": "PortfolioTrackingClient/1.0"})
                if resp.status_code != 200:
                    return []
            except Exception:
                return []
        else:
            resp.raise_for_status()
    except Exception:
        return []

    html = resp.text or ""
    start = html.lower().find("top 25 holdings")
    if start >= 0:
        html = html[start:]

    rows = []
    for row_html in re.findall(r"(?is)<tr[^>]*>(.*?)</tr>", html):
        cells = re.findall(r"(?is)<td[^>]*>(.*?)</td>", row_html)
        if len(cells) < 4:
            continue

        rank = _strip_html_text(cells[0])
        symbol = _strip_html_text(cells[1])
        name = _strip_html_text(cells[2])
        weight_text = _strip_html_text(cells[3])

        if not rank.isdigit() or not symbol or symbol.lower() == "symbol":
            continue
        if not weight_text.endswith("%"):
            continue
        try:
            weight = round(float(weight_text.replace("%", "").replace(",", "").strip()), 2)
        except Exception:
            weight = None

        rows.append({
            "symbol": symbol,
            "name": name or symbol,
            "weight_pct": weight,
        })
        if len(rows) >= limit:
            break
    return rows


def _fetch_cefconnect_top_holdings(ticker, limit=25):
    """Fetch top holdings for a CEF from CEF Connect's fund page HTML."""
    if not ticker:
        return []
    sym = ticker.strip().upper()
    try:
        html = _cefconnect_text(f"/fund/{urllib.parse.quote(sym)}", f"fund-html:{sym}")
    except Exception:
        return []
    if not html:
        return []
    holding_rows = _cef_extract_table(html, "ucPortChar_TopHoldingsGrid")
    # First row is often the header
    if holding_rows and len(holding_rows[0]) >= 3 and not holding_rows[0][2].replace(".", "").replace("%", "").strip().lstrip("-").isdigit():
        holding_rows = holding_rows[1:]
    rows = []
    for row in holding_rows[:limit]:
        if len(row) < 2:
            continue
        name = row[0].strip()
        pct_text = row[-1].strip().replace("%", "").replace(",", "")
        try:
            weight = round(float(pct_text), 2)
        except Exception:
            weight = None
        if not name:
            continue
        rows.append({"symbol": "", "name": name, "weight_pct": weight})
    return rows


def _research_top_holdings(fund_data, limit=25, ticker=None, description=""):
    if _is_tuttle_capital_fund(ticker, description):
        income_blast_rows = _fetch_income_blast_top_holdings(ticker, limit=limit)
        if income_blast_rows:
            return income_blast_rows

    if _is_neos_fund(ticker, description):
        neos_rows = _fetch_neos_top_holdings(ticker, limit=limit)
        if neos_rows:
            return neos_rows

    stockanalysis_rows = _fetch_stockanalysis_top_holdings(ticker, limit=limit)
    if len(stockanalysis_rows) >= 5:
        return stockanalysis_rows

    cefconnect_rows = _fetch_cefconnect_top_holdings(ticker, limit=limit)
    if len(cefconnect_rows) >= 3:
        return cefconnect_rows

    try:
        holdings = fund_data.top_holdings
    except Exception:
        return stockanalysis_rows
    if holdings is None or holdings.empty:
        return stockanalysis_rows

    rows = []
    for symbol, row in holdings.head(limit).iterrows():
        percent = _research_clean_value(row.get("Holding Percent"))
        rows.append({
            "symbol": str(symbol) if symbol is not None else "",
            "name": row.get("Name") or str(symbol),
            "weight_pct": round(float(percent) * 100, 2) if percent is not None and abs(float(percent)) <= 1 else _research_pct(percent),
        })
    return stockanalysis_rows if len(stockanalysis_rows) > len(rows) else rows


def _research_weight_map(value):
    if not isinstance(value, dict):
        return []
    rows = []
    for key, weight in value.items():
        clean = _research_clean_value(weight)
        if clean is None:
            continue
        label = str(key).replace("_", " ").replace("-", " ").title()
        rows.append({"name": label, "weight_pct": round(float(clean) * 100, 2)})
    return sorted(rows, key=lambda r: r["weight_pct"], reverse=True)


def _research_adjusted_close_series(ticker, force_refresh=False):
    """Load a split/dividend-adjusted close series for a single ticker."""
    import warnings
    import yfinance as yf

    warnings.filterwarnings("ignore")

    symbol = (ticker or "").strip().upper()
    if not symbol:
        return None, symbol

    if not force_refresh:
        cached = _cache_get(
            _RESEARCH_RETURN_SERIES_CACHE,
            symbol,
            _RESEARCH_RETURN_SERIES_TTL_SEC,
        )
        if cached is not None:
            return cached

    dl_symbol = _yahoo_symbol_for_ticker(symbol)
    description = symbol
    try:
        yf_ticker = yf.Ticker(dl_symbol)
        info = _cached_yf_info(yf_ticker, dl_symbol)
        description = info.get("longName") or info.get("shortName") or info.get("displayName") or symbol
        info_symbol = (info.get("symbol") or "").upper()
        if info_symbol and info_symbol != dl_symbol:
            dl_symbol = info_symbol
    except Exception:
        pass

    try:
        raw = _chunked_yf_download(dl_symbol, period="max", auto_adjust=True, progress=False)
    except Exception:
        return None, description

    if raw is None or raw.empty:
        return None, description

    try:
        if isinstance(raw.columns, pd.MultiIndex):
            close = raw["Close"]
            if dl_symbol in close.columns:
                series = close[dl_symbol]
            else:
                series = close.iloc[:, 0]
        else:
            series = raw["Close"]
    except Exception:
        return None, description

    if not isinstance(series, pd.Series):
        series = pd.Series(series)
    series = series.dropna()
    series.index = pd.to_datetime(series.index)
    result = (series, description)
    _cache_set(_RESEARCH_RETURN_SERIES_CACHE, symbol, result)
    return result


def _research_window_return(series, start_dt, annualize=False):
    if series is None or series.empty:
        return None
    window = series.loc[series.index >= pd.Timestamp(start_dt)].dropna()
    if len(window) < 2:
        return None
    base = float(window.iloc[0])
    if base <= 0:
        return None
    end_value = float(window.iloc[-1])
    if annualize:
        elapsed_days = max((window.index[-1] - window.index[0]).days, 0)
        years = elapsed_days / 365.25
        if years <= 0:
            return None
        value = float(((end_value / base) ** (1 / years) - 1) * 100)
    else:
        value = float((end_value / base - 1) * 100)
    if math.isnan(value) or math.isinf(value):
        return None
    return round(value, 2)


def _research_period_return_rows(series, benchmark_series):
    if series is None or series.empty:
        return []

    end_dt = series.index.max()
    windows = [
        ("1 Month", pd.DateOffset(months=1)),
        ("YTD", "ytd"),
        ("1 Year", pd.DateOffset(years=1)),
        ("5 Years", pd.DateOffset(years=5)),
        ("10 Years", pd.DateOffset(years=10)),
        ("Inception", "inception"),
    ]

    primary_inception = series.index.min()
    has_benchmark = benchmark_series is not None and not benchmark_series.empty
    benchmark_inception = benchmark_series.index.min() if has_benchmark else None

    # Use the later inception so both series cover the same comparison window
    common_inception = primary_inception
    if benchmark_inception is not None and benchmark_inception > common_inception:
        common_inception = benchmark_inception

    rows = []
    for label, offset in windows:
        if offset == "inception":
            start_dt = common_inception
        elif offset == "ytd":
            start_dt = pd.Timestamp(year=end_dt.year, month=1, day=1)
        else:
            start_dt = end_dt - offset

        if offset not in ("inception", "ytd") and start_dt < common_inception:
            rows.append({"label": label, "ticker_return": None, "benchmark_return": None})
        else:
            rows.append({
                "label": label,
                "ticker_return": _research_window_return(series, start_dt),
                "benchmark_return": _research_window_return(benchmark_series, start_dt) if has_benchmark else None,
            })
    return rows


def _research_multi_period_return_rows(series_by_symbol, common_window=True, include_inception=True, include_stock_long_windows=False, annualize_long_windows=False):
    valid_series = {
        symbol: series
        for symbol, series in series_by_symbol.items()
        if series is not None and not series.empty
    }
    if not valid_series:
        return []

    windows = [
        ("1 Month", pd.DateOffset(months=1)),
        ("YTD", "ytd"),
        ("1 Year", pd.DateOffset(years=1)),
        ("5 Years", pd.DateOffset(years=5)),
        ("10 Years", pd.DateOffset(years=10)),
    ]
    if include_stock_long_windows:
        windows.extend([
            ("15 Years", pd.DateOffset(years=15)),
            ("20 Years", pd.DateOffset(years=20)),
        ])
    if include_inception:
        windows.append(("Inception", "inception"))

    rows = []
    if common_window:
        end_dt = min(series.index.max() for series in valid_series.values())
        common_inception = max(series.index.min() for series in valid_series.values())

        for label, offset in windows:
            if offset == "inception":
                start_dt = common_inception
            elif offset == "ytd":
                start_dt = pd.Timestamp(year=end_dt.year, month=1, day=1)
            else:
                start_dt = end_dt - offset

            if offset != "inception" and start_dt < common_inception:
                returns = {symbol: None for symbol in valid_series}
            else:
                annualize = annualize_long_windows and label not in ("1 Month", "YTD")
                returns = {
                    symbol: _research_window_return(series.loc[series.index <= end_dt], start_dt, annualize=annualize)
                    for symbol, series in valid_series.items()
                }
            rows.append({"label": label, "returns": returns})
        return rows

    for label, offset in windows:
        returns = {}
        for symbol, series in valid_series.items():
            end_dt = series.index.max()
            inception = series.index.min()
            if offset == "inception":
                start_dt = inception
            elif offset == "ytd":
                start_dt = pd.Timestamp(year=end_dt.year, month=1, day=1)
            else:
                start_dt = end_dt - offset

            if offset != "inception" and start_dt < inception:
                returns[symbol] = None
            else:
                annualize = annualize_long_windows and label not in ("1 Month", "YTD")
                returns[symbol] = _research_window_return(series.loc[series.index <= end_dt], start_dt, annualize=annualize)
        rows.append({"label": label, "returns": returns})
    return rows


def _research_multi_return_summary(symbols, rows):
    one_year = next((row for row in rows if row["label"] == "1 Year"), None)
    ranked = [
        (symbol, one_year["returns"].get(symbol))
        for symbol in symbols
        if one_year and one_year.get("returns", {}).get(symbol) is not None
    ]
    if not ranked:
        return None

    ranked.sort(key=lambda item: item[1], reverse=True)
    best_symbol, best_return = ranked[0]
    if len(ranked) == 1:
        return f"In the past year, {best_symbol} returned a total of {best_return:.2f}%."

    last_symbol, last_return = ranked[-1]
    return (
        f"In the past year, {best_symbol} had the highest total return at {best_return:.2f}%, "
        f"compared with {last_symbol}'s {last_return:.2f}%."
    )


def _research_approx_yield(ticker):
    """Estimate annualized yield from the last 3 months of distributions (1 month fallback)."""
    try:
        import yfinance as yf
        import datetime
        t = yf.Ticker(ticker)
        divs = t.dividends
        if divs is None or divs.empty:
            return None
        divs = divs[divs > 0].dropna()
        if divs.empty:
            return None
        divs.index = divs.index.tz_localize(None) if divs.index.tz else divs.index
        cutoff_3m = datetime.datetime.now() - datetime.timedelta(days=92)
        cutoff_1m = datetime.datetime.now() - datetime.timedelta(days=31)
        recent_3m = divs[divs.index >= cutoff_3m]
        recent_1m = divs[divs.index >= cutoff_1m]
        price = None
        info = t.fast_info
        try:
            price = float(info.last_price)
        except Exception:
            pass
        if not price or price <= 0:
            return None
        if not recent_3m.empty:
            annualized = float(recent_3m.sum()) * 4
            months_used = 3
        elif not recent_1m.empty:
            annualized = float(recent_1m.sum()) * 12
            months_used = 1
        else:
            return None
        return {"yield_pct": round(annualized / price * 100, 2), "months_used": months_used}
    except Exception:
        return None


def _research_return_summary(ticker, benchmark, rows, yield_info=None):
    one_year = next((row for row in rows if row["label"] == "1 Year"), None)
    if one_year and one_year["ticker_return"] is not None:
        period_label = "In the past year"
        t_ret = one_year["ticker_return"]
        b_ret = one_year.get("benchmark_return")
    else:
        inception = next((row for row in rows if row["label"] == "Inception"), None)
        if not inception or inception["ticker_return"] is None:
            return None
        period_label = "Since inception"
        t_ret = inception["ticker_return"]
        b_ret = inception.get("benchmark_return")

    yield_suffix = ""
    if yield_info:
        yield_suffix = f" with an approximate yield of {yield_info['yield_pct']:.2f}%"

    if b_ret is None:
        return f"{period_label}, {ticker} returned a total of {t_ret:.2f}%{yield_suffix}."

    diff = t_ret - b_ret
    if abs(diff) < 0.25:
        relation = "roughly matched"
    elif diff > 0:
        relation = "slightly higher than" if diff < 2 else "higher than"
    else:
        relation = "slightly lower than" if diff > -2 else "lower than"

    return (
        f"{period_label}, {ticker} returned a total of {t_ret:.2f}%, "
        f"which is {relation} {benchmark}'s {b_ret:.2f}% return{yield_suffix}."
    )


_KNOWN_FUND_ISSUERS = (
    "iShares", "BlackRock", "Vanguard", "Schwab", "SPDR", "State Street",
    "Invesco", "JPMorgan", "JP Morgan", "Fidelity", "Goldman Sachs", "PIMCO",
    "First Trust", "Eaton Vance", "Nuveen", "Cohen & Steers", "Calamos",
    "Allspring", "T. Rowe Price", "Franklin", "WisdomTree", "Direxion",
    "ProShares", "Global X", "Hartford", "Putnam", "Neuberger Berman",
    "Tortoise", "DoubleLine", "Western Asset", "Guggenheim", "Virtus",
    "Wells Fargo", "Aberdeen", "Gabelli", "Royce", "Tri-Continental",
    "John Hancock", "MFS", "BNY Mellon", "DWS", "Pioneer", "Voya",
    "Columbia", "Lazard", "Pacer", "Roundhill", "YieldMax", "REX",
    "Defiance", "Innovator", "Amplify", "Simplify", "KraneShares", "VistaShares",
)


def _derive_issuer(info, name):
    family = _research_info_value(info, "fundFamily")
    if family:
        return family
    name_l = (name or "").lower()
    for issuer in _KNOWN_FUND_ISSUERS:
        if issuer.lower() in name_l:
            return issuer
    return None


def _derive_legal_type(quote_type, summary, fund_overview, type_disp, name=None, industry=None):
    overview_legal = (fund_overview or {}).get("legalType") if isinstance(fund_overview, dict) else None
    if overview_legal:
        return overview_legal
    summary_l = (summary or "").lower()
    name_l = (name or "").lower()
    industry_l = (industry or "").lower()
    if "business development company" in summary_l or " bdc" in summary_l or name_l.endswith(" bdc"):
        return "Business Development Company"
    if "closed ended" in summary_l or "closed-end fund" in summary_l or "closed end fund" in summary_l:
        return "Closed-End Fund"
    if "reit" in industry_l or "real estate investment trust" in summary_l or "reit" in summary_l.split() or " reit " in f" {summary_l} ":
        return "Real Estate Investment Trust"
    if quote_type == "ETF":
        return "Exchange Traded Fund"
    if quote_type == "MUTUALFUND":
        return "Mutual Fund"
    if "exchange traded fund" in summary_l or "exchange-traded fund" in summary_l:
        return "Exchange Traded Fund"
    if "open ended" in summary_l or "open-end mutual fund" in summary_l:
        return "Mutual Fund"
    return type_disp or None


def _derive_fund_type(legal_type, quote_type):
    if legal_type:
        if "Business Development" in legal_type:
            return "BDC"
        if "Closed" in legal_type:
            return "CEF"
        if "Real Estate" in legal_type:
            return "REIT"
        if "Exchange" in legal_type or legal_type == "ETF":
            return "ETF"
        if "Mutual" in legal_type:
            return "Mutual Fund"
    if quote_type == "ETF":
        return "ETF"
    if quote_type == "MUTUALFUND":
        return "Mutual Fund"
    return "Fund"


def _vistashares_page_text(ticker):
    try:
        from html import unescape
        from urllib.request import Request, urlopen
        url = f"https://www.vistashares.com/etf/{ticker.lower()}/"
        req = Request(url, headers={"User-Agent": "PortfolioTrackingClient/1.0"})
        with urlopen(req, timeout=12) as resp:
            html = resp.read().decode("utf-8", errors="ignore")
        html = re.sub(r"(?is)<(script|style).*?</\1>", " ", html)
        html = re.sub(r"(?i)<br\s*/?>", "\n", html)
        html = re.sub(r"(?i)</(p|div|li|tr|td|th|h[1-6]|section)>", "\n", html)
        text = re.sub(r"(?s)<[^>]+>", " ", html)
        text = unescape(text)
        lines = [re.sub(r"\s+", " ", line).strip() for line in text.splitlines()]
        return "\n".join(line for line in lines if line), url
    except Exception:
        return "", None


def _vistashares_match(text, pattern, flags=re.I | re.S):
    m = re.search(pattern, text, flags)
    return re.sub(r"\s+", " ", m.group(1)).strip() if m else None


def _vistashares_section(text, pattern, flags=re.I | re.S):
    m = re.search(pattern, text, flags)
    return m.group(1).strip() if m else None


def _vistashares_money(value):
    if not value:
        return None
    clean = re.sub(r"[^0-9.\-]", "", value)
    try:
        return round(float(clean), 2)
    except Exception:
        return None


def _fetch_vistashares_etf_profile(ticker):
    text, url = _vistashares_page_text(ticker)
    if not text or "VistaShares" not in text:
        return None

    summary = _vistashares_match(text, r"ETF Summary\s+(.*?)\s+ETF Objective")
    objective = _vistashares_match(text, r"ETF Objective\s+(.*?)\s+Key Information")
    description = " ".join(part for part in [summary, objective] if part)
    title = _vistashares_match(text, rf"#{re.escape(ticker)}\s+###\s+(.*?)\s+Factsheet")

    key_info = {}
    for label in ("Inception Date", "Expense Ratio", "Net Assets", "NAV", "Distribution Frequency"):
        value = _vistashares_match(
            text,
            rf"{re.escape(label)}\s+(.+?)(?=\s+(?:Inception Date|Expense Ratio|Net Assets|NAV|Distribution Frequency|Trading Details)\b)"
        )
        if value:
            key_info[label] = value

    dist_rate = _vistashares_match(text, r"Distribution Rate\s+.*?([0-9.]+%)\s+30-Day SEC Yield")
    if not dist_rate:
        dist_rate = _vistashares_match(text, r"Distribution Rate\s+([0-9.]+%)")
    sec_yield = _vistashares_match(text, r"30-Day SEC Yield\s+.*?(-?[0-9.]+%)\s+As of")

    holdings = []
    holdings_section = _vistashares_section(text, r"Top 10 Holdings\s+.*?Ticker\s+Market Value\s+Weightings\s+(.*?)\s+Swipe to view more")
    if holdings_section:
        lines = [line.strip() for line in holdings_section.splitlines() if line.strip()]
        i = 0
        while i + 3 < len(lines):
            name_symbol, symbol, market_value, weight = lines[i:i + 4]
            if re.match(r"^[A-Z][A-Z0-9.-]{0,8}$", symbol) and market_value.startswith("$") and weight.endswith("%"):
                name = re.sub(rf"\s+{re.escape(symbol)}$", "", name_symbol).strip()
                try:
                    holdings.append({
                        "symbol": symbol,
                        "name": name or name_symbol,
                        "weight_pct": round(float(weight.replace("%", "").strip()), 2),
                    })
                except Exception:
                    pass
                i += 4
            else:
                i += 1

    exposure = []
    exposure_section = _vistashares_section(text, r"Exposure\s+.*?Industry\s+Sector\s+Country\s+MCap\s+(.*?)\s+ETF Documents")
    if exposure_section:
        exp_lines = [line.strip(" *") for line in exposure_section.splitlines() if line.strip(" *")]
        for i in range(len(exp_lines) - 1):
            if re.match(r"^-?[0-9.]+\s*%$", exp_lines[i + 1]):
                try:
                    exposure.append({
                        "name": exp_lines[i],
                        "weight_pct": round(float(exp_lines[i + 1].replace("%", "").strip()), 2),
                    })
                except Exception:
                    pass

    return {
        "name": title,
        "fund_type": "ETF",
        "description": description or objective or summary,
        "objective": objective or summary,
        "issuer": "VistaShares",
        "legal_type": "Exchange Traded Fund",
        "expense_ratio_pct": _research_expense_pct(key_info.get("Expense Ratio")),
        "total_assets": _vistashares_money(key_info.get("Net Assets")),
        "total_assets_label": "Net Assets",
        "nav_price": _vistashares_money(key_info.get("NAV")),
        "nav_label": "NAV",
        "inception_date": key_info.get("Inception Date"),
        "dividend_frequency": key_info.get("Distribution Frequency"),
        "estimated_yield_pct": _research_pct(dist_rate),
        "distribution_rate_pct": _research_pct(dist_rate),
        "sec_30_day_yield_pct": _research_pct(sec_yield),
        "target_yield_label": "Distribution Rate",
        "top_holdings": holdings,
        "sector_weightings": exposure[:10],
        "source_url": url,
        "data_source": "VistaShares",
    }


def _fetch_income_blast_etf_profile(ticker):
    html_text, url = _income_blast_page(ticker)
    if not html_text or "Tuttle Capital" not in html_text:
        return None

    text = _income_blast_text_from_html(html_text)
    if not _is_tuttle_capital_fund(ticker, text):
        return None

    title = _vistashares_match(text, rf"#\s*{re.escape((ticker or '').strip().upper())}\s+(.*?)\s+Prospectus")
    objective = _vistashares_match(text, r"Investment Objective:\s+(.*?)\s+NAV Price")
    holdings = _fetch_income_blast_top_holdings(ticker, limit=25)

    dist_rate = _vistashares_match(text, r"Distribution Rate\s+([0-9.]+)\s+X\.XX%")
    sec_yield = _vistashares_match(text, r"30 Day SEC\s*Yield\s+(-?[0-9.]+)\s+X\.XX%")
    expense_ratio = _vistashares_match(text, r"Expense Ratio\s+([0-9.]+)\s+X\.XX%")
    net_assets = _vistashares_match(text, r"Net Assets\s+([0-9.,]+)\s+\$XXX")
    nav_price = _vistashares_match(text, r"NAV Price\s+([0-9.]+)\s+\$XX")
    inception = _vistashares_match(text, r"inception date\s+([A-Za-z]{3}\s+\d{1,2},\s+\d{4})\s+MM/DD/YYYY")

    return {
        "name": title,
        "fund_type": "ETF",
        "description": objective,
        "objective": objective,
        "issuer": "Tuttle Capital Management",
        "legal_type": "Exchange Traded Fund",
        "expense_ratio_pct": _research_expense_pct(expense_ratio),
        "total_assets": _vistashares_money(net_assets),
        "total_assets_label": "Net Assets",
        "nav_price": _vistashares_money(nav_price),
        "nav_label": "NAV",
        "inception_date": inception,
        "estimated_yield_pct": _research_pct(dist_rate),
        "distribution_rate_pct": _research_pct(dist_rate),
        "sec_30_day_yield_pct": _research_pct(sec_yield),
        "target_yield_label": "Distribution Rate",
        "top_holdings": holdings,
        "source_url": url,
        "data_source": "Income Blast ETFs",
    }


def _research_has_value(value):
    return value not in (None, "", [])


def _research_needs_provider_fallback(response):
    fields = (
        "description", "issuer", "category", "expense_ratio_pct",
        "total_assets", "nav_price", "inception_date",
        "dividend_frequency", "estimated_yield_pct",
    )
    present = sum(1 for field in fields if _research_has_value(response.get(field)))
    has_holdings = bool(response.get("top_holdings"))
    return present < 6 or not has_holdings


def _fetch_provider_etf_profile(ticker, response):
    """Try official issuer/provider pages when the market-data feed is sparse."""
    provider_hints = " ".join(str(response.get(k) or "") for k in ("name", "issuer", "data_source"))
    fetchers = []
    if _is_tuttle_capital_fund(ticker, provider_hints):
        fetchers.append(_fetch_income_blast_etf_profile)
    if "vistashares" in provider_hints.lower():
        fetchers.append(_fetch_vistashares_etf_profile)
    fetchers.append(_fetch_income_blast_etf_profile)
    fetchers.append(_fetch_vistashares_etf_profile)

    seen = set()
    for fetcher in fetchers:
        if fetcher in seen:
            continue
        seen.add(fetcher)
        profile = fetcher(ticker)
        if profile:
            return profile
    return None


@app.route("/api/security-research/<kind>/<ticker>", methods=["GET"])
def security_research(kind, ticker):
    """Return ETF or stock research facts for a user-entered symbol."""
    import yfinance as yf

    kind = (kind or "").strip().lower()
    ticker = (ticker or "").strip().upper()
    lookup_symbol = _yahoo_symbol_for_ticker(ticker)
    if kind not in {"etf", "stock"}:
        return jsonify({"error": "kind must be etf or stock"}), 400
    if not ticker:
        return jsonify({"error": "ticker is required"}), 400

    try:
        yf_ticker = yf.Ticker(lookup_symbol)
        info = _cached_yf_info(yf_ticker, lookup_symbol)
        info_symbol = (info.get("symbol") or "").upper()
        if info_symbol and info_symbol != lookup_symbol:
            lookup_symbol = info_symbol
            yf_ticker = yf.Ticker(lookup_symbol)
            info = _cached_yf_info(yf_ticker, lookup_symbol)
    except Exception as exc:
        return jsonify({"error": f"Could not load {ticker}: {exc}"}), 404

    name = _research_info_value(info, "longName", "shortName", "displayName") or ticker
    quote_type = (_research_info_value(info, "quoteType") or "").upper()
    summary = _research_info_value(info, "longBusinessSummary") or ""

    dividends = _cached_yf_dividends(yf_ticker, lookup_symbol)

    dividend_frequency = _research_dividend_frequency(dividends)
    ttm_dividend = None
    last_dividend = None
    if dividends is not None and not dividends.empty:
        divs = dividends[dividends > 0].dropna()
        if not divs.empty:
            last_dividend = {
                "date": divs.index[-1].strftime("%Y-%m-%d"),
                "amount": round(float(divs.iloc[-1]), 4),
            }
            trailing = divs[divs.index >= (pd.Timestamp.now(tz=divs.index.tz) - pd.DateOffset(years=1))]
            ttm_dividend = round(float(trailing.sum()), 4) if not trailing.empty else None

    if kind == "etf":
        fund_data = None
        fund_overview = {}
        fund_operations = {}
        try:
            fund_data = yf_ticker.funds_data
            fund_overview = getattr(fund_data, "fund_overview", None) or {}
            ops = getattr(fund_data, "fund_operations", None)
            if ops is not None and not ops.empty:
                for attr in ops.index:
                    value = _research_clean_value(ops.iloc[ops.index.get_loc(attr), 0])
                    if value is not None:
                        fund_operations[str(attr)] = value
        except Exception:
            fund_data = None

        objective = summary
        if fund_data is not None:
            try:
                objective = getattr(fund_data, "description", None) or objective
            except Exception:
                pass

        type_disp = _research_info_value(info, "typeDisp")
        industry_value = _research_info_value(info, "industry", "industryDisp")
        legal_type = _derive_legal_type(quote_type, summary, fund_overview, type_disp, name, industry_value)
        fund_type = _derive_fund_type(legal_type, quote_type)
        is_traded_fund = legal_type in {"Closed-End Fund", "Business Development Company", "Real Estate Investment Trust"}
        is_cef = is_traded_fund

        category = _research_info_value(info, "category") or (fund_overview.get("categoryName") if isinstance(fund_overview, dict) else None)
        if category is None:
            industry = _research_info_value(info, "industry")
            sector = _research_info_value(info, "sector")
            if industry and sector and industry != sector:
                category = f"{industry} \u2014 {sector}"
            else:
                category = industry or sector

        total_assets = _research_money(_research_info_value(info, "totalAssets") or (fund_operations.get("Total Net Assets") if isinstance(fund_operations, dict) else None))
        total_assets_label = "Total Assets"
        if total_assets is None:
            try:
                bs = yf_ticker.balance_sheet
                if bs is not None and not bs.empty and "Total Assets" in bs.index:
                    total_assets = _research_money(bs.loc["Total Assets", bs.columns[0]])
            except Exception:
                pass
        if total_assets is None and is_traded_fund:
            total_assets = _research_money(_research_info_value(info, "marketCap"))
            if total_assets is not None:
                total_assets_label = "Market Cap"

        market_price = _research_money(_research_info_value(info, "regularMarketPrice", "currentPrice"))
        nav_price = _research_money(_research_info_value(info, "navPrice"))
        nav_label = "NAV"
        if nav_price is None:
            book_value = _research_money(_research_info_value(info, "bookValue"))
            if book_value is not None:
                nav_price = book_value
                nav_label = "NAV / Share" if is_traded_fund else "Book Value / Share"
        if nav_price is None and is_traded_fund:
            nav_price = market_price
            if nav_price is not None:
                nav_label = "Market Price"

        response = {
            "kind": "etf",
            "ticker": lookup_symbol,
            "requested_ticker": ticker,
            "name": name,
            "quote_type": quote_type,
            "fund_type": fund_type,
            "description": objective,
            "objective": objective,
            "issuer": _derive_issuer(info, name) or (fund_overview.get("family") if isinstance(fund_overview, dict) else None),
            "category": category,
            "legal_type": legal_type,
            "expense_ratio_pct": _research_expense_pct(
                _research_info_value(info, "netExpenseRatio", "annualReportExpenseRatio"),
                fund_operations.get("Annual Report Expense Ratio") if isinstance(fund_operations, dict) else None,
            ),
            "total_assets": total_assets,
            "total_assets_label": total_assets_label,
            "price": market_price,
            "nav_price": nav_price,
            "nav_label": nav_label,
            "inception_date": None,
            "dividend_frequency": dividend_frequency,
            "last_dividend": last_dividend,
            "ttm_dividend_per_share": ttm_dividend,
            "estimated_yield_pct": _research_pct(_research_info_value(info, "yield", "dividendYield", "trailingAnnualDividendYield")),
            "target_yield_label": "Estimated forward yield",
            "top_holdings": _research_top_holdings(fund_data, ticker=lookup_symbol, description=f"{name} {summary}"),
            "sector_weightings": _research_weight_map(getattr(fund_data, "sector_weightings", None)) if fund_data is not None else [],
            "asset_classes": _research_weight_map(getattr(fund_data, "asset_classes", None)) if fund_data is not None else [],
            "closure_risk": _assess_etf_closure_risk(info),
            "data_source": "Yahoo Finance",
        }
        official_profile = _fetch_provider_etf_profile(lookup_symbol, response) if _research_needs_provider_fallback(response) else None
        if official_profile:
            for key, value in official_profile.items():
                if value not in (None, "", []):
                    response[key] = value

        # ── Official fund-site yield & distribution history ──────────────
        description_text = f"{name} {summary}"
        official_snapshot = None
        try:
            official_snapshot = _fetch_official_distribution_snapshot(lookup_symbol, description_text)
        except Exception:
            pass

        dist_history_series = None
        if official_snapshot and official_snapshot.get("history") is not None:
            h = official_snapshot["history"]
            if hasattr(h, "empty") and not h.empty:
                dist_history_series = h
                rate = official_snapshot.get("distribution_rate_pct")
                if rate is not None:
                    response["estimated_yield_pct"] = round(float(rate), 2)
                    response["target_yield_label"] = "Distribution Rate"
                if official_snapshot.get("freq"):
                    response["dividend_frequency"] = {
                        "W": "Weekly", "M": "Monthly", "Q": "Quarterly",
                        "SA": "Semi-Annual", "A": "Annual",
                    }.get(official_snapshot["freq"], response.get("dividend_frequency"))
                last_entry = official_snapshot.get("div")
                ex_date = official_snapshot.get("ex_div_date")
                if last_entry and ex_date:
                    response["last_dividend"] = {"amount": round(float(last_entry), 4), "date": ex_date}
                response["yield_source"] = official_snapshot.get("source") or "Fund Site"
                response["distribution_source"] = response["yield_source"]

        if dist_history_series is None and dividends is not None and not dividends.empty:
            divs = dividends[dividends > 0].dropna()
            if not divs.empty:
                dist_history_series = divs
                response["yield_source"] = "Yahoo Finance"
                response["distribution_source"] = "Yahoo Finance"

        response["distribution_history"] = []
        if dist_history_series is not None and not dist_history_series.empty:
            for dt, amt in dist_history_series.items():
                response["distribution_history"].append({
                    "date": dt.strftime("%Y-%m-%d"),
                    "amount": round(float(amt), 4),
                })

        inception = _research_info_value(info, "fundInceptionDate")
        if inception:
            try:
                response["inception_date"] = pd.to_datetime(int(inception), unit="s").strftime("%Y-%m-%d")
            except Exception:
                response["inception_date"] = None
        if response["inception_date"] is None:
            first_trade_ms = _research_info_value(info, "firstTradeDateMilliseconds")
            if first_trade_ms:
                try:
                    response["inception_date"] = pd.to_datetime(int(first_trade_ms), unit="ms").strftime("%Y-%m-%d")
                except Exception:
                    response["inception_date"] = None
        return jsonify(response)

    response = {
        "kind": "stock",
        "ticker": lookup_symbol,
        "requested_ticker": ticker,
        "name": name,
        "quote_type": quote_type,
        "business_summary": summary,
        "sector": _research_info_value(info, "sector"),
        "industry": _research_info_value(info, "industry"),
        "country": _research_info_value(info, "country"),
        "website": _research_info_value(info, "website"),
        "exchange": _research_info_value(info, "exchange", "fullExchangeName"),
        "price": _research_money(_research_info_value(info, "regularMarketPrice", "currentPrice")),
        "market_cap": _research_money(_research_info_value(info, "marketCap")),
        "enterprise_value": _research_money(_research_info_value(info, "enterpriseValue")),
        "beta": _research_clean_value(_research_info_value(info, "beta")),
        "trailing_pe": _research_clean_value(_research_info_value(info, "trailingPE")),
        "forward_pe": _research_clean_value(_research_info_value(info, "forwardPE")),
        "price_to_book": _research_clean_value(_research_info_value(info, "priceToBook")),
        "price_to_sales_ttm": _research_clean_value(_research_info_value(info, "priceToSalesTrailing12Months")),
        "revenue": _research_money(_research_info_value(info, "totalRevenue")),
        "revenue_growth_pct": _research_pct(_research_info_value(info, "revenueGrowth")),
        "gross_margin_pct": _research_pct(_research_info_value(info, "grossMargins")),
        "operating_margin_pct": _research_pct(_research_info_value(info, "operatingMargins")),
        "profit_margin_pct": _research_pct(_research_info_value(info, "profitMargins")),
        "net_income": _research_money(_research_info_value(info, "netIncomeToCommon")),
        "ebitda": _research_money(_research_info_value(info, "ebitda")),
        "free_cash_flow": _research_money(_research_info_value(info, "freeCashflow")),
        "total_cash": _research_money(_research_info_value(info, "totalCash")),
        "total_debt": _research_money(_research_info_value(info, "totalDebt")),
        "debt_to_equity": _research_clean_value(_research_info_value(info, "debtToEquity")),
        "dividend_frequency": dividend_frequency,
        "last_dividend": last_dividend,
        "ttm_dividend_per_share": ttm_dividend,
        "dividend_rate": _research_money(_research_info_value(info, "dividendRate")),
        "dividend_yield_pct": None,
        "payout_ratio_pct": _research_pct(_research_info_value(info, "payoutRatio")),
        "peg_ratio": _research_clean_value(_research_info_value(info, "pegRatio", "trailingPegRatio")),
        "eps": _research_clean_value(_research_info_value(info, "trailingEps")),
        "dividend_growth_pct": None,
        "fifty_two_week_low": _research_money(_research_info_value(info, "fiftyTwoWeekLow")),
        "fifty_two_week_high": _research_money(_research_info_value(info, "fiftyTwoWeekHigh")),
        "data_source": "Yahoo Finance",
    }
    # Include dividend distribution history for stocks (same as ETF branch)
    response["distribution_history"] = []
    if dividends is not None and not dividends.empty:
        divs = dividends[dividends > 0].dropna()
        if not divs.empty:
            response["distribution_source"] = "Yahoo Finance"
            for dt, amt in divs.items():
                response["distribution_history"].append({
                    "date": dt.strftime("%Y-%m-%d"),
                    "amount": round(float(amt), 4),
                })
    # Compute yield from TTM dividends / price — avoids yfinance field scaling inconsistencies
    try:
        price_val = response.get("price")
        if ttm_dividend and price_val:
            response["dividend_yield_pct"] = round(float(ttm_dividend) / float(price_val) * 100, 4)
    except Exception:
        pass
    if response["dividend_yield_pct"] is None:
        response["dividend_yield_pct"] = _research_pct(_research_info_value(info, "dividendYield", "trailingAnnualDividendYield"))
    try:
        freq_code = _div_calc_infer_frequency(dividends)
        growth = _div_calc_growth_pct(dividends, freq_code)
        if growth:
            response["dividend_growth_pct"] = round(growth, 2)
    except Exception:
        pass
    return jsonify(response)


