@app.route("/api/security-research/<kind>/<ticker>/average-return", methods=["GET"])
def security_research_average_return(kind, ticker):
    """Return multi-period total-return comparisons for the research page."""
    import warnings
    warnings.filterwarnings("ignore")

    kind = (kind or "").strip().lower()
    ticker = (ticker or "").strip().upper()
    benchmark = (request.args.get("benchmark", "SPY") or "SPY").strip().upper()

    if kind not in {"etf", "stock"}:
        return jsonify({"error": "kind must be etf or stock"}), 400
    if not ticker:
        return jsonify({"error": "ticker is required"}), 400
    if not benchmark:
        benchmark = "SPY"

    force_refresh = request.args.get("refresh", "0") not in ("", "0")
    primary_series, primary_name = _research_adjusted_close_series(ticker, force_refresh=force_refresh)
    benchmark_series, benchmark_name = _research_adjusted_close_series(benchmark, force_refresh=force_refresh)

    if primary_series is None or primary_series.empty:
        return jsonify({"error": f"No return data for {ticker}"}), 404

    rows = _research_period_return_rows(primary_series, benchmark_series)
    yield_info = _research_approx_yield(ticker)
    summary = _research_return_summary(ticker, benchmark, rows, yield_info)

    return jsonify({
        "kind": kind,
        "ticker": ticker,
        "ticker_name": primary_name,
        "benchmark": benchmark,
        "benchmark_name": benchmark_name,
        "periods": rows,
        "series": [
            {"name": ticker, "values": [row["ticker_return"] for row in rows], "color": "#4d8dff"},
            {"name": benchmark, "values": [row["benchmark_return"] for row in rows], "color": "#ff8c42"},
        ],
        "summary": summary,
        "note": "Returns are total returns based on split/dividend-adjusted prices and are shown from each period's start date.",
    })


@app.route("/api/security-research/<kind>/average-returns", methods=["GET"])
def security_research_average_returns(kind):
    """Return multi-period adjusted returns for multiple research symbols."""
    import warnings
    warnings.filterwarnings("ignore")

    kind = (kind or "").strip().lower()
    symbols = []
    for raw in (request.args.get("tickers", "") or "").split(","):
        symbol = raw.strip().upper()
        if symbol and symbol not in symbols:
            symbols.append(symbol)

    if kind not in {"etf", "stock"}:
        return jsonify({"error": "kind must be etf or stock"}), 400
    if not symbols:
        return jsonify({"error": "tickers are required"}), 400

    force_refresh = request.args.get("refresh", "0") not in ("", "0")
    series_by_symbol = {}
    names = {}
    errors = {}
    for symbol in symbols:
        series, name = _research_adjusted_close_series(symbol, force_refresh=force_refresh)
        if series is None or series.empty:
            errors[symbol] = f"No return data for {symbol}"
            continue
        series_by_symbol[symbol] = series
        names[symbol] = name

    rows = _research_multi_period_return_rows(
        series_by_symbol,
        common_window=False,
        include_inception=(kind == "etf"),
        include_stock_long_windows=(kind == "stock"),
        annualize_long_windows=True,
    )
    summary = _research_multi_return_summary(symbols, rows)

    # ETF comparer: make the "Inception" comparison fair. Each fund's own
    # inception spans a different length (e.g. QQQ since 1999 vs a 2024 income
    # fund), so expose (a) per-fund inception spans for bar labelling and
    # (b) a "Common History" period measured over the identical window shared
    # by every fund (starting at the latest inception), annualized when ≥1yr.
    inception_meta = {}
    common_history = None
    if kind == "etf":
        valid = {s: ser for s, ser in series_by_symbol.items() if ser is not None and not ser.empty}
        for s, ser in valid.items():
            start = ser.index.min()
            inception_meta[s] = {
                "date": start.strftime("%Y-%m-%d"),
                "years": round((ser.index.max() - start).days / 365.25, 1),
            }
        if len(valid) >= 2:
            common_start = max(ser.index.min() for ser in valid.values())
            common_end = min(ser.index.max() for ser in valid.values())
            span_days = (common_end - common_start).days
            if span_days > 5:
                annualized = span_days >= 365
                common_returns = {
                    s: _research_window_return(ser.loc[ser.index <= common_end], common_start, annualize=annualized)
                    for s, ser in valid.items()
                }
                rows.append({"label": "Common History", "returns": common_returns})
                common_history = {
                    "start": common_start.strftime("%Y-%m-%d"),
                    "end": common_end.strftime("%Y-%m-%d"),
                    "years": round(span_days / 365.25, 1),
                    "annualized": annualized,
                }

    return jsonify({
        "kind": kind,
        "symbols": [symbol for symbol in symbols if symbol in series_by_symbol],
        "names": names,
        "periods": rows,
        "series": [
            {"name": symbol, "values": [row["returns"].get(symbol) for row in rows]}
            for symbol in symbols
            if symbol in series_by_symbol
        ],
        "summary": summary,
        "errors": errors,
        "inception_meta": inception_meta,
        "common_history": common_history,
        "note": "Returns are based on split/dividend-adjusted prices. 1 Month and YTD are cumulative; longer windows are annualized average returns.",
    })


@app.route("/api/data/clear-all", methods=["POST"])
def clear_all_data():
    """Delete all holdings, dividends, and related data for the current profile."""
    profile_id = get_profile_id()
    # Snapshot the database before a destructive operation so the user can roll back.
    _create_import_backup(profile_id)
    conn = get_connection()
    tables = [
        "all_account_info", "holdings", "dividends", "income_tracking",
        "weekly_payouts", "monthly_payouts", "weekly_payout_tickers", "monthly_payout_tickers",
    ]
    counts = {}
    for t in tables:
        r = conn.execute(f"DELETE FROM {t} WHERE profile_id = ?", (profile_id,))
        counts[t] = r.rowcount
    conn.commit()
    conn.close()
    return jsonify({"message": "All data cleared for the current portfolio", "deleted": counts})


@app.route("/api/data/stats", methods=["GET"])
def data_stats():
    """Return row counts for key tables."""
    is_agg, pids = get_profile_filter()
    conn = get_connection()
    placeholders = ",".join("?" * len(pids))
    holdings = conn.execute(
        f"SELECT COUNT(DISTINCT ticker) as c FROM all_account_info WHERE profile_id IN ({placeholders})", pids
    ).fetchone()["c"]
    dividends = conn.execute(
        f"SELECT COUNT(*) as c FROM dividends WHERE profile_id IN ({placeholders})", pids
    ).fetchone()["c"]
    income = conn.execute(
        f"SELECT COUNT(*) as c FROM income_tracking WHERE profile_id IN ({placeholders})", pids
    ).fetchone()["c"]
    conn.close()
    return jsonify({"holdings": holdings, "dividends": dividends, "income_tracking": income})


def _nav_benchmark_overrides():
    try:
        import json as _json
        now = time.time()
        cached = _NAV_BENCHMARK_OVERRIDE_CACHE
        if cached.get("data") is not None and (now - float(cached.get("ts") or 0)) < 60:
            return cached.get("data") or {}
        conn = get_connection()
        row = conn.execute("SELECT value FROM settings WHERE key = 'nav_benchmark_overrides'").fetchone()
        conn.close()
        raw = _json.loads(row["value"]) if row and row["value"] else {}
        data = {
            str(k).strip().upper(): str(v).strip().upper()
            for k, v in raw.items()
            if str(k).strip() and str(v).strip()
        }
        _NAV_BENCHMARK_OVERRIDE_CACHE.update({"ts": now, "data": data})
        return data
    except Exception:
        _NAV_BENCHMARK_OVERRIDE_CACHE.update({"ts": time.time(), "data": {}})
        return {}


