def _nav_benchmark_parts(benchmark):
    parts = [
        p.strip().upper()
        for p in str(benchmark or "").replace("/", "+").split("+")
        if p.strip()
    ]
    return parts or ["SPY"]


def _nav_date_indexed_series(series):
    try:
        s = series.dropna()
        if s.empty:
            return s
        idx = pd.to_datetime(s.index)
        try:
            idx = idx.tz_convert(None)
        except Exception:
            try:
                idx = idx.tz_localize(None)
            except Exception:
                pass
        s = s.copy()
        s.index = idx.normalize()
        return s.groupby(level=0).last()
    except Exception:
        return series


def _nav_align_series(*series):
    named = []
    for i, s in enumerate(series):
        if s is None:
            return pd.DataFrame()
        clean = _nav_date_indexed_series(s)
        if clean is None or clean.empty:
            return pd.DataFrame()
        named.append(clean.rename(getattr(s, "name", None) or f"s{i}"))
    return pd.concat(named, axis=1, join="inner").dropna()


def _nav_benchmark_close_from_df(close_df, benchmark, fallback_close):
    parts = _nav_benchmark_parts(benchmark)
    series = []
    try:
        for part in parts:
            if part in close_df.columns:
                s = close_df[part].dropna()
                if len(s) >= 2:
                    series.append(s.rename(part))
        if not series:
            return fallback_close
        if len(series) == 1:
            return series[0]
        aligned = _nav_align_series(*series)
        if len(aligned) < 2:
            return fallback_close
        composite = 1.0
        for col in aligned.columns:
            start = float(aligned[col].iloc[0])
            if start <= 0:
                return fallback_close
            composite = composite + (aligned[col] / start - 1.0)
        composite.name = benchmark
        return composite
    except Exception:
        return fallback_close


def _is_nav_erosion_candidate(ticker, name="", category=""):
    """True only for products where structural NAV decay is plausible.

    Plain equities and broad/dividend/growth ETFs can underperform, but that is
    not NAV erosion in the income-fund sense.
    """
    t = str(ticker or "").upper()
    text = f"{name or ''} {category or ''}".lower()
    safe_plain_tickers = {
        "SCHD", "SCHG", "SCHB", "SCHF", "SCHX", "VOO", "VTI", "VT", "QQQ",
        "QQQM", "SPY", "IVV", "IWM", "DIA", "VIG", "DGRO", "VYM", "HDV",
        "PBDC", "BIZD", "ARCC", "MAIN", "OBDC",
        "BXSL", "HTGC", "GBDC", "FDUS", "CSWC", "FSK", "OCSL", "TCPC",
        "TPVG", "PSEC", "NMFC", "TSLX", "BDC", "HRZN", "GLAD", "GAIN",
        "SAR", "CGBD", "CCAP", "TRIN", "RWAY",
    }
    if t in safe_plain_tickers:
        return False
    known_risky = {
        "DIVO", "JEPI", "JEPQ", "QQQI", "SPYI", "TSPY", "TDAQ", "XQQI",
        "IWMI", "SPYH", "CSHI", "KQQQ", "TQQY", "QDTE", "XDTE", "RDTE",
        "QYLD", "XYLD", "RYLD",
        "BTCI", "KYLD", "BLOX", "ISBG", "ISSB", "BITY", "XBCI",
        "ETTY", "ETHI", "ETHY", "NEHI", "SOL", "SOLM", "SOLY", "TSYX", "TDAX", "BNDI",
        "IAUI", "KGLD", "KCOP", "YQQQ",
        "ULTY", "ULTI", "YMAX", "YMAG", "YBIT", "BIGY", "FIVY", "LFGY", "SLTY",
        "TSLY", "NVDY", "CONY", "MSTY", "AMZY", "MSFO", "APLY", "GOOY", "FBY",
        "NFLY", "DISO", "PYPY", "SQY", "AMDY", "OARK", "MRNY", "SNOY", "JPMO",
        "BABO", "TSMY", "PLTY", "FIAT", "GMEY", "MARO", "CRSH", "ABNY", "SMCY",
        "METY", "TSLP", "NVDP", "QQQY", "JEPY", "IWMY", "PFFA",
        "FEPI", "AIPI", "CEPI", "GIF", "TLDR", "ATCL",
        "GIAX", "FIAX", "WEPN", "NUKX", "GLDN", "SLVX", "SLJY",
        "XLEI", "CHPY", "GPTY", "GOOP", "WNTR", "BEGS", "OVL", "SEPI",
    }
    risky_markers = (
        "yieldmax", "single stock", "synthetic", "ultra option income",
        "ultra income", "2x", "leveraged", "daily target", "daily leveraged",
        "defiance", "rex shares", "graniteshares yieldboost",
    )
    option_markers = (
        "covered call", "buywrite", "buy-write", "option income",
        "options income", "option strategy", "option premium", "premium income",
        "high income", "daily income", "enhanced income", "boosted",
        "hedged equity income", "income max", "incomemax",
    )
    return (
        t in known_risky
        or any(marker in text for marker in risky_markers)
        or any(marker in text for marker in option_markers)
    )


def _should_test_nav_erosion(ticker, name="", category="", scope="auto"):
    scope = str(scope or "auto").strip().lower()
    if scope == "test":
        return True
    if scope == "skip":
        return False
    return _is_nav_erosion_candidate(ticker, name, category)


def _nav_erosion_numerator(fund_return, benchmark_return):
    """Only count the fund's own price decay, not benchmark underperformance.

    Benchmark is a gate: if the underlying market is down too, the fund's price
    decline is not treated as structural NAV erosion.
    """
    if fund_return is None or benchmark_return is None:
        return None
    if fund_return >= 0 or benchmark_return < 0:
        return 0.0
    return abs(fund_return)


def _nav_distribution_yield_from_history(divs_series, current_price, close_series=None):
    """Return distribution yield using TTM, or all available history under 12 months."""
    try:
        cur_price = float(current_price or 0)
    except (TypeError, ValueError):
        cur_price = 0.0
    if cur_price <= 0 or divs_series is None:
        return 0.0, 0.0
    try:
        divs = divs_series.dropna()
        divs = divs[divs > 0]
    except Exception:
        return 0.0, 0.0
    if divs.empty:
        return 0.0, 0.0

    end_ts = None
    start_ts = None
    try:
        if close_series is not None:
            close = close_series.dropna()
            if len(close) >= 2:
                start_ts = pd.Timestamp(close.index[0])
                end_ts = pd.Timestamp(close.index[-1])
    except Exception:
        start_ts = None
        end_ts = None
    if end_ts is None:
        end_ts = pd.Timestamp(divs.index[-1])

    try:
        cutoff = end_ts - pd.DateOffset(months=12)
        if start_ts is not None and start_ts > cutoff:
            cutoff = start_ts
        if getattr(divs.index, "tz", None) is not None and cutoff.tzinfo is None:
            cutoff = cutoff.tz_localize(divs.index.tz)
        elif getattr(divs.index, "tz", None) is None and cutoff.tzinfo is not None:
            cutoff = cutoff.tz_localize(None)
        if start_ts is not None and start_ts > end_ts - pd.DateOffset(months=12):
            trailing = divs[divs.index >= cutoff]
        else:
            trailing = divs[divs.index > cutoff]
    except Exception:
        trailing = divs

    dist_per_share = float(trailing.sum()) if trailing is not None and not trailing.empty else 0.0
    return dist_per_share / cur_price, dist_per_share


def _nav_erosion_from_adjusted_ratio(ratio, price_change_pct=None, deficit_pct=None):
    try:
        if price_change_pct is not None and float(price_change_pct) <= -50:
            return "High"
    except (TypeError, ValueError):
        pass
    try:
        if deficit_pct is not None and float(deficit_pct) >= 5:
            return "High"
    except (TypeError, ValueError):
        pass
    try:
        if ratio is None:
            return None
        ratio = float(ratio)
    except (TypeError, ValueError):
        return None
    if ratio <= 0.25:
        return "Low"
    if ratio <= 0.75:
        return "Medium"
    return "High"


def _nav_signal_from_adjusted_ratio(ratio, price_change_pct=None, deficit_pct=None):
    erosion = _nav_erosion_from_adjusted_ratio(ratio, price_change_pct, deficit_pct)
    if erosion == "Low":
        return "BUY"
    if erosion == "High":
        return "SELL"
    if erosion == "Medium":
        return "NEUTRAL"
    return None


def _nav_adjusted_erosion_ratio(close, divs_series, benchmark_close):
    """Destructive NAV erosion ratio: fund price decline / distribution yield, gated by flat/up benchmark."""
    try:
        if close is None or benchmark_close is None:
            return None
        close = close.dropna()
        benchmark_close = benchmark_close.dropna()
        if len(close) < 2 or len(benchmark_close) < 2:
            return None
        aligned = _nav_align_series(close.rename("fund"), benchmark_close.rename("benchmark"))
        if len(aligned) < 2:
            return None
        fund_close = aligned["fund"]
        bench_close = aligned["benchmark"]
        cur_price = float(fund_close.iloc[-1])
        start_price = float(fund_close.iloc[0])
        bench_start = float(bench_close.iloc[0])
        bench_end = float(bench_close.iloc[-1])
        if min(cur_price, start_price, bench_start, bench_end) <= 0:
            return None
        fund_return = (cur_price - start_price) / start_price
        benchmark_return = (bench_end - bench_start) / bench_start
        ttm_dist_yield, _ = _nav_distribution_yield_from_history(divs_series, cur_price, fund_close)
        if ttm_dist_yield <= 0:
            return None
        numerator = _nav_erosion_numerator(fund_return, benchmark_return)
        if numerator is None:
            return None
        ratio = round(numerator / ttm_dist_yield, 4)
        return ratio
    except Exception:
        return None


# ── Income Summary ────────────────────────────────────────────────────────────

@app.route("/api/income-summary", methods=["GET"])
def income_summary():
    """Compute current month and YTD income from payout tables + estimates."""
    import datetime
    is_agg, pids = get_profile_filter()
    conn = get_connection()
    today = datetime.date.today()
    placeholders = ",".join("?" * len(pids))

    # Use stored actuals from refresh, fall back to estimates for holdings without data
    holdings = conn.execute(
        f"""SELECT quantity, div, ex_div_date, div_frequency, purchase_date,
                   ytd_divs, current_month_income
            FROM all_account_info
            WHERE profile_id IN ({placeholders})
              AND quantity IS NOT NULL AND quantity > 0""",
        pids,
    ).fetchall()

    total_month = 0.0
    total_ytd = 0.0
    for row in holdings:
        h = dict(row)
        stored_month = h.get("current_month_income")
        stored_ytd = h.get("ytd_divs")
        # Use "is None" not falsy — 0 means refresh ran and found no dividends
        # yet this period, which is correct (not a reason to use the full estimate)
        total_month += _estimate_current_month_income(h) if stored_month is None else stored_month
        total_ytd += _estimate_ytd_income(h) if stored_ytd is None else stored_ytd
    estimated_month_to_date = total_month

    # Estimated reinvest fraction (forward-looking run-rate split by the
    # per-holding reinvest flag). Used as a proportional fallback when actual
    # income can't be attributed to individual tickers (e.g. monthly_payouts).
    frac_row = conn.execute(
        f"""SELECT
               COALESCE(SUM(CASE WHEN reinvest = 'Y'
                                 THEN approx_monthly_income ELSE 0 END), 0) AS reinv,
               COALESCE(SUM(approx_monthly_income), 0) AS total
            FROM all_account_info
            WHERE profile_id IN ({placeholders})
              AND quantity IS NOT NULL AND quantity > 0""",
        pids,
    ).fetchone()
    est_total = float(frac_row["total"] or 0)
    reinvest_fraction = (float(frac_row["reinv"] or 0) / est_total) if est_total else 0.0

    payment_pids = pids
    if not is_agg and len(pids) == 1 and pids[0] == 1:
        owner_source_ids = _get_owner_source_profile_ids(conn)
        if owner_source_ids:
            payment_pids = owner_source_ids
    payment_placeholders = ",".join("?" * len(payment_pids))
    month_start = today.replace(day=1).isoformat()
    today_iso = today.isoformat()

    payment_month = conn.execute(
        f"""SELECT COALESCE(SUM(amount), 0) as amount, COUNT(*) as rows
            FROM dividend_payments
            WHERE profile_id IN ({payment_placeholders})
              AND payment_date >= ? AND payment_date <= ?""",
        payment_pids + [month_start, today_iso],
    ).fetchone()
    paid_month_to_date = None
    current_month_income_source = "holding_estimates"
    current_month_payment_rows = 0
    if payment_month and payment_month["rows"]:
        paid_month_to_date = float(payment_month["amount"] or 0)
        current_month_payment_rows = int(payment_month["rows"] or 0)
        current_month_income_source = "dividend_payments"
        total_month = paid_month_to_date

    payment_ytd = conn.execute(
        f"""SELECT COALESCE(SUM(amount), 0) as amount, COUNT(*) as rows
            FROM dividend_payments
            WHERE profile_id IN ({payment_placeholders})
              AND payment_date >= ? AND payment_date <= ?""",
        payment_pids + [today.replace(month=1, day=1).isoformat(), today_iso],
    ).fetchone()
    ytd_income_source = "holding_estimates"
    ytd_payment_rows = 0
    if payment_ytd and payment_ytd["rows"]:
        total_ytd = float(payment_ytd["amount"] or 0)
        ytd_payment_rows = int(payment_ytd["rows"] or 0)
        ytd_income_source = "dividend_payments"

    payout_month = conn.execute(
        f"""SELECT COALESCE(SUM(amount), 0) as amount, COUNT(*) as rows
            FROM monthly_payouts
            WHERE profile_id IN ({placeholders})
              AND year = ? AND month = ?""",
        pids + [today.year, today.month],
    ).fetchone()
    if paid_month_to_date is None and payout_month and payout_month["rows"]:
        total_month = float(payout_month["amount"] or 0)
        current_month_income_source = "monthly_payouts"

    completed_payout_ytd = conn.execute(
        f"""SELECT COALESCE(SUM(amount), 0) as amount,
                   COUNT(DISTINCT month) as months
            FROM monthly_payouts
            WHERE profile_id IN ({placeholders})
              AND year = ? AND month < ?""",
        pids + [today.year, today.month],
    ).fetchone()
    if (
        not ytd_payment_rows
        and
        paid_month_to_date is not None
        and int(completed_payout_ytd["months"] or 0) >= today.month - 1
    ):
        total_ytd = float(completed_payout_ytd["amount"] or 0) + paid_month_to_date
        ytd_income_source = "monthly_payouts"

    payout_ytd = conn.execute(
        f"""SELECT COALESCE(SUM(amount), 0) as amount,
                   COUNT(DISTINCT month) as months
            FROM monthly_payouts
            WHERE profile_id IN ({placeholders})
              AND year = ? AND month <= ?""",
        pids + [today.year, today.month],
    ).fetchone()
    if (
        not ytd_payment_rows
        and paid_month_to_date is None
        and payout_ytd
        and int(payout_ytd["months"] or 0) >= today.month
    ):
        total_ytd = float(payout_ytd["amount"] or 0)
        ytd_income_source = "monthly_payouts"

    # Split the actual current-month income into reinvested vs not-reinvested.
    # When income comes from recorded dividend payments we can attribute each
    # payment to its ticker's reinvest flag exactly; otherwise fall back to the
    # estimated reinvest fraction so the two always sum to current_month_income.
    if current_month_income_source == "dividend_payments":
        # Attribute each payment to ITS OWN account's reinvest flag (ticker +
        # profile_id). The same ticker can be reinvested in one account (e.g. a
        # Roth IRA) and taken as cash in another, so collapsing to one flag per
        # ticker would mis-bucket the cash payments.
        split = conn.execute(
            f"""SELECT
                   COALESCE(SUM(CASE WHEN a.reinvest = 'Y'
                                     THEN dp.amount ELSE 0 END), 0) AS reinv,
                   COALESCE(SUM(CASE WHEN a.reinvest IS NULL OR a.reinvest != 'Y'
                                     THEN dp.amount ELSE 0 END), 0) AS not_reinv
                FROM dividend_payments dp
                LEFT JOIN all_account_info a
                  ON a.ticker = dp.ticker AND a.profile_id = dp.profile_id
                WHERE dp.profile_id IN ({payment_placeholders})
                  AND dp.payment_date >= ? AND dp.payment_date <= ?""",
            payment_pids + [month_start, today_iso],
        ).fetchone()
        current_month_reinvested = float(split["reinv"] or 0)
        current_month_not_reinvested = float(split["not_reinv"] or 0)
    else:
        current_month_reinvested = round(total_month * reinvest_fraction, 2)
        current_month_not_reinvested = round(total_month - current_month_reinvested, 2)

    conn.close()
    return jsonify({
        "ytd_income": total_ytd,
        "ytd_income_source": ytd_income_source,
        "ytd_payment_rows": ytd_payment_rows,
        "current_month_income": total_month,
        "current_month_income_reinvested": current_month_reinvested,
        "current_month_income_not_reinvested": current_month_not_reinvested,
        "current_month_income_source": current_month_income_source,
        "current_month_payment_rows": current_month_payment_rows,
        "current_month_payment_start": month_start,
        "current_month_payment_through": today_iso,
        "estimated_month_to_date": estimated_month_to_date,
        "month_label": today.strftime("%B"),
    })


@app.route("/api/reinvestment-actual-pct", methods=["GET"])
def reinvestment_actual_pct():
    """Actual reinvested share of distributions over the trailing N *completed*
    calendar months (default 3), from recorded dividend payments split by each
    account's reinvest flag.

    The in-progress current month is excluded so the figure is stable and
    available from the first of a new month (no ramp-up). Used by the
    Reinvestment Impact page as a real-data alternative seed for Reinvest %.
    """
    import datetime
    is_agg, pids = get_profile_filter()
    try:
        months = max(1, min(24, int(request.args.get("months", 3))))
    except (TypeError, ValueError):
        months = 3
    conn = get_connection()
    today = datetime.date.today()

    # Window: first day of (months) ago .. last day of the previous month.
    current_month_start = today.replace(day=1)
    window_end_date = current_month_start - datetime.timedelta(days=1)
    y, m = current_month_start.year, current_month_start.month
    m -= months
    while m <= 0:
        m += 12
        y -= 1
    window_start_date = datetime.date(y, m, 1)
    window_start = window_start_date.isoformat()
    window_end = window_end_date.isoformat()

    # Payments live on the Owner's source profiles when viewing the Owner roll-up.
    payment_pids = pids
    if not is_agg and len(pids) == 1 and pids[0] == 1:
        owner_source_ids = _get_owner_source_profile_ids(conn)
        if owner_source_ids:
            payment_pids = owner_source_ids
    payment_placeholders = ",".join("?" * len(payment_pids))

    row = conn.execute(
        f"""SELECT
               COALESCE(SUM(CASE WHEN a.reinvest = 'Y'
                                 THEN dp.amount ELSE 0 END), 0) AS reinv,
               COALESCE(SUM(CASE WHEN a.reinvest IS NULL OR a.reinvest != 'Y'
                                 THEN dp.amount ELSE 0 END), 0) AS not_reinv,
               COUNT(*) AS rows,
               COUNT(DISTINCT substr(dp.payment_date, 1, 7)) AS months_with_data
            FROM dividend_payments dp
            LEFT JOIN all_account_info a
              ON a.ticker = dp.ticker AND a.profile_id = dp.profile_id
            WHERE dp.profile_id IN ({payment_placeholders})
              AND dp.payment_date >= ? AND dp.payment_date <= ?""",
        payment_pids + [window_start, window_end],
    ).fetchone()
    conn.close()

    reinv = float(row["reinv"] or 0)
    not_reinv = float(row["not_reinv"] or 0)
    total = reinv + not_reinv
    pct = (reinv / total * 100) if total > 0 else None

    return jsonify({
        "pct_reinvested": round(pct, 1) if pct is not None else None,
        "reinvested": round(reinv, 2),
        "not_reinvested": round(not_reinv, 2),
        "total": round(total, 2),
        "payment_rows": int(row["rows"] or 0),
        "months_requested": months,
        "months_with_data": int(row["months_with_data"] or 0),
        "window_start": window_start,
        "window_end": window_end,
    })


# ── Categories ────────────────────────────────────────────────────────────────

_CLASSIFICATION_NAMES = {
    "A": "Anchors", "B": "Boosters", "G": "Growth", "J": "Juicers",
    "BDC": "BDC", "HA": "Hedged Anchor", "GS": "Gold Silver",
    "ETF": "ETF", "EQUITY": "Equity", "CEF": "CEF", "REIT": "REIT",
}


def _attach_subcategories(conn, profile_ids, categories):
    """Add a 'subcategories' list to each category dict (for filter dropdowns)."""
    if not categories:
        return categories
    ph = ",".join("?" * len(profile_ids))
    rows = conn.execute(
        f"SELECT id, category_id, name FROM subcategories WHERE profile_id IN ({ph}) ORDER BY sort_order, name",
        list(profile_ids),
    ).fetchall()
    subs_by_cat = {}
    for s in rows:
        subs_by_cat.setdefault(s["category_id"], []).append({"id": s["id"], "name": s["name"]})
    for c in categories:
        c["subcategories"] = subs_by_cat.get(c["id"], [])
    return categories


def _parse_subcategory_ids(value):
    """Parse a comma-separated subcategory id query param into a list of ints."""
    return [int(s) for s in str(value or "").split(",") if s.strip().isdigit()]


def _subcategory_ticker_set(conn, profile_ids, sub_ids):
    """Tickers assigned to any of the given subcategory ids."""
    if not sub_ids:
        return set()
    ph = ",".join("?" * len(profile_ids))
    sph = ",".join("?" * len(sub_ids))
    rows = conn.execute(
        f"SELECT DISTINCT ticker FROM ticker_categories WHERE profile_id IN ({ph}) AND subcategory_id IN ({sph})",
        list(profile_ids) + list(sub_ids),
    ).fetchall()
    return {r["ticker"] for r in rows}


@app.route("/api/categories/data", methods=["GET"])
def categories_data():
    """Return categories with assigned tickers, unallocated tickers, and total value."""
    profile_id = get_profile_id()
    conn = get_connection()

    # Auto-seed categories from classification_type if none exist
    cat_count = conn.execute(
        "SELECT COUNT(*) as c FROM categories WHERE profile_id = ?", (profile_id,)
    ).fetchone()["c"]

    if cat_count == 0:
        types = conn.execute(
            "SELECT DISTINCT classification_type FROM all_account_info WHERE profile_id = ? AND classification_type IS NOT NULL",
            (profile_id,),
        ).fetchall()
        for i, row in enumerate(types):
            ct = row["classification_type"]
            name = _CLASSIFICATION_NAMES.get(ct, ct)
            conn.execute(
                "INSERT OR IGNORE INTO categories (name, profile_id, sort_order) VALUES (?, ?, ?)",
                (name, profile_id, i),
            )
        conn.commit()
        # Auto-assign tickers to their seeded categories
        cats = conn.execute(
            "SELECT id, name FROM categories WHERE profile_id = ?", (profile_id,)
        ).fetchall()
        name_to_id = {r["name"]: r["id"] for r in cats}
        holdings = conn.execute(
            "SELECT ticker, classification_type FROM all_account_info WHERE profile_id = ?",
            (profile_id,),
        ).fetchall()
        for h in holdings:
            ct = h["classification_type"]
            cat_name = _CLASSIFICATION_NAMES.get(ct, ct)
            cat_id = name_to_id.get(cat_name)
            if cat_id:
                conn.execute(
                    "INSERT OR IGNORE INTO ticker_categories (ticker, category_id, profile_id) VALUES (?, ?, ?)",
                    (h["ticker"], cat_id, profile_id),
                )
        conn.commit()

    # Fetch categories
    cats = conn.execute(
        "SELECT id, name, target_pct, sort_order FROM categories WHERE profile_id = ? ORDER BY sort_order, name",
        (profile_id,),
    ).fetchall()

    # Fetch active holdings only
    all_holdings = conn.execute(
        """SELECT ticker, description, classification_type, quantity, current_price,
                  current_value, approx_monthly_income,
                  current_annual_yield, div_frequency, nav_erosion_scope, gain_or_loss_percentage
           FROM all_account_info
           WHERE profile_id = ? AND quantity > 0""",
        (profile_id,),
    ).fetchall()
    total_value = sum(float(h["current_value"] or 0) for h in all_holdings)
    total_monthly_income = sum(float(h["approx_monthly_income"] or 0) for h in all_holdings)
    weekly_value = sum(
        float(h["current_value"] or 0)
        for h in all_holdings
        if str(h["div_frequency"] or "").strip().upper() in {"W", "52", "WEEKLY"}
    )
    weekly_income = sum(
        float(h["approx_monthly_income"] or 0)
        for h in all_holdings
        if str(h["div_frequency"] or "").strip().upper() in {"W", "52", "WEEKLY"}
    )

    # Fetch ticker-category assignments
    assignments = conn.execute(
        "SELECT ticker, category_id, subcategory_id FROM ticker_categories WHERE profile_id = ?",
        (profile_id,),
    ).fetchall()
    # Fetch subcategories (second tier within a category)
    subcat_rows = conn.execute(
        "SELECT id, category_id, name, target_pct, sort_order FROM subcategories WHERE profile_id = ? ORDER BY sort_order, name",
        (profile_id,),
    ).fetchall()
    subcats_by_category = {}
    for s in subcat_rows:
        subcats_by_category.setdefault(s["category_id"], []).append({
            "id": s["id"],
            "name": s["name"],
            "target_pct": s["target_pct"],
            "sort_order": s["sort_order"],
        })
    # Build response
    holding_map = {h["ticker"]: h for h in all_holdings}
    categories = []
    assigned_tickers = set()
    for cat in cats:
        cat_tickers = []
        for a in assignments:
            if a["category_id"] == cat["id"]:
                t = a["ticker"]
                h = holding_map.get(t)
                if h:
                    h_value = float(h["current_value"] or 0)
                    h_monthly_income = float(h["approx_monthly_income"] or 0)
                    h_freq = str(h["div_frequency"] or "").strip().upper()
                    h_nav_risk = bool(_is_nav_erosion_candidate(
                        t,
                        h["description"] or "",
                        h["classification_type"] or "",
                    )) or str(h["nav_erosion_scope"] or "").strip().lower() == "test"
                    cat_tickers.append({
                        "ticker": t,
                        "description": h["description"],
                        "classification_type": h["classification_type"],
                        "quantity": float(h["quantity"] or 0),
                        "current_price": float(h["current_price"] or 0),
                        "current_value": h_value,
                        "monthly_income": h_monthly_income,
                        "current_yield": (h_monthly_income * 12 / h_value * 100) if h_value > 0 else 0,
                        "div_frequency": h["div_frequency"],
                        "weekly": h_freq in {"W", "52", "WEEKLY"},
                        "nav_erosion_scope": h["nav_erosion_scope"] or "auto",
                        "nav_risk": h_nav_risk,
                        "gain_or_loss_percentage": float(h["gain_or_loss_percentage"] or 0),
                        "subcategory_id": a["subcategory_id"],
                    })
                    assigned_tickers.add(t)
        cat_value = sum(t["current_value"] for t in cat_tickers)
        cat_monthly_income = sum(t["monthly_income"] for t in cat_tickers)
        cat_weekly_value = sum(t["current_value"] for t in cat_tickers if t["weekly"])
        cat_weekly_income = sum(t["monthly_income"] for t in cat_tickers if t["weekly"])
        cat_nav_risk_value = sum(t["current_value"] for t in cat_tickers if t["nav_risk"])
        cat_largest_holding_pct = (
            max((t["current_value"] for t in cat_tickers), default=0) / cat_value * 100
            if cat_value > 0 else 0
        )
        cat_income_concentration_pct = (
            max((t["monthly_income"] for t in cat_tickers), default=0) / cat_monthly_income * 100
            if cat_monthly_income > 0 else 0
        )
        weighted_gain_loss = (
            sum(t["gain_or_loss_percentage"] * t["current_value"] for t in cat_tickers) / cat_value
            if cat_value > 0 else 0
        )
        categories.append({
            "id": cat["id"],
            "name": cat["name"],
            "target_pct": cat["target_pct"],
            "sort_order": cat["sort_order"],
            "subcategories": subcats_by_category.get(cat["id"], []),
            "tickers": sorted(cat_tickers, key=lambda x: x["ticker"]),
            "actual_value": cat_value,
            "actual_pct": (cat_value / total_value * 100) if total_value else 0,
            "monthly_income": cat_monthly_income,
            "current_yield": (cat_monthly_income * 12 / cat_value * 100) if cat_value > 0 else 0,
            "weekly_value": cat_weekly_value,
            "weekly_income": cat_weekly_income,
            "weekly_value_pct": (cat_weekly_value / cat_value * 100) if cat_value > 0 else 0,
            "nav_risk_value_pct": (cat_nav_risk_value / cat_value * 100) if cat_value > 0 else 0,
            "nav_risk_count": sum(1 for t in cat_tickers if t["nav_risk"]),
            "largest_holding_pct": cat_largest_holding_pct,
            "income_concentration_pct": cat_income_concentration_pct,
            "weighted_gain_loss_pct": weighted_gain_loss,
        })

    unallocated = []
    for h in all_holdings:
        if h["ticker"] not in assigned_tickers:
            h_value = float(h["current_value"] or 0)
            h_monthly_income = float(h["approx_monthly_income"] or 0)
            h_freq = str(h["div_frequency"] or "").strip().upper()
            h_nav_risk = bool(_is_nav_erosion_candidate(
                h["ticker"],
                h["description"] or "",
                h["classification_type"] or "",
            )) or str(h["nav_erosion_scope"] or "").strip().lower() == "test"
            unallocated.append({
                "ticker": h["ticker"],
                "description": h["description"],
                "classification_type": h["classification_type"],
                "quantity": float(h["quantity"] or 0),
                "current_price": float(h["current_price"] or 0),
                "current_value": h_value,
                "monthly_income": h_monthly_income,
                "current_yield": (h_monthly_income * 12 / h_value * 100) if h_value > 0 else 0,
                "div_frequency": h["div_frequency"],
                "weekly": h_freq in {"W", "52", "WEEKLY"},
                "nav_erosion_scope": h["nav_erosion_scope"] or "auto",
                "nav_risk": h_nav_risk,
                "gain_or_loss_percentage": float(h["gain_or_loss_percentage"] or 0),
            })
    unallocated.sort(key=lambda x: x["ticker"])

    conn.close()
    return jsonify({
        "categories": categories,
        "unallocated": unallocated,
        "total_value": total_value,
        "monthly_income": total_monthly_income,
        "portfolio_yield": (total_monthly_income * 12 / total_value * 100) if total_value else 0,
        "weekly_value": weekly_value,
        "weekly_income": weekly_income,
        "weekly_value_pct": (weekly_value / total_value * 100) if total_value else 0,
    })


@app.route("/api/categories/owner-target-reference", methods=["GET"])
def owner_target_reference():
    """Return read-only subaccount target weights for the Owner categories page."""
    if _request_aggregate_id() is not None or get_profile_id() != 1:
        return jsonify({
            "is_owner": False,
            "profiles": [],
            "rows": [],
            "total_value": 0,
            "weighted_total_pct": None,
        })

    conn = get_connection()
    source_ids = _get_owner_source_profile_ids(conn)
    if not source_ids:
        conn.close()
        return jsonify({
            "is_owner": True,
            "profiles": [],
            "rows": [],
            "total_value": 0,
            "weighted_total_pct": None,
        })

    placeholders = ",".join("?" * len(source_ids))
    profile_rows = conn.execute(
        f"SELECT id, name FROM profiles WHERE id IN ({placeholders})",
        source_ids,
    ).fetchall()
    profile_names = {
        int(row["id"]): row["name"]
        for row in profile_rows
    }

    value_rows = conn.execute(
        f"""SELECT profile_id, COALESCE(SUM(current_value), 0) AS total_value
            FROM all_account_info
            WHERE profile_id IN ({placeholders}) AND IFNULL(quantity, 0) > 0
            GROUP BY profile_id""",
        source_ids,
    ).fetchall()
    values_by_profile = {
        int(row["profile_id"]): float(row["total_value"] or 0)
        for row in value_rows
    }

    target_rows = conn.execute(
        f"""SELECT profile_id, name, target_pct, sort_order
            FROM categories
            WHERE profile_id IN ({placeholders})
            ORDER BY sort_order, name""",
        source_ids,
    ).fetchall()
    conn.close()

    targets_by_category = {}
    category_order = {}
    for row in target_rows:
        name = (row["name"] or "").strip()
        if not name:
            continue
        profile_id = int(row["profile_id"])
        target = row["target_pct"]
        targets_by_category.setdefault(name, {})[profile_id] = (
            None if target is None else float(target)
        )
        sort_order = int(row["sort_order"] or 0)
        category_order[name] = min(category_order.get(name, sort_order), sort_order)

    profiles = []
    for pid in source_ids:
        account_targets = [
            targets.get(pid)
            for targets in targets_by_category.values()
            if targets.get(pid) is not None
        ]
        target_total = sum(account_targets)
        profiles.append({
            "id": pid,
            "name": profile_names.get(pid, f"Profile {pid}"),
            "total_value": values_by_profile.get(pid, 0),
            "target_total_pct": target_total,
            "has_targets": target_total > 0.0001,
        })

    total_value = sum(profile["total_value"] for profile in profiles)
    rows = []
    for category in sorted(targets_by_category, key=lambda name: (category_order.get(name, 0), name.lower())):
        targets = targets_by_category[category]
        if not any(target is not None for target in targets.values()):
            continue
        weighted = None
        if total_value > 0:
            weighted = sum(
                values_by_profile.get(pid, 0) * float(targets.get(pid) or 0) / 100
                for pid in source_ids
            ) / total_value * 100
        rows.append({
            "category": category,
            "targets": {str(pid): targets.get(pid) for pid in source_ids},
            "weighted_guide_pct": weighted,
            "missing_profile_ids": [
                pid for pid in source_ids if targets.get(pid) is None
            ],
        })

    weighted_total = None
    if rows and total_value > 0:
        weighted_total = sum(row["weighted_guide_pct"] or 0 for row in rows)

    return jsonify({
        "is_owner": True,
        "profiles": profiles,
        "rows": rows,
        "total_value": total_value,
        "weighted_total_pct": weighted_total,
    })


@app.route("/api/categories", methods=["POST"])
def create_category():
    aggregate_error = _reject_aggregate_category_write()
    if aggregate_error:
        return aggregate_error
    profile_id = get_profile_id()
    data = request.get_json()
    name = (data.get("name") or "").strip()
    if not name:
        return jsonify({"error": "Name is required"}), 400
    target_pct = data.get("target_pct")
    conn = get_connection()
    max_order = conn.execute(
        "SELECT COALESCE(MAX(sort_order), -1) + 1 as n FROM categories WHERE profile_id = ?",
        (profile_id,),
    ).fetchone()["n"]
    try:
        conn.execute(
            "INSERT INTO categories (name, target_pct, profile_id, sort_order) VALUES (?, ?, ?, ?)",
            (name, target_pct, profile_id, max_order),
        )
        conn.commit()
    except Exception:
        conn.close()
        return jsonify({"error": f"Category '{name}' already exists"}), 409
    conn.close()
    return jsonify({"message": f"Category '{name}' created"})


