@app.route("/api/tax-report/overrides", methods=["PUT"])
def tax_report_set_override():
    """Body: {ticker, year (0 = all years), treatment in qualified|ordinary|roc|split|default}.
    Treatment of 'default' deletes the override."""
    profile_id = get_profile_id()
    data = request.get_json(force=True) or {}
    ticker = (data.get("ticker") or "").strip().upper()
    treatment = (data.get("treatment") or "").strip().lower()
    try:
        year = int(data.get("year", 0))
    except (TypeError, ValueError):
        return jsonify({"error": "year must be an integer"}), 400
    if not ticker:
        return jsonify({"error": "ticker is required"}), 400
    if treatment not in ("qualified", "ordinary", "roc", "split", "default"):
        return jsonify({"error": "treatment must be qualified, ordinary, roc, split, or default"}), 400

    split_defaults = {
        "qualified": (100.0, 0.0, 0.0),
        "ordinary": (0.0, 100.0, 0.0),
        "roc": (0.0, 0.0, 100.0),
    }
    if treatment == "split":
        try:
            qualified_pct = float(data.get("qualified_pct", 0))
            ordinary_pct = float(data.get("ordinary_pct", 0))
            roc_pct = float(data.get("roc_pct", 0))
        except (TypeError, ValueError):
            return jsonify({"error": "split percentages must be numbers"}), 400
        if min(qualified_pct, ordinary_pct, roc_pct) < 0 or max(qualified_pct, ordinary_pct, roc_pct) > 100:
            return jsonify({"error": "split percentages must be between 0 and 100"}), 400
        if abs((qualified_pct + ordinary_pct + roc_pct) - 100.0) > 0.01:
            return jsonify({"error": "qualified, ordinary, and ROC percentages must sum to 100"}), 400
    else:
        qualified_pct, ordinary_pct, roc_pct = split_defaults.get(treatment, (None, None, None))

    total_amount = data.get("total_amount")
    if total_amount in ("", None):
        total_amount = None
    else:
        try:
            total_amount = float(total_amount)
        except (TypeError, ValueError):
            return jsonify({"error": "total amount must be a number"}), 400
        if total_amount < 0:
            return jsonify({"error": "total amount cannot be negative"}), 400

    conn = get_connection()
    try:
        if treatment == "default":
            conn.execute(
                "DELETE FROM dividend_tax_overrides WHERE ticker = ? AND profile_id = ? AND year = ?",
                (ticker, profile_id, year),
            )
        else:
            conn.execute(
                "INSERT INTO dividend_tax_overrides (ticker, profile_id, year, treatment, qualified_pct, ordinary_pct, roc_pct, total_amount) "
                "VALUES (?, ?, ?, ?, ?, ?, ?, ?) "
                "ON CONFLICT(ticker, profile_id, year) DO UPDATE SET "
                "treatment = excluded.treatment, qualified_pct = excluded.qualified_pct, "
                "ordinary_pct = excluded.ordinary_pct, roc_pct = excluded.roc_pct, "
                "total_amount = excluded.total_amount, "
                "updated_at = CURRENT_TIMESTAMP",
                (ticker, profile_id, year, treatment, qualified_pct, ordinary_pct, roc_pct, total_amount),
            )
        conn.commit()
        return jsonify({"ok": True})
    finally:
        conn.close()


@app.route("/api/tax-report/export", methods=["GET"])
def tax_report_export():
    """Download CSV for the given year. format=1099div | 8949 | dividends | lots."""
    import io, csv
    profile_id = get_profile_id()
    try:
        year = int(request.args.get("year", "0"))
    except ValueError:
        return jsonify({"error": "year must be an integer"}), 400
    if year <= 0:
        return jsonify({"error": "year is required"}), 400
    fmt = (request.args.get("format") or "dividends").strip().lower()

    conn = get_connection()
    try:
        summary = tax_report.build_summary(conn, profile_id, year)
    finally:
        conn.close()

    buf = io.StringIO()
    writer = csv.writer(buf)

    if fmt == "1099div":
        writer.writerow(["Box", "Description", "Amount"])
        p = summary["form_1099_div_preview"]
        writer.writerow(["1a", "Total Ordinary Dividends", p["box_1a_total_ordinary"]])
        writer.writerow(["1b", "Qualified Dividends", p["box_1b_qualified"]])
        writer.writerow(["3", "Nondividend Distributions (ROC)", p["box_3_nondividend_distributions"]])
        filename = f"1099-div-preview-{year}.csv"
    elif fmt == "8949":
        writer.writerow(["Description", "Date Acquired", "Date Sold", "Proceeds",
                         "Cost Basis", "Gain/Loss", "Term", "Holding Days"])
        for lot in summary["realized"]["lots"]:
            writer.writerow([
                f"{lot['shares']} sh {lot['ticker']}",
                lot["buy_date"] or "",
                lot["sell_date"] or "",
                lot["proceeds"],
                lot["cost"],
                lot["gain"],
                "Long-Term" if lot["term"] == "LT" else "Short-Term",
                lot["holding_days"] if lot["holding_days"] is not None else "",
            ])
        filename = f"form-8949-preview-{year}.csv"
    elif fmt == "lots":
        writer.writerow(["Ticker", "Shares", "Buy Date", "Buy Price", "Sell Date",
                         "Sell Price", "Proceeds", "Cost", "Gain/Loss", "Term",
                         "Holding Days"])
        for lot in summary["realized"]["lots"]:
            writer.writerow([
                lot["ticker"], lot["shares"],
                lot["buy_date"] or "", lot["buy_price"],
                lot["sell_date"] or "", lot["sell_price"],
                lot["proceeds"], lot["cost"], lot["gain"], lot["term"],
                lot["holding_days"] if lot["holding_days"] is not None else "",
            ])
        filename = f"realized-lots-{year}.csv"
    else:
        writer.writerow(["Ticker", "Classification", "Treatment", "Override?",
                         "Qualified", "Ordinary", "ROC", "Total", "Payments"])
        for row in summary["dividends"]["by_ticker"]:
            writer.writerow([
                row["ticker"], row.get("classification_type") or "",
                row.get("treatment") or "",
                "Yes" if row.get("is_override") else "",
                round(row.get("qualified", 0), 2),
                round(row.get("ordinary", 0), 2),
                round(row.get("roc", 0), 2),
                round(row.get("total", 0), 2),
                row.get("count", 0),
            ])
        filename = f"dividends-by-ticker-{year}.csv"

    payload = buf.getvalue().encode("utf-8")
    from flask import Response
    return Response(
        payload,
        mimetype="text/csv",
        headers={"Content-Disposition": f"attachment; filename={filename}"},
    )


# ── Growth ─────────────────────────────────────────────────────────────────────

@app.route("/api/growth/data", methods=["GET"])
def growth_data():
    """Portfolio growth charts, heatmap, correlation, and grading."""
    import math
    import warnings
    import numpy as np
    import yfinance as yf
    from grading import grade_portfolio, letter_grade, _sharpe, _sortino, _is_stale_or_dead
    warnings.filterwarnings("ignore")

    def _clean(v):
        """Convert NaN/Inf to None for JSON safety."""
        if v is None:
            return None
        try:
            if math.isnan(v) or math.isinf(v):
                return None
        except (TypeError, ValueError):
            pass
        return v

    profile_id = get_profile_id()
    period = request.args.get("period", "1y")
    benchmark = request.args.get("benchmark", "SPY").upper().strip()
    category_id = request.args.get("category")
    subcategory_id = request.args.get("subcategory")

    if period not in ("1y", "5y", "max"):
        period = "1y"

    conn = get_connection()

    # Fetch holdings (optionally filtered by category and/or sub-category).
    # A selected category includes all of its holdings; a selected sub-category
    # includes only its holdings. The two selections are OR-combined.
    cat_ids = [int(c) for c in category_id.split(",") if c.strip().isdigit()] if category_id else []
    sub_ids = [int(s) for s in subcategory_id.split(",") if s.strip().isdigit()] if subcategory_id else []
    if cat_ids or sub_ids:
        conds, qparams = [], [profile_id]
        if cat_ids:
            conds.append(f"tc.category_id IN ({','.join('?' * len(cat_ids))})")
            qparams += cat_ids
        if sub_ids:
            conds.append(f"tc.subcategory_id IN ({','.join('?' * len(sub_ids))})")
            qparams += sub_ids
        rows = conn.execute(
            f"""SELECT DISTINCT a.ticker, a.quantity, a.current_value
               FROM all_account_info a
               JOIN ticker_categories tc ON a.ticker = tc.ticker AND a.profile_id = tc.profile_id
               WHERE a.profile_id = ? AND ({' OR '.join(conds)})
                 AND a.purchase_value > 0 AND a.quantity > 0""",
            qparams,
        ).fetchall()
    else:
        rows = conn.execute(
            """SELECT ticker, quantity, current_value
               FROM all_account_info
               WHERE profile_id = ? AND purchase_value > 0 AND quantity > 0""",
            (profile_id,),
        ).fetchall()

    # Fetch categories (with sub-categories) for the filter dropdown
    cats = conn.execute(
        "SELECT id, name FROM categories WHERE profile_id = ? ORDER BY sort_order, name",
        (profile_id,),
    ).fetchall()
    subcat_rows = conn.execute(
        "SELECT id, category_id, name FROM subcategories WHERE profile_id = ? ORDER BY sort_order, name",
        (profile_id,),
    ).fetchall()
    conn.close()

    subs_by_cat = {}
    for s in subcat_rows:
        subs_by_cat.setdefault(s["category_id"], []).append({"id": s["id"], "name": s["name"]})
    categories = [
        {"id": c["id"], "name": c["name"], "subcategories": subs_by_cat.get(c["id"], [])}
        for c in cats
    ]

    if not rows:
        return jsonify({"error": "No holdings found", "categories": categories}), 400

    tickers = [r["ticker"] for r in rows]
    quantities = {r["ticker"]: float(r["quantity"] or 0) for r in rows}
    values = {r["ticker"]: float(r["current_value"] or 0) for r in rows}
    yahoo_by_symbol = {sym: _yahoo_symbol_for_ticker(sym) for sym in tickers + [benchmark]}
    yahoo_symbols = list(dict.fromkeys(yahoo_by_symbol.values()))

    try:
        raw = _chunked_yf_download(
            " ".join(yahoo_symbols), period=period, auto_adjust=True,
            actions=True, progress=False
        )
        if raw.empty:
            return jsonify({"error": "No price data"}), 500
    except Exception as e:
        return jsonify({"error": str(e)}), 500

    # Parse close prices and dividends
    if isinstance(raw.columns, pd.MultiIndex):
        close = raw["Close"].dropna(how="all")
        divs = raw["Dividends"].fillna(0) if "Dividends" in raw.columns.get_level_values(0) else pd.DataFrame(0, index=close.index, columns=close.columns)
    else:
        close = raw[["Close"]].dropna(how="all")
        close.columns = [yahoo_symbols[0]]
        divs = raw[["Dividends"]].fillna(0) if "Dividends" in raw.columns else pd.DataFrame(0, index=close.index, columns=[yahoo_symbols[0]])
        divs.columns = [yahoo_symbols[0]]

    # Convert Yahoo-specific symbols (e.g. BRK-B, CODI-PB) back to the app's
    # tickers, and ignore empty download columns so one failed ticker cannot
    # turn the whole portfolio series into NaN.
    close_by_ticker = pd.DataFrame(index=close.index)
    divs_by_ticker = pd.DataFrame(index=close.index)
    for symbol, yahoo_symbol in yahoo_by_symbol.items():
        if yahoo_symbol not in close.columns:
            continue
        symbol_close = close[yahoo_symbol].dropna()
        if len(symbol_close) < 2:
            continue
        close_by_ticker[symbol] = close[yahoo_symbol]
        if yahoo_symbol in divs.columns:
            divs_by_ticker[symbol] = divs[yahoo_symbol]
        else:
            divs_by_ticker[symbol] = 0
    close = close_by_ticker.dropna(how="all")
    divs = divs_by_ticker.reindex(close.index).fillna(0)

    # Filter to tickers actually present in data
    available_tickers = [t for t in tickers if t in close.columns and len(close[t].dropna()) >= 2]
    if not available_tickers:
        return jsonify({"error": "No price data for holdings"}), 500

    # ── Portfolio value series (price-only and total return) ──
    first_valid = close[available_tickers].dropna(how="all").index[0]
    close_aligned = close[available_tickers].loc[first_valid:].ffill().bfill()
    divs_aligned = divs[available_tickers].loc[first_valid:].fillna(0) if set(available_tickers).issubset(divs.columns) else pd.DataFrame(0, index=close_aligned.index, columns=available_tickers)

    # Cumulative dividends per share
    cum_divs = divs_aligned.cumsum()

    # Portfolio price-only value
    port_price = pd.Series(0.0, index=close_aligned.index)
    port_total = pd.Series(0.0, index=close_aligned.index)
    for t in available_tickers:
        q = quantities.get(t, 0)
        port_price += close_aligned[t] * q
        port_total += (close_aligned[t] + cum_divs[t]) * q

    # Normalize to 100
    p0 = port_price.iloc[0]
    t0 = port_total.iloc[0]
    port_price_norm = (port_price / p0 * 100) if p0 > 0 else port_price
    port_total_norm = (port_total / t0 * 100) if t0 > 0 else port_total

    # ── Benchmark series ──
    bench_price_norm = pd.Series(dtype=float)
    bench_total_norm = pd.Series(dtype=float)
    if benchmark in close.columns:
        bc = close[benchmark].loc[first_valid:].ffill().bfill()
        bd = divs[benchmark].loc[first_valid:].fillna(0) if benchmark in divs.columns else pd.Series(0, index=bc.index)
        bc_cum_div = bd.cumsum()
        b0 = bc.iloc[0]
        bench_price_norm = (bc / b0 * 100) if b0 > 0 else bc
        bench_total_norm = ((bc + bc_cum_div) / b0 * 100) if b0 > 0 else bc

    dates_str = [d.strftime("%Y-%m-%d") for d in port_price_norm.index]

    # ── Per-ticker returns for bar chart ──
    def pct_return(series, n):
        if len(series) < n + 1:
            return None
        v = float((series.iloc[-1] / series.iloc[-n] - 1) * 100)
        return _clean(round(v, 2))

    def ytd_return(series):
        yr = series.index[-1].year
        yr_start = series.loc[series.index >= f"{yr}-01-01"]
        if len(yr_start) < 2:
            return None
        v = float((yr_start.iloc[-1] / yr_start.iloc[0] - 1) * 100)
        return _clean(round(v, 2))

    windows = {"1M": 21, "3M": 63, "6M": 126, "1Y": 252}
    ticker_returns = []
    for t in available_tickers:
        tc = close_aligned[t]
        row = {"ticker": t}
        for label, n in windows.items():
            row[label] = pct_return(tc, n)
        row["YTD"] = ytd_return(tc)
        ticker_returns.append(row)
    ticker_returns.sort(key=lambda r: r.get("1Y") or 0, reverse=True)

    # ── Heatmap ──
    heatmap_windows = {"1D": 1, "7D": 5, "1M": 21, "3M": 63, "6M": 126, "1Y": 252}
    heatmap_tickers = [r["ticker"] for r in ticker_returns]
    heatmap_labels = list(heatmap_windows.keys()) + ["YTD"]
    heatmap_values = []
    for t in heatmap_tickers:
        tc = close_aligned[t]
        row = []
        for label, n in heatmap_windows.items():
            row.append(pct_return(tc, n))
        row.append(ytd_return(tc))
        heatmap_values.append(row)

    # ── Correlation matrix ──
    daily_returns = close_aligned[available_tickers].pct_change().dropna(how="all")
    corr = daily_returns.corr()
    corr_tickers = list(corr.columns)
    corr_matrix = [[_clean(round(float(corr.iloc[i, j]), 3)) for j in range(len(corr_tickers))] for i in range(len(corr_tickers))]

    # ── Portfolio grade ──
    grade_info = {}
    if len(available_tickers) >= 2 and len(daily_returns) >= 30:
        # Drop delisted / flat-lined / penny-stock series from the overall grade
        live_tickers = [
            t for t in available_tickers
            if not _is_stale_or_dead(close_aligned[t].dropna(), daily_returns[t])
        ]
        if not live_tickers:
            live_tickers = available_tickers  # fallback
        weights_arr = np.array([values.get(t, 0.0) for t in live_tickers])
        bench_ret = close[benchmark].loc[first_valid:].ffill().pct_change().dropna() if benchmark in close.columns else None
        returns_for_grade = daily_returns[live_tickers]
        pm = grade_portfolio(returns_for_grade, weights_arr, bench_ret)
        g = pm.get("grade", {})
        grade_info = {
            "overall": g.get("overall", "N/A"),
            "score": _clean(g.get("score")),
            "sharpe": _clean(pm.get("sharpe")),
            "sortino": _clean(pm.get("sortino")),
        }

    # ── Benchmark metrics ──
    benchmark_metrics = {}
    if benchmark in close.columns:
        bc_full = close[benchmark].loc[first_valid:].dropna()
        benchmark_metrics = {
            "sharpe": _clean(_sharpe(bc_full)),
            "sortino": _clean(_sortino(bc_full)),
        }

    def _clean_series(s):
        return [_clean(round(float(v), 2)) for v in s]

    return jsonify(
        portfolio_price={"dates": dates_str, "values": _clean_series(port_price_norm)},
        portfolio_total={"dates": dates_str, "values": _clean_series(port_total_norm)},
        benchmark_price={"dates": [d.strftime("%Y-%m-%d") for d in bench_price_norm.index] if len(bench_price_norm) else [], "values": _clean_series(bench_price_norm)},
        benchmark_total={"dates": [d.strftime("%Y-%m-%d") for d in bench_total_norm.index] if len(bench_total_norm) else [], "values": _clean_series(bench_total_norm)},
        benchmark_ticker=benchmark,
        ticker_returns=ticker_returns,
        heatmap={"tickers": heatmap_tickers, "windows": heatmap_labels, "values": heatmap_values},
        correlation={"tickers": corr_tickers, "matrix": corr_matrix},
        grade=grade_info,
        benchmark_metrics=benchmark_metrics,
        categories=categories,
    )


# ── ETF Screen ─────────────────────────────────────────────────────────────────

def _blend_price_drip(close_series, divs_series, frac, track_cash=True):
    """Simulate reinvestment of dividends.

    frac=0 → price + cash dividends (no reinvestment)
    frac=1 → full DRIP (all dividends reinvested)
    Returns a pandas Series normalised to 100 at start.
    """
    shares = 1.0
    cash_divs = 0.0
    start_price = float(close_series.iloc[0])
    vals = []
    for i in range(len(close_series)):
        price = float(close_series.iloc[i])
        d = float(divs_series.iloc[i]) if i < len(divs_series) else 0.0
        if d > 0 and price > 0:
            reinvest = d * shares * frac
            if track_cash:
                cash_divs += d * shares * (1 - frac)
            shares += reinvest / price
        vals.append((shares * price + cash_divs) / start_price * 100)
    return pd.Series(vals, index=close_series.index)


def _series_return(values, default=None):
    if not values:
        return default
    return round(float(values[-1]) - 100, 2)


def _normalized_drawdown(values):
    if not values:
        return None
    series = pd.Series(values, dtype=float)
    running_max = series.cummax()
    drawdown = ((series - running_max) / running_max * 100).dropna()
    if drawdown.empty:
        return None
    return round(float(drawdown.min()), 2)


def _beta_and_corr(fund_close, bench_close):
    """Beta and correlation of a fund vs a benchmark from aligned periodic returns.

    Many newer/option-income ETFs (QQQI, SPYI, JEPQ, ...) have no usable beta on
    Yahoo (it returns 0.0 or None), so we regress the fund's own price returns
    against the benchmark's over the same window. Returns (beta, correlation) with
    beta rounded to two decimals, or None when there isn't enough overlapping data.
    """
    try:
        import numpy as np
        f = pd.Series(fund_close).dropna()
        b = pd.Series(bench_close).dropna()
        if f.empty or b.empty:
            return None
        # Align on common dates first, then take returns so each return pairs
        # the fund and benchmark over the identical span.
        aligned = pd.concat({"f": f, "b": b}, axis=1).dropna()
        fr = aligned["f"].pct_change().dropna()
        br = aligned["b"].pct_change().dropna()
        common = fr.index.intersection(br.index)
        fr, br = fr.loc[common], br.loc[common]
        if len(fr) < 15:
            return None
        var_b = float(np.var(br.values, ddof=1))
        if var_b <= 0:
            return None
        cov = float(np.cov(fr.values, br.values, ddof=1)[0][1])
        sd_f = float(np.std(fr.values, ddof=1))
        sd_b = float(np.std(br.values, ddof=1))
        corr = cov / (sd_f * sd_b) if sd_f > 0 and sd_b > 0 else 0.0
        return round(cov / var_b, 2), corr
    except Exception:
        return None


def _best_fit_beta(fund_close, benchmarks, primary="SPY", min_corr=0.3):
    """Pick the benchmark the fund tracks most closely and return its beta.

    `benchmarks` is a list of (name, close_series). We pick whichever has the
    highest *signed* correlation (a negative correlation is never a good fit),
    but only when it clears `min_corr` — otherwise we fall back to the primary
    benchmark (SPY), the standard equity proxy. SPY and QQQ are themselves ~90%
    correlated, so correlation barely separates them; without the floor, tiny
    noise routes weakly-correlated names (JNJ, KO) to whichever index they
    happen to anti-correlate with, yielding a misleading negative beta. This
    keeps clearly Nasdaq-driven instruments (QQQI, JEPQ, NVDA...) on QQQ while
    routing broad/defensive names to SPY. Returns (beta, benchmark_name), or
    (None, None) when no regression is possible.
    """
    results = {}
    for name, bench_close in benchmarks:
        res = _beta_and_corr(fund_close, bench_close)
        if res is not None:
            results[name] = res  # (beta, corr)
    if not results:
        return None, None
    best_name = max(results, key=lambda n: results[n][1])  # highest signed corr
    if results[best_name][1] < min_corr and primary in results:
        best_name = primary
    return results[best_name][0], best_name


def _capture_deltas(fund_close, bench_close, min_days=10):
    """Approximate effective delta vs the underlying, split by market direction.

    Regress the fund's daily returns on the benchmark's separately for up-days
    and down-days. The two slopes are the fund's sensitivity (≈ delta) when the
    underlying rises vs falls — exposing the covered-call asymmetry (negative
    gamma) that a single symmetric beta hides: option-income funds tend to show
    a lower up-delta (capped upside) than down-delta (fuller downside). This is
    an empirical proxy from prices, NOT the fund's true option-greek delta.
    Returns (delta_up, delta_down), each rounded or None when too few days.
    """
    try:
        import numpy as np
        f = pd.Series(fund_close).dropna()
        b = pd.Series(bench_close).dropna()
        aligned = pd.concat({"f": f, "b": b}, axis=1).dropna()
        rets = pd.concat({"f": aligned["f"].pct_change(), "b": aligned["b"].pct_change()}, axis=1).dropna()

        def _slope(sub):
            if len(sub) < min_days:
                return None
            var_b = float(np.var(sub["b"].values, ddof=1))
            if var_b <= 0:
                return None
            cov = float(np.cov(sub["f"].values, sub["b"].values, ddof=1)[0][1])
            return round(cov / var_b, 2)

        return _slope(rets[rets["b"] > 0]), _slope(rets[rets["b"] < 0])
    except Exception:
        return None, None


@app.route("/api/etf-screen/data")
def etf_screen_data():
    """Return OHLCV + return data for one or more tickers."""
    import yfinance as yf
    from grading import _sharpe, _sortino

    ticker = request.args.get("ticker", "").strip().upper()
    extra = request.args.get("extra", "").strip()
    period = request.args.get("period", "1y")
    mode = request.args.get("mode", "ohlcv")  # ohlcv | total | price | pricediv | both | all3 | all4 | bundle
    reinvest_pct = min(100, max(0, int(request.args.get("reinvest", 100))))
    interval = request.args.get("interval", "")
    # Optional explicit date window. When both are present they override `period`
    # so the chart/returns are computed over exactly the requested span.
    start = request.args.get("start", "").strip()
    end = request.args.get("end", "").strip()
    use_range = bool(start and end)
    # Comparers can prioritize the visible chart/table, then enrich full
    # distribution histories and issuer data through Security Research.
    defer_details = request.args.get("defer_details", "0").lower() in {"1", "true", "yes"}

    # yfinance's `period` only accepts a fixed set of strings (1mo/3mo/6mo/ytd/
    # 1y/2y/5y/10y/max). 3Y and 4Y aren't supported, so translate them into an
    # explicit date window and let the existing range machinery handle them.
    if not use_range and period in ("3y", "4y"):
        years = int(period[0])
        today = datetime.date.today()
        start = (today - datetime.timedelta(days=365 * years)).strftime("%Y-%m-%d")
        end = today.strftime("%Y-%m-%d")
        use_range = True

    if not ticker:
        return jsonify(error="ticker is required"), 400

    # Serve a recent identical request straight from cache. The query string
    # (including the Refresh button's nonce) is the key, so a manual refresh
    # naturally misses and re-fetches.
    _resp_cache_key = request.full_path
    _cached_resp = _cache_get(_ETF_SCREEN_DATA_CACHE, _resp_cache_key, _ETF_SCREEN_DATA_TTL_SEC)
    if _cached_resp is not None:
        return jsonify(_cached_resp)

    def _end_exclusive(end_str):
        """yfinance `end` is exclusive — bump by one day to include the end date."""
        try:
            d = datetime.datetime.strptime(end_str, "%Y-%m-%d") + datetime.timedelta(days=1)
            return d.strftime("%Y-%m-%d")
        except Exception:
            return end_str

    def _range_kwargs():
        """Download kwargs for the requested window (explicit dates or period)."""
        if use_range:
            return {"start": start, "end": _end_exclusive(end)}
        return {"period": period}

    # Collect all symbols
    symbols = [ticker]
    if extra:
        for s in extra.split(","):
            s = s.strip().upper()
            if s and s not in symbols:
                symbols.append(s)
    yahoo_by_symbol = {sym: _yahoo_symbol_for_ticker(sym) for sym in symbols}
    yahoo_symbols = list(dict.fromkeys(yahoo_by_symbol.values()))

    # Auto-select interval
    if not interval:
        if use_range:
            try:
                span_days = (datetime.datetime.strptime(end, "%Y-%m-%d")
                             - datetime.datetime.strptime(start, "%Y-%m-%d")).days
            except Exception:
                span_days = 365
            if span_days <= 365 * 3:
                interval = "1d"
            elif span_days <= 365 * 6:
                interval = "1wk"
            else:
                interval = "1mo"
        else:
            period_intervals = {
                "1mo": "1d", "3mo": "1d", "6mo": "1d",
                "ytd": "1d", "1y": "1d", "2y": "1wk",
                "5y": "1wk", "10y": "1mo", "max": "1mo",
            }
            interval = period_intervals.get(period, "1d")

    # ---------- OHLCV mode (for candlestick / technical chart) ----------
    if mode == "ohlcv":
        dl_ticker = yahoo_by_symbol.get(ticker, ticker)
        try:
            tk = yf.Ticker(dl_ticker)
            df = tk.history(interval=interval, auto_adjust=False, **_range_kwargs())
            if df.empty:
                return jsonify(error=f"No data found for {ticker}"), 404

            df = df.dropna(subset=["Open", "High", "Low", "Close"])
            records = []
            for dt, row in df.iterrows():
                records.append({
                    "date": dt.strftime("%Y-%m-%d %H:%M") if interval in ("1m","2m","5m","15m","30m","60m","90m","1h") else dt.strftime("%Y-%m-%d"),
                    "open": round(float(row["Open"]), 4),
                    "high": round(float(row["High"]), 4),
                    "low": round(float(row["Low"]), 4),
                    "close": round(float(row["Close"]), 4),
                    "volume": int(row["Volume"]),
                })

            info = _cached_yf_info(tk, dl_ticker)

            # Fetch ATM implied volatility from nearest options expiration
            iv_data = None
            try:
                expirations = tk.options
                if expirations:
                    chain = tk.option_chain(expirations[0])
                    last_close = float(df["Close"].iloc[-1])
                    # Find ATM call (closest strike to last close)
                    calls = chain.calls
                    if not calls.empty and "strike" in calls.columns and "impliedVolatility" in calls.columns:
                        calls = calls.dropna(subset=["impliedVolatility"])
                        if not calls.empty:
                            atm_idx = (calls["strike"] - last_close).abs().idxmin()
                            atm_call_iv = float(calls.loc[atm_idx, "impliedVolatility"]) * 100
                            # Also get ATM put
                            puts = chain.puts
                            atm_put_iv = None
                            if not puts.empty and "impliedVolatility" in puts.columns:
                                puts = puts.dropna(subset=["impliedVolatility"])
                                if not puts.empty:
                                    atm_put_idx = (puts["strike"] - last_close).abs().idxmin()
                                    atm_put_iv = float(puts.loc[atm_put_idx, "impliedVolatility"]) * 100
                            # Average call and put IV for ATM IV
                            if atm_put_iv is not None:
                                iv_data = {"atm_iv": round((atm_call_iv + atm_put_iv) / 2, 2),
                                           "call_iv": round(atm_call_iv, 2),
                                           "put_iv": round(atm_put_iv, 2),
                                           "expiration": expirations[0]}
                            else:
                                iv_data = {"atm_iv": round(atm_call_iv, 2),
                                           "call_iv": round(atm_call_iv, 2),
                                           "put_iv": None,
                                           "expiration": expirations[0]}
            except Exception:
                pass  # Options data not available for all tickers

            _ohlcv_payload = {
                "ticker": dl_ticker,
                "requested_ticker": ticker,
                "name": info.get("longName") or info.get("shortName") or ticker,
                "records": records,
                "iv": iv_data,
            }
            _cache_set(_ETF_SCREEN_DATA_CACHE, _resp_cache_key, _ohlcv_payload)
            return jsonify(_ohlcv_payload)
        except Exception as e:
            return jsonify(error=str(e)), 500

    # ---------- Return modes ----------
    frac = reinvest_pct / 100.0
    try:
        # Return-mode and reinvestment changes use the same market history.
        # Cache that raw download independently of the rendered response so
        # toggles only recompute traces instead of going back to Yahoo.
        _market_key = (
            tuple(sorted(yahoo_symbols)),
            interval,
            tuple(sorted(_range_kwargs().items())),
            request.args.get("refresh", "0"),
        )
        market_frames = _cache_get(
            _ETF_SCREEN_MARKET_CACHE,
            _market_key,
            _ETF_SCREEN_MARKET_TTL_SEC,
        )
        if market_frames is None:
            # Download daily data with dividends for return calcs.
            div_df = _chunked_yf_download(yahoo_symbols, interval="1d", auto_adjust=False, actions=True, progress=False, **_range_kwargs())

            # Unadjusted price frame. For daily intervals it's the same download
            # as div_df, so reuse it instead of fetching identical data twice.
            if interval == "1d":
                price_df = div_df
            else:
                price_df = _chunked_yf_download(yahoo_symbols, interval=interval, auto_adjust=False, progress=False, **_range_kwargs())
            _cache_set(_ETF_SCREEN_MARKET_CACHE, _market_key, (div_df, price_df))
        else:
            div_df, price_df = market_frames
        if price_df.empty:
            return jsonify(error="No price data found"), 404

        # Benchmark daily closes for computing beta when Yahoo lacks it. We pull
        # both SPY and QQQ and let each fund regress against whichever it tracks
        # most closely (Nasdaq-like funds -> QQQ, broad funds -> SPY). The
        # benchmark frame is identical across all requests for a given window,
        # so cache it rather than re-downloading per ticker/request.
        BETA_BENCHMARKS = ["SPY", "QQQ"]
        _bench_key = tuple(sorted(_range_kwargs().items()))
        bench_df = _cache_get(_ETF_SCREEN_BENCH_CACHE, _bench_key, _ETF_SCREEN_BENCH_TTL_SEC)
        if bench_df is None:
            try:
                bench_df = _chunked_yf_download(BETA_BENCHMARKS, interval="1d", auto_adjust=False, progress=False, **_range_kwargs())
            except Exception:
                bench_df = pd.DataFrame()
            _cache_set(_ETF_SCREEN_BENCH_CACHE, _bench_key, bench_df)

        result = {
            "mode": mode,
            "reinvest_pct": reinvest_pct,
            "series": {},
            "stats": {},
            "profiles": {},
            "warnings": [],
            "symbol_map": yahoo_by_symbol,
            # Flask's jsonify() alphabetically sorts dict keys by default, so
            # "series"/"profiles" keys can't be trusted to preserve request
            # order (e.g. primary=SPY, extra=QQQ comes back QQQ-then-SPY).
            # This array isn't reordered by that sort, so callers that need
            # to know which symbol is the primary ticker should use it.
            "requested_symbols": list(symbols),
        }
        saved_fund_data = {}
        try:
            lookup_symbols = list(dict.fromkeys(symbols + yahoo_symbols))
            placeholders = ",".join("?" for _ in lookup_symbols)
            conn = get_connection()
            conn.row_factory = __import__("sqlite3").Row
            for row in conn.execute(
                f"""SELECT f.symbol, f.fund_name, f.assets, f.div_yield, f.exp_ratio, f.change_1y,
                          f.annual_div, f.frequency,
                          p.provider
                   FROM etf_provider_funds f
                   JOIN etf_providers p ON p.id = f.provider_id
                   WHERE UPPER(f.symbol) IN ({placeholders})""",
                lookup_symbols,
            ).fetchall():
                saved_fund_data[str(row["symbol"]).upper()] = dict(row)
            for row in conn.execute(
                f"""SELECT ticker, name, price, change_pct, volume, dollar_volume, market_cap,
                          pe_ratio, dividend_yield, expense_ratio, aum, etf_category, etf_strategy,
                          country, updated_at
                   FROM general_scanner_cache
                   WHERE UPPER(ticker) IN ({placeholders})""",
                lookup_symbols,
            ).fetchall():
                current = saved_fund_data.setdefault(str(row["ticker"]).upper(), {})
                updated_at = row["updated_at"]
                is_fresh = False
                try:
                    if updated_at:
                        age = datetime.datetime.utcnow() - datetime.datetime.fromisoformat(str(updated_at).replace("Z", "+00:00").replace("+00:00", ""))
                        is_fresh = age.days <= 7
                except Exception:
                    is_fresh = False
                if is_fresh:
                    current.update({k: row[k] for k in row.keys()})
            conn.close()
        except Exception:
            saved_fund_data = {}

        def _extract_col(df, col, sym):
            """Safely extract a Series from yfinance download (handles multi-level columns)."""
            if col not in df.columns and hasattr(df.columns, 'get_level_values'):
                # Multi-level columns
                if col in df.columns.get_level_values(0):
                    sub = df[col]
                    if isinstance(sub, pd.DataFrame):
                        if sym in sub.columns:
                            return sub[sym].dropna()
                        elif len(sub.columns) == 1:
                            return sub.iloc[:, 0].dropna()
                    return sub.dropna() if isinstance(sub, pd.Series) else pd.Series(dtype=float)
                return pd.Series(dtype=float)
            if col in df.columns:
                s = df[col]
                if isinstance(s, pd.DataFrame):
                    if sym in s.columns:
                        return s[sym].dropna()
                    elif len(s.columns) == 1:
                        return s.iloc[:, 0].dropna()
                    return pd.Series(dtype=float)
                return s.dropna()
            return pd.Series(dtype=float)

        def _fmt_yf_date(value):
            if not value:
                return None
            try:
                if isinstance(value, (int, float)):
                    return datetime.datetime.fromtimestamp(value).strftime("%Y-%m-%d")
                if hasattr(value, "strftime"):
                    return value.strftime("%Y-%m-%d")
                return str(value)[:10]
            except Exception:
                return None

        bench_closes = []
        if not bench_df.empty:
            for bm in BETA_BENCHMARKS:
                bc = _extract_col(bench_df, "Close", bm)
                if not bc.empty:
                    bench_closes.append((bm, bc))

        for sym in symbols:
            dl_sym = yahoo_by_symbol.get(sym, sym)
            close = _extract_col(price_df, "Close", dl_sym)
            div_close = _extract_col(div_df, "Close", dl_sym)
            if div_close.empty:
                div_close = close
            divs_raw = _extract_col(div_df, "Dividends", dl_sym)
            divs = divs_raw.reindex(div_close.index, fill_value=0.0) if not divs_raw.empty else pd.Series(0.0, index=div_close.index)

            if close.empty and div_close.empty:
                try:
                    fallback = yf.Ticker(dl_sym).history(interval="1d", auto_adjust=False, actions=True, **_range_kwargs())
                except Exception:
                    fallback = pd.DataFrame()
                if fallback is not None and not fallback.empty and "Close" in fallback.columns:
                    close = fallback["Close"].dropna()
                    div_close = close
                    divs_raw = fallback["Dividends"].dropna() if "Dividends" in fallback.columns else pd.Series(dtype=float)
                    divs = divs_raw.reindex(div_close.index, fill_value=0.0) if not divs_raw.empty else pd.Series(0.0, index=div_close.index)
                else:
                    result["warnings"].append(f"{sym}: no data available")
                    continue

            # Use div_close (daily) for dates and price normalization so all
            # traces share the same x-axis.  close (from price_df) may use a
            # coarser interval (weekly/monthly) whose length differs from the
            # daily return traces, causing misaligned chart data.
            base = div_close if not div_close.empty else close
            dates = [d.strftime("%Y-%m-%d") for d in base.index]
            norm_price = [round(float(v), 4) for v in (base / float(base.iloc[0]) * 100)]

            # Compute return series based on mode
            traces = {}
            if mode == "price":
                traces["price"] = norm_price
            elif mode == "pricediv":
                pd_series = _blend_price_drip(div_close, divs, 0.0, track_cash=True)
                traces["pricediv"] = [round(v, 4) for v in pd_series.tolist()]
            elif mode == "total":
                tot = _blend_price_drip(div_close, divs, 1.0, track_cash=True)
                traces["total"] = [round(v, 4) for v in tot.tolist()]
            elif mode == "both":
                tot = _blend_price_drip(div_close, divs, 1.0, track_cash=True)
                traces["total"] = [round(v, 4) for v in tot.tolist()]
                traces["price"] = norm_price
            elif mode == "all3":
                traces["price"] = norm_price
                blend = _blend_price_drip(div_close, divs, frac, track_cash=True)
                traces["blend"] = [round(v, 4) for v in blend.tolist()]
                drip = _blend_price_drip(div_close, divs, 1.0, track_cash=True)
                traces["drip"] = [round(v, 4) for v in drip.tolist()]
            elif mode in ("all4", "bundle"):
                traces["price"] = norm_price
                pdiv = _blend_price_drip(div_close, divs, 0.0, track_cash=True)
                traces["pricediv"] = [round(v, 4) for v in pdiv.tolist()]
                blend = _blend_price_drip(div_close, divs, frac, track_cash=True)
                traces["blend"] = [round(v, 4) for v in blend.tolist()]
                drip = _blend_price_drip(div_close, divs, 1.0, track_cash=True)
                traces["drip"] = [round(v, 4) for v in drip.tolist()]

            # Statistics — use base (daily) consistently with traces
            price_ret = round((float(base.iloc[-1]) / float(base.iloc[0]) - 1) * 100, 2)
            # Match stats to the selected/custom total-return path.
            if "total" in traces:
                total_ret = _series_return(traces["total"], price_ret)
                drawdown_basis = traces["total"]
            elif mode == "bundle" and "drip" in traces:
                # A bundle is shared by every display mode, so its comparison
                # statistics consistently represent canonical total return.
                total_ret = _series_return(traces["drip"], price_ret)
                drawdown_basis = traces["drip"]
            elif "blend" in traces:
                total_ret = _series_return(traces["blend"], price_ret)
                drawdown_basis = traces["blend"]
            elif "pricediv" in traces:
                total_ret = _series_return(traces["pricediv"], price_ret)
                drawdown_basis = traces["pricediv"]
            elif "drip" in traces:
                total_ret = _series_return(traces["drip"], price_ret)
                drawdown_basis = traces["drip"]
            else:
                total_ret = price_ret
                drawdown_basis = traces.get("price", norm_price)
            div_contrib = round(total_ret - price_ret, 2)

            # Annualized return
            n_days = (base.index[-1] - base.index[0]).days
            if n_days > 30:
                years = n_days / 365.25
                final_norm = 100 + total_ret
                ann = round(((final_norm / 100) ** (1 / years) - 1) * 100, 2)
            else:
                ann = None

            # Max drawdown for the selected return path, not price-only.
            mdd = _normalized_drawdown(drawdown_basis)
            risk_basis = pd.Series(drawdown_basis, index=base.index[:len(drawdown_basis)]).dropna()
            sharpe = _sharpe(risk_basis)
            sortino = _sortino(risk_basis)
            # Regress the fund's price returns against the best-fitting benchmark
            # for a real beta (Yahoo returns 0.0/None for many option-income ETFs).
            computed_beta, beta_benchmark = _best_fit_beta(base, bench_closes)
            # Approximate effective delta (up-/down-day capture) vs that same
            # underlying — surfaces the covered-call asymmetry beta can't show.
            delta_up = delta_down = None
            if beta_benchmark:
                _bclose = dict(bench_closes).get(beta_benchmark)
                if _bclose is not None:
                    delta_up, delta_down = _capture_deltas(base, _bclose)

            result["series"][sym] = {"dates": dates, "traces": traces}
            result["stats"][sym] = {
                "total_ret": total_ret,
                "price_ret": price_ret,
                "div_contrib": div_contrib,
                "annualized": ann,
                "max_drawdown": mdd,
            }

            try:
                tk_obj = yf.Ticker(dl_sym)
                info = _cached_yf_info(tk_obj, dl_sym)
            except Exception:
                tk_obj = None
                info = {}

            last_price = float(base.iloc[-1]) if not base.empty else None
            prev_close = info.get("previousClose")
            open_price = info.get("open") or info.get("regularMarketOpen")
            day_change_pct = None
            if prev_close and last_price:
                try:
                    day_change_pct = round((last_price / float(prev_close) - 1) * 100, 2)
                except Exception:
                    day_change_pct = None

            assets = info.get("totalAssets") or info.get("totalNetAssets")
            volume = info.get("volume") or info.get("regularMarketVolume")
            dollar_volume = None
            if volume and last_price:
                try:
                    dollar_volume = float(volume) * float(last_price)
                except Exception:
                    dollar_volume = None

            dividend_yield = info.get("yield")
            if dividend_yield is None:
                dividend_yield = info.get("dividendYield")
            saved = saved_fund_data.get(sym) or saved_fund_data.get(dl_sym, {})
            expected_dividend_yield = None
            expected_annual_dividend = None
            expected_yield_source = None
            distribution_history = []
            distribution_source = None
            distribution_frequency = None

            def _set_expected_yield(yield_value=None, annual_dividend=None, source=None):
                nonlocal expected_dividend_yield, expected_annual_dividend, expected_yield_source
                if expected_dividend_yield is not None:
                    return
                try:
                    if yield_value is not None:
                        y = float(yield_value)
                        expected_dividend_yield = round(y if abs(y) <= 1 else y / 100.0, 6)
                    elif annual_dividend is not None and last_price:
                        annual = float(annual_dividend)
                        if annual <= 0:
                            return
                        expected_annual_dividend = round(annual, 6)
                        expected_dividend_yield = round(annual / float(last_price), 6)
                    if expected_dividend_yield is not None:
                        expected_yield_source = source
                except Exception:
                    pass

            description_text = " ".join(str(v or "") for v in (
                saved.get("fund_name"), saved.get("name"), info.get("longName"),
                info.get("shortName"), info.get("fundFamily"), sym,
            ))
            official_snapshot = None
            if not defer_details:
                try:
                    official_snapshot = _fetch_official_distribution_snapshot(dl_sym, description_text)
                except Exception:
                    official_snapshot = None
            if official_snapshot and official_snapshot.get("has_dividend"):
                official_source = official_snapshot.get("source") or "Fund Site"
                official_history = official_snapshot.get("history")
                if hasattr(official_history, "empty") and not official_history.empty:
                    for dt, amt in official_history.items():
                        try:
                            distribution_history.append({
                                "date": dt.strftime("%Y-%m-%d"),
                                "amount": round(float(amt), 4),
                            })
                        except Exception:
                            continue
                    if distribution_history:
                        distribution_source = official_source
                        distribution_frequency = official_snapshot.get("freq")
                _set_expected_yield(official_snapshot.get("distribution_rate_pct"), source=official_source)
                if expected_dividend_yield is None and official_history is not None:
                    try:
                        if hasattr(official_history, "empty") and not official_history.empty:
                            annual_div, _ttm_div, _yield_source = _div_calc_annual_dividend(
                                official_history,
                                official_snapshot.get("freq") or _div_calc_infer_frequency(official_history),
                            )
                            _set_expected_yield(annual_dividend=annual_div, source=official_source)
                    except Exception:
                        pass

            if expected_dividend_yield is None and not defer_details:
                try:
                    provider_profile = _fetch_provider_etf_profile(dl_sym, {
                        "name": saved.get("fund_name") or saved.get("name") or info.get("longName") or info.get("shortName") or sym,
                        "issuer": saved.get("provider") or info.get("fundFamily"),
                        "data_source": saved.get("provider") or "Yahoo Finance",
                    })
                    if provider_profile:
                        _set_expected_yield(
                            provider_profile.get("distribution_rate_pct") or provider_profile.get("estimated_yield_pct"),
                            source=provider_profile.get("data_source") or "Fund Site",
                        )
                except Exception:
                    pass

            _set_expected_yield(annual_dividend=saved.get("annual_div"), source=saved.get("provider"))
            _set_expected_yield(saved.get("div_yield"), source=saved.get("provider"))

            history_divs = (
                divs_raw
                if defer_details
                else (_cached_yf_dividends(tk_obj, dl_sym) if tk_obj is not None else pd.Series(dtype=float))
            )
            if history_divs is None or history_divs.empty:
                history_divs = divs_raw
            freq_code = None
            try:
                freq_code = _div_calc_infer_frequency(history_divs)
                annual_div, _ttm_div, yield_source = _div_calc_annual_dividend(history_divs, freq_code)
                _set_expected_yield(annual_dividend=annual_div, source=f"Yahoo Finance ({yield_source})")
            except Exception:
                pass
            if not distribution_history:
                try:
                    yahoo_history = _div_calc_positive_dividends(history_divs)
                    if not yahoo_history.empty:
                        for dt, amt in yahoo_history.items():
                            try:
                                distribution_history.append({
                                    "date": dt.strftime("%Y-%m-%d"),
                                    "amount": round(float(amt), 4),
                                })
                            except Exception:
                                continue
                        if distribution_history:
                            distribution_source = "Yahoo Finance"
                            distribution_frequency = freq_code or _div_calc_infer_frequency(yahoo_history)
                except Exception:
                    pass
            try:
                _set_expected_yield(annual_dividend=info.get("dividendRate"), source="Yahoo Finance (dividendRate)")
            except Exception:
                pass
            _set_expected_yield(dividend_yield, source="Yahoo Finance (yield)")
            expense_ratio = info.get("annualReportExpenseRatio") or info.get("netExpenseRatio")
            pe_ratio = info.get("trailingPE") or info.get("forwardPE")

            result["profiles"][sym] = {
                "symbol": dl_sym,
                "requested_symbol": sym,
                "name": saved.get("fund_name") or saved.get("name") or info.get("longName") or info.get("shortName") or sym,
                "price": round(last_price, 2) if last_price is not None else saved.get("price"),
                "change_pct": day_change_pct if day_change_pct is not None else saved.get("change_pct"),
                "assets": assets or saved.get("assets") or saved.get("aum") or saved.get("market_cap"),
                "expense_ratio": expense_ratio if expense_ratio is not None else (saved.get("expense_ratio") if saved.get("expense_ratio") is not None else saved.get("exp_ratio")),
                "pe_ratio": pe_ratio or saved.get("pe_ratio"),
                "dividend_yield": dividend_yield if dividend_yield is not None else (saved.get("dividend_yield") if saved.get("dividend_yield") is not None else saved.get("div_yield")),
                "expected_dividend_yield": expected_dividend_yield,
                "expected_annual_dividend": expected_annual_dividend,
                "expected_yield_source": expected_yield_source,
                "distribution_history": distribution_history,
                "distribution_source": distribution_source,
                "distribution_frequency": distribution_frequency,
                "volume": volume or saved.get("volume"),
                "dollar_volume": dollar_volume or saved.get("dollar_volume"),
                "open": open_price,
                "previous_close": prev_close,
                "low_price": info.get("dayLow") or info.get("regularMarketDayLow"),
                "high_price": info.get("dayHigh") or info.get("regularMarketDayHigh"),
                "fifty_two_week_low": info.get("fiftyTwoWeekLow"),
                "fifty_two_week_high": info.get("fiftyTwoWeekHigh"),
                "beta": computed_beta if computed_beta is not None else (info.get("beta") or info.get("beta3Year")),
                "beta_benchmark": beta_benchmark if computed_beta is not None else None,
                "delta_up": delta_up,
                "delta_down": delta_down,
                "category": saved.get("etf_category") or saved.get("etf_strategy") or info.get("category"),
                "issuer": saved.get("provider") or info.get("fundFamily"),
                "inception_date": _fmt_yf_date(info.get("fundInceptionDate")),
                "return_1y": saved.get("change_1y") if saved.get("change_1y") is not None else total_ret,
                "return_annualized": ann,
                "max_drawdown": mdd,
                "sharpe": sharpe,
                "sortino": sortino,
            }

        _cache_set(_ETF_SCREEN_DATA_CACHE, _resp_cache_key, result)
        return jsonify(result)
    except Exception as e:
        return jsonify(error=str(e)), 500


@app.route("/api/etf-screen/tickers")
def etf_screen_tickers():
    """Return list of portfolio tickers for the quick-pick dropdown."""
    profile_id = get_profile_id()
    conn = get_connection()
    conn.row_factory = __import__("sqlite3").Row
    rows = conn.execute(
        """SELECT ticker, description
           FROM all_account_info WHERE profile_id = ? ORDER BY ticker""",
        (profile_id,),
    ).fetchall()
    conn.close()
    return jsonify(tickers=[dict(r) for r in rows])


# ── Dividend Calendar ──────────────────────────────────────────────────────────

def _yf_div_pay_date(ticker):
    """Fetch next dividend pay date from yfinance. Returns date or None."""
    try:
        import yfinance as yf
        cal = yf.Ticker(ticker).calendar
        if not cal or not isinstance(cal, dict):
            return None
        d = cal.get("Dividend Date")
        if d is None:
            return None
        if hasattr(d, "date"):
            d = d.date()
        elif isinstance(d, str):
            from datetime import datetime as _dtm
            d = _dtm.strptime(d[:10], "%Y-%m-%d").date()
        import datetime as _dtmod
        if not isinstance(d, _dtmod.date):
            return None
        if d < _dtmod.date.today() - _dtmod.timedelta(days=548):
            return None
        return d
    except Exception:
        return None


def _build_cal_events():
    """Build dividend calendar events from all_account_info."""
    from datetime import datetime, timedelta

    FREQ_LABEL = {
        "M": "monthly", "52": "weekly", "W": "weekly",
        "Q": "quarterly", "SA": "semi-annual", "A": "annual",
    }
    FREQ_COLOR = {
        "M": "#00c9a7", "52": "#FFD700", "W": "#FFD700",
        "Q": "#7ecfff", "SA": "#f0a0ff", "A": "#f0a0ff",
    }
    profile_id = get_profile_id()
    conn = get_connection()
    try:
        df = pd.read_sql("""
            SELECT ticker, description, ex_div_date, div_pay_date, div, div_frequency,
                   quantity, current_price, estim_payment_per_year
            FROM all_account_info
            WHERE ex_div_date IS NOT NULL
              AND ex_div_date NOT IN ('', '--')
              AND current_price IS NOT NULL
              AND COALESCE(quantity, 0) > 0
              AND profile_id = ?
            ORDER BY ticker
        """, conn, params=[profile_id])
    except Exception:
        conn.close()
        return []
    conn.close()

    today_d = datetime.today().date()
    cache_columns = (
        "ticker", "description", "ex_div_date", "div_pay_date", "div", "div_frequency",
        "quantity", "current_price", "estim_payment_per_year",
    )
    cache_rows = df.to_dict("records")
    cache_key = (
        profile_id,
        today_d.isoformat(),
        _rows_signature(cache_rows, cache_columns),
    )
    cached = _cache_get(_DIVIDEND_CALENDAR_CACHE, cache_key)
    if cached is not None:
        return cached

    official_cache = {}

    def official_snapshot_for(ticker, description):
        key = ((ticker or "").strip().upper(), description or "")
        if key not in official_cache:
            try:
                official_cache[key] = _fetch_official_distribution_snapshot(key[0], key[1])
            except Exception:
                official_cache[key] = None
        return official_cache[key]

    # Pre-fetch yfinance pay dates for non-weekly tickers
    yf_pay_dates = {}
    for tkr in df.loc[~df["div_frequency"].isin(["52", "W"]), "ticker"].tolist():
        pd_date = _yf_div_pay_date(tkr)
        if pd_date:
            yf_pay_dates[tkr] = pd_date

    events = []

    conn = get_connection()
    lag_pattern_map = _build_dividend_lag_patterns(conn)
    conn.close()

    for _, row in df.iterrows():
        ticker = str(row["ticker"] or "").strip().upper()
        description = str(row["description"]) if pd.notna(row["description"]) else ""
        freq = str(row["div_frequency"]).strip() if pd.notna(row["div_frequency"]) else ""
        amount = float(row["div"]) if pd.notna(row["div"]) and row["div"] else None
        quantity = float(row["quantity"]) if pd.notna(row["quantity"]) and row["quantity"] else 0.0
        current_price = float(row["current_price"]) if pd.notna(row["current_price"]) and row["current_price"] else 0.0
        annual_income = (
            float(row["estim_payment_per_year"])
            if pd.notna(row["estim_payment_per_year"]) and row["estim_payment_per_year"]
            else 0.0
        )
        ex_value = row["ex_div_date"]
        pay_value = row.get("div_pay_date")
        official_pay_ts = None
        official_lag = None

        official = official_snapshot_for(ticker, description)
        if official and official.get("has_dividend"):
            official_freq = (official.get("freq") or "").strip().upper()
            if official_freq:
                freq = official_freq
            try:
                official_div = official.get("div")
                if official_div is not None and float(official_div) > 0:
                    amount = float(official_div)
            except Exception:
                pass
            if official.get("ex_div_date"):
                ex_value = official.get("ex_div_date")
            if official.get("div_pay_date"):
                pay_value = official.get("div_pay_date")
                official_pay_ts = _parse_timestamp_value(pay_value)
            lag_val = official.get("pay_lag_days")
            if lag_val is not None:
                try:
                    official_lag = int(lag_val)
                except (TypeError, ValueError):
                    official_lag = None

        dt_ts = _parse_timestamp_value(ex_value)
        if dt_ts is None:
            continue
        dt = dt_ts.date()
        stored_pay_ts = _parse_timestamp_value(pay_value)

        # Project ex-div date forward to next upcoming occurrence
        # Owner (pid==1) non-weekly dates come from Excel import and are kept as-is
        # Weekly payers always project forward since the next ex-div is always ~1 week away
        threshold = today_d - timedelta(days=1)
        is_weekly = freq in ("52", "W")
        cycle_steps = 0
        if (is_weekly or profile_id != 1) and dt < threshold and freq:
            while dt < threshold:
                next_dt = _advance_dividend_cycle(pd.Timestamp(dt), freq, 1)
                if next_dt is None:
                    break
                dt = next_dt.date()
                cycle_steps += 1

        # Determine pay date
        pay_estimated = True

        if official_pay_ts is not None and cycle_steps == 0:
            # Issuer-published pay dates supersede Yahoo calendar values.
            pay_dt = official_pay_ts
            pay_estimated = False
        elif official_lag is not None:
            # Project a future pay date using the issuer's real ex->pay lag.
            pay_dt = _next_business_day(pd.Timestamp(dt) + pd.Timedelta(days=official_lag))
        elif freq in ("52", "W"):
            # Weekly: pay 1 business day after ex-div
            pay_dt = _estimate_dividend_pay_timestamp(dt, freq)
        elif ticker in yf_pay_dates:
            # Confirmed pay date from Yahoo Finance
            pay_dt = yf_pay_dates[ticker]
            pay_estimated = False
        else:
            projected_pay = _estimate_dividend_pay_timestamp(dt, freq, stored_pay_ts, cycle_steps)
            pay_dt = projected_pay or _estimate_dividend_pay_from_pattern(
                dt,
                freq,
                pattern=lag_pattern_map.get(ticker),
                ticker=ticker,
                description=description,
            )
            if pay_dt is None:
                continue

        events.append({
            "ticker":        ticker,
            "description":   description,
            "date":          dt.isoformat(),
            "day":           str(dt.day),
            "month":         dt.strftime("%b"),
            "weekday":       dt.strftime("%a"),
            "amount":        round(amount, 4) if amount is not None else None,
            "quantity":      round(quantity, 6),
            "current_price": round(current_price, 4) if current_price > 0 else None,
            "annual_income": round(annual_income, 2) if annual_income > 0 else None,
            "freq":          freq,
            "freq_label":    FREQ_LABEL.get(freq, freq.lower() if freq else ""),
            "color":         FREQ_COLOR.get(freq, "#8899aa"),
            "pay_date":      pay_dt.date().isoformat() if hasattr(pay_dt, "date") else pay_dt.isoformat(),
            "pay_month":     pay_dt.strftime("%b"),
            "pay_day":       str(pay_dt.day),
            "pay_estimated": pay_estimated,
        })

    events.sort(key=lambda e: e["pay_date"])
    _cache_set(_DIVIDEND_CALENDAR_CACHE, cache_key, events)
    return events


@app.route("/api/div-calendar")
def div_calendar():
    """Return dividend calendar events as JSON."""
    from datetime import date
    try:
        events = _build_cal_events()
        return jsonify(events=events, today=date.today().isoformat())
    except Exception as e:
        return jsonify(error=str(e)), 500


# ── Earnings Calendar ──────────────────────────────────────────────────────────

_EARNINGS_TICKER_CACHE = {}
_EARNINGS_TICKER_TTL_SEC = 6 * 60 * 60


def _coerce_earnings_timestamp(value):
    """Convert assorted yfinance/Nasdaq date values to a date object, or None."""
    from datetime import datetime, date
    if value is None:
        return None
    try:
        if pd.isna(value):
            return None
    except Exception:
        pass
    if isinstance(value, date) and not isinstance(value, datetime):
        return value
    if hasattr(value, "to_pydatetime"):
        try:
            return value.to_pydatetime().date()
        except Exception:
            pass
    if isinstance(value, datetime):
        return value.date()
    if isinstance(value, (int, float)):
        try:
            return datetime.utcfromtimestamp(float(value)).date()
        except Exception:
            return None
    if isinstance(value, str):
        s = value.strip()
        if not s:
            return None
        for fmt in ("%Y-%m-%d", "%m/%d/%Y", "%m/%d/%y", "%b %d, %Y", "%B %d, %Y"):
            try:
                return datetime.strptime(s, fmt).date()
            except ValueError:
                continue
        try:
            return pd.to_datetime(s, errors="coerce").date()
        except Exception:
            return None
    return None


def _yf_earnings_info(ticker):
    """Pull next earnings date + last quarter's actual/estimate via yfinance.

    Returns dict or None. Result fields:
      next_date (date or None), eps_estimate, last_date, last_eps_estimate,
      last_eps_actual, last_surprise_pct.
    """
    import yfinance as yf
    from datetime import date

    sym = (ticker or "").strip().upper()
    if not sym:
        return None

    cached = _cache_get(_EARNINGS_TICKER_CACHE, sym, ttl=_EARNINGS_TICKER_TTL_SEC)
    if cached is not None:
        return cached if cached else None

    out = {
        "next_date": None,
        "eps_estimate": None,
        "last_date": None,
        "last_eps_estimate": None,
        "last_eps_actual": None,
        "last_surprise_pct": None,
    }
    found = False

    try:
        tk = yf.Ticker(sym)
    except Exception:
        _cache_set(_EARNINGS_TICKER_CACHE, sym, {})
        return None

    today_d = date.today()

    # Preferred source: earnings_dates DataFrame (history + upcoming).
    try:
        ed = tk.earnings_dates
    except Exception:
        ed = None

    if ed is not None and hasattr(ed, "empty") and not ed.empty:
        try:
            df = ed.copy()
            # Index is timezone-aware Timestamp; pull date components.
            df["_d"] = [
                (idx.date() if hasattr(idx, "date") else _coerce_earnings_timestamp(idx))
                for idx in df.index
            ]
            df = df[df["_d"].notna()]

            def _col(name):
                # Find a column whose name contains `name`, case-insensitive.
                for c in df.columns:
                    if name.lower() in str(c).lower():
                        return c
                return None

            est_col = _col("EPS Estimate")
            act_col = _col("Reported EPS")
            sur_col = _col("Surprise")

            upcoming = df[df["_d"] >= today_d].sort_values("_d")
            if not upcoming.empty:
                row = upcoming.iloc[0]
                out["next_date"] = row["_d"]
                if est_col is not None:
                    val = row.get(est_col)
                    try:
                        if pd.notna(val):
                            out["eps_estimate"] = float(val)
                    except Exception:
                        pass
                found = True

            past = df[df["_d"] < today_d].sort_values("_d")
            if not past.empty:
                row = past.iloc[-1]
                out["last_date"] = row["_d"]
                if est_col is not None:
                    try:
                        v = row.get(est_col)
                        if pd.notna(v):
                            out["last_eps_estimate"] = float(v)
                    except Exception:
                        pass
                if act_col is not None:
                    try:
                        v = row.get(act_col)
                        if pd.notna(v):
                            out["last_eps_actual"] = float(v)
                    except Exception:
                        pass
                if sur_col is not None:
                    try:
                        v = row.get(sur_col)
                        if pd.notna(v):
                            out["last_surprise_pct"] = float(v)
                    except Exception:
                        pass
                # Derive surprise % if missing but actual + estimate present.
                if (
                    out["last_surprise_pct"] is None
                    and out["last_eps_actual"] is not None
                    and out["last_eps_estimate"] is not None
                    and out["last_eps_estimate"] != 0
                ):
                    out["last_surprise_pct"] = (
                        (out["last_eps_actual"] - out["last_eps_estimate"])
                        / abs(out["last_eps_estimate"])
                        * 100.0
                    )
                found = True
        except Exception:
            pass

    # Fallback: calendar dict has "Earnings Date" (list of one or two dates).
    if out["next_date"] is None:
        try:
            cal = tk.calendar
        except Exception:
            cal = None
        if cal is not None:
            ed_val = None
            try:
                if isinstance(cal, dict):
                    ed_val = cal.get("Earnings Date")
                elif hasattr(cal, "loc") and "Earnings Date" in getattr(cal, "index", []):
                    ed_val = cal.loc["Earnings Date"]
                    if hasattr(ed_val, "iloc"):
                        ed_val = ed_val.iloc[0]
            except Exception:
                ed_val = None
            if isinstance(ed_val, (list, tuple)) and ed_val:
                cand = _coerce_earnings_timestamp(ed_val[0])
            else:
                cand = _coerce_earnings_timestamp(ed_val)
            if cand and cand >= today_d:
                out["next_date"] = cand
                found = True

    _cache_set(_EARNINGS_TICKER_CACHE, sym, out if found else {})
    return out if found else None


_EARNINGS_FIELDS = (
    "next_date",
    "eps_estimate",
    "last_date",
    "last_eps_estimate",
    "last_eps_actual",
    "last_surprise_pct",
)


def _empty_earnings_info():
    return {f: None for f in _EARNINGS_FIELDS}


def _merge_earnings_info(primary, fallback):
    """Fill any None fields in `primary` from `fallback` (in place to a new dict)."""
    if not fallback:
        return primary
    if not primary:
        return dict(fallback)
    out = dict(primary)
    for k in _EARNINGS_FIELDS:
        if out.get(k) is None and fallback.get(k) is not None:
            out[k] = fallback[k]
    return out


def _earnings_info_complete(info):
    """True when info has both upcoming and last-quarter data fully populated."""
    if not info:
        return False
    return all(info.get(f) is not None for f in _EARNINGS_FIELDS)


def _safe_float(value):
    if value is None:
        return None
    try:
        s = str(value).strip().replace("$", "").replace(",", "").replace("+", "").replace("%", "")
        if not s or s == "-" or s.upper() in ("NA", "N/A"):
            return None
        return float(s)
    except (ValueError, TypeError):
        return None


def _nasdaq_surprise_info(ticker):
    """Past quarterly results from Nasdaq's earnings-surprise endpoint."""
    import urllib.request
    import urllib.error
    import json
    from datetime import date

    sym = (ticker or "").strip().upper()
    if not sym:
        return None
    cache_key = f"NASDAQ_SURPRISE::{sym}"
    cached = _cache_get(_EARNINGS_TICKER_CACHE, cache_key, ttl=_EARNINGS_TICKER_TTL_SEC)
    if cached is not None:
        return cached if cached else None

    out = _empty_earnings_info()
    url = f"https://api.nasdaq.com/api/company/{sym}/earnings-surprise"
    req = urllib.request.Request(
        url,
        headers={
            "User-Agent": "Mozilla/5.0 (Portfolio Tracking)",
            "Accept": "application/json",
        },
    )
    try:
        with urllib.request.urlopen(req, timeout=6) as resp:
            payload = json.loads(resp.read().decode("utf-8", errors="replace"))
    except Exception:
        _cache_set(_EARNINGS_TICKER_CACHE, cache_key, {})
        return None

    found = False
    try:
        rows = ((payload or {}).get("data") or {}).get("earningsSurpriseTable", {}).get("rows") or []
        today_d = date.today()
        parsed = []
        for r in rows:
            d = _coerce_earnings_timestamp(r.get("dateReported") or r.get("fiscalQtrEnd"))
            if d:
                parsed.append((d, r))
        parsed.sort(key=lambda t: t[0])
        for d, r in reversed(parsed):
            if d < today_d:
                out["last_date"] = d
                out["last_eps_estimate"] = _safe_float(r.get("consensusForecast"))
                out["last_eps_actual"] = _safe_float(r.get("eps"))
                out["last_surprise_pct"] = _safe_float(r.get("percentageSurprise"))
                found = True
                break
    except Exception:
        pass

    _cache_set(_EARNINGS_TICKER_CACHE, cache_key, out if found else {})
    return out if found else None


def _nasdaq_eps_info(ticker):
    """Upcoming EPS consensus from Nasdaq's quote/{sym}/eps endpoint.

    Response shape: {data: {earningsPerShare: [{type, period, consensus, earnings}]}}
    where type is 'PreviousQuarter' or 'UpcomingQuarter'. We pick the first
    upcoming row's consensus as the next-quarter estimate.
    """
    import urllib.request
    import urllib.error
    import json

    sym = (ticker or "").strip().upper()
    if not sym:
        return None
    cache_key = f"NASDAQ_EPS::{sym}"
    cached = _cache_get(_EARNINGS_TICKER_CACHE, cache_key, ttl=_EARNINGS_TICKER_TTL_SEC)
    if cached is not None:
        return cached if cached else None

    out = _empty_earnings_info()
    found = False

    for asset_class in ("stocks", "etf"):
        url = f"https://api.nasdaq.com/api/quote/{sym}/eps?assetclass={asset_class}"
        req = urllib.request.Request(
            url,
            headers={
                "User-Agent": "Mozilla/5.0 (Portfolio Tracking)",
                "Accept": "application/json",
            },
        )
        try:
            with urllib.request.urlopen(req, timeout=6) as resp:
                payload = json.loads(resp.read().decode("utf-8", errors="replace"))
        except Exception:
            continue
        try:
            data = (payload or {}).get("data") or {}
            if not data:
                continue
            eps_rows = data.get("earningsPerShare") or []
            for r in eps_rows:
                rtype = str(r.get("type") or "").lower()
                if "upcoming" in rtype:
                    est = _safe_float(r.get("consensus"))
                    if est is not None:
                        out["eps_estimate"] = est
                        found = True
                        break
            # Past rows can also fill in last-quarter estimate/actual when missing.
            past = [r for r in eps_rows if "previous" in str(r.get("type") or "").lower()]
            if past:
                last = past[-1]
                est = _safe_float(last.get("consensus"))
                act = _safe_float(last.get("earnings"))
                if est is not None:
                    out["last_eps_estimate"] = est
                    found = True
                if act is not None:
                    out["last_eps_actual"] = act
                    found = True
                if est not in (None, 0) and act is not None and out.get("last_surprise_pct") is None:
                    out["last_surprise_pct"] = (act - est) / abs(est) * 100.0
            if found:
                break
        except Exception:
            continue

    _cache_set(_EARNINGS_TICKER_CACHE, cache_key, out if found else {})
    return out if found else None


def _nasdaq_info_next_date(ticker):
    """Pull the next earnings announcement date from quote/{sym}/info keyStats.

    The 'info' endpoint embeds messages like "Earnings Date : Apr 30, 2026" in
    a keyStats / events block. We regex-scrape that out as a focused fallback.
    """
    import urllib.request
    import urllib.error
    import json
    import re

    sym = (ticker or "").strip().upper()
    if not sym:
        return None
    cache_key = f"NASDAQ_INFO::{sym}"
    cached = _cache_get(_EARNINGS_TICKER_CACHE, cache_key, ttl=_EARNINGS_TICKER_TTL_SEC)
    if cached is not None:
        return cached if cached else None

    out = _empty_earnings_info()
    found = False
    for asset_class in ("stocks", "etf"):
        url = f"https://api.nasdaq.com/api/quote/{sym}/info?assetclass={asset_class}"
        req = urllib.request.Request(
            url,
            headers={
                "User-Agent": "Mozilla/5.0 (Portfolio Tracking)",
                "Accept": "application/json",
            },
        )
        try:
            with urllib.request.urlopen(req, timeout=6) as resp:
                body = resp.read().decode("utf-8", errors="replace")
        except Exception:
            continue
        m = re.search(r"Earnings\s+Date\s*:\s*([A-Za-z]{3,9}\s+\d{1,2},\s+\d{4})", body)
        if m:
            d = _coerce_earnings_timestamp(m.group(1))
            if d:
                out["next_date"] = d
                found = True
                break
        # Some payloads stash the date as a structured field — try JSON parse too.
        try:
            payload = json.loads(body)
        except Exception:
            payload = None
        if payload:
            try:
                key_stats = (((payload.get("data") or {}).get("keyStats") or {}))
                ed = (
                    (key_stats.get("EarningsDate") or {}).get("value")
                    if isinstance(key_stats.get("EarningsDate"), dict)
                    else None
                )
                if ed:
                    d = _coerce_earnings_timestamp(ed)
                    if d:
                        out["next_date"] = d
                        found = True
                        break
            except Exception:
                pass

    _cache_set(_EARNINGS_TICKER_CACHE, cache_key, out if found else {})
    return out if found else None


# NOTE: Zacks's per-symbol earnings pages and helper PHPs are gated by Imperva
# bot detection — server-side scrapes return a JS challenge page or 403, not
# the earnings table. Their public quote-feed JSON (quote-feed.zacks.com) does
# not include earnings dates either. Until Zacks ships a usable public feed
# we cover the same fields via Nasdaq's quote/eps and quote/info endpoints.


def _build_earnings_events():
    """Build earnings-calendar events for the active portfolio (or aggregate)."""
    from datetime import datetime, date

    is_aggregate, profile_ids = get_profile_filter()
    if not profile_ids:
        return []
    placeholders = ",".join("?" * len(profile_ids))
    conn = get_connection()
    try:
        df = pd.read_sql(
            f"""
            SELECT ticker, MAX(description) AS description
            FROM all_account_info
            WHERE profile_id IN ({placeholders})
              AND COALESCE(quantity, 0) > 0
              AND ticker IS NOT NULL
              AND ticker NOT IN ('', '--')
            GROUP BY ticker
            ORDER BY ticker
            """,
            conn,
            params=profile_ids,
        )
    except Exception:
        conn.close()
        return []
    conn.close()

    today_d = date.today()
    cache_columns = ("ticker", "description")
    cache_rows = df.to_dict("records")
    cache_scope = ("agg", tuple(sorted(profile_ids))) if is_aggregate else ("single", profile_ids[0])
    cache_key = (
        cache_scope,
        today_d.isoformat(),
        _rows_signature(cache_rows, cache_columns),
    )
    cached = _cache_get(_EARNINGS_CALENDAR_CACHE, cache_key, ttl=_EARNINGS_EVENT_TTL_SEC)
    if cached is not None:
        return cached

    def _fetch_ticker_event(row):
        ticker = str(row["ticker"] or "").strip().upper()
        if not ticker:
            return None
        description = str(row["description"]) if pd.notna(row["description"]) else ""

        info = _yf_earnings_info(ticker) or _empty_earnings_info()

        # Layer Nasdaq sources for fields yfinance left blank.
        if info.get("next_date") is None:
            info = _merge_earnings_info(info, _nasdaq_info_next_date(ticker))
        if not _earnings_info_complete(info):
            info = _merge_earnings_info(info, _nasdaq_eps_info(ticker))
        if not _earnings_info_complete(info):
            info = _merge_earnings_info(info, _nasdaq_surprise_info(ticker))

        next_d = info.get("next_date")
        last_d = info.get("last_date")
        if not next_d and not last_d:
            return None

        color = "#8899aa"
        if next_d:
            days = (next_d - today_d).days
            if days <= 7:
                color = "#00e89a"
            elif days <= 30:
                color = "#00c9a7"
            else:
                color = "#7ecfff"

        primary = next_d or last_d
        is_upcoming = bool(next_d and next_d >= today_d)
        days_until = (next_d - today_d).days if next_d else None

        return {
            "ticker": ticker,
            "description": description,
            "date": primary.isoformat(),
            "day": str(primary.day),
            "month": primary.strftime("%b"),
            "weekday": primary.strftime("%a"),
            "year": primary.year,
            "is_upcoming": is_upcoming,
            "days_until": days_until,
            "eps_estimate": info.get("eps_estimate"),
            "last_date": last_d.isoformat() if last_d else None,
            "last_date_label": last_d.strftime("%b %d, %Y") if last_d else None,
            "last_eps_actual": info.get("last_eps_actual"),
            "last_eps_estimate": info.get("last_eps_estimate"),
            "last_surprise_pct": (
                round(info["last_surprise_pct"], 2)
                if info.get("last_surprise_pct") is not None
                else None
            ),
            "color": color,
        }

    from concurrent.futures import ThreadPoolExecutor, as_completed
    rows = [row for _, row in df.iterrows()]
    events = []
    with ThreadPoolExecutor(max_workers=min(5, len(rows))) as pool:
        futures = {pool.submit(_fetch_ticker_event, row): row for row in rows}
        for future in as_completed(futures):
            try:
                result = future.result()
                if result:
                    events.append(result)
            except Exception:
                pass

    # Upcoming first (soonest first), then past (most recent first).
    def _sort_key(ev):
        if ev["is_upcoming"]:
            return (0, ev["days_until"] if ev["days_until"] is not None else 9999)
        return (1, -datetime.fromisoformat(ev["date"]).toordinal())

    events.sort(key=_sort_key)
    _cache_set(_EARNINGS_CALENDAR_CACHE, cache_key, events)
    return events


@app.route("/api/earnings-calendar")
def earnings_calendar():
    """Return earnings calendar events for the active portfolio."""
    from datetime import date
    try:
        events = _build_earnings_events()
        return jsonify(events=events, today=date.today().isoformat())
    except Exception as e:
        return jsonify(error=str(e)), 500


