def _bss_ao(high, low):
    if len(high) < 34:
        return "NEUTRAL", None, ""
    mid = (high + low) / 2
    ao_v = (mid.rolling(5).mean() - mid.rolling(34).mean()).dropna()
    if len(ao_v) < 2:
        return "NEUTRAL", None, ""
    cur, prv = float(ao_v.iloc[-1]), float(ao_v.iloc[-2])
    direction = "Rising" if cur > prv else ("Falling" if cur < prv else "Flat")
    if cur > 0 and cur > prv:
        return "BUY", cur, direction
    if cur < 0 and cur < prv:
        return "SELL", cur, direction
    return "NEUTRAL", cur, direction


def _bss_rsi(close, period=14):
    if len(close) < period + 1:
        return "NEUTRAL", None
    delta = close.diff()
    avg_gain = delta.clip(lower=0).ewm(com=period - 1, adjust=False, min_periods=period).mean()
    avg_loss = (-delta).clip(lower=0).ewm(com=period - 1, adjust=False, min_periods=period).mean()
    rs = avg_gain / avg_loss
    val = float((100 - 100 / (1 + rs)).iloc[-1])
    if pd.isna(val):
        return "NEUTRAL", None
    if val < 30:
        return "BUY", val
    if val > 70:
        return "SELL", val
    return "NEUTRAL", val


def _bss_macd(close):
    if len(close) < 26:
        return "NEUTRAL"
    macd_line = close.ewm(span=12, adjust=False).mean() - close.ewm(span=26, adjust=False).mean()
    sig_line = macd_line.ewm(span=9, adjust=False).mean()
    m, s = float(macd_line.iloc[-1]), float(sig_line.iloc[-1])
    if pd.isna(m) or pd.isna(s):
        return "NEUTRAL"
    return "BUY" if m > s else "SELL"


def _bss_sma(close, period):
    if len(close) < period:
        return "NEUTRAL", None, None
    sma_val = close.rolling(period).mean().iloc[-1]
    price = close.iloc[-1]
    if pd.isna(sma_val) or pd.isna(price) or float(sma_val) == 0:
        return "NEUTRAL", None, None
    sma_f, price_f = float(sma_val), float(price)
    pct = (price_f - sma_f) / sma_f * 100
    if price_f > sma_f * 1.01:
        return "BUY", sma_f, pct
    if price_f < sma_f * 0.99:
        return "SELL", sma_f, pct
    return "NEUTRAL", sma_f, pct


def _slow_stochastic(high, low, close, k_period=14, k_smooth=3, d_period=3):
    """Slow Stochastic. Returns (slow_k, slow_d) latest values."""
    needed = k_period + k_smooth + d_period
    if len(close) < needed:
        return None, None
    lowest_low = low.rolling(k_period).min()
    highest_high = high.rolling(k_period).max()
    denom = highest_high - lowest_low
    denom = denom.replace(0, float("nan"))
    raw_k = (close - lowest_low) / denom * 100
    slow_k = raw_k.rolling(k_smooth).mean()
    slow_d = slow_k.rolling(d_period).mean()
    k_val = float(slow_k.iloc[-1]) if not pd.isna(slow_k.iloc[-1]) else None
    d_val = float(slow_d.iloc[-1]) if not pd.isna(slow_d.iloc[-1]) else None
    return k_val, d_val


def _bss_vote(signals):
    """Majority-vote: need >50% of valid (non-None) signals to agree."""
    valid = [s for s in signals if s is not None]
    if not valid:
        return "NEUTRAL"
    threshold = len(valid) / 2
    if valid.count("BUY") > threshold:
        return "BUY"
    if valid.count("SELL") > threshold:
        return "SELL"
    return "NEUTRAL"


def _bss_coverage(close, divs_series, benchmark_close=None):
    """Compute benchmark-adjusted NAV erosion ratio for Buy/Sell Signals.

    ratio = fund price decline / TTM distribution yield, only when benchmark is flat/up
    Lower is better: <=0.25 Low, <=0.75 Medium, >0.75 High.
    Returns (ratio, signal, nav_erosion_label).
    """
    ratio = _nav_adjusted_erosion_ratio(close, divs_series, benchmark_close if benchmark_close is not None else close)
    price_change_pct = None
    try:
        clean = close.dropna()
        if len(clean) >= 2 and float(clean.iloc[0]) > 0:
            price_change_pct = (float(clean.iloc[-1]) - float(clean.iloc[0])) / float(clean.iloc[0]) * 100
    except Exception:
        price_change_pct = None
    return (
        ratio,
        _nav_signal_from_adjusted_ratio(ratio, price_change_pct=price_change_pct),
        _nav_erosion_from_adjusted_ratio(ratio, price_change_pct=price_change_pct),
    )


def _bss_sharpe(close, risk_free_annual=0.05):
    import numpy as np
    try:
        if len(close) < 30:
            return None
        daily_ret = close.pct_change().dropna()
        if len(daily_ret) < 30:
            return None
        std = float(daily_ret.std())
        if std == 0 or np.isnan(std):
            return None
        return round((float(daily_ret.mean()) - risk_free_annual / 252) / std * np.sqrt(252), 2)
    except Exception:
        return None


def _bss_sortino(close, risk_free_annual=0.05):
    import numpy as np
    try:
        if len(close) < 30:
            return None
        daily_ret = close.pct_change().dropna()
        if len(daily_ret) < 30:
            return None
        neg_ret = daily_ret[daily_ret < 0]
        if len(neg_ret) == 0:
            return None
        down_std = float(neg_ret.std())
        if down_std == 0 or np.isnan(down_std):
            return None
        return round((float(daily_ret.mean()) - risk_free_annual / 252) / down_std * np.sqrt(252), 2)
    except Exception:
        return None


# ── Stock Buying Checklist: extra indicators + metric builder ────────────────

def _awesome_oscillator(high, low, fast=5, slow=34):
    """Bill Williams Awesome Oscillator: SMA(fast) - SMA(slow) of median price.

    Returns (value, signal). Bullish above zero and rising, bearish below and
    falling, otherwise neutral.
    """
    if high is None or low is None or len(high) < slow + 1:
        return None, "NEUTRAL"
    median = (high + low) / 2
    ao = median.rolling(fast).mean() - median.rolling(slow).mean()
    if len(ao) < 2 or pd.isna(ao.iloc[-1]) or pd.isna(ao.iloc[-2]):
        return None, "NEUTRAL"
    last = float(ao.iloc[-1])
    prev = float(ao.iloc[-2])
    eps = 1e-9  # tolerate float noise so a flat-but-positive AO still reads bullish
    if last > 0 and last >= prev - eps:
        sig = "BUY"
    elif last < 0 and last <= prev + eps:
        sig = "SELL"
    else:
        sig = "NEUTRAL"
    return round(last, 4), sig


def _obv_volume_signal(close, volume, lookback=20):
    """On-Balance Volume trend + latest volume vs its recent average.

    Returns {obv_trend_pct, volume_vs_avg, signal}. Rising OBV (accumulation)
    confirms buying interest; falling OBV (distribution) confirms selling.
    """
    import numpy as np

    result = {"obv_trend_pct": None, "volume_vs_avg": None, "signal": "NEUTRAL"}
    if close is None or volume is None or len(close) < lookback + 1:
        return result
    volume = volume.fillna(0)
    direction = np.sign(close.diff().fillna(0))
    obv = (direction * volume).cumsum()
    window = obv.iloc[-lookback:]
    start = float(window.iloc[0])
    end = float(window.iloc[-1])
    if start != 0:
        result["obv_trend_pct"] = round((end - start) / abs(start) * 100, 2)
    avg_vol = float(volume.iloc[-lookback:].mean())
    if avg_vol > 0:
        result["volume_vs_avg"] = round(float(volume.iloc[-1]) / avg_vol, 2)
    delta = end - start
    if delta > 0:
        result["signal"] = "BUY"
    elif delta < 0:
        result["signal"] = "SELL"
    return result


def _macd_values(close):
    """Return {macd, signal_line, histogram, state} for the standard 12/26/9 MACD."""
    result = {"macd": None, "signal_line": None, "histogram": None, "state": "NEUTRAL"}
    if close is None or len(close) < 35:
        return result
    macd_line = close.ewm(span=12, adjust=False).mean() - close.ewm(span=26, adjust=False).mean()
    sig_line = macd_line.ewm(span=9, adjust=False).mean()
    m, s = macd_line.iloc[-1], sig_line.iloc[-1]
    if pd.isna(m) or pd.isna(s):
        return result
    m, s = float(m), float(s)
    result.update({
        "macd": round(m, 4),
        "signal_line": round(s, 4),
        "histogram": round(m - s, 4),
        "state": "BUY" if m > s else "SELL",
    })
    return result


def _stochastic_state(slow_k, slow_d):
    """Classify a slow stochastic reading: oversold (<20) buy, overbought (>80) sell."""
    if slow_k is None or slow_d is None:
        return "NEUTRAL"
    if slow_k < 20 and slow_d < 20:
        return "BUY"
    if slow_k > 80 and slow_d > 80:
        return "SELL"
    return "NEUTRAL"


def _stock_earnings_facts(tk):
    """Best-effort next-earnings date and recent surprise history (optional)."""
    facts = {
        "next_earnings_date": None,
        "days_to_earnings": None,
        "last_surprise_pct": None,
        "recent_beats": None,
        "recent_reports": None,
    }
    try:
        ed = None
        getter = getattr(tk, "get_earnings_dates", None)
        if callable(getter):
            ed = getter(limit=12)
        else:
            ed = getattr(tk, "earnings_dates", None)
        if ed is None or ed.empty:
            return facts
        now = pd.Timestamp.now(tz=ed.index.tz)
        future = ed[ed.index >= now]
        if not future.empty:
            nd = future.index.min()
            facts["next_earnings_date"] = nd.strftime("%Y-%m-%d")
            facts["days_to_earnings"] = int((nd - now).days)
        past = ed[ed.index < now]
        col = next((c for c in ed.columns if "surprise" in str(c).lower()), None)
        if col and not past.empty:
            sp = past[col].dropna()
            if not sp.empty:
                raw = float(sp.iloc[0])
                facts["last_surprise_pct"] = round(raw * 100, 2) if abs(raw) <= 1 else round(raw, 2)
                facts["recent_reports"] = int(len(sp))
                facts["recent_beats"] = int((sp > 0).sum())
    except Exception:
        pass
    return facts


def _checklist_frac_pct(value):
    """Convert a yfinance ratio that is always stored as a fraction (margins,
    ROE/ROA, growth rates, payout ratio) into a percentage. Unlike
    ``_research_pct`` this always multiplies by 100, so values above 1.0
    (e.g. an ROE of 1.41 = 141%) are handled correctly.
    """
    value = _research_clean_value(value)
    if value is None:
        return None
    try:
        return round(float(value) * 100, 2)
    except (TypeError, ValueError):
        return None


def _stock_checklist_fund_kind(quote_type, info, name):
    """Classify a ticker as a fund kind (or None for an ordinary stock).

    ETFs and mutual funds are detected from quoteType; closed-end funds and
    BDCs report as EQUITY on Yahoo, so they are caught via the shared
    legal-type classifier. REITs are treated as stocks (they file normal
    company financials), so they are NOT flagged here.
    """
    summary = _research_info_value(info, "longBusinessSummary") or ""
    industry = _research_info_value(info, "industry", "industryDisp") or ""
    legal = (_derive_legal_type(quote_type, summary, None, None, name, industry) or "").lower()
    if quote_type == "ETF" or "exchange traded fund" in legal:
        return "ETF"
    if quote_type in {"MUTUALFUND", "MONEYMARKET"} or "mutual fund" in legal:
        return "Mutual Fund"
    if "business development" in legal:
        return "BDC"
    if "closed" in legal:
        return "Closed-End Fund"
    # Many closed-end funds report as EQUITY with no legalType; their summaries
    # phrase it loosely ("close ended", "closed-end management investment
    # company"), which the shared classifier misses — catch those here.
    s = summary.lower().replace("-", " ")
    if ("close end" in s or "closed end" in s) and ("fund" in s or "investment company" in s):
        return "Closed-End Fund"
    if "business development company" in s:
        return "BDC"
    return None


def _build_stock_checklist(symbol, skip_if_fund=False):
    """Fetch fundamentals + technicals for one ticker for the buying checklist.

    Returns (metrics_dict, error). Scoring/grading happens client-side so the
    sector-relative thresholds stay user-editable; this only supplies raw
    fundamentals and standard technical indicator values/signals.
    """
    import yfinance as yf

    symbol = (symbol or "").strip().upper()
    if not symbol:
        return None, "ticker is required"
    lookup = _yahoo_symbol_for_ticker(symbol)
    try:
        tk = yf.Ticker(lookup)
        info = tk.info or {}
        info_symbol = (info.get("symbol") or "").upper()
        if info_symbol and info_symbol != lookup:
            lookup = info_symbol
            tk = yf.Ticker(lookup)
            info = tk.info or {}
    except Exception as exc:
        return None, f"Could not load {symbol}: {exc}"

    name = _research_info_value(info, "longName", "shortName", "displayName")
    quote_type = (_research_info_value(info, "quoteType") or "").upper()
    if not name:
        return None, f"Ticker {symbol} not found in Yahoo Finance."

    fund_kind = _stock_checklist_fund_kind(quote_type, info, name)
    # The checklist grades individual stocks. When asked to skip funds (batch
    # scan), short-circuit before the expensive history fetch and let the caller
    # report it as skipped instead of scoring it on stock criteria.
    if skip_if_fund and fund_kind:
        return {
            "ticker": lookup, "requested_ticker": symbol, "name": name,
            "quote_type": quote_type, "sector": _research_info_value(info, "sector"),
            "is_fund": True, "fund_kind": fund_kind, "skipped": True,
        }, None

    enterprise_value = _research_clean_value(_research_info_value(info, "enterpriseValue"))
    ebitda = _research_clean_value(_research_info_value(info, "ebitda"))
    ev_to_ebitda = None
    if enterprise_value is not None and ebitda not in (None, 0):
        try:
            ev_to_ebitda = round(float(enterprise_value) / float(ebitda), 2)
        except (TypeError, ZeroDivisionError, ValueError):
            ev_to_ebitda = None

    fundamentals = {
        "trailing_pe": _research_clean_value(_research_info_value(info, "trailingPE")),
        "forward_pe": _research_clean_value(_research_info_value(info, "forwardPE")),
        "peg_ratio": _research_clean_value(_research_info_value(info, "pegRatio", "trailingPegRatio")),
        "price_to_book": _research_clean_value(_research_info_value(info, "priceToBook")),
        "price_to_sales_ttm": _research_clean_value(_research_info_value(info, "priceToSalesTrailing12Months")),
        "ev_to_ebitda": ev_to_ebitda,
        "profit_margin_pct": _checklist_frac_pct(_research_info_value(info, "profitMargins")),
        "operating_margin_pct": _checklist_frac_pct(_research_info_value(info, "operatingMargins")),
        "gross_margin_pct": _checklist_frac_pct(_research_info_value(info, "grossMargins")),
        "roe_pct": _checklist_frac_pct(_research_info_value(info, "returnOnEquity")),
        "roa_pct": _checklist_frac_pct(_research_info_value(info, "returnOnAssets")),
        "revenue_growth_pct": _checklist_frac_pct(_research_info_value(info, "revenueGrowth")),
        "earnings_growth_pct": _checklist_frac_pct(_research_info_value(info, "earningsGrowth")),
        "earnings_q_growth_pct": _checklist_frac_pct(_research_info_value(info, "earningsQuarterlyGrowth")),
        "eps": _research_clean_value(_research_info_value(info, "trailingEps")),
        "forward_eps": _research_clean_value(_research_info_value(info, "forwardEps")),
        "debt_to_equity": _research_clean_value(_research_info_value(info, "debtToEquity")),
        "current_ratio": _research_clean_value(_research_info_value(info, "currentRatio")),
        "quick_ratio": _research_clean_value(_research_info_value(info, "quickRatio")),
        "free_cash_flow": _research_money(_research_info_value(info, "freeCashflow")),
        "total_cash": _research_money(_research_info_value(info, "totalCash")),
        "total_debt": _research_money(_research_info_value(info, "totalDebt")),
        # yfinance reports dividendYield already as a percent (e.g. 2.68 = 2.68%),
        # so it is used as-is; payoutRatio is a fraction and is scaled to a percent.
        "dividend_yield_pct": _research_money(_research_info_value(info, "dividendYield", "trailingAnnualDividendYield")),
        "payout_ratio_pct": _checklist_frac_pct(_research_info_value(info, "payoutRatio")),
        "beta": _research_clean_value(_research_info_value(info, "beta")),
    }

    price = _research_money(_research_info_value(info, "regularMarketPrice", "currentPrice", "previousClose"))
    week_low = _research_money(_research_info_value(info, "fiftyTwoWeekLow"))
    week_high = _research_money(_research_info_value(info, "fiftyTwoWeekHigh"))
    range_position_pct = None
    if price is not None and week_low is not None and week_high is not None and week_high > week_low:
        range_position_pct = round((price - week_low) / (week_high - week_low) * 100, 1)

    # ── Technicals from 1y daily history ─────────────────────────────────────
    technicals = {
        "price": price,
        "sma50": None, "sma200": None,
        "pct_vs_sma50": None, "pct_vs_sma200": None,
        "trend_state": "NEUTRAL", "golden_cross": None,
        "rsi14": None, "rsi_state": "NEUTRAL",
        "macd": None, "macd_signal_line": None, "macd_histogram": None, "macd_state": "NEUTRAL",
        "stoch_k": None, "stoch_d": None, "stoch_state": "NEUTRAL",
        "awesome_oscillator": None, "ao_state": "NEUTRAL",
        "obv_trend_pct": None, "volume_vs_avg": None, "volume_state": "NEUTRAL",
        "fifty_two_week_low": week_low,
        "fifty_two_week_high": week_high,
        "range_position_pct": range_position_pct,
    }
    try:
        hist = tk.history(period="1y", auto_adjust=False)
    except Exception:
        hist = None
    if hist is not None and not hist.empty and "Close" in hist.columns:
        close = hist["Close"].dropna()
        high = hist["High"].dropna() if "High" in hist.columns else None
        low = hist["Low"].dropna() if "Low" in hist.columns else None
        volume = hist["Volume"] if "Volume" in hist.columns else None
        if len(close) >= 2:
            sma50_sig, sma50_val, sma50_pct = _bss_sma(close, 50)
            sma200_sig, sma200_val, sma200_pct = _bss_sma(close, 200)
            technicals["sma50"] = round(sma50_val, 4) if sma50_val is not None else None
            technicals["sma200"] = round(sma200_val, 4) if sma200_val is not None else None
            technicals["pct_vs_sma50"] = round(sma50_pct, 2) if sma50_pct is not None else None
            technicals["pct_vs_sma200"] = round(sma200_pct, 2) if sma200_pct is not None else None
            technicals["trend_state"] = sma200_sig if sma200_val is not None else sma50_sig
            if sma50_val is not None and sma200_val is not None:
                technicals["golden_cross"] = bool(sma50_val > sma200_val)

            rsi_sig, rsi_val = _bss_rsi(close)
            technicals["rsi14"] = round(rsi_val, 2) if rsi_val is not None else None
            technicals["rsi_state"] = rsi_sig

            macd = _macd_values(close)
            technicals["macd"] = macd["macd"]
            technicals["macd_signal_line"] = macd["signal_line"]
            technicals["macd_histogram"] = macd["histogram"]
            technicals["macd_state"] = macd["state"]

            if high is not None and low is not None:
                k_val, d_val = _slow_stochastic(high, low, close)
                technicals["stoch_k"] = round(k_val, 2) if k_val is not None else None
                technicals["stoch_d"] = round(d_val, 2) if d_val is not None else None
                technicals["stoch_state"] = _stochastic_state(k_val, d_val)

                ao_val, ao_sig = _awesome_oscillator(high, low)
                technicals["awesome_oscillator"] = ao_val
                technicals["ao_state"] = ao_sig

            vol = _obv_volume_signal(close, volume)
            technicals["obv_trend_pct"] = vol["obv_trend_pct"]
            technicals["volume_vs_avg"] = vol["volume_vs_avg"]
            technicals["volume_state"] = vol["signal"]
            if technicals["price"] is None:
                technicals["price"] = round(float(close.iloc[-1]), 4)

    metrics = {
        "ticker": lookup,
        "requested_ticker": symbol,
        "name": name,
        "quote_type": quote_type,
        "sector": _research_info_value(info, "sector"),
        "industry": _research_info_value(info, "industry"),
        "price": technicals["price"],
        "market_cap": _research_money(_research_info_value(info, "marketCap")),
        "is_fund": fund_kind is not None,
        "fund_kind": fund_kind,
        "fundamentals": fundamentals,
        "technicals": technicals,
        "earnings": _stock_earnings_facts(tk),
        "data_source": "Yahoo Finance",
    }
    return metrics, None


@app.route("/api/stock-evaluate/<ticker>")
def stock_evaluate(ticker):
    """Fundamental + technical metrics for a single ticker (Stock Buying Checklist)."""
    metrics, error = _build_stock_checklist(ticker)
    if error:
        status = 404 if "not found" in error.lower() else 502
        return jsonify({"error": error}), status
    return jsonify(metrics)


def _val_stmt_value(df, *labels):
    """Best-effort single-cell (most recent period) lookup from a yfinance
    financial-statement DataFrame, tolerant of label/version differences."""
    try:
        if df is None or getattr(df, "empty", True):
            return None
        for label in labels:
            if label in df.index:
                return _research_money(df.loc[label, df.columns[0]])
    except Exception:
        pass
    return None


def _val_fcf_cagr(cashflow):
    """Compound annual growth of free cash flow across the statement's columns,
    used only as a last-resort DCF growth default. Returns a fraction or None."""
    try:
        if cashflow is None or cashflow.empty:
            return None
        op_label = next((l for l in ("Operating Cash Flow", "Total Cash From Operating Activities")
                         if l in cashflow.index), None)
        capex_label = next((l for l in ("Capital Expenditure", "Capital Expenditures")
                            if l in cashflow.index), None)
        if not op_label:
            return None
        op = cashflow.loc[op_label].dropna()
        capex = cashflow.loc[capex_label].dropna() if capex_label else None
        fcf = []
        for col in cashflow.columns:
            o = _research_clean_value(op.get(col)) if col in op.index else None
            if o is None:
                continue
            c = _research_clean_value(capex.get(col)) if (capex is not None and col in capex.index) else 0.0
            fcf.append(float(o) + float(c or 0.0))  # capex is reported negative
        # Columns are most-recent-first; reverse to oldest→newest for the CAGR.
        fcf = list(reversed(fcf))
        if len(fcf) < 2 or fcf[0] <= 0 or fcf[-1] <= 0:
            return None
        n = len(fcf) - 1
        return (fcf[-1] / fcf[0]) ** (1 / n) - 1
    except Exception:
        return None


def _build_stock_valuation(symbol, overrides=None):
    """Estimate intrinsic value for one ticker via a DCF blended with multiples,
    plus the full ratio set and a quality/risk scorecard.

    Returns (payload, error). Funds (ETF/CEF/mutual fund/BDC) are rejected with a
    friendly payload because a company DCF does not apply to them.
    """
    import yfinance as yf
    import valuation as ve

    overrides = overrides or {}
    symbol = (symbol or "").strip().upper()
    if not symbol:
        return None, "ticker is required"
    lookup = _yahoo_symbol_for_ticker(symbol)
    try:
        tk = yf.Ticker(lookup)
        info = tk.info or {}
        info_symbol = (info.get("symbol") or "").upper()
        if info_symbol and info_symbol != lookup:
            lookup = info_symbol
            tk = yf.Ticker(lookup)
            info = tk.info or {}
    except Exception as exc:
        return None, f"Could not load {symbol}: {exc}"

    name = _research_info_value(info, "longName", "shortName", "displayName")
    quote_type = (_research_info_value(info, "quoteType") or "").upper()
    if not name:
        return None, f"Ticker {symbol} not found in Yahoo Finance."

    sector = _research_info_value(info, "sector")
    industry = _research_info_value(info, "industry")
    currency = _research_info_value(info, "currency") or "USD"
    price = _research_money(_research_info_value(info, "regularMarketPrice", "currentPrice", "previousClose"))
    market_cap = _research_money(_research_info_value(info, "marketCap"))

    fund_kind = _stock_checklist_fund_kind(quote_type, info, name)
    if fund_kind:
        return {
            "ticker": lookup, "requested_ticker": symbol, "name": name,
            "sector": sector, "industry": industry, "price": price, "currency": currency,
            "is_fund": True, "fund_kind": fund_kind,
            "message": (
                f"{lookup} is a {fund_kind}, not an operating company. A discounted-cash-flow "
                "valuation models company earnings and doesn't apply to funds. Use the ETF, "
                "Option-Income ETF, or CEF evaluators for funds instead."
            ),
        }, None

    # ── raw inputs from the info blob ────────────────────────────────────────
    shares = _research_clean_value(_research_info_value(info, "sharesOutstanding", "impliedSharesOutstanding"))
    beta = _research_clean_value(_research_info_value(info, "beta"))
    forward_eps = _research_clean_value(_research_info_value(info, "forwardEps"))
    trailing_eps = _research_clean_value(_research_info_value(info, "trailingEps"))
    book_value_ps = _research_clean_value(_research_info_value(info, "bookValue"))
    revenue_ps = _research_clean_value(_research_info_value(info, "revenuePerShare"))
    forward_pe = _research_clean_value(_research_info_value(info, "forwardPE"))
    price_to_book = _research_clean_value(_research_info_value(info, "priceToBook"))
    price_to_sales = _research_clean_value(_research_info_value(info, "priceToSalesTrailing12Months"))
    free_cash_flow = _research_money(_research_info_value(info, "freeCashflow"))
    total_cash = _research_money(_research_info_value(info, "totalCash"))
    total_debt = _research_money(_research_info_value(info, "totalDebt"))
    dividend_rate = _research_clean_value(_research_info_value(info, "dividendRate"))
    operating_margin = _checklist_frac_pct(_research_info_value(info, "operatingMargins"))
    profit_margin = _checklist_frac_pct(_research_info_value(info, "profitMargins"))
    gross_margin = _checklist_frac_pct(_research_info_value(info, "grossMargins"))
    debt_to_equity = _research_clean_value(_research_info_value(info, "debtToEquity"))
    current_ratio = _research_clean_value(_research_info_value(info, "currentRatio"))
    earnings_growth_pct = _checklist_frac_pct(_research_info_value(info, "earningsGrowth"))
    revenue_growth_pct = _checklist_frac_pct(_research_info_value(info, "revenueGrowth"))
    info_payout = _checklist_frac_pct(_research_info_value(info, "payoutRatio"))
    info_peg = _research_clean_value(_research_info_value(info, "pegRatio", "trailingPegRatio"))
    info_roe = _checklist_frac_pct(_research_info_value(info, "returnOnEquity"))
    info_roa = _checklist_frac_pct(_research_info_value(info, "returnOnAssets"))

    # ── financial statements (tolerant lookups) ──────────────────────────────
    try:
        balance_sheet = tk.balance_sheet
    except Exception:
        balance_sheet = None
    try:
        income_stmt = tk.financials
    except Exception:
        income_stmt = None
    try:
        cashflow = tk.cashflow
    except Exception:
        cashflow = None

    total_assets = _val_stmt_value(balance_sheet, "Total Assets")
    equity = _val_stmt_value(balance_sheet, "Stockholders Equity", "Total Stockholder Equity", "Common Stock Equity")
    ebit = _val_stmt_value(income_stmt, "EBIT", "Operating Income", "Ebit")
    interest_expense = _val_stmt_value(income_stmt, "Interest Expense", "Interest Expense Non Operating")
    net_income = _val_stmt_value(income_stmt, "Net Income", "Net Income Common Stockholders")

    # FCF fallback from the cash-flow statement (capex is reported negative).
    if free_cash_flow is None:
        op_cf = _val_stmt_value(cashflow, "Operating Cash Flow", "Total Cash From Operating Activities")
        capex = _val_stmt_value(cashflow, "Capital Expenditure", "Capital Expenditures")
        if op_cf is not None:
            free_cash_flow = round(float(op_cf) + float(capex or 0.0), 2)

    # ── derived ratios (compute what yfinance omitted) ───────────────────────
    fcf_yield = ve.fcf_yield_pct(free_cash_flow, market_cap)
    dratio = ve.debt_ratio(total_debt, total_assets)
    int_cov = ve.interest_coverage(ebit, interest_expense)
    payout = info_payout if info_payout is not None else ve.payout_ratio_pct(dividend_rate, trailing_eps)
    peg = info_peg if info_peg is not None else ve.peg_ratio(forward_pe, earnings_growth_pct)
    roe = info_roe if info_roe is not None else ve.roe_pct(net_income, equity)
    roa = info_roa if info_roa is not None else ve.roa_pct(net_income, total_assets)
    if revenue_ps is None and shares not in (None, 0):
        total_revenue = _val_stmt_value(income_stmt, "Total Revenue", "Operating Revenue")
        revenue_ps = _research_money(_research_clean_value(total_revenue) / float(shares)) if total_revenue else None

    # ── DCF assumptions (auto defaults, query-overridable) ───────────────────
    def _clamp(v, lo, hi):
        return max(lo, min(hi, v))

    growth_default = None
    for cand in (earnings_growth_pct, revenue_growth_pct):
        if cand is not None and cand > 0:
            growth_default = cand / 100.0
            break
    if growth_default is None:
        cagr = _val_fcf_cagr(cashflow)
        growth_default = cagr if (cagr is not None and cagr > 0) else 0.05
    growth_default = round(_clamp(growth_default, 0.03, 0.20), 4)

    discount_default = ve.capm_cost_of_equity(beta)
    terminal_default = 0.025
    years_default = 10

    def _ov(key, fallback):
        try:
            return float(overrides[key]) if overrides.get(key) not in (None, "") else fallback
        except (TypeError, ValueError):
            return fallback

    growth = round(_clamp(_ov("growth", growth_default), -0.5, 0.6), 4)
    discount = round(_clamp(_ov("discount", discount_default), 0.03, 0.30), 4)
    terminal = round(_clamp(_ov("terminal", terminal_default), 0.0, 0.05), 4)
    try:
        years = int(_ov("years", years_default))
    except (TypeError, ValueError):
        years = years_default
    years = int(_clamp(years, 3, 20))
    # Gordon terminal value requires the discount rate to exceed terminal growth.
    if terminal >= discount:
        terminal = round(discount - 0.01, 4)

    net_cash = None
    if total_cash is not None or total_debt is not None:
        net_cash = (total_cash or 0.0) - (total_debt or 0.0)

    dcf = ve.discounted_cash_flow(
        base_fcf=free_cash_flow, growth=growth, discount=discount,
        terminal_growth=terminal, years=years, net_cash=net_cash or 0.0, shares=shares,
    )
    dcf_value = dcf["value"] if dcf else None

    # ── multiples-implied fair values + DDM ──────────────────────────────────
    fair = ve.sector_fair_multiples(sector)
    pe_fv = ve.fair_value_from_multiple(fair["forward_pe"], forward_eps)
    pb_fv = ve.fair_value_from_multiple(fair["price_to_book"], book_value_ps)
    ps_fv = ve.fair_value_from_multiple(fair["price_to_sales"], revenue_ps)
    # The Gordon DDM explodes as dividend growth approaches the discount rate
    # (common for low-beta payers where CAPM gives a small discount). Cap growth
    # so there is always a ≥3% spread, keeping the DDM value realistic.
    div_growth = round(min(growth, 0.06, discount - 0.03), 4)
    ddm_fv = ve.dividend_discount_value(dividend_rate, discount, div_growth)

    intrinsic = ve.blend_intrinsic_value([
        {"name": "Discounted cash flow", "value": dcf_value, "weight": 0.45},
        {"name": "Fair forward P/E", "value": pe_fv, "weight": 0.25},
        {"name": "Fair price / book", "value": pb_fv, "weight": 0.15},
        {"name": "Fair price / sales", "value": ps_fv, "weight": 0.10},
        {"name": "Dividend discount model", "value": ddm_fv, "weight": 0.15},
    ])
    intrinsic["upside_pct"] = None
    if intrinsic["value"] is not None and price not in (None, 0):
        intrinsic["upside_pct"] = round((intrinsic["value"] - price) / price * 100, 1)

    verdict = ve.valuation_verdict(price, intrinsic["value"])

    # ── risk-adjusted ratios from ~3y daily history ──────────────────────────
    try:
        hist = tk.history(period="3y", auto_adjust=True)
        close = hist["Close"].dropna() if (hist is not None and not hist.empty and "Close" in hist.columns) else None
    except Exception:
        close = None
    risk = ve.risk_ratios(close)

    sections = [
        ve.valuation_section(forward_pe, peg, price_to_book, price_to_sales, fcf_yield, payout, sector),
        ve.quality_section(roe, roa, operating_margin, profit_margin, gross_margin),
        ve.health_section(debt_to_equity, dratio, int_cov, current_ratio),
        ve.risk_section(risk["sharpe"], risk["sortino"], risk["calmar"], risk["omega"]),
    ]

    payload = {
        "ticker": lookup, "requested_ticker": symbol, "name": name,
        "sector": sector, "industry": industry, "currency": currency,
        "price": price, "market_cap": market_cap, "is_fund": False,
        "intrinsic": intrinsic,
        "verdict": verdict,
        "dcf": {
            "assumptions": {"growth": growth, "discount": discount, "terminal": terminal, "years": years},
            "defaults": {"growth": growth_default, "discount": discount_default,
                         "terminal": terminal_default, "years": years_default},
            "value": dcf_value,
            "projection": dcf["projection"] if dcf else [],
            "base_fcf": free_cash_flow,
            "net_cash": _research_money(net_cash) if net_cash is not None else None,
            "note": (
                None if dcf else
                "DCF unavailable — needs positive free cash flow and a share count. "
                "The blended value below leans on the multiples instead."
            ),
        },
        "sections": sections,
        "data_source": "Yahoo Finance",
    }
    return payload, None


@app.route("/api/stock-valuation/<ticker>")
def stock_valuation(ticker):
    """Blended DCF + multiples intrinsic value, ratios, and a quality/risk scorecard."""
    overrides = {k: request.args.get(k) for k in ("growth", "discount", "terminal", "years")}
    payload, error = _build_stock_valuation(ticker, overrides)
    if error:
        status = 404 if "not found" in error.lower() else 502
        return jsonify({"error": error}), status
    return jsonify(payload)


@app.route("/api/stock-checklist/scan", methods=["POST"])
def stock_checklist_scan():
    """Batch metrics for a list of tickers or a named source (portfolio/watchlist).

    Body: {"tickers": [...]} and/or {"source": "portfolio" | "watchlist"}.
    Sector-relative grading is done client-side from the returned set.
    """
    SCAN_LIMIT = 60
    payload = request.get_json(silent=True) or {}
    tickers = []

    raw_list = payload.get("tickers") or []
    if isinstance(raw_list, str):
        raw_list = re.split(r"[\s,;]+", raw_list)
    for t in raw_list:
        sym = str(t or "").strip().upper()
        if sym:
            tickers.append(sym)

    source = (payload.get("source") or "").strip().lower()
    if source == "portfolio":
        profile_id = get_profile_id()
        conn = get_connection()
        try:
            rows = conn.execute(
                "SELECT DISTINCT ticker FROM all_account_info "
                "WHERE profile_id = ? AND quantity > 0 ORDER BY ticker",
                (profile_id,),
            ).fetchall()
        finally:
            conn.close()
        tickers += [r["ticker"] if isinstance(r, dict) else r[0] for r in rows]
    elif source == "watchlist":
        tickers += [r["Ticker"] for r in _read_watchlist_rows() if r.get("Ticker")]

    # De-dupe while preserving order, then cap.
    seen = set()
    ordered = []
    for sym in tickers:
        if sym and sym not in seen:
            seen.add(sym)
            ordered.append(sym)
    if not ordered:
        return jsonify({"error": "No tickers to scan. Provide a ticker list or a source."}), 400
    truncated = len(ordered) > SCAN_LIMIT
    ordered = ordered[:SCAN_LIMIT]

    results = []
    errors = []
    skipped_funds = []
    for sym in ordered:
        try:
            metrics, error = _build_stock_checklist(sym, skip_if_fund=True)
            if error:
                errors.append({"ticker": sym, "error": error})
            elif metrics.get("is_fund"):
                skipped_funds.append({
                    "ticker": metrics.get("ticker", sym),
                    "name": metrics.get("name", ""),
                    "kind": metrics.get("fund_kind") or "Fund",
                })
            else:
                results.append(metrics)
        except Exception as exc:  # noqa: BLE001 - one bad ticker must not kill the batch
            errors.append({"ticker": sym, "error": str(exc)})

    return jsonify({
        "results": results,
        "errors": errors,
        "skipped_funds": skipped_funds,
        "requested": len(ordered),
        "returned": len(results),
        "truncated": truncated,
        "scan_limit": SCAN_LIMIT,
    })


@app.route("/api/buy-sell-signals")
def buy_sell_signals_data():
    """Compute 5-indicator majority-vote signals for portfolio + sector/watchlist tickers."""
    import yfinance as yf
    import json
    import math
    import warnings
    warnings.filterwarnings("ignore")

    try:
        import plotly.graph_objects as go
        import plotly.utils
        has_plotly = True
    except ImportError:
        has_plotly = False

    WATCHLIST_SIZE = 1000

    def _fmt_pct(v):
        if v is None:
            return "\u2014"
        return f"+{v:.1f}%" if v >= 0 else f"{v:.1f}%"

    profile_id = get_profile_id()
    conn = get_connection()
    try:
        port = pd.read_sql("""
            SELECT ticker, description, classification_type, purchase_value,
                   current_annual_yield, estim_payment_per_year,
                   div_frequency, div
            FROM all_account_info
            WHERE purchase_value IS NOT NULL AND purchase_value > 0
              AND profile_id = ?
            ORDER BY ticker
        """, conn, params=[profile_id])
    except Exception:
        port = pd.DataFrame(columns=[
            "ticker", "description", "classification_type", "purchase_value",
            "current_annual_yield", "estim_payment_per_year", "div_frequency", "div",
        ])
    try:
        safety_by_ticker = get_dividend_safety_for_holdings(
            conn,
            profile_id,
            port.to_dict("records"),
            refresh=request.args.get("refresh_safety") in {"1", "true", "yes"},
        )
    except Exception:
        safety_by_ticker = {}
    conn.close()

    port["description"] = port["description"].fillna("")
    port["classification_type"] = port["classification_type"].fillna("")
    port_sizes = dict(zip(port["ticker"].tolist(), port["purchase_value"].tolist()))
    port_desc = dict(zip(port["ticker"].tolist(), port["description"].tolist()))
    port_type = dict(zip(port["ticker"].tolist(), port["classification_type"].tolist()))

    all_wl = SECTOR_WATCHLIST + ALT_WATCHLIST
    display_tickers = sorted(set(port["ticker"].tolist() + all_wl))
    benchmark_tickers = sorted({
        part
        for t in display_tickers
        for part in _nav_benchmark_parts(_nav_benchmark_for_ticker(
            t,
            port_desc.get(t) or BSS_WATCHLIST_NAMES.get(t, ""),
            port_type.get(t, ""),
        ))
    })
    all_tickers = sorted(set(display_tickers + benchmark_tickers))

    error = None
    fig_json = None
    table_rows = []

    try:
        raw = _chunked_yf_download(
            " ".join(all_tickers),
            period="1y",
            interval="1d",
            auto_adjust=False,
            actions=True,
            progress=False,
            ignore_tz=True,
            threads=False,
        )

        if raw.empty:
            error = "No price data returned from Yahoo Finance."
        else:
            try:
                high_df = raw["High"]
                low_df = raw["Low"]
                close_df = raw["Adj Close"] if "Adj Close" in raw.columns.get_level_values(0) else raw["Close"]
                nav_close_df = raw["Close"]
            except KeyError:
                high_df = low_df = close_df = nav_close_df = None

            # Extract distributions for NAV erosion ratio
            try:
                divs_df = raw["Dividends"]
            except KeyError:
                divs_df = None

            if any(df is None for df in [high_df, low_df, close_df, nav_close_df]):
                error = "Missing OHLC price data from Yahoo Finance."
            else:
                SECTOR_SET = set(SECTOR_WATCHLIST)
                labels = ["State Street Sectors"]
                parents_list = [""]
                values_list = [0]
                colors_list = ["#1a1a3a"]
                hover_texts = [""]
                empty = pd.Series([], dtype=float)

                for ticker in display_tickers:
                    has_data = (ticker in close_df.columns and
                                ticker in high_df.columns and
                                ticker in low_df.columns)
                    if has_data:
                        close = close_df[ticker].dropna()
                        high = high_df[ticker].dropna()
                        low = low_df[ticker].dropna()
                    else:
                        close = high = low = empty

                    ao_sig, ao_val, ao_dir = _bss_ao(high, low)
                    rsi_sig, rsi_val = _bss_rsi(close)
                    macd_sig = _bss_macd(close)
                    sma50_sig, sma50_v, sma50_pct = _bss_sma(close, 50)
                    sma200_sig, sma200_v, sma200_pct = _bss_sma(close, 200)
                    sharpe_val = _bss_sharpe(close)
                    sortino_val = _bss_sortino(close)

                    # Benchmark-adjusted NAV erosion ratio (same formula as /api/portfolio-coverage)
                    tk_divs = pd.Series(dtype=float)
                    if divs_df is not None and has_data:
                        if isinstance(divs_df, pd.DataFrame) and ticker in divs_df.columns:
                            tk_divs = divs_df[ticker].dropna()
                        elif isinstance(divs_df, pd.Series):
                            tk_divs = divs_df.dropna()
                    nav_name = port_desc.get(ticker) or BSS_WATCHLIST_NAMES.get(ticker, "")
                    nav_type = port_type.get(ticker, "")
                    if _is_nav_erosion_candidate(ticker, nav_name, nav_type):
                        bench_ticker = _nav_benchmark_for_ticker(ticker, nav_name, nav_type)
                        nav_close = nav_close_df[ticker].dropna() if ticker in nav_close_df.columns else close
                        bench_close = _nav_benchmark_close_from_df(close_df, bench_ticker, close)
                        cov_ratio, cov_sig, nav_erosion = _bss_coverage(nav_close, tk_divs, bench_close)
                    else:
                        cov_ratio, cov_sig, nav_erosion = None, None, None

                    signal = _bss_vote([ao_sig, rsi_sig, macd_sig, sma50_sig, sma200_sig, cov_sig])

                    is_portfolio = ticker in port_sizes
                    is_sector = ticker in SECTOR_SET and not is_portfolio
                    size = port_sizes.get(ticker, WATCHLIST_SIZE)
                    safety = safety_by_ticker.get(ticker, {}) if is_portfolio else {}
                    if is_portfolio:
                        safety = apply_nav_coverage_overlay(safety, cov_ratio, nav_erosion)

                    # Treemap nodes
                    if has_plotly:
                        ao_val_str = f"{ao_val:.4f}" if ao_val is not None else "\u2014"
                        rsi_val_str = f"{rsi_val:.1f}" if rsi_val is not None else "\u2014"
                        cov_str = f"{cov_ratio:.2f}" if cov_ratio is not None else "\u2014"
                        hover_text = (
                            f"<b>{signal}</b><br>"
                            f"AO: {ao_sig} ({ao_val_str}, {ao_dir or chr(8212)})<br>"
                            f"RSI: {rsi_sig} ({rsi_val_str})<br>"
                            f"MACD: {macd_sig}<br>"
                            f"SMA 50: {sma50_sig} ({_fmt_pct(sma50_pct)})<br>"
                            f"SMA 200: {sma200_sig} ({_fmt_pct(sma200_pct)})<br>"
                            f"NAV Ratio: {cov_str} ({nav_erosion or chr(8212)} erosion risk)"
                        )
                        if is_portfolio:
                            labels.append(ticker)
                            parents_list.append("")
                            values_list.append(float(size))
                            colors_list.append(SIGNAL_COLOR[signal])
                            hover_texts.append(hover_text)
                        elif is_sector:
                            labels.append(ticker)
                            parents_list.append("State Street Sectors")
                            values_list.append(WATCHLIST_SIZE)
                            colors_list.append(SIGNAL_COLOR[signal])
                            hover_texts.append(hover_text)

                    table_rows.append({
                        "ticker": ticker,
                        "desc": port_desc.get(ticker) or BSS_WATCHLIST_NAMES.get(ticker, ""),
                        "ctype": port_type.get(ticker, ""),
                        "source": "Portfolio" if is_portfolio else ("Sectors" if is_sector else "Watchlist"),
                        "signal": signal,
                        "sig_order": SIGNAL_ORDER[signal],
                        "ao_sig": ao_sig,
                        "ao_sig_ord": SIGNAL_ORDER[ao_sig],
                        "ao_value": f"{ao_val:.4f}" if ao_val is not None else "\u2014",
                        "ao_val_num": ao_val if ao_val is not None else "",
                        "ao_dir": ao_dir,
                        "rsi_sig": rsi_sig,
                        "rsi_sig_ord": SIGNAL_ORDER[rsi_sig],
                        "rsi_value": f"{rsi_val:.1f}" if rsi_val is not None else "\u2014",
                        "rsi_val_num": rsi_val if rsi_val is not None else "",
                        "macd_sig": macd_sig,
                        "macd_sig_ord": SIGNAL_ORDER[macd_sig],
                        "sma50_sig": sma50_sig,
                        "sma50_sig_ord": SIGNAL_ORDER[sma50_sig],
                        "sma50_pct": _fmt_pct(sma50_pct),
                        "sma200_sig": sma200_sig,
                        "sma200_sig_ord": SIGNAL_ORDER[sma200_sig],
                        "sma200_pct": _fmt_pct(sma200_pct),
                        "sharpe_val": f"{sharpe_val:.2f}" if sharpe_val is not None else "\u2014",
                        "sharpe_val_num": sharpe_val if sharpe_val is not None else "",
                        "sortino_val": f"{sortino_val:.2f}" if sortino_val is not None else "\u2014",
                        "sortino_val_num": sortino_val if sortino_val is not None else "",
                        "cov_ratio": f"{cov_ratio:.2f}" if cov_ratio is not None else "\u2014",
                        "cov_ratio_num": cov_ratio if cov_ratio is not None else "",
                        "cov_sig": cov_sig or "NEUTRAL",
                        "cov_sig_ord": SIGNAL_ORDER.get(cov_sig or "NEUTRAL", 1),
                        "nav_erosion": nav_erosion or "\u2014",
                        "div_safety_score": safety.get("safety_score"),
                        "div_safety_risk": safety.get("risk_level") or ("\u2014" if not is_portfolio else "Unknown"),
                        "div_cut_risk": bool(safety.get("cut_risk_flag")) if is_portfolio else False,
                        "div_risk_reasons": safety.get("risk_reasons") or [],
                        "pv_fmt": f"${size:,.2f}" if is_portfolio else "\u2014",
                        "pv_num": float(size) if is_portfolio else 0,
                        "src_order": 0 if is_portfolio else (1 if is_sector else 2),
                    })

                table_rows.sort(key=lambda r: (r["src_order"], r["sig_order"], -r["pv_num"]))

                if has_plotly:
                    fig = go.Figure(go.Treemap(
                        labels=labels,
                        parents=parents_list,
                        values=values_list,
                        text=hover_texts,
                        marker=dict(colors=colors_list),
                        textinfo="label",
                        hovertemplate="<b>%{label}</b><br>%{text}<extra></extra>",
                    ))
                    fig.update_layout(
                        title="Buy / Sell Signal Dashboard",
                        template="plotly_dark",
                        margin=dict(t=50, l=5, r=5, b=5),
                        height=720,
                        hoverlabel=dict(bgcolor="#111124", bordercolor="#3a3a5c",
                                        font=dict(color="#e0e0e0", size=13)),
                    )
                    fig_json = json.dumps(fig, cls=plotly.utils.PlotlyJSONEncoder)

    except Exception:
        import traceback
        error = traceback.format_exc(limit=5)

    def _scrub(obj):
        if isinstance(obj, list):
            return [_scrub(v) for v in obj]
        if isinstance(obj, dict):
            return {k: _scrub(v) for k, v in obj.items()}
        if isinstance(obj, float) and (math.isnan(obj) or math.isinf(obj)):
            return None
        if obj is pd.NaT:
            return None
        if hasattr(obj, 'isoformat'):
            return obj.isoformat()
        return obj

    table_rows = _scrub(table_rows)
    return jsonify(fig_json=fig_json, error=error, table_rows=table_rows)


# ── Watchlist ──────────────────────────────────────────────────────────────────

@app.route("/api/watchlist/watching", methods=["GET", "POST"])
def watchlist_watching_list():
    """GET: return watching rows.  POST: bulk-replace watching list."""
    conn = get_connection()

    if request.method == "POST":
        data = request.get_json(force=True)
        rows = data.get("rows", [])
        preserve_notes = bool(data.get("preserve_notes"))
        existing_notes = {
            r["ticker"]: r["notes"] or ""
            for r in conn.execute("SELECT ticker, notes FROM watchlist_watching").fetchall()
        }
        conn.execute("DELETE FROM watchlist_watching")
        for i, r in enumerate(rows):
            ticker = str(r.get("ticker", "")).strip().upper()
            if not ticker:
                continue
            notes_value = existing_notes.get(ticker, "") if preserve_notes else r.get("notes", existing_notes.get(ticker, ""))
            notes = str(notes_value)[:500]
            override_raw = r.get("div_yield_override", None)
            override = None
            if override_raw is not None and override_raw != "":
                try:
                    override = float(override_raw)
                except (TypeError, ValueError):
                    override = None
            scope = str(r.get("nav_erosion_scope") or "auto").strip().lower()
            if scope not in ("auto", "test", "skip"):
                scope = "auto"
            bench_override = str(r.get("nav_benchmark_override") or "").strip().upper() or None
            conn.execute(
                "INSERT INTO watchlist_watching (ticker, notes, sort_order, div_yield_override, "
                "nav_erosion_scope, nav_benchmark_override) VALUES (?, ?, ?, ?, ?, ?)",
                (ticker, notes, i, override, scope, bench_override),
            )
        conn.commit()
        conn.close()
        return jsonify(ok=True)

    # GET
    rows = conn.execute(
        "SELECT ticker, notes, added_date, div_yield_override, "
        "nav_erosion_scope, nav_benchmark_override "
        "FROM watchlist_watching ORDER BY sort_order, id"
    ).fetchall()
    conn.close()
    result = []
    for r in rows:
        result.append({
            "ticker": r["ticker"],
            "notes": r["notes"] or "",
            "added_date": r["added_date"] or "",
            "div_yield_override": r["div_yield_override"],
            "nav_erosion_scope": r["nav_erosion_scope"] or "auto",
            "nav_benchmark_override": r["nav_benchmark_override"] or "",
        })
    return jsonify(rows=result)


@app.route("/api/watchlist/data")
def watchlist_data():
    """Analysis data for all watchlist tickers."""
    import yfinance as yf
    import numpy as np
    import warnings
    import math
    warnings.filterwarnings("ignore")

    conn = get_connection()
    try:
        watching_rows = conn.execute(
            "SELECT ticker, notes, div_yield_override, "
            "nav_erosion_scope, nav_benchmark_override "
            "FROM watchlist_watching ORDER BY sort_order, id"
        ).fetchall()
    except Exception:
        watching_rows = []
    conn.close()

    watching_tickers = [r["ticker"] for r in watching_rows]
    yield_overrides = {
        r["ticker"]: r["div_yield_override"]
        for r in watching_rows
        if r["div_yield_override"] is not None
    }
    nav_scopes = {
        r["ticker"]: (str(r["nav_erosion_scope"] or "auto").strip().lower() or "auto")
        for r in watching_rows
    }
    nav_bench_overrides = {
        r["ticker"]: (str(r["nav_benchmark_override"] or "").strip().upper())
        for r in watching_rows
        if r["nav_benchmark_override"]
    }
    if not watching_tickers:
        return jsonify(watching=[], counts={"BUY": 0, "SELL": 0, "NEUTRAL": 0})

    # Resolve benchmark per ticker once (per-row override > global override > auto-detect),
    # but only for tickers that will actually be NAV-tested.
    resolved_benchmark = {}
    for t in watching_tickers:
        scope = nav_scopes.get(t, "auto")
        if not _should_test_nav_erosion(t, scope=scope):
            continue
        resolved_benchmark[t] = nav_bench_overrides.get(t) or _nav_benchmark_for_ticker(t)
    benchmark_tickers = sorted({
        part
        for bench in resolved_benchmark.values()
        for part in _nav_benchmark_parts(bench)
    })
    download_tickers = sorted(set(watching_tickers + benchmark_tickers))

    error = None
    result_rows = []
    counts = {"BUY": 0, "SELL": 0, "NEUTRAL": 0}

    # ── Indicator helpers ──

    def _ao(high, low):
        if len(high) < 34:
            return "NEUTRAL", None, ""
        mid = (high + low) / 2
        ao_v = (mid.rolling(5).mean() - mid.rolling(34).mean()).dropna()
        if len(ao_v) < 2:
            return "NEUTRAL", None, ""
        cur, prv = float(ao_v.iloc[-1]), float(ao_v.iloc[-2])
        direction = "Rising" if cur > prv else ("Falling" if cur < prv else "Flat")
        if cur > 0 and cur > prv:
            return "BUY", cur, direction
        if cur < 0 and cur < prv:
            return "SELL", cur, direction
        return "NEUTRAL", cur, direction

    def _rsi(close, period=14):
        if len(close) < period + 1:
            return "NEUTRAL", None
        delta = close.diff()
        avg_gain = delta.clip(lower=0).ewm(com=period - 1, adjust=False, min_periods=period).mean()
        avg_loss = (-delta).clip(lower=0).ewm(com=period - 1, adjust=False, min_periods=period).mean()
        rs = avg_gain / avg_loss
        val = float((100 - 100 / (1 + rs)).iloc[-1])
        if pd.isna(val):
            return "NEUTRAL", None
        if val < 30:
            return "BUY", val
        if val > 70:
            return "SELL", val
        return "NEUTRAL", val

    def _macd(close):
        if len(close) < 26:
            return "NEUTRAL"
        macd_line = close.ewm(span=12, adjust=False).mean() - close.ewm(span=26, adjust=False).mean()
        sig_line = macd_line.ewm(span=9, adjust=False).mean()
        m, s = float(macd_line.iloc[-1]), float(sig_line.iloc[-1])
        if pd.isna(m) or pd.isna(s):
            return "NEUTRAL"
        return "BUY" if m > s else "SELL"

    def _sma(close, period):
        if len(close) < period:
            return "NEUTRAL", None, None
        sma_val = close.rolling(period).mean().iloc[-1]
        price = close.iloc[-1]
        if pd.isna(sma_val) or pd.isna(price) or float(sma_val) == 0:
            return "NEUTRAL", None, None
        sma_f, price_f = float(sma_val), float(price)
        pct = (price_f - sma_f) / sma_f * 100
        if price_f > sma_f * 1.01:
            return "BUY", sma_f, pct
        if price_f < sma_f * 0.99:
            return "SELL", sma_f, pct
        return "NEUTRAL", sma_f, pct

    def _vote(signals):
        valid = [s for s in signals if s is not None]
        if not valid:
            return "NEUTRAL"
        threshold = len(valid) / 2
        if valid.count("BUY") > threshold:
            return "BUY"
        if valid.count("SELL") > threshold:
            return "SELL"
        return "NEUTRAL"

    def _sharpe(close, risk_free_annual=0.05):
        try:
            if len(close) < 30:
                return None
            daily_ret = close.pct_change().dropna()
            if len(daily_ret) < 30:
                return None
            std = float(daily_ret.std())
            if std == 0 or np.isnan(std):
                return None
            daily_rf = risk_free_annual / 252
            excess = float(daily_ret.mean()) - daily_rf
            return round(excess / std * np.sqrt(252), 2)
        except Exception:
            return None

    def _sortino(close, risk_free_annual=0.05):
        try:
            if len(close) < 30:
                return None
            daily_ret = close.pct_change().dropna()
            if len(daily_ret) < 30:
                return None
            daily_rf = risk_free_annual / 252
            neg_ret = daily_ret[daily_ret < 0]
            if len(neg_ret) == 0:
                return None
            down_std = float(neg_ret.std())
            if down_std == 0 or np.isnan(down_std):
                return None
            excess = float(daily_ret.mean()) - daily_rf
            return round(excess / down_std * np.sqrt(252), 2)
        except Exception:
            return None

    try:
        raw = _chunked_yf_download(
            " ".join(download_tickers),
            period="1y",
            interval="1d",
            auto_adjust=False,
            actions=True,
            progress=False,
            ignore_tz=True,
            threads=False,
        )

        if raw.empty:
            return jsonify(watching=[], counts=counts, error="No price data returned.")

        try:
            _top = raw.columns.get_level_values(0)
            has_multi = True
        except AttributeError:
            has_multi = False

        if has_multi:
            close_df = raw["Adj Close"] if "Adj Close" in _top else raw["Close"]
            unadj_close_df = raw["Close"]
            high_df = raw["High"]
            low_df = raw["Low"]
            divs_df = raw["Dividends"] if "Dividends" in _top else None
        else:
            single_symbol = download_tickers[0] if len(download_tickers) == 1 else None
            close_col = "Adj Close" if "Adj Close" in raw.columns else "Close"
            close_df = raw[[close_col]]
            unadj_close_df = raw[["Close"]]
            high_df = raw[["High"]]
            low_df = raw[["Low"]]
            divs_df = raw[["Dividends"]] if "Dividends" in raw.columns else None
            if single_symbol:
                close_df.columns = [single_symbol]
                unadj_close_df.columns = [single_symbol]
                high_df.columns = [single_symbol]
                low_df.columns = [single_symbol]
                if divs_df is not None:
                    divs_df.columns = [single_symbol]

        empty = pd.Series([], dtype=float)
        ticker_info = {}

        for ticker in watching_tickers:
            has_data = (ticker in close_df.columns and
                        ticker in high_df.columns and
                        ticker in low_df.columns)
            if has_data:
                close = close_df[ticker].dropna()
                high = high_df[ticker].dropna()
                low = low_df[ticker].dropna()
            else:
                close = high = low = empty

            ao_sig, ao_val, ao_dir = _ao(high, low)
            rsi_sig, rsi_val = _rsi(close)
            macd_sig = _macd(close)
            sma50_sig, sma50_v, sma50_pct = _sma(close, 50)
            sma200_sig, sma200_v, sma200_pct = _sma(close, 200)
            # Benchmark-adjusted NAV erosion ratio
            cov_ratio, cov_sig, cov_erosion = None, None, None
            scope = nav_scopes.get(ticker, "auto")
            bench_used = resolved_benchmark.get(ticker)
            bench_valid = True
            nav_tested = False
            if divs_df is not None and has_data and bench_used:
                try:
                    t_divs_cov = divs_df[ticker].dropna() if ticker in divs_df.columns else pd.Series([], dtype=float)
                    t_divs_cov = t_divs_cov[t_divs_cov > 0]
                    nav_close = unadj_close_df[ticker].dropna() if ticker in unadj_close_df.columns else close
                    div_yield_override = yield_overrides.get(ticker)
                    if div_yield_override is not None and len(nav_close) >= 1:
                        try:
                            override_yield = float(div_yield_override) / 100.0
                            nav_price = float(nav_close.iloc[-1])
                            if override_yield > 0 and nav_price > 0:
                                t_divs_cov = pd.Series([nav_price * override_yield], dtype=float)
                        except (TypeError, ValueError):
                            pass
                    bench_close = _nav_benchmark_close_from_df(close_df, bench_used, close)
                    # Detect when no benchmark history was returned for an explicit override.
                    if bench_used and bench_close is close:
                        bench_parts = _nav_benchmark_parts(bench_used)
                        if not any(part in close_df.columns and len(close_df[part].dropna()) >= 2 for part in bench_parts):
                            bench_valid = False
                    if bench_valid:
                        cov_ratio, cov_sig, cov_erosion = _bss_coverage(nav_close, t_divs_cov, bench_close)
                        nav_tested = True
                except Exception:
                    pass

            signal = _vote([ao_sig, rsi_sig, macd_sig, sma50_sig, sma200_sig, cov_sig])

            sharpe_val = _sharpe(close)
            sortino_val = _sortino(close)

            price = float(close.iloc[-1]) if len(close) >= 1 else None
            prev_price = float(close.iloc[-2]) if len(close) >= 2 else None
            change_1d = round((price - prev_price) / prev_price * 100, 2) \
                if price is not None and prev_price else None

            div_yield = None
            if divs_df is not None and price is not None and price > 0:
                try:
                    t_divs = divs_df[ticker].dropna() if ticker in divs_df.columns else pd.Series([], dtype=float)
                    ttm_divs = t_divs[t_divs > 0].sum()
                    if ttm_divs > 0:
                        div_yield = round(ttm_divs / price * 100, 2)
                except Exception:
                    pass
            div_yield_override = yield_overrides.get(ticker)
            if div_yield_override is not None:
                try:
                    div_yield = round(float(div_yield_override), 2)
                except (TypeError, ValueError):
                    pass

            one_yr_ret = None
            if len(close) >= 2:
                first_price = float(close.iloc[0])
                if first_price > 0:
                    one_yr_ret = round((price - first_price) / first_price * 100, 2)

            nav_erosion = False
            unadj_close = unadj_close_df[ticker].dropna() if ticker in unadj_close_df.columns else pd.Series([], dtype=float)
            if len(unadj_close) >= 2:
                unadj_first = float(unadj_close.iloc[0])
                unadj_last = float(unadj_close.iloc[-1])
                if unadj_first > 0:
                    unadj_ret = (unadj_last - unadj_first) / unadj_first * 100
                    if unadj_ret < -5:
                        nav_erosion = True

            ticker_info[ticker] = {
                "price": round(price, 2) if price is not None else None,
                "change_1d": change_1d,
                "div_yield": div_yield,
                "div_yield_overridden": ticker in yield_overrides,
                "signal": signal,
                "ao_sig": ao_sig,
                "ao_val": round(ao_val, 4) if ao_val is not None else None,
                "ao_dir": ao_dir,
                "rsi_sig": rsi_sig,
                "rsi_val": round(rsi_val, 1) if rsi_val is not None else None,
                "macd_sig": macd_sig,
                "sma50_sig": sma50_sig,
                "sma50_pct": round(sma50_pct, 1) if sma50_pct is not None else None,
                "sma200_sig": sma200_sig,
                "sma200_pct": round(sma200_pct, 1) if sma200_pct is not None else None,
                "one_yr_ret": one_yr_ret,
                "nav_erosion": nav_erosion,
                "sharpe": round(sharpe_val, 2) if sharpe_val is not None else None,
                "sortino": round(sortino_val, 2) if sortino_val is not None else None,
                "cov_ratio": round(cov_ratio, 4) if cov_ratio is not None else None,
                "cov_sig": cov_sig,
                "nav_erosion_prob": cov_erosion,
                "nav_erosion_scope": scope,
                "nav_benchmark_override": nav_bench_overrides.get(ticker, ""),
                "benchmark": bench_used,
                "benchmark_valid": bench_valid,
                "nav_tested": nav_tested,
            }

        # Build watching result rows
        for wr in watching_rows:
            t = wr["ticker"]
            info = ticker_info.get(t, {})
            result_rows.append({
                "ticker": t,
                "notes": wr["notes"] or "",
                **info,
            })

    except Exception:
        import traceback
        error = traceback.format_exc(limit=5)

    # Scrub NaN/NaT
    def _scrub(obj):
        if isinstance(obj, list):
            return [_scrub(v) for v in obj]
        if isinstance(obj, dict):
            return {k: _scrub(v) for k, v in obj.items()}
        if isinstance(obj, float) and (math.isnan(obj) or math.isinf(obj)):
            return None
        if obj is pd.NaT:
            return None
        if hasattr(obj, 'isoformat'):
            return obj.isoformat()
        return obj

    result_rows = _scrub(result_rows)

    counts = {"BUY": 0, "SELL": 0, "NEUTRAL": 0}
    for row in result_rows:
        sig = row.get("signal", "NEUTRAL")
        counts[sig] = counts.get(sig, 0) + 1

    return jsonify(watching=result_rows, counts=counts, error=error)


# ── NAV Erosion Back-Tester ────────────────────────────────────────────────────

@app.route("/api/nav-erosion/data")
def nav_erosion_data():
    """Back-test a ticker for NAV erosion over a custom date range."""
    import warnings
    warnings.filterwarnings("ignore")

    sym = request.args.get("ticker", "").strip().upper()
    try:
        initial_investment = float(request.args.get("amount", 0))
    except (TypeError, ValueError):
        initial_investment = 0.0
    start_date = request.args.get("start", "")
    end_date = request.args.get("end", "")
    try:
        reinvest_pct = float(request.args.get("reinvest", 0))
    except (TypeError, ValueError):
        reinvest_pct = 0.0

    if not sym:
        return jsonify(error="Please enter a ticker symbol.")
    if initial_investment <= 0:
        return jsonify(error="Initial investment must be greater than zero.")
    if not start_date or not end_date:
        return jsonify(error="Please select both start and end dates.")

    error = None
    warning = None
    fig_json = None
    rows = []
    summary = {}

    try:
        from datetime import datetime as _dt
        import json
        import yfinance as yf
        import plotly.graph_objects as go
        import plotly.utils

        benchmark = _nav_benchmark_for_ticker(sym)
        hist = yf.Ticker(sym).history(
            start=start_date, end=end_date,
            interval="1d", auto_adjust=False, actions=True,
        )
        bench_series = []
        for bench in _nav_benchmark_parts(benchmark):
            try:
                bench_hist = yf.Ticker(bench).history(
                    start=start_date, end=end_date,
                    interval="1d", auto_adjust=True,
                )
                if bench_hist is not None and not bench_hist.empty and "Close" in bench_hist.columns:
                    bench_close = bench_hist["Close"].dropna().rename(bench)
                    if len(bench_close) >= 2:
                        bench_series.append(bench_close)
            except Exception:
                pass

        if hist.empty:
            return jsonify(error=f"No data found for ticker {sym}. Check the symbol and date range.")

        # Detect if data starts later than requested
        requested_start = _dt.strptime(start_date, "%Y-%m-%d").date()
        actual_start = hist.index[0].date()
        if (actual_start - requested_start).days > 30:
            warning = (
                f"{sym} only has data going back to {actual_start.strftime('%B %d, %Y')}. "
                f"Results are shown from that date — your requested start "
                f"({requested_start.strftime('%B %d, %Y')}) predates when this ETF existed."
            )

        monthly_close = hist["Close"].resample("ME").last()
        monthly_divs = hist["Dividends"].resample("ME").sum()
        if len(bench_series) == 1:
            monthly_benchmark = bench_series[0].resample("ME").last()
        elif len(bench_series) > 1:
            aligned_bench = pd.concat(bench_series, axis=1, join="inner").dropna()
            if len(aligned_bench) >= 2:
                composite = 1.0
                for col in aligned_bench.columns:
                    composite = composite + (aligned_bench[col] / float(aligned_bench[col].iloc[0]) - 1.0)
                monthly_benchmark = composite.resample("ME").last()
            else:
                monthly_benchmark = monthly_close
        else:
            monthly_benchmark = monthly_close

        df = pd.DataFrame({"price": monthly_close, "div": monthly_divs, "benchmark_price": monthly_benchmark}).dropna(subset=["price"])
        df["div"] = df["div"].fillna(0.0)
        df["benchmark_price"] = df["benchmark_price"].ffill()

        if df.empty:
            return jsonify(error=f"No usable monthly data for {sym}.")

        initial_price = float(df["price"].iloc[0])
        if initial_price == 0:
            return jsonify(error=f"Initial price for {sym} is zero — cannot calculate.")

        current_shares = initial_investment / initial_price
        cumulative_dist = 0.0
        cumulative_reinvested = 0.0
        cumulative_shares_bought = 0.0
        prev_price = initial_price
        prev_benchmark_price = float(df["benchmark_price"].dropna().iloc[0]) if not df["benchmark_price"].dropna().empty else initial_price
        cumulative_divs_per_share = 0.0

        for dt, row in df.iterrows():
            price = float(row["price"])
            benchmark_price = float(row["benchmark_price"]) if pd.notna(row["benchmark_price"]) else prev_benchmark_price
            div_per_share = float(row["div"])
            total_dist = div_per_share * current_shares
            reinvest_amt = total_dist * reinvest_pct / 100.0
            shares_bought = (reinvest_amt / price) if price > 0 else 0.0
            current_shares += shares_bought
            portfolio_val = current_shares * price
            breakeven_sh = (initial_investment / price) if price > 0 else 0.0
            shares_deficit = breakeven_sh - current_shares
            price_delta_pct = (price - initial_price) / initial_price * 100 if initial_price else 0.0
            cumulative_dist += total_dist
            cumulative_reinvested += reinvest_amt
            cumulative_shares_bought += shares_bought
            cumulative_divs_per_share += div_per_share

            # Benchmark-adjusted NAV erosion ratio. Lower is better.
            if div_per_share > 0 and prev_price > 0 and prev_benchmark_price > 0 and benchmark_price > 0:
                fund_month_return = (price - prev_price) / prev_price
                benchmark_month_return = (benchmark_price - prev_benchmark_price) / prev_benchmark_price
                month_dist_yield = div_per_share / price if price > 0 else 0.0
                numerator = _nav_erosion_numerator(fund_month_return, benchmark_month_return)
                coverage_ratio = round(numerator / month_dist_yield, 4) if month_dist_yield > 0 and numerator is not None else None
            else:
                coverage_ratio = None
            prev_price = price
            prev_benchmark_price = benchmark_price

            rows.append({
                "date": dt.strftime("%b %Y"),
                "price": round(price, 4),
                "benchmark_price": round(benchmark_price, 4) if benchmark_price is not None else None,
                "price_delta_pct": round(price_delta_pct, 2),
                "div_per_share": round(div_per_share, 4),
                "total_dist": round(total_dist, 2),
                "reinvested": round(reinvest_amt, 2),
                "shares_bought": round(shares_bought, 4),
                "total_shares": round(current_shares, 4),
                "portfolio_val": round(portfolio_val, 2),
                "breakeven_sh": round(breakeven_sh, 4),
                "shares_deficit": round(shares_deficit, 4),
                "coverage_ratio": coverage_ratio,
            })

        final_row = rows[-1]
        # Aggregate benchmark-adjusted NAV erosion ratio across the selected period.
        benchmark_start = float(df["benchmark_price"].dropna().iloc[0]) if not df["benchmark_price"].dropna().empty else initial_price
        benchmark_end = float(df["benchmark_price"].dropna().iloc[-1]) if not df["benchmark_price"].dropna().empty else final_row["price"]
        fund_return = (final_row["price"] - initial_price) / initial_price if initial_price > 0 else 0.0
        benchmark_return = (benchmark_end - benchmark_start) / benchmark_start if benchmark_start > 0 else fund_return
        period_dist_yield, _ = _nav_distribution_yield_from_history(
            df["div"],
            final_row["price"],
            df["price"],
        )
        numerator = _nav_erosion_numerator(fund_return, benchmark_return)
        if period_dist_yield > 0 and numerator is not None:
            total_coverage = round(numerator / period_dist_yield, 4)
        else:
            total_coverage = None
        deficit_pct = (
            final_row["shares_deficit"] / final_row["breakeven_sh"] * 100
            if final_row.get("breakeven_sh", 0) and final_row["shares_deficit"] > 0
            else 0.0
        )
        total_severity = _nav_erosion_from_adjusted_ratio(
            total_coverage,
            price_change_pct=final_row["price_delta_pct"],
            deficit_pct=deficit_pct,
        )
        summary = {
            "benchmark": benchmark,
            "total_dist": round(cumulative_dist, 2),
            "total_shares_bought": round(cumulative_shares_bought, 4),
            "total_reinvested": round(cumulative_reinvested, 2),
            "final_value": final_row["portfolio_val"],
            "price_chg_pct": final_row["price_delta_pct"],
            "has_erosion": final_row["shares_deficit"] > 0,
            "final_deficit": final_row["shares_deficit"],
            "final_deficit_pct": round(deficit_pct, 2),
            "total_coverage": total_coverage,
            "nav_erosion_severity": total_severity,
        }

        dates_list = [r["date"] for r in rows]
        prices_list = [r["price"] for r in rows]
        vals_list = [r["portfolio_val"] for r in rows]
        breakeven_list = [initial_investment] * len(rows)

        fig = go.Figure()
        fig.add_trace(go.Scatter(
            x=dates_list, y=prices_list,
            name="Share Price",
            line=dict(color="#7ecfff", width=2),
            yaxis="y1",
            hovertemplate="<b>%{x}</b><br>Price: $%{y:.2f}<extra></extra>",
        ))
        fig.add_trace(go.Scatter(
            x=dates_list, y=vals_list,
            name="Portfolio Value",
            line=dict(color="#00e89a", width=2),
            yaxis="y2",
            hovertemplate="<b>%{x}</b><br>Portfolio Value: $%{y:,.2f}<extra></extra>",
        ))
        fig.add_trace(go.Scatter(
            x=dates_list, y=breakeven_list,
            name="Initial Investment",
            line=dict(color="#888", width=1.5, dash="dash"),
            yaxis="y2",
            hovertemplate="<b>%{x}</b><br>Break-Even: $%{y:,.2f}<extra></extra>",
        ))
        fig.update_layout(
            title=f"{sym} — NAV Erosion Back-Test ({rows[0]['date']} → {rows[-1]['date']})",
            template="plotly_dark",
            margin=dict(t=50, l=60, r=60, b=50),
            height=420,
            legend=dict(orientation="h", y=1.08, x=0),
            hoverlabel=dict(
                bgcolor="#111124",
                bordercolor="#3a3a5c",
                font=dict(color="#e0e0e0", size=13),
            ),
            yaxis=dict(title="Share Price ($)", tickprefix="$", side="left"),
            yaxis2=dict(
                title="Portfolio Value ($)", tickprefix="$",
                overlaying="y", side="right", showgrid=False,
            ),
            hovermode="x unified",
        )
        fig_json = json.dumps(fig, cls=plotly.utils.PlotlyJSONEncoder)

    except Exception:
        import traceback
        error = traceback.format_exc(limit=5)

    return jsonify(fig_json=fig_json, error=error, warning=warning, rows=rows, summary=summary)


# ── NAV Erosion Portfolio Screener ─────────────────────────────────────────────

def _nav_erosion_portfolio_profile_scope(conn):
    agg_id = _request_aggregate_id()
    if agg_id is not None:
        pids = _get_aggregate_member_profile_ids(conn, agg_id)
        return pids or [1], "aggregate"

    profile_id = get_profile_id()
    if profile_id == 1:
        pids = _get_owner_source_profile_ids(conn)
        return pids or [1], "owner"
    return [profile_id], "profile"


# Reserved name for the auto-saved backtest mirroring the live portfolio.
NAV_EROSION_CURRENT_NAME = "My Current Portfolio"


def _nav_erosion_current_rows(conn):
    """Build NAV erosion screener rows from the currently selected portfolio.

    Returns (rows, scope, total_count) where rows is a list of
    {ticker, amount, reinvest_pct} dicts (capped at 80).
    """
    profile_ids, scope = _nav_erosion_portfolio_profile_scope(conn)
    placeholders = ",".join("?" * len(profile_ids))
    basis_expr = _basis_total_expr("")
    value_expr = (
        "COALESCE(NULLIF(current_value, 0), "
        "CASE WHEN COALESCE(quantity, 0) > 0 AND COALESCE(current_price, 0) > 0 "
        "THEN quantity * current_price END, "
        f"NULLIF({basis_expr}, 0), 0)"
    )
    rows = conn.execute(
        f"""SELECT ticker,
                   SUM({value_expr}) AS amount,
                   SUM(CASE WHEN UPPER(COALESCE(reinvest, '')) = 'Y'
                            THEN {value_expr} ELSE 0 END) AS reinvest_amount
              FROM all_account_info
             WHERE profile_id IN ({placeholders})
               AND COALESCE(quantity, 0) > 0
               AND ticker IS NOT NULL
               AND TRIM(ticker) != ''
          GROUP BY UPPER(TRIM(ticker))
            HAVING amount > 0
          ORDER BY amount DESC""",
        profile_ids,
    ).fetchall()

    total_count = len(rows)
    out = []
    for r in rows[:80]:
        amount = float(r["amount"] or 0)
        reinvest_amount = float(r["reinvest_amount"] or 0)
        out.append({
            "ticker": str(r["ticker"] or "").strip().upper(),
            "amount": round(amount, 2),
            "reinvest_pct": round((reinvest_amount / amount * 100.0) if amount > 0 else 0.0, 1),
        })
    return out, scope, total_count


@app.route("/api/nav-erosion-portfolio/current")
def nav_erosion_portfolio_current():
    """Return NAV erosion screener rows for the currently selected portfolio."""
    conn = get_connection()
    ensure_tables_exist(conn)
    out, scope, total_count = _nav_erosion_current_rows(conn)
    conn.close()
    return jsonify(
        rows=out,
        source=scope,
        total_count=total_count,
        truncated=total_count > 80,
    )


@app.route("/api/nav-erosion-portfolio/save-current", methods=["POST"])
def nav_erosion_portfolio_save_current():
    """Upsert the live portfolio into a single reserved saved backtest.

    Keeps one always-fresh "My Current Portfolio" entry in the Saved Backtests
    list so the user can run it on demand. Does NOT run the backtest. Reuses the
    reserved name so repeated saves refresh in place rather than duplicating.
    """
    import json as _json
    data = request.get_json(force=True, silent=True) or {}
    start = str(data.get("start", "") or "")
    end = str(data.get("end", "") or "")

    conn = get_connection()
    ensure_tables_exist(conn)
    out, scope, total_count = _nav_erosion_current_rows(conn)

    if not out:
        conn.close()
        return jsonify(rows=[], saved=False, source=scope, total_count=total_count)

    cur = conn.cursor()
    rows_json = _json.dumps(out)
    cur.execute(
        "SELECT id FROM nav_erosion_saved_backtests WHERE name = ?",
        (NAV_EROSION_CURRENT_NAME,),
    )
    existing = cur.fetchone()
    if existing:
        saved_id = existing[0]
        cur.execute(
            "UPDATE nav_erosion_saved_backtests "
            "SET start_date=?, end_date=?, rows_json=?, created_at=CURRENT_TIMESTAMP "
            "WHERE id=?",
            (start, end, rows_json, saved_id),
        )
    else:
        cur.execute(
            "INSERT INTO nav_erosion_saved_backtests (name, start_date, end_date, rows_json) "
            "VALUES (?, ?, ?, ?)",
            (NAV_EROSION_CURRENT_NAME, start, end, rows_json),
        )
        saved_id = cur.lastrowid
    conn.commit()
    conn.close()

    return jsonify(
        rows=out,
        saved=True,
        id=saved_id,
        name=NAV_EROSION_CURRENT_NAME,
        start=start,
        end=end,
        source=scope,
        total_count=total_count,
        truncated=total_count > 80,
    )


@app.route("/api/nav-erosion-portfolio/list", methods=["GET", "POST"])
def nav_erosion_portfolio_list():
    conn = get_connection()
    ensure_tables_exist(conn)
    cur = conn.cursor()

    if request.method == "GET":
        cur.execute(
            "SELECT ticker, amount, reinvest_pct FROM nav_erosion_portfolio_list ORDER BY sort_order"
        )
        rows = [{"ticker": r[0], "amount": r[1], "reinvest_pct": r[2]} for r in cur.fetchall()]
        conn.close()
        return jsonify(rows=rows)

    # POST — replace list
    data = request.get_json(force=True, silent=True) or {}
    rows = data.get("rows", [])

    if len(rows) > 80:
        conn.close()
        return jsonify(error="Maximum 80 ETFs allowed.")

    validated = []
    for i, r in enumerate(rows):
        ticker = str(r.get("ticker", "")).strip().upper()
        if not ticker:
            conn.close()
            return jsonify(error=f"Row {i+1}: ticker is required.")
        try:
            amount = float(r.get("amount", 0))
        except (TypeError, ValueError):
            conn.close()
            return jsonify(error=f"Row {i+1}: invalid amount.")
        if amount <= 0:
            conn.close()
            return jsonify(error=f"Row {i+1}: amount must be greater than 0.")
        try:
            reinvest_pct = float(r.get("reinvest_pct", 0))
        except (TypeError, ValueError):
            conn.close()
            return jsonify(error=f"Row {i+1}: invalid reinvest %.")
        if reinvest_pct < 0 or reinvest_pct > 100:
            conn.close()
            return jsonify(error=f"Row {i+1}: reinvest % must be 0–100.")
        validated.append((ticker, amount, reinvest_pct, i))

    cur.execute("DELETE FROM nav_erosion_portfolio_list")
    for ticker, amount, reinvest_pct, sort_order in validated:
        cur.execute(
            "INSERT INTO nav_erosion_portfolio_list (ticker, amount, reinvest_pct, sort_order) "
            "VALUES (?, ?, ?, ?)",
            (ticker, amount, reinvest_pct, sort_order),
        )
    conn.commit()
    conn.close()
    return jsonify(ok=True)


