@app.route("/api/analytics/peers", methods=["POST"])
def analytics_peers():
    import yfinance as yf
    data = request.get_json() or {}
    ticker = (data.get("ticker", "")).upper()
    if not ticker:
        return jsonify({"ticker": "", "category": "", "peers": []})

    # Find which group(s) this ticker belongs to
    found_category = ""
    peer_tickers = []
    for cat, members in PEER_GROUPS.items():
        if ticker in members:
            found_category = cat
            peer_tickers = [t for t in members if t != ticker]
            break

    # Also check single-stock ETFs
    if not found_category and ticker in _get_single_stock_etfs():
        found_category = "Single-Stock ETFs"
        ss = _get_single_stock_etfs()
        peer_tickers = sorted([t for t in ss if t != ticker])[:10]

    if not peer_tickers:
        return jsonify({"ticker": ticker, "category": "", "peers": []})

    # Fetch quick metrics for peers
    from concurrent.futures import ThreadPoolExecutor

    def _fetch_peer(t):
        try:
            info = yf.Ticker(t).info
            name = info.get("shortName", info.get("longName", ""))
            yld = info.get("yield", info.get("dividendYield", 0))
            if yld and yld > 0:
                yld = float(yld) * 100
            else:
                yld = None
            # 1Y return from regularMarketPrice / fiftyTwoWeekLow approximate
            price = info.get("regularMarketPrice", info.get("previousClose", 0))
            year_low = info.get("fiftyTwoWeekLow", 0)
            if price and year_low and year_low > 0:
                ret_1y = (price / year_low - 1) * 100  # approximation from 52w low
            else:
                ret_1y = None
            return {"ticker": t, "name": name, "yield_pct": round(yld, 2) if yld else None, "return_1y": round(ret_1y, 1) if ret_1y else None}
        except Exception:
            return {"ticker": t, "name": "", "yield_pct": None, "return_1y": None}

    with ThreadPoolExecutor(max_workers=6) as pool:
        peers = list(pool.map(_fetch_peer, peer_tickers))

    return jsonify({"ticker": ticker, "category": found_category, "peers": peers})


# ── Portfolio Tester (head-to-head backtester) ────────────────────────────────

@app.route("/api/portfolio-tester/holdings", methods=["GET"])
def portfolio_tester_holdings():
    """Return the user's current holdings with user-defined category names
    (from the Categories page) for filtered loading."""
    is_agg, pids = get_profile_filter()
    conn = get_connection()
    placeholders = ",".join("?" * len(pids))
    rows = conn.execute(
        f"""SELECT ticker,
                   SUM(COALESCE(current_value, 0)) AS current_value
              FROM all_account_info
             WHERE profile_id IN ({placeholders})
               AND current_value IS NOT NULL
               AND current_value > 0
          GROUP BY ticker
          ORDER BY current_value DESC""",
        pids,
    ).fetchall()

    cat_rows = conn.execute(
        f"""SELECT tc.ticker, c.name
              FROM ticker_categories tc
              JOIN categories c ON c.id = tc.category_id
             WHERE tc.profile_id IN ({placeholders})
               AND c.profile_id IN ({placeholders})""",
        pids + pids,
    ).fetchall()
    conn.close()

    cats_by_ticker = {}
    for r in cat_rows:
        cats_by_ticker.setdefault(r["ticker"], []).append(r["name"])

    total = sum((r["current_value"] or 0) for r in rows) or 1.0
    out = [{
        "ticker": r["ticker"],
        "current_value": float(r["current_value"] or 0),
        "weight": float(r["current_value"] or 0) / total,
        "categories": sorted(set(cats_by_ticker.get(r["ticker"], []))),
    } for r in rows]
    all_cats = sorted({name for names in cats_by_ticker.values() for name in names})
    return jsonify({"holdings": out, "categories": all_cats})


@app.route("/api/portfolio-tester/run", methods=["POST"])
def portfolio_tester_run():
    from portfolio_tester import run_backtest, MAX_TICKERS_PER_PORTFOLIO, MAX_YEARS
    data = request.get_json(force=True, silent=True) or {}

    portfolios = data.get("portfolios") or []
    if len(portfolios) < 1 or len(portfolios) > 2:
        return jsonify(error="Provide 1 or 2 portfolios."), 400

    start = data.get("start")
    end = data.get("end")
    if not start or not end:
        return jsonify(error="start and end dates are required."), 400

    initial = float(data.get("initial", 10000))
    include_div = bool(data.get("include_div", True))
    reinvest_div = bool(data.get("reinvest_div", True))
    rebalance = (data.get("rebalance") or "none").lower()

    # Income-mode controls. distribution_policy, when supplied, is the canonical
    # control and overrides include_div/reinvest_div; otherwise the legacy flags
    # win so existing callers behave identically.
    spend_income = bool(data.get("spend_income", False))
    policy = (data.get("distribution_policy") or "").strip().lower()
    if policy == "exclude":
        include_div = False
    elif policy == "reinvest":
        include_div, reinvest_div, spend_income = True, True, False
    elif policy in ("spend", "spend_target"):
        include_div, reinvest_div, spend_income = True, False, True

    def _as_fraction(v):
        """Accept either a fraction (0.25) or a percentage (25); clamp to [0,1]."""
        x = float(v or 0)
        if x > 1:
            x = x / 100.0
        return min(max(x, 0.0), 1.0)

    # Blended distribution tax rate.
    tax_rate = _as_fraction(data.get("tax_rate", 0))

    # Target-income spending: withdraw_rate (fraction of initial per year) with
    # surplus reinvested / shortfall sold. 0 = spend all distributions. Only the
    # spend_target policy turns it on.
    withdraw_rate = _as_fraction(data.get("withdraw_rate", 0)) if policy == "spend_target" else 0.0
    withdraw_inflation = _as_fraction(data.get("withdraw_inflation", 0))

    equal_withdrawal = bool(data.get("equal_withdrawal", False))

    # Respect explicit include_benchmark=false so the user can compare A vs B only.
    # Default to True for backward compatibility.
    include_benchmark = data.get("include_benchmark", True)
    if include_benchmark:
        benchmark = (data.get("benchmark") or "SPY").strip().upper() or None
    else:
        benchmark = None

    try:
        result = run_backtest(
            portfolios=portfolios,
            benchmark=benchmark,
            start=start, end=end,
            initial=initial,
            include_div=include_div,
            reinvest_div=reinvest_div,
            rebalance=rebalance,
            tax_rate=tax_rate,
            spend_income=spend_income,
            equal_withdrawal=equal_withdrawal,
            withdraw_rate=withdraw_rate,
            withdraw_inflation=withdraw_inflation,
        )
    except ValueError as e:
        return jsonify(error=str(e)), 400
    except Exception as e:
        return jsonify(error=f"Backtest failed: {e}"), 500

    return jsonify(result)


