@app.route("/api/rebalance/category-plan", methods=["POST"])
def rebalance_category_plan():
    """Generate a category-target rebalance plan with income constraints."""
    data = request.get_json() or {}
    income_mode = data.get("income_mode", "preserve_current")
    rebalance_strategy = data.get("rebalance_strategy", "match_targets_preserve_income")
    min_yield = data.get("min_yield")
    min_monthly_income = data.get("min_monthly_income")
    new_cash = max(float(data.get("new_cash") or 0), 0)
    allow_sells = bool(data.get("allow_sells", True))
    min_trade_amount = max(float(data.get("min_trade_amount") or 100), 0)
    locked_tickers = {str(t).strip().upper() for t in data.get("locked_tickers", []) if str(t).strip()}

    _, pids = get_profile_filter()
    placeholders = ",".join("?" * len(pids))
    conn = get_connection()

    cats = conn.execute(
        f"""SELECT id, name, target_pct, profile_id
            FROM categories
            WHERE profile_id IN ({placeholders})
            ORDER BY profile_id, sort_order, name""",
        pids,
    ).fetchall()

    holdings_rows = conn.execute(
        f"""SELECT ticker, description, profile_id, quantity, current_price, current_value,
                   approx_monthly_income, current_annual_yield, reinvest, nav_erosion_scope
            FROM all_account_info
            WHERE profile_id IN ({placeholders}) AND IFNULL(quantity, 0) > 0""",
        pids,
    ).fetchall()

    assignments = conn.execute(
        f"""SELECT tc.ticker, tc.profile_id, tc.category_id, c.name AS category_name
            FROM ticker_categories tc
            JOIN categories c ON c.id = tc.category_id
            WHERE tc.profile_id IN ({placeholders})""",
        pids,
    ).fetchall()

    candidate_rows = conn.execute(
        f"""SELECT a.ticker, a.description, a.profile_id, a.current_price, a.current_value,
                   a.approx_monthly_income, a.current_annual_yield, a.nav_erosion_scope,
                   c.name AS category_name
            FROM ticker_categories tc
            JOIN categories c ON c.id = tc.category_id
            LEFT JOIN all_account_info a ON a.ticker = tc.ticker AND a.profile_id = tc.profile_id
            WHERE tc.profile_id IN ({placeholders})""",
        pids,
    ).fetchall()

    pref_rows = conn.execute(
        f"""SELECT category, ticker, rank, preferred
            FROM rebalance_candidate_preferences
            WHERE profile_id IN ({placeholders})
            ORDER BY category, rank, ticker""",
        pids,
    ).fetchall()
    conn.close()

    if not holdings_rows:
        return jsonify({"error": "No active holdings found for this portfolio."}), 400
    if not cats:
        return jsonify({"error": "Please set your category target weights before running this."}), 400

    category_targets = {}
    target_conflicts = []
    missing_targets = []
    for cat in cats:
        name = cat["name"]
        target = cat["target_pct"]
        if target is None:
            missing_targets.append(name)
            continue
        target = float(target)
        if name in category_targets and abs(category_targets[name] - target) > 0.01:
            target_conflicts.append(name)
        category_targets[name] = target

    if not category_targets:
        return jsonify({"error": "Please set your category target weights before running this."}), 400
    if missing_targets:
        names = ", ".join(sorted(set(missing_targets))[:8])
        more = "" if len(set(missing_targets)) <= 8 else "..."
        return jsonify({"error": f"Please set target weights for every category before rebalancing. Missing: {names}{more}."}), 400
    if target_conflicts:
        names = ", ".join(sorted(set(target_conflicts))[:8])
        return jsonify({"error": f"Category target weights conflict across selected portfolios: {names}. Please align them before rebalancing."}), 400

    target_total = sum(category_targets.values())
    if abs(target_total - 100.0) > 0.2:
        return jsonify({"error": f"Category target weights must total 100% before rebalancing. Current total: {target_total:.1f}%."}), 400

    assignment_map = {}
    for a in assignments:
        assignment_map[(str(a["ticker"]).upper(), a["profile_id"])] = a["category_name"]

    holdings = []
    unallocated = []
    total_value = 0.0
    total_monthly_income = 0.0
    for row in holdings_rows:
        ticker = str(row["ticker"]).upper()
        value = float(row["current_value"] or 0)
        monthly_income = float(row["approx_monthly_income"] or 0)
        annual_yield = row["current_annual_yield"]
        if annual_yield is None and value > 0:
            annual_yield = (monthly_income * 12) / value
        annual_yield = float(annual_yield or 0)
        if annual_yield > 1:
            annual_yield = annual_yield / 100.0
        category = assignment_map.get((ticker, row["profile_id"]))
        holding = {
            "ticker": ticker,
            "description": row["description"] or "",
            "category": category,
            "quantity": float(row["quantity"] or 0),
            "current_price": float(row["current_price"] or 0),
            "current_value": value,
            "monthly_income": monthly_income,
            "annual_yield": annual_yield,
            "reinvest": row["reinvest"] or "",
            "nav_erosion_scope": row["nav_erosion_scope"] or "auto",
            "locked": ticker in locked_tickers,
        }
        if not category:
            unallocated.append(holding)
        holdings.append(holding)
        total_value += value
        total_monthly_income += monthly_income

    if total_value <= 0:
        return jsonify({"error": "Portfolio value is zero, so a rebalance plan cannot be generated."}), 400
    if unallocated:
        sample = ", ".join(h["ticker"] for h in unallocated[:8])
        more = "" if len(unallocated) <= 8 else "..."
        return jsonify({"error": f"Assign all holdings to categories before rebalancing. Unallocated: {sample}{more}."}), 400

    before_yield = (total_monthly_income * 12) / total_value if total_value > 0 else 0
    required_monthly_income = total_monthly_income if income_mode == "preserve_current" else 0
    if min_monthly_income not in (None, ""):
        required_monthly_income = max(required_monthly_income, float(min_monthly_income))
    if min_yield not in (None, ""):
        required_monthly_income = max(required_monthly_income, (float(min_yield) / 100.0) * (total_value + new_cash) / 12.0)
    suspicious_yield_threshold = max(0.25, before_yield * 2.0, 0.02)

    buckets = {
        name: {
            "name": name,
            "target_pct": target,
            "current_value": 0.0,
            "monthly_income": 0.0,
            "holdings": [],
        }
        for name, target in category_targets.items()
    }
    for h in holdings:
        if h["category"] not in buckets:
            return jsonify({"error": f"Holding {h['ticker']} is assigned to category '{h['category']}', which has no target weight."}), 400
        b = buckets[h["category"]]
        b["current_value"] += h["current_value"]
        b["monthly_income"] += h["monthly_income"]
        b["holdings"].append(h)

    category_candidate_rows = {}
    for r in candidate_rows:
        cat_name = r["category_name"]
        if not cat_name:
            continue
        ticker = str(r["ticker"] or "").strip().upper()
        if not ticker:
            continue
        price = float(r["current_price"] or 0)
        monthly_income = float(r["approx_monthly_income"] or 0)
        current_value = float(r["current_value"] or 0)
        annual_yield = r["current_annual_yield"]
        if annual_yield is None and current_value > 0:
            annual_yield = (monthly_income * 12) / current_value
        annual_yield = float(annual_yield or 0)
        if annual_yield > 1:
            annual_yield = annual_yield / 100.0
        category_candidate_rows.setdefault(cat_name, {})[ticker] = {
            "ticker": ticker,
            "description": r["description"] or "",
            "price": price,
            "yield": annual_yield,
            "current_value": current_value,
            "monthly_income": monthly_income,
            "nav_erosion_scope": r["nav_erosion_scope"] or "auto",
        }

    preference_map = {}
    for r in pref_rows:
        category = _rebalance_pref_key(r["category"])
        preference_map.setdefault(category, []).append({
            "ticker": str(r["ticker"] or "").upper(),
            "rank": int(r["rank"] or 0),
            "preferred": bool(r["preferred"]),
        })

    plan_value = total_value + new_cash
    bucket_results = []
    for b in buckets.values():
        target_value = plan_value * b["target_pct"] / 100.0
        gap = target_value - b["current_value"]
        actual_pct = (b["current_value"] / total_value * 100.0) if total_value > 0 else 0
        bucket_results.append({
            "category": b["name"],
            "target_pct": round(b["target_pct"], 4),
            "actual_pct": round(actual_pct, 4),
            "drift_pct": round(actual_pct - b["target_pct"], 4),
            "current_value": round(b["current_value"], 2),
            "target_value": round(target_value, 2),
            "gap_dollars": round(gap, 2),
            "monthly_income": round(b["monthly_income"], 2),
        })

    trades = []
    warnings = []
    projected_monthly = total_monthly_income
    cash_available = new_cash

    underweights = sorted(
        [r for r in bucket_results if r["gap_dollars"] >= min_trade_amount],
        key=lambda r: r["gap_dollars"],
        reverse=True,
    )
    overweights = sorted(
        [r for r in bucket_results if r["gap_dollars"] <= -min_trade_amount],
        key=lambda r: r["gap_dollars"],
    )

    def _sell_candidates(category):
        rows = [h for h in buckets[category]["holdings"] if not h["locked"] and h["current_value"] > 0]
        return sorted(rows, key=lambda h: (h["annual_yield"], -h["current_value"]))

    def _buy_candidate(category):
        rows = [h for h in buckets[category]["holdings"] if not h["locked"] and h["current_price"] > 0]
        if not rows:
            rows = [h for h in buckets[category]["holdings"] if h["current_price"] > 0]
        if not rows:
            return None
        return sorted(rows, key=lambda h: (h["annual_yield"], h["current_value"]), reverse=True)[0]

    if rebalance_strategy == "maximize_income_reduce_drift":
        underweights = sorted(
            underweights,
            key=lambda r: ((_buy_candidate(r["category"]) or {}).get("annual_yield", 0), r["gap_dollars"]),
            reverse=True,
        )

    def _candidate_payload(raw, category, source, rank=999, preferred=False):
        ticker = str(raw.get("ticker") or "").upper()
        price = float(raw.get("price") or raw.get("current_price") or 0)
        annual_yield = float(raw.get("yield") or raw.get("annual_yield") or 0)
        if annual_yield > 1:
            annual_yield = annual_yield / 100.0
        amount = float(raw.get("sample_amount") or 0)
        return {
            "ticker": ticker,
            "description": raw.get("description") or "",
            "price": round(price, 4) if price > 0 else None,
            "yield": round(annual_yield * 100, 4) if annual_yield > 0 else None,
            "monthly_income_per_dollar": annual_yield / 12.0 if annual_yield > 0 else None,
            "sample_monthly_income": round(amount * annual_yield / 12.0, 2) if amount > 0 and annual_yield > 0 else None,
            "suspicious_yield": annual_yield >= suspicious_yield_threshold,
            "suspicious_yield_threshold": round(suspicious_yield_threshold * 100, 4),
            "current_value": round(float(raw.get("current_value") or 0), 2),
            "monthly_income": round(float(raw.get("monthly_income") or 0), 2),
            "nav_erosion_scope": raw.get("nav_erosion_scope") or "auto",
            "nav_risk": _rebalance_nav_risk(ticker, raw.get("description") or "", category, raw.get("nav_erosion_scope") or "auto"),
            "source": source,
            "rank": rank,
            "preferred": preferred,
        }

    def _buy_candidates(category, selected=None, amount=0):
        seen = set()
        out = []
        pref_tickers = preference_map.get(_rebalance_pref_key(category), [])
        assigned_candidates = category_candidate_rows.get(category, {})
        for pref in pref_tickers:
            ticker = pref["ticker"]
            raw = assigned_candidates.get(ticker, {"ticker": ticker, "sample_amount": amount})
            raw = {**raw, "sample_amount": amount}
            if ticker in seen:
                continue
            seen.add(ticker)
            out.append(_candidate_payload(raw, category, "preferred", pref["rank"], preferred=True))
        rows = sorted(
            [h for h in buckets[category]["holdings"] if h["current_price"] > 0],
            key=lambda h: (h["annual_yield"], h["current_value"]),
            reverse=True,
        )
        for h in rows:
            if h["ticker"] in seen:
                continue
            seen.add(h["ticker"])
            out.append(_candidate_payload({
                "ticker": h["ticker"],
                "description": h["description"],
                "price": h["current_price"],
                "yield": h["annual_yield"],
                "current_value": h["current_value"],
                "monthly_income": h["monthly_income"],
                "nav_erosion_scope": h["nav_erosion_scope"],
                "sample_amount": amount,
            }, category, "held"))
        for ticker, raw in sorted(assigned_candidates.items()):
            if ticker in seen:
                continue
            seen.add(ticker)
            out.append(_candidate_payload({**raw, "sample_amount": amount}, category, "assigned"))
        for ticker in _rebalance_category_seed_tickers(category):
            t = ticker.upper()
            if t in seen:
                continue
            seen.add(t)
            out.append(_candidate_payload({"ticker": t, "sample_amount": amount}, category, "library"))
        if selected and selected not in seen:
            out.insert(0, _candidate_payload({"ticker": selected, "sample_amount": amount}, category, "selected"))
        return out

    sell_pool = []
    if allow_sells:
        for over in overweights:
            remaining = abs(over["gap_dollars"])
            for h in _sell_candidates(over["category"]):
                if remaining < min_trade_amount:
                    break
                amount = min(h["current_value"], remaining)
                if amount < min_trade_amount:
                    continue
                monthly_delta = -(amount * h["annual_yield"] / 12.0)
                sell_pool.append({
                    "action": "sell",
                    "ticker": h["ticker"],
                    "category": over["category"],
                    "amount": amount,
                    "price": h["current_price"],
                    "shares": amount / h["current_price"] if h["current_price"] > 0 else None,
                    "monthly_income_delta": monthly_delta,
                    "yield": h["annual_yield"],
                    "reason": "Reduce overweight category; lower-yield positions are sold first to protect income.",
                })
                remaining -= amount

    for under in underweights:
        need = under["gap_dollars"]
        buy = _buy_candidate(under["category"])
        if not buy:
            warnings.append(f"No priced holding exists in {under['category']} to receive buys.")
            continue
        funded = min(cash_available, need)
        if funded < need and allow_sells:
            while funded < need and sell_pool:
                s = sell_pool.pop(0)
                trades.append(s)
                projected_monthly += s["monthly_income_delta"]
                cash_available += s["amount"]
                funded = min(cash_available, need)
        amount = min(cash_available, need)
        if amount < min_trade_amount:
            continue
        monthly_delta = amount * buy["annual_yield"] / 12.0
        trades.append({
            "action": "buy",
            "ticker": buy["ticker"],
            "category": under["category"],
            "amount": amount,
            "price": buy["current_price"],
            "shares": amount / buy["current_price"] if buy["current_price"] > 0 else None,
            "monthly_income_delta": monthly_delta,
            "yield": buy["annual_yield"],
            "candidates": _buy_candidates(under["category"], selected=buy["ticker"], amount=amount),
            "reason": "Add to underweight category; highest-yield existing position is preferred.",
        })
        if buy["annual_yield"] >= suspicious_yield_threshold:
            trades[-1]["suspicious_yield"] = True
        projected_monthly += monthly_delta
        cash_available -= amount

    if not allow_sells and new_cash <= 0:
        warnings.append("No trades were generated because sells are disabled and no new cash was provided.")

    if projected_monthly + 0.01 < required_monthly_income:
        warnings.append(
            f"Projected income is below the required floor: ${projected_monthly:,.2f}/mo vs ${required_monthly_income:,.2f}/mo."
        )
    if any(t.get("suspicious_yield") for t in trades):
        warnings.append(
            f"One or more replacement buys yields at least {suspicious_yield_threshold * 100:.1f}%. Review the payout source before trading."
        )

    buy_total = sum(t["amount"] for t in trades if t["action"] == "buy")
    sell_total = sum(t["amount"] for t in trades if t["action"] == "sell")
    after_value = total_value + new_cash
    after_yield = (projected_monthly * 12) / after_value if after_value > 0 else 0
    category_candidates = {
        b["category"]: _buy_candidates(
            b["category"],
            amount=max(float(b.get("gap_dollars") or 0), min_trade_amount),
        )
        for b in bucket_results
    }

    return jsonify({
        "before": {
            "value": round(total_value, 2),
            "monthly_income": round(total_monthly_income, 2),
            "annual_income": round(total_monthly_income * 12, 2),
            "yield": round(before_yield * 100, 4),
        },
        "after": {
            "value": round(after_value, 2),
            "monthly_income": round(projected_monthly, 2),
            "annual_income": round(projected_monthly * 12, 2),
            "yield": round(after_yield * 100, 4),
        },
        "required": {
            "monthly_income": round(required_monthly_income, 2),
            "yield": round((required_monthly_income * 12 / after_value * 100) if after_value > 0 else 0, 4),
        },
        "summary": {
            "total_buys": round(buy_total, 2),
            "total_sells": round(sell_total, 2),
            "net_cash": round(buy_total - sell_total, 2),
            "cash_remaining": round(cash_available, 2),
            "strategy": rebalance_strategy,
        },
        "guardrails": {
            "income_floor_enforced": required_monthly_income > 0,
            "income_floor_met": projected_monthly + 0.01 >= required_monthly_income,
            "suspicious_yield_pct": round(suspicious_yield_threshold * 100, 4),
        },
        "bucket_results": bucket_results,
        "category_candidates": category_candidates,
        "trades": [
            {
                **t,
                "amount": round(t["amount"], 2),
                "shares": round(t["shares"], 4) if t["shares"] is not None else None,
                "monthly_income_delta": round(t["monthly_income_delta"], 2),
                "yield": round(t["yield"] * 100, 4),
                "candidates": t.get("candidates", []),
                "suspicious_yield": bool(t.get("suspicious_yield")),
            }
            for t in trades
        ],
        "warnings": warnings,
    })


@app.route("/api/builder/portfolios/<int:port_id>", methods=["DELETE"])
def builder_delete_portfolio(port_id):
    pid = get_profile_id()
    conn = get_connection()
    conn.execute("DELETE FROM builder_holdings WHERE portfolio_id = ?", (port_id,))
    conn.execute("DELETE FROM builder_portfolios WHERE id = ? AND profile_id = ?", (port_id, pid))
    conn.commit()
    conn.close()
    return jsonify({"ok": True})


@app.route("/api/builder/portfolios/<int:port_id>/holdings", methods=["GET"])
def builder_list_holdings(port_id):
    conn = get_connection()
    rows = conn.execute(
        "SELECT id, ticker, dollar_amount, added_at FROM builder_holdings WHERE portfolio_id = ? ORDER BY added_at",
        (port_id,)).fetchall()
    conn.close()
    return jsonify({"holdings": rows_to_dicts(rows)})


@app.route("/api/builder/portfolios/<int:port_id>/holdings", methods=["POST"])
def builder_add_holding(port_id):
    data = request.get_json()
    ticker = (data.get("ticker") or "").strip().upper()
    dollar_amount = float(data.get("dollar_amount", 0))
    if not ticker:
        return jsonify({"error": "Ticker is required"}), 400
    conn = get_connection()
    conn.execute(
        "INSERT OR REPLACE INTO builder_holdings (portfolio_id, ticker, dollar_amount) VALUES (?, ?, ?)",
        (port_id, ticker, dollar_amount))
    conn.execute("UPDATE builder_portfolios SET updated_at = CURRENT_TIMESTAMP WHERE id = ?", (port_id,))
    conn.commit()
    conn.close()
    return jsonify({"ticker": ticker, "dollar_amount": dollar_amount})


@app.route("/api/builder/portfolios/<int:port_id>/holdings/<ticker>", methods=["DELETE"])
def builder_delete_holding(port_id, ticker):
    conn = get_connection()
    conn.execute("DELETE FROM builder_holdings WHERE portfolio_id = ? AND ticker = ?", (port_id, ticker.upper()))
    conn.execute("UPDATE builder_portfolios SET updated_at = CURRENT_TIMESTAMP WHERE id = ?", (port_id,))
    conn.commit()
    conn.close()
    return jsonify({"ok": True})


# ── Portfolio Builder Analyze ────────────────────────────────────────────────

@app.route("/api/builder/portfolios/<int:port_id>/analyze", methods=["POST"])
def builder_analyze(port_id):
    import numpy as np
    import math
    import yfinance as yf
    from grading import (ticker_score, grade_portfolio, letter_grade,
                         _ulcer_index, _sharpe, _sortino, _calmar, _omega,
                         _max_drawdown, _capture_ratios, _safe,
                         _is_stale_or_dead)

    data = request.get_json() or {}
    benchmark = (data.get("benchmark") or "SPY").strip().upper()
    period = data.get("period", "1y")

    conn = get_connection()
    rows = conn.execute(
        "SELECT ticker, dollar_amount FROM builder_holdings WHERE portfolio_id = ?",
        (port_id,)).fetchall()
    pname = conn.execute("SELECT name FROM builder_portfolios WHERE id = ?", (port_id,)).fetchone()
    conn.close()

    if not rows:
        return jsonify({"error": "No holdings in this portfolio"}), 400

    holdings_raw = [{"ticker": r["ticker"].upper(), "dollar_amount": float(r["dollar_amount"])} for r in rows]
    tickers = [h["ticker"] for h in holdings_raw]
    all_tickers = list(set(tickers + [benchmark]))

    # Download price data
    try:
        df = _chunked_yf_download(all_tickers, period=period, auto_adjust=True, progress=False)
    except Exception as e:
        return jsonify({"error": f"yfinance download failed: {e}"}), 500

    if df.empty:
        return jsonify({"error": "No price data returned"}), 500

    if isinstance(df.columns, pd.MultiIndex):
        close_df = df["Close"] if "Close" in df.columns.get_level_values(0) else df
    else:
        close_df = df if len(all_tickers) == 1 else df
        if len(all_tickers) == 1:
            close_df = pd.DataFrame({all_tickers[0]: df["Close"] if "Close" in df.columns else df.iloc[:, 0]})

    close_df = close_df.ffill().dropna(how="all")
    bench_close = close_df[benchmark] if benchmark in close_df.columns else None
    bench_ret = bench_close.pct_change().dropna() if bench_close is not None else None

    # NAV erosion
    nav_erosion = _compute_nav_erosion(close_df, tickers)

    # Total portfolio value
    total_value = sum(h["dollar_amount"] for h in holdings_raw)
    if total_value <= 0:
        total_value = 1.0

    # Per-ticker analysis
    result_holdings = []
    returns_cols = {}
    weights_list = []

    for h in holdings_raw:
        t = h["ticker"]
        amt = h["dollar_amount"]
        weight = amt / total_value

        row = {
            "ticker": t, "dollar_amount": amt, "weight_pct": round(weight * 100, 2),
            "shares": 0, "current_price": 0, "score": 0, "grade": "N/A",
            "ulcer_index": None, "sharpe": None, "sortino": None, "calmar": None,
            "omega": None, "up_capture": None, "down_capture": None,
            "annual_ret": None, "annual_vol": None, "max_drawdown": None,
            "week52_high": None, "week52_low": None,
            "annual_yield_pct": 0, "annual_income": 0, "monthly_income": 0,
            "nav_erosion_pct": round((nav_erosion.get(t, 0)) * 100, 2),
        }

        if t not in close_df.columns:
            result_holdings.append(row)
            weights_list.append(weight)
            continue

        tc = close_df[t].dropna()
        if len(tc) < 10:
            result_holdings.append(row)
            weights_list.append(weight)
            continue

        daily_ret = tc.pct_change().dropna()
        returns_cols[t] = daily_ret

        # Current price and shares
        cur_price = float(tc.iloc[-1])
        row["current_price"] = round(cur_price, 2)
        row["shares"] = round(amt / cur_price, 4) if cur_price > 0 else 0

        # 52-week
        row["week52_high"] = round(float(tc.max()), 2)
        row["week52_low"] = round(float(tc.min()), 2)

        # Annualized return and vol
        n_days = len(tc)
        total_ret = float(tc.iloc[-1] / tc.iloc[0]) - 1.0
        ann_ret = (1 + total_ret) ** (252 / max(n_days, 1)) - 1.0
        ann_vol = float(daily_ret.std()) * np.sqrt(252) if len(daily_ret) > 1 else None

        row["annual_ret"] = round(ann_ret * 100, 2)
        row["annual_vol"] = round(ann_vol * 100, 2) if ann_vol is not None else None
        row["annual_total_ret"] = row["annual_ret"]

        # Ticker score (includes ulcer index)
        score, sharpe, sortino, calmar, omega, mdd, dc, ulcer = ticker_score(tc, daily_ret, bench_ret)
        row["score"] = score
        row["grade"] = letter_grade(score)
        row["sharpe"] = sharpe
        row["sortino"] = sortino
        row["calmar"] = calmar
        row["omega"] = omega
        row["max_drawdown"] = round(mdd * 100, 2) if mdd is not None else None
        row["down_capture"] = dc
        row["ulcer_index"] = ulcer

        # Up capture
        if bench_ret is not None:
            uc, _ = _capture_ratios(daily_ret, bench_ret)
            row["up_capture"] = uc

        # Dividend income — try info first, fall back to dividend history
        try:
            yf_ticker = yf.Ticker(t)
            info = yf_ticker.info or {}
            div_yield = info.get("yield") or 0
            # dividendYield from yfinance can be a percentage (e.g. 11.84) or
            # decimal (e.g. 0.1184) depending on the ticker — use "yield" which
            # is consistently a decimal, and fall back to dividendYield only if
            # it looks like a decimal (< 1)
            if div_yield == 0:
                dy = info.get("dividendYield") or 0
                if dy > 0:
                    div_yield = dy / 100 if dy > 1 else dy

            # Fallback: compute yield from dividend history, annualizing if < 1 year
            if div_yield == 0 and cur_price > 0:
                try:
                    divs = yf_ticker.dividends
                    if divs is not None and len(divs) > 0:
                        cutoff = divs.index[-1] - pd.Timedelta(days=365)
                        recent_divs = divs[divs.index >= cutoff]
                        if len(recent_divs) > 0:
                            total_div = float(recent_divs.sum())
                            span_days = (recent_divs.index[-1] - recent_divs.index[0]).days
                            if span_days < 300 and len(recent_divs) >= 2:
                                # Short history: annualize using avg payment × estimated frequency
                                avg_gap = span_days / (len(recent_divs) - 1)
                                payments_per_year = 365.0 / max(avg_gap, 1)
                                avg_payment = total_div / len(recent_divs)
                                annual_div_per_share = avg_payment * payments_per_year
                            else:
                                annual_div_per_share = total_div
                            div_yield = annual_div_per_share / cur_price
                except Exception:
                    pass

            # Fallback 2: check distributions (for return-of-capital / covered-call ETFs)
            if div_yield == 0 and cur_price > 0:
                try:
                    actions = yf_ticker.actions
                    if actions is not None and "Dividends" in actions.columns:
                        div_col = actions["Dividends"]
                        div_col = div_col[div_col > 0]
                        if len(div_col) > 0:
                            cutoff = div_col.index[-1] - pd.Timedelta(days=365)
                            recent = div_col[div_col.index >= cutoff]
                            if len(recent) > 0:
                                total_div = float(recent.sum())
                                span_days = (recent.index[-1] - recent.index[0]).days
                                if span_days < 300 and len(recent) >= 2:
                                    avg_gap = span_days / (len(recent) - 1)
                                    payments_per_year = 365.0 / max(avg_gap, 1)
                                    avg_payment = total_div / len(recent)
                                    annual_div_per_share = avg_payment * payments_per_year
                                else:
                                    annual_div_per_share = total_div
                                div_yield = annual_div_per_share / cur_price
                except Exception:
                    pass

            row["annual_yield_pct"] = round(div_yield * 100, 2)
            row["annual_income"] = round(amt * div_yield, 2)
            row["monthly_income"] = round(amt * div_yield / 12, 2)
        except Exception:
            pass

        result_holdings.append(row)
        weights_list.append(weight)

    # Portfolio-level metrics
    if returns_cols:
        # Exclude tickers with < 30 data points so they don't truncate
        # the overlap window below the grading minimum
        long_cols = {t: s for t, s in returns_cols.items() if len(s) >= 30}
        if not long_cols:
            long_cols = returns_cols  # fallback: use whatever we have
        # Drop delisted / flat-lined / penny-stock series so they don't mask
        # the portfolio's real risk profile in the overall grade.
        live_cols = {
            t: s for t, s in long_cols.items()
            if not _is_stale_or_dead(close_df[t].dropna(), s)
        }
        if not live_cols:
            live_cols = long_cols  # fallback: avoid empty grade
        returns_df = pd.DataFrame(live_cols).dropna()
        available = [t for t in tickers if t in live_cols]
        avail_weights = np.array([weights_list[tickers.index(t)] for t in available])
        if avail_weights.sum() > 0:
            avail_weights = avail_weights / avail_weights.sum()
        port_grade = grade_portfolio(returns_df[available], avail_weights, bench_ret)
    else:
        port_grade = {"grade": {"overall": "N/A", "score": 0, "breakdown": []}}
        returns_df = pd.DataFrame()
        available = []

    # NAV Health factor — add to grade breakdown
    if returns_cols and available:
        weighted_nav = sum(
            avail_weights[i] * nav_erosion.get(available[i], 0)
            for i in range(len(available))
        )
        if weighted_nav < 0:
            nav_health_score = max(0.0, 100.0 + weighted_nav * 200.0)
        else:
            nav_health_score = 100.0

        port_grade["grade"]["breakdown"].append({
            "category": "NAV Health",
            "score": round(nav_health_score, 1),
            "weight": 10,
            "grade": letter_grade(nav_health_score),
        })
        # Recalculate overall
        total_w = sum(b["weight"] for b in port_grade["grade"]["breakdown"])
        total_s = sum(b["score"] * b["weight"] for b in port_grade["grade"]["breakdown"])
        new_score = round(total_s / total_w, 1) if total_w > 0 else 0.0
        port_grade["grade"]["score"] = new_score
        port_grade["grade"]["overall"] = letter_grade(new_score)
        port_grade["nav_erosion_avg_pct"] = round(weighted_nav * 100, 2)

    port_grade["n_holdings"] = len(tickers)
    port_grade["total_value"] = round(total_value, 2)
    ann_income = sum(h["annual_income"] for h in result_holdings)
    port_grade["est_annual_income"] = round(ann_income, 2)
    port_grade["est_monthly_income"] = round(ann_income / 12, 2)

    # Correlation matrix
    corr_data = None
    if len(returns_cols) > 1:
        corr_df = pd.DataFrame(returns_cols).dropna().corr()
        labels = list(corr_df.columns)
        matrix = []
        for i in range(len(labels)):
            row = []
            for j in range(len(labels)):
                v = corr_df.iloc[i, j]
                row.append(round(float(v), 3) if not (math.isnan(v) or math.isinf(v)) else 0)
            matrix.append(row)
        corr_data = {"labels": labels, "matrix": matrix}

    # Drawdown series
    dd_data = None
    if returns_cols and available:
        port_daily = returns_df[available].dot(avail_weights)
        port_cum = (1 + port_daily).cumprod()
        running_max = port_cum.cummax()
        drawdown = ((port_cum - running_max) / running_max) * 100
        dates = [d.strftime("%Y-%m-%d") for d in drawdown.index]
        vals = [round(float(v), 2) for v in drawdown.values]
        # Subsample if > 300 points
        if len(dates) > 300:
            step = len(dates) // 300
            dates = dates[::step]
            vals = vals[::step]
        dd_data = {"dates": dates, "values": vals}

    return jsonify({
        "portfolio_id": port_id,
        "portfolio_name": pname["name"] if pname else "",
        "portfolio_metrics": port_grade,
        "holdings": result_holdings,
        "correlation": corr_data,
        "drawdown_series": dd_data,
    })


# ── Portfolio Builder Compare ────────────────────────────────────────────────

@app.route("/api/builder/compare", methods=["POST"])
def builder_compare():
    import numpy as np
    import yfinance as yf
    from grading import grade_portfolio, letter_grade, _is_stale_or_dead

    data = request.get_json() or {}
    port_ids = data.get("portfolio_ids", [])
    period = data.get("period", "1y")
    benchmark = (data.get("benchmark") or "SPY").strip().upper()

    if len(port_ids) < 2:
        return jsonify({"error": "Select at least 2 portfolios"}), 400

    conn = get_connection()
    results = []

    # Gather all tickers across all portfolios
    all_tickers_set = {benchmark}
    port_data = []
    for pid in port_ids:
        rows = conn.execute(
            "SELECT ticker, dollar_amount FROM builder_holdings WHERE portfolio_id = ?", (pid,)).fetchall()
        pname = conn.execute("SELECT name FROM builder_portfolios WHERE id = ?", (pid,)).fetchone()
        holdings = [{"ticker": r["ticker"].upper(), "dollar_amount": float(r["dollar_amount"])} for r in rows]
        for h in holdings:
            all_tickers_set.add(h["ticker"])
        port_data.append({"id": pid, "name": pname["name"] if pname else f"Portfolio {pid}", "holdings": holdings})
    conn.close()

    all_tickers = list(all_tickers_set)
    try:
        df = _chunked_yf_download(all_tickers, period=period, auto_adjust=True, progress=False)
    except Exception as e:
        return jsonify({"error": f"yfinance download failed: {e}"}), 500

    if df.empty:
        return jsonify({"error": "No price data"}), 500

    if isinstance(df.columns, pd.MultiIndex):
        close_df = df["Close"]
    else:
        close_df = df if len(all_tickers) > 1 else pd.DataFrame({all_tickers[0]: df["Close"]})

    close_df = close_df.ffill().dropna(how="all")
    bench_ret = close_df[benchmark].pct_change().dropna() if benchmark in close_df.columns else None

    for p in port_data:
        holdings = p["holdings"]
        total_val = sum(h["dollar_amount"] for h in holdings)
        if total_val <= 0:
            continue

        avail_tickers = [h["ticker"] for h in holdings if h["ticker"] in close_df.columns]
        if not avail_tickers:
            continue

        # Build returns per ticker, then exclude short-history tickers
        # (< 30 days) so they don't truncate the overlap below grading minimum
        returns_cols = {}
        for t in avail_tickers:
            col = close_df[t].dropna()
            if len(col) >= 2:
                returns_cols[t] = col.pct_change().dropna()
        if not returns_cols:
            continue
        long_cols = {t: s for t, s in returns_cols.items() if len(s) >= 30}
        if not long_cols:
            long_cols = returns_cols  # fallback
        # Drop delisted / flat-lined / penny-stock series from the portfolio grade
        live_cols = {
            t: s for t, s in long_cols.items()
            if not _is_stale_or_dead(close_df[t].dropna(), s)
        }
        if not live_cols:
            live_cols = long_cols  # fallback: avoid empty grade
        returns_df = pd.DataFrame(live_cols).dropna()
        if len(returns_df) < 2:
            returns_df = pd.DataFrame(live_cols).fillna(0)
        used_tickers = list(live_cols.keys())
        weights = np.array([next(h["dollar_amount"] for h in holdings if h["ticker"] == t) for t in used_tickers])
        weights = weights / weights.sum()

        pg = grade_portfolio(returns_df[used_tickers], weights, bench_ret)

        # Add NAV Health to match analyze endpoint grading
        nav_erosion = _compute_nav_erosion(close_df, used_tickers)
        weighted_nav = sum(
            weights[i] * nav_erosion.get(used_tickers[i], 0)
            for i in range(len(used_tickers))
        )
        nav_health_score = max(0.0, 100.0 + weighted_nav * 200.0) if weighted_nav < 0 else 100.0
        pg["grade"]["breakdown"].append({
            "category": "NAV Health",
            "score": round(nav_health_score, 1),
            "weight": 10,
            "grade": letter_grade(nav_health_score),
        })
        total_w = sum(b["weight"] for b in pg["grade"]["breakdown"])
        total_s = sum(b["score"] * b["weight"] for b in pg["grade"]["breakdown"])
        new_score = round(total_s / total_w, 1) if total_w > 0 else 0.0
        pg["grade"]["score"] = new_score
        pg["grade"]["overall"] = letter_grade(new_score)

        ann_income = 0
        for h in holdings:
            try:
                info = yf.Ticker(h["ticker"]).info or {}
                dy = info.get("yield") or 0
                if dy == 0:
                    raw_dy = info.get("dividendYield") or 0
                    if raw_dy > 0:
                        dy = raw_dy / 100 if raw_dy > 1 else raw_dy
                ann_income += h["dollar_amount"] * dy
            except Exception:
                pass

        results.append({
            "id": p["id"],
            "name": p["name"],
            "score": pg["grade"]["score"],
            "grade": pg["grade"]["overall"],
            "monthly_income": round(ann_income / 12, 2),
            "sharpe": pg.get("sharpe"),
            "sortino": pg.get("sortino"),
            "calmar": pg.get("calmar"),
            "omega": pg.get("omega"),
            "ulcer_index": pg.get("ulcer_index"),
            "max_drawdown": pg.get("max_drawdown"),
            "effective_n": pg.get("effective_n"),
            "breakdown": {b["category"]: b["score"] for b in pg["grade"]["breakdown"]},
        })

    return jsonify({"results": results})


