@app.route("/api/single-stock-etfs", methods=["GET"])
def get_single_stock_etfs():
    """Return built-in and user-added single-stock ETFs."""
    conn = get_connection()
    row = conn.execute("SELECT value FROM settings WHERE key = 'single_stock_etfs'").fetchone()
    conn.close()
    user_added = []
    if row and row["value"]:
        user_added = [t.strip().upper() for t in row["value"].split(",") if t.strip()]
    return jsonify({
        "builtin": sorted(_DEFAULT_SINGLE_STOCK_ETFS),
        "user_added": sorted(set(user_added)),
    })


@app.route("/api/single-stock-etfs", methods=["POST"])
def save_single_stock_etfs():
    """Save user-added single-stock ETF tickers."""
    data = request.get_json() or {}
    tickers = data.get("tickers", [])
    # Normalize and deduplicate, exclude any already in defaults
    cleaned = sorted({t.strip().upper() for t in tickers if t.strip()} - _DEFAULT_SINGLE_STOCK_ETFS)
    value = ",".join(cleaned)
    conn = get_connection()
    conn.execute("INSERT OR REPLACE INTO settings (key, value) VALUES (?, ?)",
                 ("single_stock_etfs", value))
    conn.commit()
    conn.close()
    return jsonify({"ok": True, "user_added": cleaned})


@app.route("/api/settings", methods=["GET"])
def get_settings():
    conn = get_connection()
    rows = conn.execute("SELECT key, value FROM settings").fetchall()
    conn.close()
    out = {}
    for r in rows:
        k = r["key"]
        v = r["value"]
        # Mask sensitive keys
        if "key" in k.lower() or "secret" in k.lower():
            out[k] = v[:4] + "..." + v[-4:] if v and len(v) > 8 else "***"
        else:
            out[k] = v
    return jsonify(out)


@app.route("/api/settings", methods=["POST"])
def save_settings():
    data = request.get_json() or {}
    conn = get_connection()
    for k, v in data.items():
        conn.execute("INSERT OR REPLACE INTO settings (key, value) VALUES (?, ?)", (k, str(v)))
    conn.commit()
    conn.close()
    if "nav_benchmark_overrides" in data:
        _NAV_BENCHMARK_OVERRIDE_CACHE.update({"ts": 0, "data": {}})
        _PORTFOLIO_COVERAGE_CACHE.clear()
    return jsonify({"ok": True})


def _fx_settings():
    keys = (
        "usd_cad_rate", "usd_cad_rate_as_of", "usd_cad_rate_updated_at",
        "usd_cad_rate_source", "usd_cad_manual_rate", "usd_cad_manual_updated_at",
    )
    conn = get_connection()
    rows = conn.execute(
        f"SELECT key, value FROM settings WHERE key IN ({','.join('?' for _ in keys)})",
        keys,
    ).fetchall()
    conn.close()
    return {row["key"]: row["value"] for row in rows}


def _valid_fx_rate(value):
    try:
        rate = float(value)
    except (TypeError, ValueError):
        return None
    return rate if 0.5 < rate < 2.5 else None


def _fx_age_seconds(timestamp):
    if not timestamp:
        return None
    try:
        parsed = datetime.datetime.fromisoformat(str(timestamp).replace("Z", "+00:00"))
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=datetime.timezone.utc)
        return max(0, int((datetime.datetime.now(datetime.timezone.utc) - parsed).total_seconds()))
    except (TypeError, ValueError):
        return None


def _with_fx_override(payload, stored):
    live_rate = _valid_fx_rate(payload.get("rate"))
    manual_rate = _valid_fx_rate(stored.get("usd_cad_manual_rate"))
    result = dict(payload)
    result.update({
        "live_rate": live_rate,
        "manual_rate": manual_rate,
        "live_updated_at": payload.get("updated_at"),
        "manual_updated_at": stored.get("usd_cad_manual_updated_at"),
        "mode": "manual" if manual_rate else "live",
        "cache_ttl_seconds": _FX_RATE_TTL_SEC,
    })
    if manual_rate:
        result.update({
            "rate": manual_rate,
            "source": "Manual override",
            "updated_at": stored.get("usd_cad_manual_updated_at") or payload.get("updated_at"),
            "stale": False,
        })
    result["cache_age_seconds"] = _fx_age_seconds(result.get("updated_at"))
    return result


@app.route("/api/exchange-rates/usd-cad", methods=["GET", "POST"])
def get_usd_cad_exchange_rate():
    if request.method == "POST":
        data = request.get_json() or {}
        manual_value = data.get("manual_rate")
        conn = get_connection()
        if manual_value in (None, ""):
            conn.execute("DELETE FROM settings WHERE key IN ('usd_cad_manual_rate', 'usd_cad_manual_updated_at')")
        else:
            manual_rate = _valid_fx_rate(manual_value)
            if manual_rate is None:
                conn.close()
                return jsonify({"error": "Manual USD/CAD rate must be between 0.5 and 2.5."}), 400
            now = datetime.datetime.now(datetime.timezone.utc).isoformat()
            conn.executemany(
                "INSERT OR REPLACE INTO settings (key, value) VALUES (?, ?)",
                [("usd_cad_manual_rate", str(manual_rate)), ("usd_cad_manual_updated_at", now)],
            )
        conn.commit()
        conn.close()
        _FX_RATE_CACHE.clear()

    force_refresh = request.args.get("refresh", "").lower() in {"1", "true", "yes"}
    cached = None if force_refresh else _cache_get(_FX_RATE_CACHE, "USD_CAD", ttl=_FX_RATE_TTL_SEC)
    if cached is not None:
        cached_payload = dict(cached)
        cached_payload["cached"] = True
        cached_payload["cache_age_seconds"] = _fx_age_seconds(cached_payload.get("updated_at"))
        return jsonify(cached_payload)

    stored = _fx_settings()
    stored_rate = _valid_fx_rate(stored.get("usd_cad_rate"))
    stored_updated_at = stored.get("usd_cad_rate_updated_at")
    stored_age = _fx_age_seconds(stored_updated_at)

    if not force_refresh and stored_rate and stored_age is not None and stored_age <= _FX_RATE_TTL_SEC:
        payload = _with_fx_override({
            "base": "USD", "quote": "CAD", "rate": stored_rate,
            "as_of": stored.get("usd_cad_rate_as_of"),
            "updated_at": stored_updated_at,
            "source": stored.get("usd_cad_rate_source") or "Yahoo Finance",
            "stale": False, "cached": True,
        }, stored)
        _cache_set(_FX_RATE_CACHE, "USD_CAD", payload)
        return jsonify(payload)

    try:
        raw = _chunked_yf_download(
            "CAD=X",
            period="5d",
            interval="1d",
            auto_adjust=False,
            progress=False,
        )
        if raw is None or raw.empty or "Close" not in raw.columns.get_level_values(0):
            raise ValueError("USD/CAD market data was empty")

        close = raw["Close"]
        if isinstance(close, pd.DataFrame):
            close = close.iloc[:, 0]
        close = pd.to_numeric(close, errors="coerce").dropna()
        if close.empty:
            raise ValueError("USD/CAD close price was unavailable")

        rate = float(close.iloc[-1])
        if not 0.5 < rate < 2.5:
            raise ValueError("USD/CAD rate was outside the expected range")
        last_index = close.index[-1]
        as_of = last_index.date().isoformat() if hasattr(last_index, "date") else str(last_index)[:10]
        updated_at = datetime.datetime.now(datetime.timezone.utc).isoformat()
        live_payload = {
            "base": "USD",
            "quote": "CAD",
            "rate": rate,
            "as_of": as_of,
            "updated_at": updated_at,
            "source": "Yahoo Finance",
            "stale": False,
            "cached": False,
        }

        conn = get_connection()
        conn.executemany(
            "INSERT OR REPLACE INTO settings (key, value) VALUES (?, ?)",
            [
                ("usd_cad_rate", str(rate)),
                ("usd_cad_rate_as_of", as_of),
                ("usd_cad_rate_updated_at", updated_at),
                ("usd_cad_rate_source", "Yahoo Finance"),
            ],
        )
        conn.commit()
        conn.close()
        stored.update({"usd_cad_rate": str(rate), "usd_cad_rate_as_of": as_of,
                       "usd_cad_rate_updated_at": updated_at, "usd_cad_rate_source": "Yahoo Finance"})
        payload = _with_fx_override(live_payload, stored)
        _cache_set(_FX_RATE_CACHE, "USD_CAD", payload)
        return jsonify(payload)
    except Exception as exc:
        manual_rate = _valid_fx_rate(stored.get("usd_cad_manual_rate"))
        if stored_rate or manual_rate:
            payload = _with_fx_override({
                "base": "USD",
                "quote": "CAD",
                "rate": stored_rate or manual_rate,
                "as_of": stored.get("usd_cad_rate_as_of"),
                "updated_at": stored_updated_at,
                "source": stored.get("usd_cad_rate_source") or "Cached rate",
                "stale": True,
                "cached": True,
                "refresh_error": str(exc),
            }, stored)
            _cache_set(_FX_RATE_CACHE, "USD_CAD", payload)
            return jsonify(payload)
        return jsonify({
            "error": "USD/CAD exchange rate is unavailable.",
            "detail": str(exc),
        }), 503


# ── Portfolio Builder Rebalance ────────────────────────────────────────────────

@app.route("/api/builder/portfolios/<int:pid>/rebalance", methods=["POST"])
def builder_rebalance(pid):
    data = request.get_json() or {}
    mode = data.get("mode", "income")
    strategy = data.get("strategy", "all_weather")

    targets = get_strategy_targets(strategy, mode)

    # Fetch portfolio holdings
    conn = get_connection()
    rows = conn.execute(
        "SELECT ticker, dollar_amount FROM builder_holdings WHERE portfolio_id = ?", (pid,)
    ).fetchall()
    if not rows:
        conn.close()
        return jsonify({"error": "Portfolio has no holdings"}), 400

    port_holdings = [{"ticker": r["ticker"].upper(), "amount": float(r["dollar_amount"] or 0)} for r in rows]
    total_value = sum(h["amount"] for h in port_holdings)
    if total_value <= 0:
        conn.close()
        return jsonify({"error": "Portfolio total value is zero"}), 400

    # Build ETF → asset class lookup
    etf_to_class = {}
    for slot in targets:
        for etf in slot["etfs"]:
            etf_to_class[etf.upper()] = slot["asset_class"]

    # Classify holdings
    class_holdings = {slot["asset_class"]: [] for slot in targets}
    unclassified = []
    for h in port_holdings:
        ac = etf_to_class.get(h["ticker"])
        if ac:
            class_holdings[ac].append(h)
        else:
            unclassified.append(h)

    # Get user's real holdings for suggesting new ETFs
    _, r_pids = get_profile_filter()
    r_ph = ",".join("?" * len(r_pids))
    existing = conn.execute(
        f"SELECT ticker, SUM(current_value) as current_value FROM holdings WHERE profile_id IN ({r_ph}) GROUP BY ticker", r_pids
    ).fetchall()
    conn.close()
    existing_map = {r["ticker"].upper(): float(r["current_value"] or 0) for r in existing}

    suggestions = []
    for slot in targets:
        ac = slot["asset_class"]
        current_amount = sum(h["amount"] for h in class_holdings[ac])
        current_pct = round(current_amount / total_value * 100, 1)
        target_pct = slot["target_pct"]
        drift_pct = round(current_pct - target_pct, 1)
        target_amount = round(total_value * target_pct / 100, 2)
        change_amount = round(target_amount - current_amount, 2)

        # Determine action
        if not class_holdings[ac]:
            action = "add_new"
        elif change_amount > 0:
            action = "buy"
        elif change_amount < 0:
            action = "reduce"
        else:
            action = "on_target"

        # Suggest ETF: use existing holding in that class, or auto-select
        if class_holdings[ac]:
            suggested = max(class_holdings[ac], key=lambda h: h["amount"])["ticker"]
        else:
            # Same auto-select logic: prefer user's real holdings
            suggested = None
            best_val = -1
            for etf in slot["etfs"]:
                if etf.upper() in existing_map and existing_map[etf.upper()] > best_val:
                    best_val = existing_map[etf.upper()]
                    suggested = etf
            if suggested is None:
                suggested = slot["etfs"][0]

        suggestions.append({
            "asset_class": ac,
            "target_pct": target_pct,
            "current_pct": current_pct,
            "drift_pct": drift_pct,
            "current_amount": round(current_amount, 2),
            "target_amount": target_amount,
            "change_amount": change_amount,
            "action": action,
            "holdings": class_holdings[ac],
            "suggested_ticker": suggested,
        })

    return jsonify({
        "total_value": round(total_value, 2),
        "mode": mode,
        "suggestions": suggestions,
        "unclassified": unclassified,
    })


# ── Distribution Comparison ────────────────────────────────────────────────────

@app.route("/api/distribution-compare/lookup")
def distribution_compare_lookup():
    import yfinance as yf
    import warnings
    warnings.filterwarnings("ignore")

    ticker = request.args.get("ticker", "").strip().upper()
    if not ticker:
        return jsonify(error="No ticker provided."), 400

    try:
        t = yf.Ticker(ticker)
        hist = t.history(period="1y", auto_adjust=False, actions=True)
    except Exception as e:
        return jsonify(error=f"Failed to fetch data for {ticker}: {str(e)}"), 400

    if hist is None or hist.empty:
        return jsonify(error=f"No data found for {ticker}."), 404

    close = hist["Close"].dropna()
    if close.empty:
        return jsonify(error=f"No price data for {ticker}."), 404

    current_price = float(close.iloc[-1])
    divs = hist["Dividends"] if "Dividends" in hist.columns else pd.Series(0.0, index=hist.index)
    ttm_divs = float(divs.sum())
    ttm_yield = ttm_divs / current_price if current_price > 0 else 0.0
    yield_found = ttm_divs > 0

    return jsonify(
        ticker=ticker,
        price=round(current_price, 4),
        ttm_yield=round(ttm_yield * 100, 4),
        yield_found=yield_found,
    )


@app.route("/api/distribution-compare/run", methods=["POST"])
def distribution_compare_run():
    import traceback as _tb
    try:
        result = _distribution_compare_compute()
        if isinstance(result, dict) and "error" in result:
            return jsonify(error=result["error"])
        return jsonify(**result)
    except Exception as _e:
        return jsonify(error=f"Server error: {str(_e)}", detail=_tb.format_exc())


@app.route("/api/distribution-compare/export", methods=["POST"])
def distribution_compare_export():
    import traceback as _tb
    try:
        return _distribution_compare_export_inner()
    except Exception as _e:
        return jsonify(error=f"Server error: {str(_e)}")


def _distribution_compare_export_inner():
    from io import BytesIO
    from openpyxl import Workbook
    from openpyxl.styles import Font, PatternFill, numbers

    result_data = _distribution_compare_compute()
    if isinstance(result_data, dict) and "error" in result_data:
        return jsonify(error=result_data["error"])

    wb = Workbook()
    # Summary sheet
    ws = wb.active
    ws.title = "Summary"
    header_font = Font(bold=True)
    ws.cell(row=1, column=1, value="Distribution Comparison Summary").font = Font(bold=True, size=14)
    ws.cell(row=2, column=1, value=f"Comparison Type: {result_data.get('comparison_type', '')}")
    ws.cell(row=3, column=1, value=f"Cash Wedge Initial: ${result_data.get('cash_wedge_initial', 0):,.2f}")

    summary_row = 5
    summary_headers = ["Metric", "Fund A", "Fund B"]
    if "fund_c" in result_data:
        summary_headers.append("Fund C")
    for ci, h in enumerate(summary_headers, 1):
        ws.cell(row=summary_row, column=ci, value=h).font = header_font

    fund_keys = ["fund_a", "fund_b"]
    if "fund_c" in result_data:
        fund_keys.append("fund_c")

    metrics = [
        ("Ticker", "ticker"),
        ("Role", "role"),
        ("Investment", "investment"),
        ("Initial Shares", "initial_shares"),
        ("Final Portfolio", "final_portfolio"),
        ("Final Withdrawn", "final_withdrawn"),
        ("Final Distributions", "final_distributions"),
        ("Final Total", "final_total"),
        ("Depleted", "depleted"),
    ]
    for mi, (metric_label, metric_key) in enumerate(metrics):
        row_num = summary_row + 1 + mi
        ws.cell(row=row_num, column=1, value=metric_label)
        for fi, fk in enumerate(fund_keys):
            if fk in result_data:
                val = result_data[fk].get(metric_key, "")
                ws.cell(row=row_num, column=2 + fi, value=val)

    # Fund detail sheets
    for fund_key in fund_keys:
        if fund_key not in result_data:
            continue
        fund = result_data[fund_key]
        ws_f = wb.create_sheet(title=f"{fund['ticker']} Detail")
        headers = ["Month", "Price", "Shares", "Portfolio", "Dist/Share", "Income",
                    "Withdrawal", "Excess", "Shares +/-", "Growth", "Cum Income",
                    "ROI ($)", "ROI (%)"]
        if fund.get("has_cash_wedge"):
            headers.insert(7, "CW Drawn")
            headers.insert(8, "CW Balance")
        if fund.get("drip") is False:
            headers.append("Cash Accumulated")
        for ci, h in enumerate(headers, 1):
            ws_f.cell(row=1, column=ci, value=h).font = header_font
        months = result_data.get("months", [])
        for ri, row in enumerate(fund["monthly_rows"], 2):
            vals = [months[ri - 2] if ri - 2 < len(months) else "",
                    row["price"], row["shares"], row["portfolio"],
                    row["dist_per_share"], row["income"], row["withdrawal"]]
            if fund.get("has_cash_wedge"):
                vals.extend([row.get("wedge_drawn", 0), row.get("wedge_bal", 0)])
            vals.extend([row["excess"], row["shares_delta"], row["growth"],
                         row["cum_income"], row["roi_dollar"], row["roi_pct"]])
            if fund.get("drip") is False:
                vals.append(row.get("cash_accumulated", 0))
            for ci, v in enumerate(vals, 1):
                ws_f.cell(row=ri, column=ci, value=v)

    buf = BytesIO()
    wb.save(buf)
    buf.seek(0)
    return send_file(buf, as_attachment=True,
                     download_name="distribution_comparison.xlsx",
                     mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")


# ── Distribution-compare shared simulation helpers ─────────────────────────────
# Used by both the single-ticker compute (_distribution_compare_compute) and the
# basket simulator (_dc_simulate_basket / portfolio-run endpoint).

def _dc_cash_flow_withdrawal_schedule(data, duration_months, *, historical=False):
    """Resolve a shared cash-flow plan into withdrawals for Distribution Compare."""
    plan_id = data.get("cash_flow_plan_id")
    funding_mode = str(
        data.get("cash_flow_funding_mode", "net_after_income")
    ).lower()
    if funding_mode not in {"gross_expenses", "net_after_income"}:
        return None, None, "Unknown cash-flow funding target."

    conn = get_connection()
    ensure_tables_exist(conn)
    try:
        plan = _cash_flow_plan_for_scope(conn, plan_id)
        if not plan:
            return None, None, "Cash-flow plan not found."
        start_month = _cash_flow_month_or_current(data.get("cash_flow_start_month"))
        if historical:
            # A backtest cannot replay future one-time dates faithfully. Use a
            # representative twelve-month average in today's dollars.
            source = _expand_cash_flow_plan(conn, plan["id"], start_month, 12)
            key = (
                "expenses"
                if funding_mode == "gross_expenses"
                else "portfolio_required"
            )
            monthly = sum(float(row[key]) for row in source) / len(source)
            schedule = [round(monthly, 2)] * max(1, int(duration_months))
        else:
            source = _expand_cash_flow_plan(
                conn, plan["id"], start_month, duration_months
            )
            key = (
                "expenses"
                if funding_mode == "gross_expenses"
                else "portfolio_required"
            )
            schedule = [round(float(row[key]), 2) for row in source]
        meta = {
            "plan_id": plan["id"],
            "plan_name": plan["name"],
            "plan_version": plan["version"],
            "funding_mode": funding_mode,
            "start_month": start_month,
            "normalized_monthly_withdrawal": round(
                sum(schedule) / len(schedule), 2
            ) if schedule else 0.0,
        }
        conn.commit()
        return schedule, meta, None
    except (TypeError, ValueError) as exc:
        return None, None, str(exc)
    finally:
        conn.close()


def _dc_effective_withdrawal(base_withdrawal, month_index, current_pv, initial_inv, *,
                             strategy="fixed", withdrawal_pct=4.0,
                             dynamic_threshold_pct=80.0, dynamic_reduce_pct=25.0,
                             inflation_rate=None):
    """Effective monthly withdrawal given the withdrawal strategy + inflation drift."""
    if strategy == "percentage":
        eff = current_pv * (withdrawal_pct / 100.0 / 12.0)
    elif strategy in ("cost_pct_4", "cost_pct_8"):
        # "4%/8% rule": withdraw a fixed % of the initial cost (investment) per
        # year, spread monthly. Unlike "percentage" (which floats with current
        # value), this is anchored to the starting cost and inflation-adjusted
        # below — the classic safe-withdrawal-rate convention.
        rule_pct = 4.0 if strategy == "cost_pct_4" else 8.0
        eff = initial_inv * (rule_pct / 100.0 / 12.0)
    elif strategy == "dynamic":
        eff = base_withdrawal
        threshold = initial_inv * (dynamic_threshold_pct / 100.0)
        if current_pv < threshold:
            eff = eff * (1.0 - dynamic_reduce_pct / 100.0)
    else:
        eff = base_withdrawal
    if inflation_rate is not None and inflation_rate != 0:
        eff *= (1.0 + inflation_rate / 100.0) ** (month_index / 12.0)
    return eff


def _dc_risk_metrics(portfolio_values, monthly_rows):
    """Max drawdown / ulcer / recovery metrics for a portfolio value series."""
    from grading import _max_drawdown, _ulcer_index
    pv_series = pd.Series(portfolio_values)
    max_dd = _max_drawdown(pv_series) if len(pv_series) > 1 else None
    ulcer = _ulcer_index(pv_series)
    worst_month_val = min((r["growth"] for r in monthly_rows), default=0)
    worst_month_idx = next((i for i, r in enumerate(monthly_rows)
                            if r["growth"] == worst_month_val), None)
    recovery_months = None
    if max_dd is not None and max_dd < 0 and len(pv_series) > 1:
        running_max = pv_series.cummax()
        drawdowns = (pv_series - running_max) / running_max
        trough_idx = drawdowns.idxmin()
        peak_before = running_max.iloc[trough_idx]
        for ri in range(trough_idx + 1, len(pv_series)):
            if pv_series.iloc[ri] >= peak_before:
                recovery_months = ri - trough_idx
                break
    return {
        "max_drawdown_pct": round(max_dd * 100, 2) if max_dd else None,
        "ulcer_index": ulcer,
        "worst_month_value": round(worst_month_val, 2),
        "worst_month_idx": worst_month_idx,
        "recovery_months": recovery_months,
    }


def _dc_depletion_month(depleted, monthly_rows):
    """First month index where the portfolio fully depleted, else None."""
    if not depleted:
        return None
    for di, r in enumerate(monthly_rows):
        if r["shares"] == 0 and r["portfolio"] == 0:
            return di
    return None


def _dc_nav_erosion_factor(pct_chg):
    """Distribution haircut/boost vs. the fund's price drawdown (option-income model)."""
    if pct_chg >= 10:
        return min(1.0 + (pct_chg - 10) * 0.02, 1.30)
    elif pct_chg >= -10:
        return 1.0
    elif pct_chg >= -20:
        return 0.85
    elif pct_chg >= -30:
        return 0.70
    else:
        return max(0.40, 1.0 + pct_chg * 0.02)


def _dc_simulate_price_path(sym, duration_months, market_type):
    """Monte-Carlo median monthly price path for a ticker over ``duration_months``.

    Returns ``(prices, current_price, ttm_yield_detected, error)`` where ``prices`` has
    length ``duration_months + 1`` (index 0 is the current price). On failure the first
    three are None and ``error`` is a message string.
    """
    import numpy as np
    import yfinance as yf
    import warnings
    warnings.filterwarnings("ignore")

    bias_map = {"bullish": +0.010, "bearish": -0.015, "neutral": 0.0}
    vol_mult_map = {"bullish": 0.9, "bearish": 1.2, "neutral": 1.0}
    bias = bias_map.get(market_type, 0.0)
    vol_mult = vol_mult_map.get(market_type, 1.0)

    try:
        hist = yf.Ticker(sym).history(period="1y", auto_adjust=False, actions=True)
    except Exception as e:
        return None, None, None, f"Failed to fetch data for {sym}: {str(e)}"
    if hist is None or hist.empty:
        return None, None, None, f"No data found for {sym}."
    close = hist["Close"].dropna()
    if close.empty:
        return None, None, None, f"No price data for {sym}."
    current_price = float(close.iloc[-1])
    if current_price <= 0:
        return None, None, None, f"Could not determine current price for {sym}."

    divs = hist["Dividends"] if "Dividends" in hist.columns else pd.Series(0.0, index=hist.index)
    ttm_divs_sum = float(divs.sum()) if divs is not None else 0.0
    ttm_yield = ttm_divs_sum / current_price if current_price > 0 else 0.0

    monthly_returns = close.resample("ME").last().pct_change().dropna()
    hist_sigma = float(monthly_returns.std()) if len(monthly_returns) >= 2 else 0.05

    SIGMA_CAP = 0.25
    REGIME_MONTHS = 42
    FADE_MONTHS = 6
    RALLY_PROB = 0.18
    RALLY_LEN_LO = 2
    RALLY_LEN_HI = 4
    neutral_bias = 0.0
    neutral_vol = 1.0

    mu_arr = np.empty(duration_months)
    vmul_arr = np.empty(duration_months)
    rally_remaining = 0
    for m in range(duration_months):
        if m < REGIME_MONTHS:
            regime_w = 1.0
        elif m < REGIME_MONTHS + FADE_MONTHS:
            regime_w = 1.0 - (m - REGIME_MONTHS) / FADE_MONTHS
        else:
            regime_w = 0.0
        m_bias = bias * regime_w + neutral_bias * (1.0 - regime_w)
        m_vmul = vol_mult * regime_w + neutral_vol * (1.0 - regime_w)
        if market_type == "bearish" and regime_w > 0:
            if rally_remaining > 0:
                m_bias = abs(bias) * 0.6 * regime_w
                m_vmul = 0.9 * regime_w + neutral_vol * (1.0 - regime_w)
                rally_remaining -= 1
            elif np.random.random() < RALLY_PROB:
                rally_remaining = np.random.randint(RALLY_LEN_LO, RALLY_LEN_HI + 1)
                m_bias = abs(bias) * 0.6 * regime_w
                m_vmul = 0.9 * regime_w + neutral_vol * (1.0 - regime_w)
                rally_remaining -= 1
        mu_arr[m] = m_bias
        vmul_arr[m] = m_vmul

    sigma_arr = np.minimum(hist_sigma * vmul_arr, SIGMA_CAP)
    N_PATHS = 300
    # Use mu_arr directly as the log-drift (no -0.5*sigma^2 Ito term) so the *median*
    # path tracks the chosen market bias: Neutral (mu=0) renders flat instead of
    # decaying by the volatility drag. mu_arr is therefore the per-month median return.
    drift_arr = mu_arr
    np.random.seed(None)
    Z = np.random.normal(0.0, 1.0, (N_PATHS, duration_months))
    log_rets = drift_arr[np.newaxis, :] + sigma_arr[np.newaxis, :] * Z
    cum_log = np.cumsum(np.hstack([np.zeros((N_PATHS, 1)), log_rets]), axis=1)
    price_floor = max(current_price * 0.0001, 1e-10)
    price_matrix = np.maximum(current_price * np.exp(cum_log), price_floor)
    prices = [float(v) for v in np.median(price_matrix, axis=0)]
    return prices, current_price, ttm_yield, None


def _distribution_compare_compute():
    """Core computation for distribution comparison. Returns a plain dict."""
    import yfinance as yf
    import numpy as np
    import warnings
    warnings.filterwarnings("ignore")
    from grading import _max_drawdown, _ulcer_index

    data = request.get_json(force=True, silent=True) or {}
    mode = data.get("mode", "historical")
    monthly_withdrawal = float(data.get("monthly_withdrawal", 0))
    if monthly_withdrawal < 0:
        return {"error": "Monthly withdrawal cannot be negative."}

    # Withdrawal strategy parameters
    withdrawal_strategy = data.get("withdrawal_strategy", "fixed")
    cash_flow_schedule = None
    cash_flow_meta = None
    withdrawal_pct = float(data.get("withdrawal_pct", 4))
    inflation_rate = data.get("inflation_rate")
    if inflation_rate is not None:
        try:
            inflation_rate = float(inflation_rate)
        except (TypeError, ValueError):
            inflation_rate = None
    dynamic_reduce_pct = float(data.get("dynamic_reduce_pct", 25))
    dynamic_threshold_pct = float(data.get("dynamic_threshold_pct", 80))

    comparison_type = data.get("comparison_type", "income_vs_growth")
    cash_wedge_initial = float(data.get("cash_wedge", 0))
    if cash_wedge_initial < 0:
        cash_wedge_initial = 0.0

    growth_funds = set()
    if comparison_type == "income_vs_growth":
        growth_funds.add("fund_b")
    elif comparison_type == "growth_vs_growth":
        growth_funds.add("fund_a")
        growth_funds.add("fund_b")

    fund_a_input = data.get("fund_a", {})
    fund_b_input = data.get("fund_b", {})

    def _validate_fund(f, label):
        ticker = str(f.get("ticker", "")).strip().upper()
        if not ticker:
            return None, f"{label}: ticker is required."
        try:
            investment = float(f.get("investment", 0))
        except (TypeError, ValueError):
            return None, f"{label}: invalid investment amount."
        if investment <= 0:
            return None, f"{label}: investment must be greater than 0."
        yield_override = f.get("yield_override")
        if yield_override is not None and yield_override != "" and yield_override is not False:
            try:
                yield_override = float(yield_override)
                if yield_override <= 0:
                    yield_override = None
            except (TypeError, ValueError):
                yield_override = None
        else:
            yield_override = None
        drip = f.get("drip", True)
        return {"ticker": ticker, "investment": investment,
                "yield_override": yield_override, "drip": drip}, None

    fa, err = _validate_fund(fund_a_input, "Fund A")
    if err:
        return {"error": err}
    fb, err = _validate_fund(fund_b_input, "Fund B")
    if err:
        return {"error": err}

    # Optional Fund C
    fund_c_input = data.get("fund_c")
    fc = None
    if fund_c_input:
        fc, err = _validate_fund(fund_c_input, "Fund C")
        if err:
            return {"error": err}

    # Growth funds for fund_c
    if fc:
        if comparison_type == "income_vs_growth":
            growth_funds.add("fund_c")
        elif comparison_type == "growth_vs_growth":
            growth_funds.add("fund_c")
        # income_vs_income: fund_c stays as income (not in growth_funds)

    def _compute_effective_withdrawal(base_withdrawal, month_index, current_pv, initial_inv):
        strategy = withdrawal_strategy
        applied_inflation = inflation_rate
        if withdrawal_strategy == "cash_flow":
            strategy = "fixed"
            applied_inflation = None
            if cash_flow_schedule:
                base_withdrawal = cash_flow_schedule[
                    min(month_index, len(cash_flow_schedule) - 1)
                ]
        return _dc_effective_withdrawal(
            base_withdrawal, month_index, current_pv, initial_inv,
            strategy=strategy, withdrawal_pct=withdrawal_pct,
            dynamic_threshold_pct=dynamic_threshold_pct,
            dynamic_reduce_pct=dynamic_reduce_pct, inflation_rate=applied_inflation)

    def _compute_risk_metrics(portfolio_values, monthly_rows):
        return _dc_risk_metrics(portfolio_values, monthly_rows)

    def _compute_depletion_month(depleted, monthly_rows):
        return _dc_depletion_month(depleted, monthly_rows)

    # ── HISTORICAL MODE ──
    if mode == "historical":
        duration_str = data.get("duration", "10y")
        if withdrawal_strategy == "cash_flow":
            cash_flow_schedule, cash_flow_meta, cash_flow_error = (
                _dc_cash_flow_withdrawal_schedule(data, 12, historical=True)
            )
            if cash_flow_error:
                return {"error": cash_flow_error}
            monthly_withdrawal = cash_flow_schedule[0] if cash_flow_schedule else 0.0

        all_funds = [fa, fb]
        if fc:
            all_funds.append(fc)
        tickers = [f["ticker"] for f in all_funds]
        unique_tickers = list(dict.fromkeys(tickers))

        try:
            raw = _chunked_yf_download(
                unique_tickers, period="max", interval="1d",
                auto_adjust=False, actions=True, group_by="ticker", progress=False,
            )
        except Exception as e:
            return {"error": f"Failed to fetch data: {str(e)}"}

        if raw is None or raw.empty:
            return {"error": "No data returned from Yahoo Finance."}

        def _extract(sym):
            try:
                if isinstance(raw.columns, pd.MultiIndex):
                    top_keys = raw.columns.get_level_values(0).unique()
                    if sym in top_keys:
                        sub = raw[sym]
                        close = sub["Close"] if "Close" in sub.columns else None
                        divs = sub["Dividends"] if "Dividends" in sub.columns else pd.Series(0.0, index=raw.index)
                    elif "Close" in top_keys:
                        close = raw["Close"][sym] if sym in raw["Close"].columns else raw["Close"].iloc[:, 0]
                        divs_df = raw["Dividends"] if "Dividends" in top_keys else None
                        divs = divs_df[sym] if divs_df is not None and sym in divs_df.columns else pd.Series(0.0, index=raw.index)
                    else:
                        return None, None
                else:
                    close = raw["Close"] if "Close" in raw.columns else None
                    divs = raw["Dividends"] if "Dividends" in raw.columns else pd.Series(0.0, index=raw.index)
            except Exception:
                return None, None
            return close, divs

        common_start = None
        newer_ticker = None
        for fund in all_funds:
            close_tmp, _ = _extract(fund["ticker"])
            if close_tmp is None or close_tmp.dropna().empty:
                return {"error": f"No data found for {fund['ticker']}."}
            first_valid = close_tmp.dropna().index[0]
            if common_start is None or first_valid > common_start:
                common_start = first_valid
                newer_ticker = fund["ticker"]

        from datetime import datetime as _dt, timedelta
        available_months = (pd.Timestamp.now() - common_start).days / 30.44
        available_years = available_months / 12
        if duration_str != "max":
            requested_years = int(duration_str.replace("y", ""))
            if requested_years > available_years:
                max_yrs = int(available_years)
                return {"error": (
                    f"{newer_ticker} only has data from {common_start.strftime('%Y-%m-%d')} "
                    f"(~{max_yrs} year{'s' if max_yrs != 1 else ''} of overlap). "
                    f"Please select {max_yrs} year{'s' if max_yrs != 1 else ''} or less, or use Max."
                )}
            trim_start = pd.Timestamp(_dt.now() - timedelta(days=requested_years * 365))
            if trim_start > common_start:
                common_start = trim_start

        results = {}
        fund_list = [("fund_a", fa), ("fund_b", fb)]
        if fc:
            fund_list.append(("fund_c", fc))
        date_labels = []
        for label, fund in fund_list:
            sym = fund["ticker"]
            investment = fund["investment"]
            drip = fund["drip"]

            close, divs = _extract(sym)
            close = close[close.index >= common_start]
            divs = divs[divs.index >= common_start]

            monthly_close = close.resample("ME").last()
            monthly_divs = divs.resample("ME").sum()
            df_m = pd.DataFrame({"price": monthly_close, "div": monthly_divs}).dropna(subset=["price"])
            df_m["div"] = df_m["div"].fillna(0.0)

            if df_m.empty:
                return {"error": f"No usable monthly data for {sym}."}

            initial_price = float(df_m["price"].iloc[0])
            if initial_price <= 0:
                return {"error": f"Initial price for {sym} is zero."}

            is_growth = label in growth_funds
            wedge = cash_wedge_initial if is_growth else 0.0
            shares = investment / initial_price
            cum_withdrawals = 0.0
            cum_distributions = 0.0
            prev_pv = investment
            cash_accumulated = 0.0

            portfolio_values = []
            cumulative_withdrawals_list = []
            cumulative_distributions_list = []
            share_counts = []
            total_values = []
            monthly_rows = []
            depleted = False

            for month_index, (dt, row) in enumerate(df_m.iterrows()):
                price = float(row["price"])
                div_per_share = float(row["div"])

                if depleted or shares <= 0:
                    depleted = True
                    portfolio_values.append(0.0)
                    cumulative_withdrawals_list.append(round(cum_withdrawals, 2))
                    cumulative_distributions_list.append(round(cum_distributions, 2))
                    share_counts.append(0.0)
                    tv = cum_withdrawals + wedge + cash_accumulated
                    total_values.append(round(tv, 2))
                    row_data = {
                        "price": 0, "shares": 0, "portfolio": 0,
                        "dist_per_share": 0, "income": 0, "withdrawal": 0,
                        "wedge_drawn": 0, "wedge_bal": round(wedge, 2),
                        "excess": 0, "shares_delta": 0, "growth": 0,
                        "cum_income": round(cum_distributions, 2),
                        "roi_dollar": round(cum_withdrawals + wedge + cash_accumulated - investment - (cash_wedge_initial if is_growth else 0), 2),
                        "roi_pct": round(((cum_withdrawals + wedge + cash_accumulated - investment - (cash_wedge_initial if is_growth else 0)) / investment * 100), 2) if investment else 0,
                    }
                    if not drip:
                        row_data["cash_accumulated"] = round(cash_accumulated, 2)
                    monthly_rows.append(row_data)
                    continue

                shares_before = shares
                dist_this_month = div_per_share * shares
                cum_distributions += dist_this_month

                # Compute effective withdrawal for this month
                current_pv = shares * price
                effective_withdrawal = _compute_effective_withdrawal(
                    monthly_withdrawal, month_index, current_pv, investment)

                wedge_drawn = 0.0
                if is_growth:
                    need = effective_withdrawal
                    cw_draw = min(wedge, need)
                    wedge -= cw_draw
                    wedge_drawn = cw_draw
                    need -= cw_draw
                    div_used = min(dist_this_month, need)
                    need -= div_used
                    leftover_div = dist_this_month - div_used
                    if drip:
                        if leftover_div > 0 and price > 0:
                            shares += leftover_div / price
                    else:
                        cash_accumulated += leftover_div
                    if need > 0:
                        if not drip and cash_accumulated > 0:
                            cash_draw = min(cash_accumulated, need)
                            cash_accumulated -= cash_draw
                            need -= cash_draw
                        if need > 0 and price > 0:
                            shares -= need / price
                    cum_withdrawals += effective_withdrawal
                    excess = dist_this_month + cw_draw - effective_withdrawal
                else:
                    excess = dist_this_month - effective_withdrawal
                    if dist_this_month >= effective_withdrawal:
                        if drip:
                            if price > 0:
                                shares += excess / price
                        else:
                            cash_accumulated += excess
                        cum_withdrawals += effective_withdrawal
                    else:
                        shortfall = -excess
                        if not drip and cash_accumulated > 0:
                            cash_draw = min(cash_accumulated, shortfall)
                            cash_accumulated -= cash_draw
                            shortfall -= cash_draw
                        if shortfall > 0 and price > 0:
                            shares -= shortfall / price
                        cum_withdrawals += effective_withdrawal

                if shares <= 0:
                    shares = 0.0
                    depleted = True

                pv = shares * price
                growth = pv - prev_pv
                shares_delta = shares - shares_before
                total_basis = investment + (cash_wedge_initial if is_growth else 0)
                roi_dollar = pv + cum_withdrawals + wedge + cash_accumulated - total_basis
                roi_pct = roi_dollar / investment * 100 if investment else 0

                portfolio_values.append(round(pv, 2))
                cumulative_withdrawals_list.append(round(cum_withdrawals, 2))
                cumulative_distributions_list.append(round(cum_distributions, 2))
                share_counts.append(round(shares, 4))
                total_values.append(round(pv + cum_withdrawals + wedge + cash_accumulated, 2))
                row_data = {
                    "price": round(price, 2),
                    "shares": round(shares, 4),
                    "portfolio": round(pv, 2),
                    "dist_per_share": round(div_per_share, 4),
                    "income": round(dist_this_month, 2),
                    "withdrawal": round(effective_withdrawal, 2),
                    "wedge_drawn": round(wedge_drawn, 2),
                    "wedge_bal": round(wedge, 2),
                    "excess": round(excess, 2),
                    "shares_delta": round(shares_delta, 4),
                    "growth": round(growth, 2),
                    "cum_income": round(cum_distributions, 2),
                    "roi_dollar": round(roi_dollar, 2),
                    "roi_pct": round(roi_pct, 2),
                }
                if not drip:
                    row_data["cash_accumulated"] = round(cash_accumulated, 2)
                monthly_rows.append(row_data)
                prev_pv = pv

            date_labels = [dt.strftime("%Y-%m") for dt in df_m.index]
            total_bought = sum(r["shares_delta"] for r in monthly_rows if r["shares_delta"] > 0)
            total_sold = sum(-r["shares_delta"] for r in monthly_rows if r["shares_delta"] < 0)
            initial_shares = investment / initial_price
            role = "Growth" if is_growth else "Income"

            risk_metrics = _compute_risk_metrics(portfolio_values, monthly_rows)
            depletion_month = _compute_depletion_month(depleted, monthly_rows)

            fund_result = {
                "ticker": sym,
                "role": role,
                "investment": round(investment, 2),
                "initial_shares": round(initial_shares, 4),
                "has_cash_wedge": is_growth and cash_wedge_initial > 0,
                "cash_wedge_remaining": round(wedge, 2) if is_growth else None,
                "portfolio_values": portfolio_values,
                "cumulative_withdrawals": cumulative_withdrawals_list,
                "cumulative_distributions": cumulative_distributions_list,
                "total_values": total_values,
                "shares": share_counts,
                "monthly_rows": monthly_rows,
                "total_shares_bought": round(total_bought, 4),
                "total_shares_sold": round(total_sold, 4),
                "final_portfolio": portfolio_values[-1] if portfolio_values else 0.0,
                "final_withdrawn": round(cum_withdrawals, 2),
                "final_distributions": round(cum_distributions, 2),
                "final_total": total_values[-1] if total_values else 0.0,
                "depleted": depleted,
                "depletion_month": depletion_month,
                "risk_metrics": risk_metrics,
                "drip": drip,
            }
            if not drip:
                fund_result["cash_accumulated"] = round(cash_accumulated, 2)
            results[label] = fund_result

        results["months"] = date_labels
        results["data_start"] = common_start.strftime("%Y-%m-%d")
        results["cash_wedge_initial"] = cash_wedge_initial
        results["comparison_type"] = comparison_type
        if cash_flow_meta:
            results["cash_flow_plan"] = cash_flow_meta
        return results

    # ── SIMULATION MODE ──
    if mode == "simulate":
        market_type = data.get("market", "neutral")
        duration_months = int(data.get("duration_months", 120))
        if duration_months < 1 or duration_months > 240:
            return {"error": "Simulation duration must be between 1 and 240 months (20 years max)."}
        if withdrawal_strategy == "cash_flow":
            cash_flow_schedule, cash_flow_meta, cash_flow_error = (
                _dc_cash_flow_withdrawal_schedule(data, duration_months)
            )
            if cash_flow_error:
                return {"error": cash_flow_error}
            monthly_withdrawal = cash_flow_schedule[0] if cash_flow_schedule else 0.0

        bias_map = {"bullish": +0.010, "bearish": -0.015, "neutral": 0.0}
        vol_mult_map = {"bullish": 0.9, "bearish": 1.2, "neutral": 1.0}
        bias = bias_map.get(market_type, 0.0)
        vol_mult = vol_mult_map.get(market_type, 1.0)

        results = {}
        fund_list = [("fund_a", fa), ("fund_b", fb)]
        if fc:
            fund_list.append(("fund_c", fc))
        date_labels = []
        for label, fund in fund_list:
            sym = fund["ticker"]
            investment = fund["investment"]
            yo = fund["yield_override"]
            drip = fund["drip"]

            prices, current_price, ttm_detected, perr = _dc_simulate_price_path(
                sym, duration_months, market_type)
            if perr:
                return {"error": perr}
            ttm_yield = (yo / 100.0) if yo is not None else ttm_detected

            is_growth = label in growth_funds
            wedge = cash_wedge_initial if is_growth else 0.0
            shares = investment / current_price
            cum_withdrawals = 0.0
            cum_distributions = 0.0
            prev_pv = investment
            cash_accumulated = 0.0

            portfolio_values = []
            cumulative_withdrawals_list = []
            cumulative_distributions_list = []
            share_counts = []
            total_values = []
            monthly_rows = []
            depleted = False

            for month_index, price in enumerate(prices[1:]):
                if depleted or shares <= 0:
                    depleted = True
                    portfolio_values.append(0.0)
                    cumulative_withdrawals_list.append(round(cum_withdrawals, 2))
                    cumulative_distributions_list.append(round(cum_distributions, 2))
                    share_counts.append(0.0)
                    tv = cum_withdrawals + wedge + cash_accumulated
                    total_values.append(round(tv, 2))
                    row_data = {
                        "price": 0, "shares": 0, "portfolio": 0,
                        "dist_per_share": 0, "income": 0, "withdrawal": 0,
                        "wedge_drawn": 0, "wedge_bal": round(wedge, 2),
                        "excess": 0, "shares_delta": 0, "growth": 0,
                        "cum_income": round(cum_distributions, 2),
                        "roi_dollar": round(cum_withdrawals + wedge + cash_accumulated - investment - (cash_wedge_initial if is_growth else 0), 2),
                        "roi_pct": round(((cum_withdrawals + wedge + cash_accumulated - investment - (cash_wedge_initial if is_growth else 0)) / investment * 100), 2) if investment else 0,
                    }
                    if not drip:
                        row_data["cash_accumulated"] = round(cash_accumulated, 2)
                    monthly_rows.append(row_data)
                    continue

                pct_chg = (price - current_price) / current_price * 100
                factor = _dc_nav_erosion_factor(pct_chg)

                shares_before = shares
                dist_per_share = (ttm_yield / 12) * price * factor
                dist_this_month = dist_per_share * shares
                cum_distributions += dist_this_month

                # Compute effective withdrawal for this month
                current_pv = shares * price
                effective_withdrawal = _compute_effective_withdrawal(
                    monthly_withdrawal, month_index, current_pv, investment)

                wedge_drawn = 0.0
                if is_growth:
                    need = effective_withdrawal
                    cw_draw = min(wedge, need)
                    wedge -= cw_draw
                    wedge_drawn = cw_draw
                    need -= cw_draw
                    div_used = min(dist_this_month, need)
                    need -= div_used
                    leftover_div = dist_this_month - div_used
                    if drip:
                        if leftover_div > 0 and price > 0:
                            shares += leftover_div / price
                    else:
                        cash_accumulated += leftover_div
                    if need > 0:
                        if not drip and cash_accumulated > 0:
                            cash_draw = min(cash_accumulated, need)
                            cash_accumulated -= cash_draw
                            need -= cash_draw
                        if need > 0 and price > 0:
                            shares -= need / price
                    cum_withdrawals += effective_withdrawal
                    excess = dist_this_month + cw_draw - effective_withdrawal
                else:
                    excess = dist_this_month - effective_withdrawal
                    if dist_this_month >= effective_withdrawal:
                        if drip:
                            if price > 0:
                                shares += excess / price
                        else:
                            cash_accumulated += excess
                        cum_withdrawals += effective_withdrawal
                    else:
                        shortfall = -excess
                        if not drip and cash_accumulated > 0:
                            cash_draw = min(cash_accumulated, shortfall)
                            cash_accumulated -= cash_draw
                            shortfall -= cash_draw
                        if shortfall > 0 and price > 0:
                            shares -= shortfall / price
                        cum_withdrawals += effective_withdrawal

                if shares <= 0:
                    shares = 0.0
                    depleted = True

                pv = shares * price
                growth = pv - prev_pv
                shares_delta = shares - shares_before
                total_basis = investment + (cash_wedge_initial if is_growth else 0)
                roi_dollar = pv + cum_withdrawals + wedge + cash_accumulated - total_basis
                roi_pct = roi_dollar / investment * 100 if investment else 0

                portfolio_values.append(round(pv, 2))
                cumulative_withdrawals_list.append(round(cum_withdrawals, 2))
                cumulative_distributions_list.append(round(cum_distributions, 2))
                share_counts.append(round(shares, 4))
                total_values.append(round(pv + cum_withdrawals + wedge + cash_accumulated, 2))
                row_data = {
                    "price": round(price, 2),
                    "shares": round(shares, 4),
                    "portfolio": round(pv, 2),
                    "dist_per_share": round(dist_per_share, 4),
                    "income": round(dist_this_month, 2),
                    "withdrawal": round(effective_withdrawal, 2),
                    "wedge_drawn": round(wedge_drawn, 2),
                    "wedge_bal": round(wedge, 2),
                    "excess": round(excess, 2),
                    "shares_delta": round(shares_delta, 4),
                    "growth": round(growth, 2),
                    "cum_income": round(cum_distributions, 2),
                    "roi_dollar": round(roi_dollar, 2),
                    "roi_pct": round(roi_pct, 2),
                }
                if not drip:
                    row_data["cash_accumulated"] = round(cash_accumulated, 2)
                monthly_rows.append(row_data)
                prev_pv = pv

            date_labels = [f"Month {i+1}" for i in range(duration_months)]
            total_bought = sum(r["shares_delta"] for r in monthly_rows if r["shares_delta"] > 0)
            total_sold = sum(-r["shares_delta"] for r in monthly_rows if r["shares_delta"] < 0)
            initial_shares = investment / current_price
            role = "Growth" if is_growth else "Income"

            risk_metrics = _compute_risk_metrics(portfolio_values, monthly_rows)
            depletion_month = _compute_depletion_month(depleted, monthly_rows)

            fund_result = {
                "ticker": sym,
                "role": role,
                "investment": round(investment, 2),
                "initial_shares": round(initial_shares, 4),
                "has_cash_wedge": is_growth and cash_wedge_initial > 0,
                "cash_wedge_remaining": round(wedge, 2) if is_growth else None,
                "portfolio_values": portfolio_values,
                "cumulative_withdrawals": cumulative_withdrawals_list,
                "cumulative_distributions": cumulative_distributions_list,
                "total_values": total_values,
                "shares": share_counts,
                "monthly_rows": monthly_rows,
                "total_shares_bought": round(total_bought, 4),
                "total_shares_sold": round(total_sold, 4),
                "final_portfolio": portfolio_values[-1] if portfolio_values else 0.0,
                "final_withdrawn": round(cum_withdrawals, 2),
                "final_distributions": round(cum_distributions, 2),
                "final_total": total_values[-1] if total_values else 0.0,
                "depleted": depleted,
                "depletion_month": depletion_month,
                "risk_metrics": risk_metrics,
                "drip": drip,
            }
            if not drip:
                fund_result["cash_accumulated"] = round(cash_accumulated, 2)
            results[label] = fund_result

        results["months"] = date_labels
        results["cash_wedge_initial"] = cash_wedge_initial
        results["comparison_type"] = comparison_type
        if cash_flow_meta:
            results["cash_flow_plan"] = cash_flow_meta
        return results

    return {"error": f"Unknown mode: {mode}"}


def _dc_simulate_basket(legs, *, duration_months, market_type, monthly_withdrawal,
                        withdrawal_strategy, withdrawal_pct, inflation_rate,
                        dynamic_reduce_pct, dynamic_threshold_pct,
                        cash_wedge_initial, is_growth, drip, name,
                        price_path_cache=None, monthly_withdrawal_schedule=None):
    """Simulate a basket of tickers as a single "fund" over ``duration_months``.

    Mirrors the single-ticker simulate loop in ``_distribution_compare_compute`` but
    pools distributions / withdrawal / cash-wedge at the basket level and spreads
    share sales proportionally across legs by value. Returns the same ``fund_result``
    dict shape the single-ticker path produces (plus ``is_basket`` / ``legs``), so the
    existing results UI renders it unchanged. Returns ``{"error": ...}`` on failure.
    """
    if price_path_cache is None:
        price_path_cache = {}

    leg_states = []
    for leg in legs:
        sym = leg["ticker"]
        try:
            amount = float(leg["amount"])
        except (TypeError, ValueError):
            return {"error": f"{name}: invalid amount for {sym}."}
        cache_key = (sym, duration_months, market_type)
        if cache_key not in price_path_cache:
            price_path_cache[cache_key] = _dc_simulate_price_path(
                sym, duration_months, market_type)
        prices, current_price, ttm_yield, perr = price_path_cache[cache_key]
        if perr:
            return {"error": perr}
        leg_states.append({
            "sym": sym, "prices": prices, "current_price": current_price,
            "ttm_yield": ttm_yield, "amount": amount,
            "shares0": amount / current_price, "shares": amount / current_price,
            "distributions_generated": 0.0,
            "withdrawals_funded": 0.0,
            "cash": 0.0,
        })

    investment = sum(s["amount"] for s in leg_states)
    if investment <= 0:
        return {"error": f"{name}: total investment must be greater than 0."}

    wedge = cash_wedge_initial if is_growth else 0.0
    cum_withdrawals = 0.0
    cum_distributions = 0.0
    cum_wedge_drawn = 0.0
    unfunded_withdrawals = 0.0
    prev_pv = investment

    portfolio_values, cumulative_withdrawals_list = [], []
    cumulative_distributions_list, share_counts, total_values, monthly_rows = [], [], [], []
    depleted = False

    def _basket_value(m_idx):
        return sum(s["shares"] * s["prices"][m_idx] for s in leg_states)

    def _price_index(m_idx):
        # gross market-value index (initial shares, ignores flows) for the Price chart
        return sum(s["shares0"] * s["prices"][m_idx] for s in leg_states)

    def _cash_total():
        return sum(s["cash"] for s in leg_states)

    def _allocate(amount, weights):
        weight_total = sum(max(0.0, float(w)) for w in weights)
        if amount <= 0 or weight_total <= 0:
            return [0.0 for _ in weights]
        return [amount * max(0.0, float(w)) / weight_total for w in weights]

    def _record_distribution_withdrawal(amount, leg_dists):
        for s, allocated in zip(leg_states, _allocate(amount, leg_dists)):
            s["withdrawals_funded"] += allocated

    def _add_distribution_cash(amount, leg_dists):
        for s, allocated in zip(leg_states, _allocate(amount, leg_dists)):
            s["cash"] += allocated

    def _draw_cash(amount_needed):
        available = _cash_total()
        amount_drawn = min(max(0.0, amount_needed), available)
        if amount_drawn <= 0:
            return 0.0
        for s, allocated in zip(
                leg_states, _allocate(amount_drawn, [s["cash"] for s in leg_states])):
            s["cash"] = max(0.0, s["cash"] - allocated)
            s["withdrawals_funded"] += allocated
        return amount_drawn

    def _sell_value(amount_needed, m_idx):
        nonlocal depleted
        total_val = _basket_value(m_idx)
        if total_val <= 0 or amount_needed <= 0:
            if total_val <= 0:
                depleted = True
            return 0.0
        amount_sold = min(amount_needed, total_val)
        frac = amount_sold / total_val
        for s in leg_states:
            leg_value = s["shares"] * s["prices"][m_idx]
            sold_value = leg_value * frac
            s["shares"] *= (1.0 - frac)
            s["withdrawals_funded"] += sold_value
        if amount_needed >= total_val:
            for s in leg_states:
                s["shares"] = 0.0
            depleted = True
        return amount_sold

    def _reinvest(amount_total, leg_dists, basket_income, m_idx):
        # reinvest leftover distribution back into each leg in proportion to its own payout
        if amount_total <= 0 or basket_income <= 0:
            return
        for s, d in zip(leg_states, leg_dists):
            price_i = s["prices"][m_idx]
            if price_i > 0:
                s["shares"] += (amount_total * (d / basket_income)) / price_i

    for month_index in range(duration_months):
        m_idx = month_index + 1  # prices index (0 == current price)

        if depleted or sum(s["shares"] for s in leg_states) <= 0:
            depleted = True
            cash_accumulated = _cash_total()
            portfolio_values.append(0.0)
            cumulative_withdrawals_list.append(round(cum_withdrawals, 2))
            cumulative_distributions_list.append(round(cum_distributions, 2))
            share_counts.append(0.0)
            tv = cum_withdrawals + wedge + cash_accumulated
            total_values.append(round(tv, 2))
            base = investment + (cash_wedge_initial if is_growth else 0)
            row_data = {
                "price": 0, "shares": 0, "portfolio": 0, "dist_per_share": 0,
                "income": 0, "withdrawal": 0, "wedge_drawn": 0, "wedge_bal": round(wedge, 2),
                "excess": 0, "shares_delta": 0, "growth": 0,
                "cum_income": round(cum_distributions, 2),
                "roi_dollar": round(cum_withdrawals + wedge + cash_accumulated - base, 2),
                "roi_pct": round((cum_withdrawals + wedge + cash_accumulated - base) / investment * 100, 2) if investment else 0,
            }
            if not drip:
                row_data["cash_accumulated"] = round(cash_accumulated, 2)
            monthly_rows.append(row_data)
            continue

        shares_before_total = sum(s["shares"] for s in leg_states)

        # Distributions this month (per leg, with NAV erosion vs. its own drawdown)
        leg_dists = []
        basket_income = 0.0
        for s in leg_states:
            price_i = s["prices"][m_idx]
            pct_chg_i = (price_i - s["current_price"]) / s["current_price"] * 100 if s["current_price"] else 0.0
            dist_i = (s["ttm_yield"] / 12.0) * price_i * _dc_nav_erosion_factor(pct_chg_i) * s["shares"]
            s["distributions_generated"] += dist_i
            leg_dists.append(dist_i)
            basket_income += dist_i
        cum_distributions += basket_income

        current_pv = _basket_value(m_idx)
        withdrawal_base = monthly_withdrawal
        effective_strategy = withdrawal_strategy
        effective_inflation = inflation_rate
        if withdrawal_strategy == "cash_flow" and monthly_withdrawal_schedule:
            withdrawal_base = monthly_withdrawal_schedule[
                min(month_index, len(monthly_withdrawal_schedule) - 1)
            ]
            effective_strategy = "fixed"
            effective_inflation = None
        effective_withdrawal = _dc_effective_withdrawal(
            withdrawal_base, month_index, current_pv, investment,
            strategy=effective_strategy, withdrawal_pct=withdrawal_pct,
            dynamic_threshold_pct=dynamic_threshold_pct,
            dynamic_reduce_pct=dynamic_reduce_pct, inflation_rate=effective_inflation)

        wedge_drawn = 0.0
        if is_growth:
            need = effective_withdrawal
            cw_draw = min(wedge, need)
            wedge -= cw_draw
            wedge_drawn = cw_draw
            cum_wedge_drawn += cw_draw
            need -= cw_draw
            div_used = min(basket_income, need)
            _record_distribution_withdrawal(div_used, leg_dists)
            need -= div_used
            leftover_div = basket_income - div_used
            if drip:
                _reinvest(leftover_div, leg_dists, basket_income, m_idx)
            else:
                _add_distribution_cash(leftover_div, leg_dists)
            if need > 0:
                if not drip and _cash_total() > 0:
                    cash_draw = _draw_cash(need)
                    need -= cash_draw
                if need > 0:
                    sold = _sell_value(need, m_idx)
                    need -= sold
                if need > 0:
                    unfunded_withdrawals += need
            cum_withdrawals += effective_withdrawal
            excess = basket_income + cw_draw - effective_withdrawal
        else:
            excess = basket_income - effective_withdrawal
            if basket_income >= effective_withdrawal:
                _record_distribution_withdrawal(effective_withdrawal, leg_dists)
                if drip:
                    _reinvest(excess, leg_dists, basket_income, m_idx)
                else:
                    _add_distribution_cash(excess, leg_dists)
                cum_withdrawals += effective_withdrawal
            else:
                _record_distribution_withdrawal(basket_income, leg_dists)
                shortfall = -excess
                if not drip and _cash_total() > 0:
                    cash_draw = _draw_cash(shortfall)
                    shortfall -= cash_draw
                if shortfall > 0:
                    sold = _sell_value(shortfall, m_idx)
                    shortfall -= sold
                if shortfall > 0:
                    unfunded_withdrawals += shortfall
                cum_withdrawals += effective_withdrawal

        total_shares_after = sum(s["shares"] for s in leg_states)
        if total_shares_after <= 1e-9:
            for s in leg_states:
                s["shares"] = 0.0
            total_shares_after = 0.0
            depleted = True

        pv = _basket_value(m_idx)
        cash_accumulated = _cash_total()
        growth = pv - prev_pv
        shares_delta = total_shares_after - shares_before_total
        total_basis = investment + (cash_wedge_initial if is_growth else 0)
        roi_dollar = pv + cum_withdrawals + wedge + cash_accumulated - total_basis
        roi_pct = roi_dollar / investment * 100 if investment else 0

        portfolio_values.append(round(pv, 2))
        cumulative_withdrawals_list.append(round(cum_withdrawals, 2))
        cumulative_distributions_list.append(round(cum_distributions, 2))
        share_counts.append(round(total_shares_after, 4))
        total_values.append(round(pv + cum_withdrawals + wedge + cash_accumulated, 2))
        row_data = {
            "price": round(_price_index(m_idx), 2),
            "shares": round(total_shares_after, 4),
            "portfolio": round(pv, 2),
            "dist_per_share": 0,
            "income": round(basket_income, 2),
            "withdrawal": round(effective_withdrawal, 2),
            "wedge_drawn": round(wedge_drawn, 2),
            "wedge_bal": round(wedge, 2),
            "excess": round(excess, 2),
            "shares_delta": round(shares_delta, 4),
            "growth": round(growth, 2),
            "cum_income": round(cum_distributions, 2),
            "roi_dollar": round(roi_dollar, 2),
            "roi_pct": round(roi_pct, 2),
        }
        if not drip:
            row_data["cash_accumulated"] = round(cash_accumulated, 2)
        monthly_rows.append(row_data)
        prev_pv = pv

    total_bought = sum(r["shares_delta"] for r in monthly_rows if r["shares_delta"] > 0)
    total_sold = sum(-r["shares_delta"] for r in monthly_rows if r["shares_delta"] < 0)
    initial_shares = sum(s["shares0"] for s in leg_states)
    final_total = total_values[-1] if total_values else 0.0

    ticker_attribution = []
    for s in leg_states:
        final_price = s["prices"][-1] if s["prices"] else s["current_price"]
        final_value = s["shares"] * final_price
        ending_wealth = final_value + s["withdrawals_funded"] + s["cash"]
        pnl = ending_wealth - s["amount"]
        ticker_attribution.append({
            "ticker": s["sym"],
            "initial_amount": round(s["amount"], 2),
            "initial_weight_pct": round(s["amount"] / investment * 100, 2),
            "initial_shares": round(s["shares0"], 4),
            "final_shares": round(s["shares"], 4),
            "final_value": round(final_value, 2),
            "distributions_generated": round(s["distributions_generated"], 2),
            "withdrawals_funded": round(s["withdrawals_funded"], 2),
            "cash_remaining": round(s["cash"], 2),
            "ending_wealth": round(ending_wealth, 2),
            "pnl": round(pnl, 2),
            "return_pct": round(pnl / s["amount"] * 100, 2) if s["amount"] else 0.0,
            "price_return_pct": round(
                (final_price / s["current_price"] - 1.0) * 100, 2
            ) if s["current_price"] else 0.0,
            "contribution_pct_points": round(pnl / investment * 100, 2) if investment else 0.0,
        })

    ticker_ending_wealth = sum(r["ending_wealth"] for r in ticker_attribution)
    wedge_contribution = cash_wedge_initial if is_growth else 0.0
    reconciled_total = ticker_ending_wealth + wedge_contribution + unfunded_withdrawals

    fund_result = {
        "ticker": name,
        "role": "Growth" if is_growth else "Income",
        "investment": round(investment, 2),
        "initial_shares": round(initial_shares, 4),
        "has_cash_wedge": is_growth and cash_wedge_initial > 0,
        "cash_wedge_remaining": round(wedge, 2) if is_growth else None,
        "portfolio_values": portfolio_values,
        "cumulative_withdrawals": cumulative_withdrawals_list,
        "cumulative_distributions": cumulative_distributions_list,
        "total_values": total_values,
        "shares": share_counts,
        "monthly_rows": monthly_rows,
        "total_shares_bought": round(total_bought, 4),
        "total_shares_sold": round(total_sold, 4),
        "final_portfolio": portfolio_values[-1] if portfolio_values else 0.0,
        "final_withdrawn": round(cum_withdrawals, 2),
        "final_distributions": round(cum_distributions, 2),
        "final_total": final_total,
        "depleted": depleted,
        "depletion_month": _dc_depletion_month(depleted, monthly_rows),
        "risk_metrics": _dc_risk_metrics(portfolio_values, monthly_rows),
        "drip": drip,
        "is_basket": True,
        "legs": [{"ticker": s["sym"], "amount": round(s["amount"], 2)} for s in leg_states],
        "ticker_attribution": ticker_attribution,
        "attribution_reconciliation": {
            "ticker_ending_wealth": round(ticker_ending_wealth, 2),
            "cash_wedge_contribution": round(wedge_contribution, 2),
            "cash_wedge_drawn": round(cum_wedge_drawn, 2),
            "unfunded_withdrawals": round(unfunded_withdrawals, 2),
            "reconciled_total": round(reconciled_total, 2),
            "difference": round(final_total - reconciled_total, 2),
        },
    }
    if not drip:
        fund_result["cash_accumulated"] = round(_cash_total(), 2)
    return fund_result


def _dc_build_comparison_attribution(results):
    """Compare ticker P/L for the winning basket against the runner-up basket."""
    funds = [
        (key, results[key])
        for key in ("fund_a", "fund_b", "fund_c")
        if results.get(key)
    ]
    eligible = any(len(fund.get("ticker_attribution") or []) > 1 for _, fund in funds)
    if not eligible or len(funds) < 2:
        return {"eligible": False}

    ranked = sorted(funds, key=lambda item: item[1].get("final_total", 0), reverse=True)
    winner_key, winner = ranked[0]
    runner_up_key, runner_up = ranked[1]
    winner_total = float(winner.get("final_total", 0) or 0)
    runner_up_total = float(runner_up.get("final_total", 0) or 0)
    lead_total = winner_total - runner_up_total
    is_tie = winner_total <= runner_up_total * 1.02

    winner_rows = {
        row["ticker"]: row for row in (winner.get("ticker_attribution") or [])
    }
    runner_up_rows = {
        row["ticker"]: row for row in (runner_up.get("ticker_attribution") or [])
    }
    tickers = sorted(set(winner_rows) | set(runner_up_rows))
    driver_rows = []
    for ticker in tickers:
        winner_row = winner_rows.get(ticker)
        runner_up_row = runner_up_rows.get(ticker)
        winner_pnl = float(winner_row.get("pnl", 0) or 0) if winner_row else 0.0
        runner_up_pnl = float(runner_up_row.get("pnl", 0) or 0) if runner_up_row else 0.0
        driver_rows.append({
            "ticker": ticker,
            "winner_pnl": round(winner_pnl, 2) if winner_row else None,
            "runner_up_pnl": round(runner_up_pnl, 2) if runner_up_row else None,
            "winner_return_pct": winner_row.get("return_pct") if winner_row else None,
            "runner_up_return_pct": runner_up_row.get("return_pct") if runner_up_row else None,
            "impact": round(winner_pnl - runner_up_pnl, 2),
        })
    driver_rows.sort(key=lambda row: (-row["impact"], row["ticker"]))

    ticker_effect_total = sum(row["impact"] for row in driver_rows)
    winner_recon = winner.get("attribution_reconciliation") or {}
    runner_recon = runner_up.get("attribution_reconciliation") or {}
    winner_basis = (
        float(winner.get("investment", 0) or 0)
        + float(winner_recon.get("cash_wedge_contribution", 0) or 0)
    )
    runner_up_basis = (
        float(runner_up.get("investment", 0) or 0)
        + float(runner_recon.get("cash_wedge_contribution", 0) or 0)
    )
    starting_capital_effect = winner_basis - runner_up_basis
    unfunded_effect = (
        float(winner_recon.get("unfunded_withdrawals", 0) or 0)
        - float(runner_recon.get("unfunded_withdrawals", 0) or 0)
    )
    explained = ticker_effect_total + starting_capital_effect + unfunded_effect
    other_effect = lead_total - explained

    best_by_fund = {}
    worst_by_fund = {}
    for key, fund in funds:
        rows = list(fund.get("ticker_attribution") or [])
        worst_rows = sorted(
            rows,
            key=lambda row: (row.get("return_pct", 0), row.get("ticker", "")),
        )
        best_rows = sorted(
            rows,
            key=lambda row: (-row.get("return_pct", 0), row.get("ticker", "")),
        )
        best_by_fund[key] = {
            "name": fund.get("ticker", key),
            "rows": best_rows[:3],
        }
        worst_by_fund[key] = {
            "name": fund.get("ticker", key),
            "rows": worst_rows[:3],
        }

    return {
        "eligible": True,
        "winner_key": winner_key,
        "runner_up_key": runner_up_key,
        "winner_name": winner.get("ticker", winner_key),
        "runner_up_name": runner_up.get("ticker", runner_up_key),
        "is_tie": is_tie,
        "lead_total": round(lead_total, 2),
        "ticker_effect_total": round(ticker_effect_total, 2),
        "starting_capital_effect": round(starting_capital_effect, 2),
        "other_effect": round(other_effect, 2),
        "driver_rows": driver_rows,
        "best_by_fund": best_by_fund,
        "worst_by_fund": worst_by_fund,
    }


def _dc_resolve_side_legs(spec, label, exclude_penny=False, penny_threshold=1.0):
    """Resolve a portfolio-compare side spec into a normalized config with concrete
    ``legs=[{ticker, amount}]``. Returns ``(side_cfg, error)``.

    When ``exclude_penny`` is set, portfolio-sourced holdings priced below
    ``penny_threshold`` are dropped before allocation (so an even split spreads
    across the remaining tickers). Manual tickers are user-entered and not filtered.
    """
    if not spec:
        return None, None
    name = (str(spec.get("name") or "").strip()) or label
    role = str(spec.get("role", "income")).lower()
    drip = bool(spec.get("drip", True))
    source = str(spec.get("source", "manual")).lower()
    allocation_mode = str(spec.get("allocation_mode", "actual")).lower()
    try:
        total = float(spec.get("total", 0) or 0)
    except (TypeError, ValueError):
        total = 0.0

    raw_legs = []
    if source == "portfolio":
        try:
            pid = int(spec.get("profile_id"))
        except (TypeError, ValueError):
            return None, f"{name}: select a portfolio."
        conn = get_connection()
        rows = conn.execute(
            """SELECT ticker, current_value, purchase_value, current_price, quantity
               FROM all_account_info
               WHERE profile_id = ? AND current_price IS NOT NULL
               ORDER BY ticker""",
            (pid,),
        ).fetchall()
        conn.close()
        agg = {}
        dropped_penny = 0
        for r in rows:
            tk = (r[0] or "").strip().upper()
            if not tk:
                continue
            cp = float(r[3] or 0)
            if exclude_penny and cp < penny_threshold:
                dropped_penny += 1
                continue
            cur_val = float(r[1] or 0)
            qty = float(r[4] or 0)
            if cur_val <= 0 and qty > 0 and cp > 0:
                cur_val = qty * cp
            a = agg.setdefault(tk, {"current_value": 0.0, "purchase_value": 0.0})
            a["current_value"] += cur_val
            a["purchase_value"] += float(r[2] or 0)
        tickers = list(agg.keys())
        if not tickers:
            if dropped_penny:
                return None, f"{name}: all holdings are below the ${penny_threshold:g} penny-stock threshold."
            return None, f"{name}: portfolio has no priced holdings."
        if allocation_mode == "even":
            if total <= 0:
                return None, f"{name}: enter a total dollar amount for the even split."
            per = total / len(tickers)
            raw_legs = [{"ticker": t, "amount": per} for t in tickers]
        else:  # actual market value (fall back to purchase value)
            for t in tickers:
                amt = agg[t]["current_value"] or agg[t]["purchase_value"]
                if amt > 0:
                    raw_legs.append({"ticker": t, "amount": amt})
            if not raw_legs:
                return None, f"{name}: portfolio holdings have no dollar value."
    else:  # manual
        legs_in = spec.get("legs") or []
        ordered_tickers = []
        for l in legs_in:
            tk = str(l.get("ticker", "")).strip().upper()
            if tk and tk not in ordered_tickers:
                ordered_tickers.append(tk)
        if not ordered_tickers:
            return None, f"{name}: add at least one ticker."
        if allocation_mode == "even":
            if total <= 0:
                return None, f"{name}: enter a total dollar amount for the even split."
            per = total / len(ordered_tickers)
            raw_legs = [{"ticker": t, "amount": per} for t in ordered_tickers]
        else:  # per-ticker amounts
            amt_by_ticker = {}
            for l in legs_in:
                tk = str(l.get("ticker", "")).strip().upper()
                if not tk:
                    continue
                try:
                    amt = float(l.get("amount", 0) or 0)
                except (TypeError, ValueError):
                    amt = 0.0
                amt_by_ticker[tk] = amt_by_ticker.get(tk, 0.0) + amt
            for t in ordered_tickers:
                if amt_by_ticker.get(t, 0) > 0:
                    raw_legs.append({"ticker": t, "amount": amt_by_ticker[t]})
            if not raw_legs:
                return None, f"{name}: enter a dollar amount for at least one ticker."

    return {"name": name, "role": role, "is_growth": role == "growth",
            "drip": drip, "legs": raw_legs}, None


def _distribution_compare_portfolio_compute():
    """Core computation for basket-vs-basket distribution comparison (simulation only)."""
    data = request.get_json(force=True, silent=True) or {}

    try:
        duration_months = int(data.get("duration_months", 120))
    except (TypeError, ValueError):
        return {"error": "Invalid duration."}
    if duration_months < 1 or duration_months > 240:
        return {"error": "Simulation duration must be between 1 and 240 months (20 years max)."}

    market_type = data.get("market", "neutral")
    try:
        monthly_withdrawal = float(data.get("monthly_withdrawal", 0))
    except (TypeError, ValueError):
        monthly_withdrawal = 0.0
    if monthly_withdrawal < 0:
        return {"error": "Monthly withdrawal cannot be negative."}

    withdrawal_strategy = data.get("withdrawal_strategy", "fixed")
    cash_flow_schedule = None
    cash_flow_meta = None
    try:
        withdrawal_pct = float(data.get("withdrawal_pct", 4))
    except (TypeError, ValueError):
        withdrawal_pct = 4.0
    inflation_rate = data.get("inflation_rate")
    if inflation_rate is not None:
        try:
            inflation_rate = float(inflation_rate)
        except (TypeError, ValueError):
            inflation_rate = None
    try:
        dynamic_reduce_pct = float(data.get("dynamic_reduce_pct", 25))
    except (TypeError, ValueError):
        dynamic_reduce_pct = 25.0
    try:
        dynamic_threshold_pct = float(data.get("dynamic_threshold_pct", 80))
    except (TypeError, ValueError):
        dynamic_threshold_pct = 80.0
    try:
        cash_wedge_initial = float(data.get("cash_wedge", 0))
    except (TypeError, ValueError):
        cash_wedge_initial = 0.0
    if cash_wedge_initial < 0:
        cash_wedge_initial = 0.0

    if withdrawal_strategy == "cash_flow":
        cash_flow_schedule, cash_flow_meta, cash_flow_error = (
            _dc_cash_flow_withdrawal_schedule(data, duration_months)
        )
        if cash_flow_error:
            return {"error": cash_flow_error}
        monthly_withdrawal = cash_flow_schedule[0] if cash_flow_schedule else 0.0

    exclude_penny = bool(data.get("exclude_penny", False))
    try:
        penny_threshold = float(data.get("penny_threshold", 1.0) or 0)
    except (TypeError, ValueError):
        penny_threshold = 1.0
    if penny_threshold < 0:
        penny_threshold = 0.0

    side_a, err = _dc_resolve_side_legs(data.get("side_a"), "Side A", exclude_penny, penny_threshold)
    if err:
        return {"error": err}
    if not side_a:
        return {"error": "Side A is required."}
    side_b, err = _dc_resolve_side_legs(data.get("side_b"), "Side B", exclude_penny, penny_threshold)
    if err:
        return {"error": err}
    if not side_b:
        return {"error": "Side B is required."}
    side_c, err = _dc_resolve_side_legs(data.get("side_c"), "Side C", exclude_penny, penny_threshold)
    if err:
        return {"error": err}

    results = {}
    price_path_cache = {}
    pairs = [("fund_a", side_a), ("fund_b", side_b)]
    if side_c:
        pairs.append(("fund_c", side_c))
    for fkey, side in pairs:
        fr = _dc_simulate_basket(
            side["legs"], duration_months=duration_months, market_type=market_type,
            monthly_withdrawal=monthly_withdrawal, withdrawal_strategy=withdrawal_strategy,
            withdrawal_pct=withdrawal_pct, inflation_rate=inflation_rate,
            dynamic_reduce_pct=dynamic_reduce_pct, dynamic_threshold_pct=dynamic_threshold_pct,
            cash_wedge_initial=cash_wedge_initial, is_growth=side["is_growth"],
            drip=side["drip"], name=side["name"],
            price_path_cache=price_path_cache,
            monthly_withdrawal_schedule=cash_flow_schedule)
        if isinstance(fr, dict) and "error" in fr:
            return {"error": fr["error"]}
        results[fkey] = fr

    results["months"] = [f"Month {i + 1}" for i in range(duration_months)]
    results["cash_wedge_initial"] = cash_wedge_initial
    results["comparison_type"] = "portfolio"
    results["attribution"] = _dc_build_comparison_attribution(results)
    if cash_flow_meta:
        results["cash_flow_plan"] = cash_flow_meta
    return results


@app.route("/api/distribution-compare/portfolio-run", methods=["POST"])
def distribution_compare_portfolio_run():
    import traceback as _tb
    try:
        result = _distribution_compare_portfolio_compute()
        if isinstance(result, dict) and "error" in result:
            return jsonify(error=result["error"])
        return jsonify(**result)
    except Exception as _e:
        return jsonify(error=f"Server error: {str(_e)}", detail=_tb.format_exc())


# ── Consolidation Analysis ─────────────────────────────────────────────────────

@app.route("/api/consolidation/clusters", methods=["POST"])
def consolidation_clusters():
    """Auto-group holdings by underlying exposure using correlation analysis."""
    import math
    import warnings
    import numpy as np
    import yfinance as yf
    from scipy.cluster.hierarchy import linkage, fcluster
    from scipy.spatial.distance import squareform
    from collections import Counter
    warnings.filterwarnings("ignore")

    def _safe(v):
        if v is None:
            return None
        try:
            f = float(v)
            return None if (math.isnan(f) or math.isinf(f)) else round(f, 4)
        except (TypeError, ValueError):
            return None

    # Get threshold from request (default 0.80)
    body = request.get_json(silent=True) or {}
    corr_threshold = float(body.get("threshold", 0.80))
    corr_threshold = max(0.50, min(0.95, corr_threshold))  # clamp
    dist_threshold = 1.0 - corr_threshold

    _, pids = get_profile_filter()
    placeholders = ",".join("?" * len(pids))
    conn = get_connection()
    rows = conn.execute(
        f"SELECT ticker, description, quantity, current_value, current_price, "
        f"approx_monthly_income, current_annual_yield "
        f"FROM all_account_info WHERE profile_id IN ({placeholders}) "
        f"AND quantity > 0 AND current_value > 0",
        pids,
    ).fetchall()
    conn.close()

    if not rows:
        return jsonify(error="No holdings found for this profile.")

    # Aggregate rows by ticker (same ticker may appear for multiple owners)
    holdings = {}
    for r in rows:
        t = r["ticker"]
        if t in holdings:
            holdings[t]["quantity"] = (holdings[t]["quantity"] or 0) + (r["quantity"] or 0)
            holdings[t]["current_value"] = (holdings[t]["current_value"] or 0) + (r["current_value"] or 0)
            holdings[t]["approx_monthly_income"] = (holdings[t]["approx_monthly_income"] or 0) + (r["approx_monthly_income"] or 0)
            # Keep current_price and current_annual_yield from existing entry (same ticker, same price)
        else:
            holdings[t] = dict(r)
    # Recalculate yield from aggregated values
    for t, h in holdings.items():
        cv = h.get("current_value") or 0
        mi = h.get("approx_monthly_income") or 0
        h["current_annual_yield"] = (mi * 12 / cv * 100) if cv > 0 else 0
    tickers = list(holdings.keys())

    if len(tickers) < 2:
        # Not enough tickers to cluster
        unclustered = []
        for t in tickers:
            h = holdings[t]
            unclustered.append({
                "ticker": t,
                "description": h.get("description") or "",
                "quantity": _safe(h.get("quantity")),
                "current_value": _safe(h.get("current_value")),
                "monthly_income": _safe(h.get("approx_monthly_income")),
                "current_yield": _safe(h.get("current_annual_yield")),
            })
        return jsonify(clusters=[], unclustered=unclustered, correlation_matrix={})

    # Download 1 year of daily close prices
    try:
        raw = _chunked_yf_download(" ".join(tickers), period="1y", auto_adjust=True, progress=False)
        if raw.empty:
            return jsonify(error="No price data returned from Yahoo Finance.")
    except Exception as e:
        return jsonify(error=f"Failed to fetch data: {str(e)}")

    if isinstance(raw.columns, pd.MultiIndex):
        close = raw["Close"].dropna(how="all")
    else:
        close = raw[["Close"]].dropna(how="all")
        close.columns = [tickers[0]]

    available = [t for t in tickers if t in close.columns and close[t].dropna().count() >= 30]
    unavailable = [t for t in tickers if t not in available]

    if len(available) < 2:
        unclustered = []
        for t in tickers:
            h = holdings[t]
            unclustered.append({
                "ticker": t,
                "description": h.get("description") or "",
                "quantity": _safe(h.get("quantity")),
                "current_value": _safe(h.get("current_value")),
                "monthly_income": _safe(h.get("approx_monthly_income")),
                "current_yield": _safe(h.get("current_annual_yield")),
            })
        return jsonify(clusters=[], unclustered=unclustered, correlation_matrix={})

    daily_returns = close[available].pct_change()
    corr = daily_returns.corr(min_periods=30).fillna(0)

    # Build correlation matrix response
    corr_matrix = {}
    for t1 in available:
        corr_matrix[t1] = {}
        for t2 in available:
            corr_matrix[t1][t2] = _safe(corr.loc[t1, t2])

    # Hierarchical clustering
    # Convert correlation to distance: distance = 1 - correlation
    dist_matrix = 1 - corr.values
    np.fill_diagonal(dist_matrix, 0)
    # Ensure symmetry and no negative values
    dist_matrix = np.clip((dist_matrix + dist_matrix.T) / 2, 0, 2)

    try:
        condensed = squareform(dist_matrix)
        Z = linkage(condensed, method="average")
        labels = fcluster(Z, t=dist_threshold, criterion="distance")
    except Exception:
        # Fallback: treat every ticker as unclustered
        labels = list(range(1, len(available) + 1))

    # Group tickers by cluster label
    cluster_groups = {}
    for i, t in enumerate(available):
        lbl = int(labels[i])
        cluster_groups.setdefault(lbl, []).append(t)

    clusters = []
    unclustered = []
    cluster_id = 0

    for lbl, group_tickers in sorted(cluster_groups.items()):
        if len(group_tickers) < 2:
            # Single ticker = unclustered
            h = holdings[group_tickers[0]]
            unclustered.append({
                "ticker": group_tickers[0],
                "description": h.get("description") or "",
                "quantity": _safe(h.get("quantity")),
                "current_value": _safe(h.get("current_value")),
                "monthly_income": _safe(h.get("approx_monthly_income")),
                "current_yield": _safe(h.get("current_annual_yield")),
            })
            continue

        cluster_id += 1

        # Calculate avg correlation within group
        pair_corrs = []
        for i, t1 in enumerate(group_tickers):
            for t2 in group_tickers[i + 1:]:
                val = corr.loc[t1, t2]
                if not math.isnan(val):
                    pair_corrs.append(val)
        avg_corr = float(np.mean(pair_corrs)) if pair_corrs else 0.0

        # Identify underlying: most common meaningful words in descriptions
        all_words = []
        for t in group_tickers:
            desc = (holdings[t].get("description") or "").strip()
            if desc:
                # Filter out common filler words
                stop = {"etf", "fund", "inc", "corp", "the", "and", "of", "trust",
                        "a", "an", "for", "in", "on", "to", "with", "&", "-", ""}
                words = [w for w in desc.lower().split() if w not in stop and len(w) > 1]
                all_words.extend(words)

        if all_words:
            word_counts = Counter(all_words)
            # Take the top 2-3 most common words to form the underlying name
            common = word_counts.most_common(3)
            underlying = " ".join(w.title() for w, _ in common if _ > 1)
            if not underlying:
                underlying = common[0][0].title() if common else group_tickers[0]
        else:
            # Fallback: ticker with most history
            max_count = 0
            best = group_tickers[0]
            for t in group_tickers:
                cnt = close[t].dropna().count() if t in close.columns else 0
                if cnt > max_count:
                    max_count = cnt
                    best = t
            underlying = best

        # Build ticker detail list
        ticker_details = []
        total_value = 0.0
        total_income = 0.0
        for t in group_tickers:
            h = holdings[t]
            cv = float(h.get("current_value") or 0)
            mi = float(h.get("approx_monthly_income") or 0)
            total_value += cv
            total_income += mi

            # Correlation to group average
            group_others = [t2 for t2 in group_tickers if t2 != t]
            if group_others:
                corr_to_group = float(np.mean([corr.loc[t, t2] for t2 in group_others
                                                if not math.isnan(corr.loc[t, t2])]))
            else:
                corr_to_group = 1.0

            ticker_details.append({
                "ticker": t,
                "description": h.get("description") or "",
                "quantity": _safe(h.get("quantity")),
                "current_value": _safe(cv),
                "monthly_income": _safe(mi),
                "current_yield": _safe(h.get("current_annual_yield")),
                "correlation_to_group": _safe(corr_to_group),
            })

        clusters.append({
            "cluster_id": cluster_id,
            "underlying": underlying,
            "tickers": ticker_details,
            "avg_correlation": _safe(avg_corr),
            "total_value": _safe(total_value),
            "total_monthly_income": _safe(total_income),
        })

    # Add unavailable tickers to unclustered
    for t in unavailable:
        h = holdings[t]
        unclustered.append({
            "ticker": t,
            "description": h.get("description") or "",
            "quantity": _safe(h.get("quantity")),
            "current_value": _safe(h.get("current_value")),
            "monthly_income": _safe(h.get("approx_monthly_income")),
            "current_yield": _safe(h.get("current_annual_yield")),
        })

    # Add "nearest cluster" info for each unclustered ticker
    for item in unclustered:
        t = item["ticker"]
        if t not in corr_matrix:
            continue
        best_cluster = None
        best_corr = -1.0
        for c in clusters:
            cluster_tickers = [ct["ticker"] for ct in c["tickers"]]
            vals = []
            for ct in cluster_tickers:
                if ct in corr_matrix.get(t, {}):
                    v = corr_matrix[t][ct]
                    if v is not None:
                        vals.append(v)
            if vals:
                avg = sum(vals) / len(vals)
                if avg > best_corr:
                    best_corr = avg
                    best_cluster = c["underlying"]
        if best_cluster and best_corr > 0:
            item["nearest_cluster"] = best_cluster
            item["nearest_correlation"] = _safe(best_corr)

    return jsonify(
        clusters=clusters,
        unclustered=unclustered,
        correlation_matrix=corr_matrix,
    )


@app.route("/api/consolidation/simulate", methods=["POST"])
def consolidation_simulate():
    """Simulate selling one ticker and redistributing to another."""
    import math
    import warnings
    import numpy as np
    import yfinance as yf
    warnings.filterwarnings("ignore")

    def _safe(v):
        if v is None:
            return None
        try:
            f = float(v)
            return None if (math.isnan(f) or math.isinf(f)) else round(f, 4)
        except (TypeError, ValueError):
            return None

    data = request.get_json(force=True, silent=True) or {}
    sell_ticker = str(data.get("sell_ticker", "")).strip().upper()
    buy_ticker = str(data.get("buy_ticker", "")).strip().upper()
    period = data.get("period", "1y")

    if not sell_ticker or not buy_ticker:
        return jsonify(error="Both sell_ticker and buy_ticker are required."), 400
    if sell_ticker == buy_ticker:
        return jsonify(error="sell_ticker and buy_ticker must be different."), 400

    valid_periods = {"3mo", "6mo", "1y", "2y", "5y"}
    if period not in valid_periods:
        period = "1y"

    # Get current holdings data (aggregate across all owners in profile)
    _, pids = get_profile_filter()
    placeholders = ",".join("?" * len(pids))
    conn = get_connection()
    sell_rows = conn.execute(
        f"SELECT ticker, description, quantity, current_value, current_price, "
        f"approx_monthly_income, current_annual_yield "
        f"FROM all_account_info WHERE ticker = ? AND profile_id IN ({placeholders}) "
        f"AND quantity > 0",
        [sell_ticker] + pids,
    ).fetchall()
    buy_rows = conn.execute(
        f"SELECT ticker, description, quantity, current_value, current_price, "
        f"approx_monthly_income, current_annual_yield "
        f"FROM all_account_info WHERE ticker = ? AND profile_id IN ({placeholders}) "
        f"AND quantity > 0",
        [buy_ticker] + pids,
    ).fetchall()
    conn.close()

    if not sell_rows:
        return jsonify(error=f"No holding found for {sell_ticker}."), 404
    if not buy_rows:
        return jsonify(error=f"No holding found for {buy_ticker}."), 404

    # Aggregate across owners
    def _aggregate_rows(rows):
        agg = dict(rows[0])
        for r in rows[1:]:
            agg["quantity"] = (agg["quantity"] or 0) + (r["quantity"] or 0)
            agg["current_value"] = (agg["current_value"] or 0) + (r["current_value"] or 0)
            agg["approx_monthly_income"] = (agg["approx_monthly_income"] or 0) + (r["approx_monthly_income"] or 0)
        cv = agg.get("current_value") or 0
        mi = agg.get("approx_monthly_income") or 0
        agg["current_annual_yield"] = (mi * 12 / cv * 100) if cv > 0 else 0
        return agg

    sell_data = _aggregate_rows(sell_rows)
    buy_data = _aggregate_rows(buy_rows)

    sell_value = float(sell_data.get("current_value") or 0)
    sell_income = float(sell_data.get("approx_monthly_income") or 0)
    sell_yield = float(sell_data.get("current_annual_yield") or 0)
    buy_value = float(buy_data.get("current_value") or 0)
    buy_income = float(buy_data.get("approx_monthly_income") or 0)
    buy_yield = float(buy_data.get("current_annual_yield") or 0)
    buy_price = float(buy_data.get("current_price") or 0)

    # _aggregate_rows always returns yield as percentage (e.g. 8.59 = 8.59%)
    # Convert to decimal for income calculations
    sell_yield_dec = sell_yield / 100
    buy_yield_dec = buy_yield / 100

    if buy_price <= 0:
        return jsonify(error=f"Cannot simulate: {buy_ticker} has no valid price."), 400

    # Calculate consolidation impact
    new_shares_added = sell_value / buy_price
    new_total_value = sell_value + buy_value  # value doesn't change at moment of swap
    # New income from added shares: sell_value * (buy annual yield as decimal) / 12
    new_monthly_from_added = (sell_value * buy_yield_dec) / 12 if buy_yield_dec else 0
    new_monthly_income = buy_income + new_monthly_from_added
    old_combined_income = sell_income + buy_income
    income_change = new_monthly_income - old_combined_income
    income_change_pct = (income_change / old_combined_income * 100) if old_combined_income > 0 else 0
    new_yield = (new_monthly_income * 12 / new_total_value * 100) if new_total_value > 0 else 0

    # Download historical data for performance comparison
    both_tickers = list(set([sell_ticker, buy_ticker]))
    try:
        raw = _chunked_yf_download(" ".join(both_tickers), period=period, auto_adjust=True,
                          actions=True, progress=False)
        if raw.empty:
            return jsonify(error="No historical data returned from Yahoo Finance.")
    except Exception as e:
        return jsonify(error=f"Failed to fetch data: {str(e)}")

    if isinstance(raw.columns, pd.MultiIndex):
        close = raw["Close"].dropna(how="all")
        # Try to get dividends
        try:
            divs = raw["Dividends"].fillna(0)
        except KeyError:
            divs = pd.DataFrame(0, index=close.index, columns=close.columns)
    else:
        close = raw[["Close"]].dropna(how="all")
        close.columns = [both_tickers[0]]
        try:
            divs = raw[["Dividends"]].fillna(0)
            divs.columns = [both_tickers[0]]
        except KeyError:
            divs = pd.DataFrame(0, index=close.index, columns=[both_tickers[0]])

    # Ensure both tickers present
    for t in [sell_ticker, buy_ticker]:
        if t not in close.columns:
            return jsonify(error=f"No price data available for {t}.")
        if t not in divs.columns:
            divs[t] = 0

    # Calculate performance metrics for each ticker
    perf = {}
    history = {"dates": [], "sell_total_return": [], "buy_total_return": [],
               "sell_price_return": [], "buy_price_return": []}

    for label, t in [("sell_ticker", sell_ticker), ("buy_ticker", buy_ticker)]:
        tc = close[t].dropna()
        if len(tc) < 2:
            perf[label] = {"total_return": None, "price_return": None,
                           "volatility": None, "max_drawdown": None, "sharpe": None}
            continue

        prices = tc.values
        start_price = float(prices[0])

        # Price return series
        price_ret_series = (prices / start_price - 1) * 100

        # Total return (including dividends reinvested)
        td = divs[t].reindex(tc.index).fillna(0)
        cum_shares = 1.0
        total_ret_series = np.zeros(len(tc))
        for i in range(len(tc)):
            d = float(td.iloc[i])
            p = float(prices[i])
            if p > 0 and d > 0:
                cum_shares += d * cum_shares / p
            total_ret_series[i] = (cum_shares * p / start_price - 1) * 100

        # Daily returns for volatility/sharpe
        daily_ret = np.diff(prices) / prices[:-1]
        vol = float(np.std(daily_ret) * np.sqrt(252) * 100) if len(daily_ret) > 1 else 0

        # Max drawdown
        running_max = np.maximum.accumulate(prices)
        drawdowns = (prices - running_max) / running_max * 100
        max_dd = float(np.min(drawdowns))

        # Sharpe (annualized, assuming 0 risk-free rate)
        mean_daily = float(np.mean(daily_ret)) if len(daily_ret) > 0 else 0
        std_daily = float(np.std(daily_ret)) if len(daily_ret) > 0 else 1
        sharpe = (mean_daily / std_daily * np.sqrt(252)) if std_daily > 0 else 0

        perf[label] = {
            "total_return": _safe(total_ret_series[-1]),
            "price_return": _safe(price_ret_series[-1]),
            "volatility": _safe(vol),
            "max_drawdown": _safe(max_dd),
            "sharpe": _safe(sharpe),
        }

        # Build history arrays
        dates_str = [d.strftime("%Y-%m-%d") for d in tc.index]
        if label == "sell_ticker":
            history["dates"] = dates_str
            history["sell_total_return"] = [_safe(v) for v in total_ret_series]
            history["sell_price_return"] = [_safe(v) for v in price_ret_series]
        else:
            # Align buy to same dates if needed (use its own dates)
            history["buy_total_return"] = [_safe(v) for v in total_ret_series]
            history["buy_price_return"] = [_safe(v) for v in price_ret_series]

    # If dates differ between tickers, use the intersection
    # For simplicity, use sell_ticker dates as base (already set)

    return jsonify(
        sell={
            "ticker": sell_ticker,
            "current_value": _safe(sell_value),
            "monthly_income": _safe(sell_income),
            "current_yield": _safe(sell_yield),
        },
        buy={
            "ticker": buy_ticker,
            "current_value": _safe(buy_value),
            "monthly_income": _safe(buy_income),
            "current_yield": _safe(buy_yield),
        },
        after_consolidation={
            "new_shares_added": _safe(new_shares_added),
            "new_total_value": _safe(new_total_value),
            "new_monthly_income": _safe(new_monthly_income),
            "income_change": _safe(income_change),
            "income_change_pct": _safe(income_change_pct),
            "new_yield": _safe(new_yield),
        },
        performance_comparison=perf,
        history=history,
    )


@app.route("/api/consolidation/regimes", methods=["POST"])
def consolidation_regimes():
    """Analyze performance by market regime (bull/bear/sideways + high vol overlay)."""
    import math
    import warnings
    import numpy as np
    import yfinance as yf
    warnings.filterwarnings("ignore")

    def _safe(v):
        if v is None:
            return None
        try:
            f = float(v)
            return None if (math.isnan(f) or math.isinf(f)) else round(f, 4)
        except (TypeError, ValueError):
            return None

    data = request.get_json(force=True, silent=True) or {}
    tickers = [str(t).strip().upper() for t in data.get("tickers", []) if str(t).strip()]
    period = data.get("period", "2y")

    if not tickers:
        return jsonify(error="No tickers provided."), 400
    if len(tickers) > 20:
        return jsonify(error="Maximum 20 tickers allowed."), 400

    valid_periods = {"6mo", "1y", "2y", "5y", "max"}
    if period not in valid_periods:
        period = "2y"

    # Download SPY, VIX, and all requested tickers
    all_dl = list(set(tickers + ["SPY", "^VIX"]))
    try:
        raw = _chunked_yf_download(" ".join(all_dl), period=period, auto_adjust=True,
                          actions=True, progress=False)
        if raw.empty:
            return jsonify(error="No price data returned from Yahoo Finance.")
    except Exception as e:
        return jsonify(error=f"Failed to fetch data: {str(e)}")

    if isinstance(raw.columns, pd.MultiIndex):
        close = raw["Close"].dropna(how="all")
        try:
            divs = raw["Dividends"].fillna(0)
        except KeyError:
            divs = pd.DataFrame(0, index=close.index, columns=close.columns)
    else:
        close = raw[["Close"]].dropna(how="all")
        close.columns = [all_dl[0]]
        try:
            divs = raw[["Dividends"]].fillna(0)
            divs.columns = [all_dl[0]]
        except KeyError:
            divs = pd.DataFrame(0, index=close.index, columns=[all_dl[0]])

    if "SPY" not in close.columns:
        return jsonify(error="Could not fetch SPY benchmark data.")

    # VIX data
    has_vix = "^VIX" in close.columns
    if has_vix:
        vix_series = close["^VIX"].ffill()
    else:
        vix_series = pd.Series(20.0, index=close.index)

    spy = close["SPY"].dropna()
    if len(spy) < 63:
        return jsonify(error="Not enough SPY data to calculate regimes (need 63+ trading days).")

    # Calculate SPY 63-day rolling return (percentage)
    spy_rolling = spy.pct_change(63) * 100
    spy_rolling = spy_rolling.reindex(close.index)

    # Classify regimes
    regime_series = pd.Series("sideways", index=close.index)
    regime_series[spy_rolling > 5] = "bull"
    regime_series[spy_rolling < -5] = "bear"
    # First 63 days have no rolling return; label as sideways
    regime_series.iloc[:63] = "sideways"

    # High vol overlay
    high_vol = vix_series > 25

    # Count regime days
    total_days = len(regime_series)
    regime_counts = regime_series.value_counts()
    regimes_summary = {}
    for r in ["bull", "bear", "sideways"]:
        days = int(regime_counts.get(r, 0))
        regimes_summary[r] = {
            "days": days,
            "pct_of_period": _safe(days / total_days * 100) if total_days > 0 else 0,
        }

    # Analyze each ticker per regime
    data_warnings = {}
    ticker_performance = {}

    for t in tickers:
        if t not in close.columns:
            data_warnings[t] = "No price data available"
            continue

        tc = close[t].dropna()
        if len(tc) < 30:
            data_warnings[t] = f"Only {len(tc)} days of history available"
            continue

        # Note if limited history
        expected_days = len(close.index)
        actual_days = len(tc)
        if actual_days < expected_days * 0.8:
            months_avail = round(actual_days / 21)
            data_warnings[t] = f"Only {months_avail} months of history available"

        td = divs[t].reindex(tc.index).fillna(0) if t in divs.columns else pd.Series(0, index=tc.index)

        ticker_perf = {}

        for regime_name in ["bull", "bear", "sideways", "high_vol"]:
            if regime_name == "high_vol":
                mask = high_vol.reindex(tc.index).fillna(False)
            else:
                mask = (regime_series.reindex(tc.index) == regime_name)

            regime_prices = tc[mask]
            regime_divs = td[mask]

            if len(regime_prices) < 2:
                ticker_perf[regime_name] = {
                    "price_return": None, "income_return": None,
                    "total_return": None, "max_drawdown": None, "volatility": None,
                }
                continue

            # Daily returns within regime days
            prices_arr = regime_prices.values
            daily_rets = np.diff(prices_arr) / prices_arr[:-1]
            daily_rets = daily_rets[np.isfinite(daily_rets)]

            if len(daily_rets) < 1:
                ticker_perf[regime_name] = {
                    "price_return": None, "income_return": None,
                    "total_return": None, "max_drawdown": None, "volatility": None,
                }
                continue

            # Annualized price return
            n_days = len(regime_prices)
            cumulative_price_ret = (float(prices_arr[-1]) / float(prices_arr[0]) - 1)
            ann_factor = 252 / n_days if n_days > 0 else 1
            ann_price_ret = cumulative_price_ret * ann_factor * 100

            # Income return: sum of dividends / average price, annualized
            total_div = float(regime_divs.sum())
            avg_price = float(regime_prices.mean())
            if avg_price > 0 and n_days > 0:
                income_ret_period = total_div / avg_price
                ann_income_ret = income_ret_period * ann_factor * 100
            else:
                ann_income_ret = 0

            ann_total_ret = ann_price_ret + ann_income_ret

            # Volatility (annualized)
            vol = float(np.std(daily_rets) * np.sqrt(252) * 100) if len(daily_rets) > 1 else 0

            # Max drawdown within regime periods
            running_max = np.maximum.accumulate(prices_arr)
            drawdowns = (prices_arr - running_max) / running_max * 100
            max_dd = float(np.min(drawdowns))

            ticker_perf[regime_name] = {
                "price_return": _safe(ann_price_ret),
                "income_return": _safe(ann_income_ret),
                "total_return": _safe(ann_total_ret),
                "max_drawdown": _safe(max_dd),
                "volatility": _safe(vol),
            }

        ticker_performance[t] = ticker_perf

    # Build timeline for visualization
    timeline = {
        "dates": [d.strftime("%Y-%m-%d") for d in close.index],
        "regime": [regime_series.iloc[i] for i in range(len(regime_series))],
        "spy_price": [_safe(float(spy.reindex(close.index).iloc[i]))
                      if i < len(spy.reindex(close.index)) and not math.isnan(spy.reindex(close.index).iloc[i])
                      else None
                      for i in range(len(close.index))],
        "vix": [_safe(float(vix_series.iloc[i]))
                if not math.isnan(vix_series.iloc[i])
                else None
                for i in range(len(close.index))],
    }

    return jsonify(
        regimes=regimes_summary,
        ticker_performance=ticker_performance,
        timeline=timeline,
        data_warnings=data_warnings,
    )


