# ── Portfolio Growth 2 ──────────────────────────────────────────────────────────

@app.route("/api/growth-2/data", methods=["GET"])
def growth_2_data():
    """Portfolio value + invested timeline and P&L breakdown by source."""
    import math
    import warnings
    import numpy as np
    import yfinance as yf
    from datetime import datetime, timedelta
    warnings.filterwarnings("ignore")

    def _clean(v):
        if v is None:
            return None
        try:
            if math.isnan(v) or math.isinf(v):
                return None
        except (TypeError, ValueError):
            pass
        return v

    profile_id = get_profile_id()
    period_param = request.args.get("period", "1y").strip().lower()
    tickers_param = request.args.get("tickers", "")
    group_by = request.args.get("group_by", "none")
    show_cost_basis = request.args.get("show_cost_basis", "true") == "true"
    show_trades = request.args.get("show_trades", "false") == "true"
    profit_mode = request.args.get("profit_mode", "dollar")
    pl_basis = request.args.get("pl_basis", "selected_period")
    group_profit_source = request.args.get("group_profit_source", "true") == "true"

    period_map = {
        "7d": 7, "1m": 30, "3m": 90, "6m": 180,
        "ytd": "ytd", "1y": 365, "5y": 1825, "all": "max",
    }
    yf_period = "1y"
    start_date = None
    end_date = None
    if period_param in period_map:
        val = period_map[period_param]
        if val == "ytd":
            start_date = datetime(datetime.now().year, 1, 1)
            yf_period = "ytd"
        elif val == "max":
            yf_period = "max"
        else:
            start_date = datetime.now() - timedelta(days=val)
            if val <= 7:
                yf_period = "1mo"
            elif val <= 30:
                yf_period = "3mo"
            elif val <= 90:
                yf_period = "6mo"
            elif val <= 180:
                yf_period = "1y"
            elif val <= 365:
                yf_period = "1y"
            else:
                yf_period = "max"
    elif period_param == "custom":
        custom_start = request.args.get("start_date", "").strip()
        custom_end = request.args.get("end_date", "").strip()
        if not custom_start or not custom_end:
            return jsonify({"error": "Choose both a custom start date and end date"}), 400
        try:
            start_date = datetime.strptime(custom_start, "%Y-%m-%d")
            end_date = datetime.strptime(custom_end, "%Y-%m-%d")
        except ValueError:
            return jsonify({"error": "Custom dates must use YYYY-MM-DD format"}), 400
        if start_date > end_date:
            return jsonify({"error": "Custom start date must be on or before the end date"}), 400
        if end_date.date() > datetime.now().date():
            return jsonify({"error": "Custom end date cannot be in the future"}), 400
    else:
        return jsonify({"error": f"Unsupported period: {period_param}"}), 400

    conn = get_connection()

    rows = conn.execute(
        """SELECT ticker, quantity, price_paid, purchase_value, current_value,
                  purchase_date
           FROM all_account_info
           WHERE profile_id = ? AND purchase_value > 0 AND quantity > 0""",
        (profile_id,),
    ).fetchall()

    cats = conn.execute(
        "SELECT id, name FROM categories WHERE profile_id = ? ORDER BY sort_order, name",
        (profile_id,),
    ).fetchall()
    categories = [{"id": c["id"], "name": c["name"]} for c in cats]

    cat_map_rows = conn.execute(
        "SELECT tc.ticker, c.name AS category_name "
        "FROM ticker_categories tc JOIN categories c ON c.id = tc.category_id "
        "WHERE tc.profile_id = ?", (profile_id,)
    ).fetchall()
    cat_map = {r["ticker"]: r["category_name"] for r in cat_map_rows}

    # Owner (profile_id=1) is the combined view — fetch transactions across all profiles
    if profile_id == 1:
        txn_rows = conn.execute(
            """SELECT ticker, transaction_type, transaction_date, shares,
                      price_per_share, fees, realized_gain
               FROM transactions
               ORDER BY transaction_date"""
        ).fetchall()
        div_rows = conn.execute(
            """SELECT ticker, payment_date, amount
               FROM dividend_payments
               ORDER BY payment_date"""
        ).fetchall()
    else:
        txn_rows = conn.execute(
            """SELECT ticker, transaction_type, transaction_date, shares,
                      price_per_share, fees, realized_gain
               FROM transactions
               WHERE profile_id = ?
               ORDER BY transaction_date""",
            (profile_id,),
        ).fetchall()
        div_rows = conn.execute(
            """SELECT ticker, payment_date, amount
               FROM dividend_payments
               WHERE profile_id = ?
               ORDER BY payment_date""",
            (profile_id,),
        ).fetchall()

    conn.close()

    if not rows:
        return jsonify({"error": "No holdings found", "categories": categories, "tickers": []}), 400

    all_tickers = sorted(set(r["ticker"] for r in rows))

    filter_tickers = None
    if tickers_param:
        filter_tickers = set(t.strip().upper() for t in tickers_param.split(",") if t.strip())

    active_rows = [r for r in rows if not filter_tickers or r["ticker"] in filter_tickers]
    if not active_rows:
        return jsonify({"error": "No holdings after filter", "categories": categories, "tickers": all_tickers}), 400

    active_tickers = sorted(set(r["ticker"] for r in active_rows))
    quantities = {
        t: sum(float(r["quantity"] or 0) for r in active_rows if r["ticker"] == t)
        for t in active_tickers
    }
    cost_basis = {
        t: sum(float(r["purchase_value"] or 0) for r in active_rows if r["ticker"] == t)
        for t in active_tickers
    }
    current_values = {
        t: sum(float(r["current_value"] or 0) for r in active_rows if r["ticker"] == t)
        for t in active_tickers
    }

    # Build the transaction list before constructing the value timeline so a
    # ticker is never backfilled into dates before the portfolio owned it.
    txn_tickers = set(dict(tx)["ticker"] for tx in txn_rows)
    synthetic_txns = []
    for r in active_rows:
        t = r["ticker"]
        if t not in txn_tickers and r["purchase_date"]:
            synthetic_txns.append({
                "ticker": t,
                "transaction_type": "BUY",
                "transaction_date": r["purchase_date"],
                "shares": float(r["quantity"] or 0),
                "price_per_share": float(r["price_paid"] or 0),
                "fees": 0,
                "realized_gain": None,
            })
    all_txns = [dict(tx) for tx in txn_rows] + synthetic_txns

    ownership_starts = {}

    def _record_ownership_start(ticker, value):
        if ticker not in active_tickers or not value:
            return
        try:
            ts = pd.Timestamp(value)
            if ts.tzinfo is not None:
                ts = ts.tz_localize(None)
            ts = ts.normalize()
        except Exception:
            return
        current = ownership_starts.get(ticker)
        if current is None or ts < current:
            ownership_starts[ticker] = ts

    for r in active_rows:
        _record_ownership_start(r["ticker"], r["purchase_date"])
    # Any recorded trade is a safer ownership boundary than inventing history
    # back to a ticker's inception. This covers legacy holdings whose purchase
    # date was not imported.
    for tx in all_txns:
        _record_ownership_start(tx.get("ticker"), tx.get("transaction_date"))

    known_portfolio_start = min(ownership_starts.values()) if ownership_starts else None
    if known_portfolio_start is not None:
        for t in active_tickers:
            ownership_starts.setdefault(t, known_portfolio_start)

    yahoo_by_ticker = {t: _yahoo_symbol_for_ticker(t) for t in active_tickers}
    ticker_by_yahoo = {yf_t: t for t, yf_t in yahoo_by_ticker.items()}
    yahoo_tickers = list(dict.fromkeys(yahoo_by_ticker.values()))

    try:
        download_kwargs = {
            "auto_adjust": True,
            "actions": True,
            "progress": False,
        }
        if period_param == "custom":
            download_kwargs["start"] = start_date.strftime("%Y-%m-%d")
            # Yahoo treats end as exclusive, so include the user's end date.
            download_kwargs["end"] = (end_date + timedelta(days=1)).strftime("%Y-%m-%d")
        else:
            download_kwargs["period"] = yf_period
        raw = _chunked_yf_download(" ".join(yahoo_tickers), **download_kwargs)
        if raw.empty:
            return jsonify({"error": "No price data", "tickers": all_tickers}), 500
    except Exception as e:
        return jsonify({"error": str(e), "tickers": all_tickers}), 500

    if isinstance(raw.columns, pd.MultiIndex):
        close = raw["Close"].dropna(how="all")
        divs_raw = raw["Dividends"].fillna(0) if "Dividends" in raw.columns.get_level_values(0) else pd.DataFrame(0, index=close.index, columns=close.columns)
    else:
        close = raw[["Close"]].dropna(how="all")
        close.columns = [yahoo_tickers[0]]
        divs_raw = raw[["Dividends"]].fillna(0) if "Dividends" in raw.columns else pd.DataFrame(0, index=close.index, columns=[yahoo_tickers[0]])
        divs_raw.columns = [yahoo_tickers[0]]

    close = close.rename(columns=ticker_by_yahoo)
    divs_raw = divs_raw.rename(columns=ticker_by_yahoo)
    # yfinance (esp. when rate-limited across chunked downloads) can return the
    # same symbol as duplicate columns. That makes close[t] a DataFrame instead
    # of a Series, which later blows up float(series.iloc[-1]) with
    # "float() argument must be ... not 'Series'". Collapse dupes to one column.
    if close.columns.duplicated().any():
        close = close.loc[:, ~close.columns.duplicated()]
    if divs_raw.columns.duplicated().any():
        divs_raw = divs_raw.loc[:, ~divs_raw.columns.duplicated()]
    if close.index.has_duplicates:
        close = close.loc[~close.index.duplicated(keep="last")]
    if divs_raw.index.has_duplicates:
        divs_raw = divs_raw.loc[~divs_raw.index.duplicated(keep="last")]
    avail = [t for t in active_tickers if t in close.columns and not close[t].dropna().empty]
    if not avail:
        return jsonify({"error": "No price data for selected holdings", "tickers": all_tickers}), 500

    first_valid = close[avail].dropna(how="all").index[0]
    close_a = close[avail].loc[first_valid:].ffill()
    divs_a = divs_raw.reindex(index=close_a.index, columns=avail).fillna(0)

    lower_bounds = []
    if start_date is not None:
        lower_bounds.append(pd.Timestamp(start_date))
    owned_dates = [ownership_starts[t] for t in avail if t in ownership_starts]
    if owned_dates:
        lower_bounds.append(min(owned_dates))
    if lower_bounds:
        effective_start = max(lower_bounds)
        close_a = close_a.loc[close_a.index >= effective_start]
        divs_a = divs_a.loc[divs_a.index >= effective_start]
    if end_date is not None:
        end_ts = pd.Timestamp(end_date)
        close_a = close_a.loc[close_a.index <= end_ts]
        divs_a = divs_a.loc[divs_a.index <= end_ts]

    if close_a.empty:
        return jsonify({"error": "No data for selected period", "tickers": all_tickers}), 500

    # ── Portfolio value timeline (current shares * historical prices) ──
    port_value = pd.Series(0.0, index=close_a.index)
    value_scale = {}
    position_values = {}
    use_current_value_scale = end_date is None or end_date.date() >= datetime.now().date()
    for t in avail:
        q = quantities.get(t, 0)
        series = close_a[t] * q
        latest_market_value = float(series.dropna().iloc[-1]) if not series.dropna().empty else 0
        stored_current_value = current_values.get(t, 0)
        scale = (
            stored_current_value / latest_market_value
            if use_current_value_scale and latest_market_value > 0 and stored_current_value > 0
            else 1.0
        )
        value_scale[t] = scale
        owned_from = ownership_starts.get(t)
        owned_mask = close_a.index >= owned_from if owned_from is not None else series.notna()
        ticker_value = (series * scale).where(owned_mask, 0).fillna(0)
        position_values[t] = ticker_value
        port_value += ticker_value

    total_invested = sum(cost_basis.get(t, 0) for t in avail)
    invested_series = pd.Series(0.0, index=close_a.index)
    for t in avail:
        owned_from = ownership_starts.get(t)
        if owned_from is None:
            invested_series += cost_basis.get(t, 0)
        else:
            invested_series.loc[invested_series.index >= owned_from] += cost_basis.get(t, 0)

    # ── Build transaction timeline for trades overlay ──
    # Tickers that have explicit transaction records
    trade_points = []
    if show_trades:
        for tx in all_txns:
            if tx["ticker"] not in avail:
                continue
            try:
                td = pd.Timestamp(tx["transaction_date"])
            except Exception:
                continue
            if td >= close_a.index[0] and td <= close_a.index[-1]:
                idx_pos = close_a.index.searchsorted(td, side="right") - 1
                if idx_pos >= 0:
                    val_at = float(port_value.iloc[idx_pos])
                    trade_points.append({
                        "date": tx["transaction_date"],
                        "value": round(val_at, 2),
                        "type": tx["transaction_type"],
                        "ticker": tx["ticker"],
                        "shares": float(tx["shares"] or 0),
                        "price": float(tx["price_per_share"] or 0),
                    })

    # ── P&L breakdown ──
    dates_idx = close_a.index

    # Capital gain = portfolio_value - invested at each point
    # For "from first trade": use absolute values from start
    # For "selected period": compute relative to period start
    start_port_val = float(port_value.iloc[0])

    # Cumulative dividends within the period (from yfinance per-share data)
    cum_divs_dollar = pd.Series(0.0, index=dates_idx)
    ticker_dividends = {}
    for t in avail:
        owned_from = ownership_starts.get(t)
        owned_mask = dates_idx >= owned_from if owned_from is not None else pd.Series(True, index=dates_idx)
        ticker_div = divs_a[t].where(owned_mask, 0).cumsum() * quantities.get(t, 0)
        ticker_dividends[t] = ticker_div
        cum_divs_dollar += ticker_div

    # Realized P&L from transactions
    realized_cum = pd.Series(0.0, index=dates_idx)
    fees_cum = pd.Series(0.0, index=dates_idx)
    for tx in all_txns:
        tx = dict(tx)
        if tx["ticker"] not in avail:
            continue
        try:
            td = pd.Timestamp(tx["transaction_date"])
        except Exception:
            continue
        if td < dates_idx[0] or td > dates_idx[-1]:
            continue
        mask = dates_idx >= td
        if tx["transaction_type"] == "SELL" and tx["realized_gain"] is not None:
            realized_cum.loc[mask] += float(tx["realized_gain"])
        if tx["fees"] is not None and float(tx["fees"]) > 0:
            fees_cum.loc[mask] -= float(tx["fees"])

    # Capital gain (unrealized price change)
    if pl_basis == "first_trade":
        capital_gain = port_value - total_invested
    else:
        capital_gain = port_value - start_port_val

    total_pl = capital_gain + cum_divs_dollar + realized_cum + fees_cum

    # Convert to percentage if needed
    def to_pct(series, base):
        if base > 0:
            return series / base * 100
        return series * 0

    dates_str = [d.strftime("%Y-%m-%d") for d in dates_idx]

    def _cs(s):
        return [_clean(round(float(v), 2)) for v in s]

    result = {
        "dates": dates_str,
        "portfolio_value": _cs(port_value),
        "invested": _cs(invested_series),
        "tickers": all_tickers,
        "categories": categories,
        "ticker_info": {t: {"category": cat_map.get(t, "Other"), "quantity": quantities.get(t, 0), "cost_basis": cost_basis.get(t, 0)} for t in avail},
        "trade_points": trade_points,
    }

    base_for_pct = total_invested if pl_basis == "first_trade" else start_port_val

    if profit_mode == "pct":
        result["performance"] = {
            "capital_gain": _cs(to_pct(capital_gain, base_for_pct)),
            "dividends": _cs(to_pct(cum_divs_dollar, base_for_pct)),
            "realized_pl": _cs(to_pct(realized_cum, base_for_pct)),
            "fees": _cs(to_pct(fees_cum, base_for_pct)),
            "total": _cs(to_pct(total_pl, base_for_pct)),
        }
        result["profit_unit"] = "%"
    else:
        result["performance"] = {
            "capital_gain": _cs(capital_gain),
            "dividends": _cs(cum_divs_dollar),
            "realized_pl": _cs(realized_cum),
            "fees": _cs(fees_cum),
            "total": _cs(total_pl),
        }
        result["profit_unit"] = "$"

    # Per-ticker breakdown when grouping requested
    if group_by == "ticker":
        per_ticker = {}
        for t in avail:
            tv = position_values[t]
            td_div = ticker_dividends[t]
            if pl_basis == "first_trade":
                t_cg = tv - cost_basis.get(t, 0)
            else:
                t_cg = tv - float(tv.iloc[0])
            t_total = t_cg + td_div
            tb = cost_basis.get(t, 0) if pl_basis == "first_trade" else float(tv.iloc[0])
            if profit_mode == "pct":
                per_ticker[t] = {
                    "value": _cs(tv),
                    "capital_gain": _cs(to_pct(t_cg, tb)),
                    "dividends": _cs(to_pct(td_div, tb)),
                    "total": _cs(to_pct(t_total, tb)),
                }
            else:
                per_ticker[t] = {
                    "value": _cs(tv),
                    "capital_gain": _cs(t_cg),
                    "dividends": _cs(td_div),
                    "total": _cs(t_total),
                }
        result["per_ticker"] = per_ticker
    elif group_by == "category":
        per_cat = {}
        for t in avail:
            cat_name = cat_map.get(t, "Other")
            if cat_name not in per_cat:
                per_cat[cat_name] = {"value": np.zeros(len(dates_idx)), "cg": np.zeros(len(dates_idx)), "div": np.zeros(len(dates_idx)), "cost": 0.0, "start_val": 0.0}
            tv = position_values[t].values
            td_div = ticker_dividends[t].values
            per_cat[cat_name]["value"] += tv
            per_cat[cat_name]["div"] += td_div
            per_cat[cat_name]["cost"] += cost_basis.get(t, 0)
            per_cat[cat_name]["start_val"] += float(position_values[t].iloc[0])

        grouped = {}
        for cat_name, d in per_cat.items():
            if pl_basis == "first_trade":
                cg = d["value"] - d["cost"]
                base = d["cost"]
            else:
                cg = d["value"] - d["start_val"]
                base = d["start_val"]
            total = cg + d["div"]
            if profit_mode == "pct":
                grouped[cat_name] = {
                    "value": _cs(d["value"]),
                    "capital_gain": _cs(to_pct(pd.Series(cg), base)),
                    "dividends": _cs(to_pct(pd.Series(d["div"]), base)),
                    "total": _cs(to_pct(pd.Series(total), base)),
                }
            else:
                grouped[cat_name] = {
                    "value": _cs(d["value"]),
                    "capital_gain": _cs(cg),
                    "dividends": _cs(d["div"]),
                    "total": _cs(total),
                }
        result["per_category"] = grouped

    return jsonify(result)


# ── ETF Providers lookup ───────────────────────────────────────────────────────

@app.route("/api/etf-providers")
def etf_providers():
    conn = get_connection()
    rows = conn.execute(
        """SELECT p.provider, p.total_assets, p.num_funds, p.avg_expense
           FROM etf_providers p
           WHERE EXISTS (SELECT 1 FROM etf_provider_funds f WHERE f.provider_id = p.id)
           ORDER BY p.total_assets DESC NULLS LAST"""
    ).fetchall()
    conn.close()
    return jsonify([
        {"provider": r[0], "total_assets": r[1], "num_funds": r[2], "avg_expense": r[3]}
        for r in rows
    ])


@app.route("/api/etf-providers/<provider_name>/funds")
def etf_provider_funds(provider_name):
    conn = get_connection()
    rows = conn.execute(
        """SELECT f.symbol, f.fund_name, f.assets, f.div_yield, f.exp_ratio, f.change_1y
           FROM etf_provider_funds f
           JOIN etf_providers p ON p.id = f.provider_id
           WHERE LOWER(p.provider) = LOWER(?)
           ORDER BY f.assets DESC NULLS LAST""",
        (provider_name,)
    ).fetchall()
    conn.close()
    return jsonify([
        {"symbol": r[0], "fund_name": r[1], "assets": r[2],
         "div_yield": r[3], "exp_ratio": r[4], "change_1y": r[5]}
        for r in rows
    ])


def _stockanalysis_provider_slug(provider):
    provider = re.sub(r"[^a-z0-9]+", "-", (provider or "").strip().lower())
    return provider.strip("-")


def _stockanalysis_number(value):
    import html

    text = html.unescape(str(value or "")).strip().replace(",", "")
    if not text or text in {"-", "—", "N/A"}:
        return None
    mult = 1.0
    suffix = text[-1:].upper()
    if suffix in {"K", "M", "B", "T"}:
        text = text[:-1]
        mult = {"K": 1e3, "M": 1e6, "B": 1e9, "T": 1e12}[suffix]
    text = re.sub(r"[^0-9.\-]", "", text)
    if not text:
        return None
    try:
        return round(float(text) * mult, 6)
    except Exception:
        return None


def _stockanalysis_percent(value):
    import html

    text = html.unescape(str(value or "")).strip()
    if not text or text in {"-", "—", "N/A"}:
        return None
    text = re.sub(r"[^0-9.\-]", "", text)
    if not text:
        return None
    try:
        return round(float(text), 3)
    except Exception:
        return None


def _stockanalysis_clean_text(value):
    import html

    text = re.sub(r"(?s)<!--.*?-->", "", str(value or ""))
    text = re.sub(r"(?s)<[^>]+>", "", text)
    return html.unescape(re.sub(r"\s+", " ", text)).strip()


def _fetch_stockanalysis_provider_funds(provider):
    import requests

    slug = _stockanalysis_provider_slug(provider)
    if not slug:
        raise ValueError("Provider is required")

    url = f"https://stockanalysis.com/etf/provider/{slug}/"
    resp = requests.get(url, timeout=30, headers={"User-Agent": "Mozilla/5.0 PortfolioTrackingClient/1.0"})
    if resp.status_code == 404:
        raise ValueError(f"StockAnalysis provider page was not found for {provider}")
    resp.raise_for_status()

    table_match = re.search(r'(?is)<table[^>]*id="main-table"[^>]*>(.*?)</table>', resp.text or "")
    if not table_match:
        raise ValueError("Could not find the StockAnalysis ETF table")

    funds = []
    for row_html in re.findall(r"(?is)<tr[^>]*>(.*?)</tr>", table_match.group(1)):
        cells = re.findall(r"(?is)<td[^>]*>(.*?)</td>", row_html)
        if len(cells) < 6:
            continue
        symbol_match = re.search(r"(?is)<a[^>]*>(.*?)</a>", cells[0])
        symbol = _stockanalysis_clean_text(symbol_match.group(1) if symbol_match else cells[0]).upper()
        if not symbol:
            continue
        funds.append({
            "symbol": symbol,
            "fund_name": _stockanalysis_clean_text(cells[1]),
            "assets": _stockanalysis_number(cells[2]),
            "div_yield": _stockanalysis_percent(cells[3]),
            "exp_ratio": _stockanalysis_percent(cells[4]),
            "change_1y": _stockanalysis_percent(cells[5]),
        })

    if not funds:
        raise ValueError(f"No funds were parsed from StockAnalysis for {provider}")
    return funds, url


@app.route("/api/etf-providers/<provider_name>/refresh-stockanalysis", methods=["POST"])
def refresh_etf_provider_stockanalysis(provider_name):
    provider_name = (provider_name or "").strip()
    if not provider_name:
        return jsonify({"error": "Provider is required"}), 400

    try:
        scraped_funds, source_url = _fetch_stockanalysis_provider_funds(provider_name)
    except Exception as e:
        return jsonify({"error": str(e)}), 502

    conn = get_connection()
    try:
        row = conn.execute(
            "SELECT id, provider FROM etf_providers WHERE LOWER(provider) = LOWER(?)",
            (provider_name,),
        ).fetchone()
        if not row:
            return jsonify({"error": f"Provider not found in database: {provider_name}"}), 404

        provider_id = row["id"]
        existing = {
            str(r["symbol"]).upper()
            for r in conn.execute("SELECT symbol FROM etf_provider_funds WHERE provider_id = ?", (provider_id,)).fetchall()
        }

        inserted = 0
        updated = 0
        for fund in scraped_funds:
            was_existing = fund["symbol"] in existing
            conn.execute(
                """INSERT INTO etf_provider_funds
                   (provider_id, symbol, fund_name, assets, div_yield, exp_ratio, change_1y)
                   VALUES (?, ?, ?, ?, ?, ?, ?)
                   ON CONFLICT(provider_id, symbol) DO UPDATE SET
                     fund_name = excluded.fund_name,
                     assets = excluded.assets,
                     div_yield = excluded.div_yield,
                     exp_ratio = excluded.exp_ratio,
                     change_1y = excluded.change_1y""",
                (
                    provider_id,
                    fund["symbol"],
                    fund["fund_name"],
                    fund["assets"],
                    fund["div_yield"],
                    fund["exp_ratio"],
                    fund["change_1y"],
                ),
            )
            if was_existing:
                updated += 1
            else:
                inserted += 1

        summary = conn.execute(
            """SELECT COUNT(*) AS num_funds,
                      SUM(assets) AS total_assets,
                      AVG(exp_ratio) AS avg_expense
               FROM etf_provider_funds
               WHERE provider_id = ?""",
            (provider_id,),
        ).fetchone()
        conn.execute(
            "UPDATE etf_providers SET total_assets = ?, num_funds = ?, avg_expense = ? WHERE id = ?",
            (summary["total_assets"], summary["num_funds"], summary["avg_expense"], provider_id),
        )
        conn.commit()
    finally:
        conn.close()

    return jsonify({
        "provider": row["provider"],
        "source_url": source_url,
        "parsed": len(scraped_funds),
        "updated": updated,
        "inserted": inserted,
        "total_assets": summary["total_assets"],
        "num_funds": summary["num_funds"],
        "avg_expense": summary["avg_expense"],
    })


@app.route("/api/etf-funds/search")
def etf_funds_search():
    search_q = request.args.get('q', '').strip().upper()
    provider_filter = request.args.get('provider', '').strip()
    sort_by = request.args.get('sort', 'symbol')

    # Whitelist sort column to prevent SQL injection
    allowed_sorts = {'symbol', 'fund_name', 'assets', 'div_yield', 'exp_ratio', 'change_1y', 'provider'}
    if sort_by not in allowed_sorts:
        sort_by = 'symbol'

    where_clauses = ["1=1"]
    params = []

    if search_q:
        where_clauses.append("(f.symbol LIKE ? OR f.fund_name LIKE ?)")
        params.extend([f"%{search_q}%", f"%{search_q}%"])

    if provider_filter:
        where_clauses.append("LOWER(p.provider) = LOWER(?)")
        params.append(provider_filter)

    conn = get_connection()
    rows = conn.execute(f"""
        SELECT f.symbol, f.fund_name, p.provider, f.assets,
               f.div_yield, f.exp_ratio, f.change_1y
        FROM etf_provider_funds f
        JOIN etf_providers p ON f.provider_id = p.id
        WHERE {' AND '.join(where_clauses)}
        ORDER BY {sort_by}
        LIMIT 5000
    """, params).fetchall()
    conn.close()

    funds = [
        {'symbol': r[0], 'fund_name': r[1], 'provider': r[2],
         'assets': r[3], 'div_yield': r[4], 'exp_ratio': r[5], 'change_1y': r[6], 'source': 'db'}
        for r in rows
    ]

    exact_symbol_found = any(str(f.get('symbol') or '').upper() == search_q for f in funds)
    looks_like_ticker = bool(re.fullmatch(r"[A-Z0-9.\-]{1,10}", search_q or ""))

    # If a ticker-like query has no exact DB symbol match, try Yahoo Finance.
    # This catches cases like "BST" where fuzzy DB search returns "YBST".
    if search_q and not provider_filter and looks_like_ticker and not exact_symbol_found:
        try:
            import yfinance as yf
            tk = yf.Ticker(search_q)
            info = tk.info or {}
            name = info.get('longName') or info.get('shortName') or ''
            if name:
                # trailingAnnualDividendYield is decimal (0.008 = 0.8%); dividendYield is already %
                trail_yield = info.get('trailingAnnualDividendYield')
                div_y_pct   = info.get('dividendYield')
                if trail_yield is not None and trail_yield > 0:
                    div_yield = round(trail_yield * 100, 3)
                elif div_y_pct is not None and div_y_pct > 0:
                    div_yield = round(float(div_y_pct), 3)
                else:
                    div_yield = None

                # netExpenseRatio is already in % form (0.49 = 0.49%)
                raw_exp = info.get('annualReportExpenseRatio') or info.get('netExpenseRatio')
                exp_ratio = round(float(raw_exp), 3) if raw_exp else None

                # 52WeekChange is decimal; ytdReturn is already %
                raw_1y = info.get('52WeekChange')
                change_1y = round(raw_1y * 100, 3) if raw_1y else None

                yahoo_fund = {
                    'symbol':    search_q,
                    'fund_name': name,
                    'provider':  info.get('fundFamily') or info.get('quoteType', 'Unknown'),
                    'assets':    info.get('totalAssets'),
                    'div_yield': div_yield,
                    'exp_ratio': exp_ratio,
                    'change_1y': change_1y,
                    'source':    'yahoo',
                }
                funds = [yahoo_fund] + [
                    f for f in funds
                    if str(f.get('symbol') or '').upper() != search_q
                ]
        except Exception:
            pass

    return jsonify({'funds': funds, 'total': len(funds)})


def _cef_cache_get(key):
    entry = _CEFCONNECT_CACHE.get(key)
    if not entry:
        return None
    ts, payload = entry
    if time.time() - ts > _CEFCONNECT_TTL_SEC:
        _CEFCONNECT_CACHE.pop(key, None)
        return None
    return payload


def _cef_cache_set(key, payload):
    _CEFCONNECT_CACHE[key] = (time.time(), payload)


def _cefconnect_json(path, cache_key):
    cached = _cef_cache_get(cache_key)
    if cached is not None:
        return cached

    req = urllib.request.Request(
        f"{_CEFCONNECT_BASE_URL}{path}",
        headers={
            "Accept": "application/json,text/plain,*/*",
            "User-Agent": "PortfolioTrackingClient/1.0",
        },
    )
    with urllib.request.urlopen(req, timeout=20) as resp:
        payload = json.loads(resp.read().decode("utf-8"))
    _cef_cache_set(cache_key, payload)
    return payload


def _cefconnect_text(path, cache_key):
    cached = _cef_cache_get(cache_key)
    if cached is not None:
        return cached

    req = urllib.request.Request(
        f"{_CEFCONNECT_BASE_URL}{path}",
        headers={
            "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
            "User-Agent": "PortfolioTrackingClient/1.0",
        },
    )
    with urllib.request.urlopen(req, timeout=20) as resp:
        payload = resp.read().decode("utf-8", errors="replace")
    _cef_cache_set(cache_key, payload)
    return payload


def _cef_value(row, key):
    value = row.get(key)
    if isinstance(value, str) and value.strip() == "":
        return None
    return value


